describe('LoginView', () => {
    beforeEach(() => {
        vi.clearAllMocks();
        // 重置 auth store
        useAuthStore.getState().logout();
    });

    const renderLoginView = () => {
        return render(
            <BrowserRouter>
                <LoginView />
            </BrowserRouter>
        );
    };

    // 获取表单元素的辅助函数
    const getFormElements = () => {
        // 使用 role 选择器，因为原始 label 没有 for 属性
        const usernameInput = screen.getByRole('textbox'); // 只有一个 text input
        const passwordInput = document.querySelector('input[type="password"]') as HTMLInputElement;
        const submitButton = screen.getByRole('button', { name: /^登录$/ });
        return { usernameInput, passwordInput, submitButton };
    };

    describe('渲染', () => {
        it('应显示登录表单标题', () => {
            renderLoginView();

            expect(screen.getByRole('heading', { name: '登录' })).toBeInTheDocument();
        });

        it('应包含用户名和密码输入框', () => {
            renderLoginView();

            const { usernameInput, passwordInput } = getFormElements();
            expect(usernameInput).toBeInTheDocument();
            expect(passwordInput).toBeInTheDocument();
        });

        it('应显示登录按钮', () => {
            renderLoginView();

            expect(screen.getByRole('button', { name: /^登录$/ })).toBeInTheDocument();
        });

        it('应显示访问产品官网按钮', () => {
            renderLoginView();

            expect(screen.getByRole('button', { name: /访问产品官网/ })).toBeInTheDocument();
        });
    });

    describe('表单输入', () => {
        it('应能输入用户名和密码', async () => {
            renderLoginView();
            const user = userEvent.setup();

            const { usernameInput, passwordInput } = getFormElements();

            await user.type(usernameInput, 'admin');
            await user.type(passwordInput, 'password123');

            expect(usernameInput).toHaveValue('admin');
            expect(passwordInput).toHaveValue('password123');
        });
    });

    describe('登录成功', () => {
        it('登录成功应调用 AuthStore.login 并导航', async () => {
            const mockLoginResponse = {
                code: 200,
                data: {
                    token: 'jwt-token-123',
                    user: {
                        id: 'user-001',
                        username: 'admin',
                        fullName: '管理员',
                        roles: ['ADMIN'],
                        permissions: ['archive:read'],
