}

/**
 * 全宗切换器组件属性
 */
export interface FondsSwitcherProps {
    /** 当前选中的全宗 */
    currentFonds: Fonds | null;
    /** 全宗列表 */
    fondsList: Fonds[];
    /** 是否正在加载 */
    isLoading: boolean;
    /** 是否已从持久化存储中恢复 */
    hasHydrated: boolean;
    /** 加载全宗列表的回调 */
    onLoadFondsList: () => void;
    /** 设置当前全宗的回调 */
    onSetCurrentFonds: (fonds: Fonds) => void;
}

/**
 * 全宗切换器组件
 *
 * 用于顶部导航栏，支持在多个全宗间快速切换
 *
 * 【架构说明】共享组件不导入 store，通过 props 接收数据和回调
 */
export const FondsSwitcher: React.FC<FondsSwitcherProps> = ({
    currentFonds,
    fondsList,
    isLoading,
    hasHydrated,
    onLoadFondsList,
    onSetCurrentFonds,
}) => {
    // 初始加载全宗列表
    useEffect(() => {
        if (hasHydrated) {
            onLoadFondsList();
        }
    }, [hasHydrated, onLoadFondsList]);

    const [isOpen, setIsOpen] = React.useState(false);


    // 加载状态
    if (isLoading && fondsList.length === 0) {
        return (
            <div className="flex items-center px-3 py-1.5 text-sm">
                <Loader2 size={14} className="animate-spin text-slate-400" />
            </div>
        );
    }

    // 无全宗权限
    if (fondsList.length === 0 && hasHydrated) {
        return (
            <div className="flex items-center px-3 py-1.5 text-sm text-slate-400">
                暂无全宗权限
            </div>
        );
    }

    // 单个全宗：纯文本显示
    if (fondsList.length === 1) {
        const fonds = fondsList[0];
        return (
            <div className="flex items-center px-3 py-1.5 text-sm">
                <span className="text-slate-700 font-medium">
                    {fonds.fondsName}
                </span>
                <span className="ml-2 text-xs text-slate-400 font-mono">
                    {fonds.fondsCode}
                </span>
            </div>
        );
    }

    return (
        <div className="relative">
            <button
                onClick={() => setIsOpen(!isOpen)}
                className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-slate-100 hover:bg-slate-200 transition-colors text-sm"
            >
                <Building2 size={16} className="text-slate-500" />
                <span className="font-medium text-slate-700 max-w-[120px] truncate">
                    {isLoading ? (
                        <Loader2 size={14} className="animate-spin" />
                    ) : (
                        currentFonds?.fondsName || '选择全宗'
                    )}
                </span>
                <ChevronDown
                    size={14}
                    className={`text-slate-400 transition-transform ${isOpen ? 'rotate-180' : ''}`}
                />
            </button>

            {/* 下拉菜单 */}
            {isOpen && (
                <>
                    {/* 遮罩 */}
                    <div
                        className="fixed inset-0 z-40"
                        onClick={() => setIsOpen(false)}
                    />

                    {/* 菜单内容 */}
                    <div className="absolute top-full left-0 mt-1 w-64 bg-white rounded-lg shadow-lg border border-slate-200 z-50 py-1 animate-in fade-in slide-in-from-top-2 duration-150">
                        <div className="px-3 py-2 border-b border-slate-100">
                            <p className="text-xs text-slate-500 font-medium">切换全宗</p>
                        </div>
                        <div className="max-h-60 overflow-y-auto">
                            {fondsList.map((fonds) => (
                                <button
                                    key={fonds.id}
                                    onClick={() => {
                                        onSetCurrentFonds(fonds);
                                        setIsOpen(false);
                                    }}
                                    className={`w-full flex items-center justify-between px-3 py-2 text-left hover:bg-slate-50 transition-colors ${currentFonds?.id === fonds.id ? 'bg-primary-50' : ''
                                        }`}
                                >
                                    <div className="flex-1 min-w-0">
                                        <p className={`text-sm font-medium truncate ${currentFonds?.id === fonds.id ? 'text-primary-600' : 'text-slate-700'
                                            }`}>
                                            {fonds.fondsName}
                                        </p>
                                        <p className="text-xs text-slate-400 font-mono">
                                            {fonds.fondsCode}
                                        </p>
                                    </div>
                                    {currentFonds?.id === fonds.id && (
                                        <Check size={16} className="text-primary-600 flex-shrink-0 ml-2" />
                                    )}
                                </button>
                            ))}
                        </div>
                    </div>
                </>
            )}
        </div>
    );
};

export default FondsSwitcher;

// Input: React、lucide-react 图标、react-dom
// Output: React 组件 MetadataEditModal（纯 UI 层）
// Pos: 通用复用组件
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useState, useEffect, useCallback } from 'react';
import { FileText } from 'lucide-react';
import { FormModal } from '../modals/FormModal';
import { MetadataForm, MetadataFormData, MetadataFormConfig } from './MetadataForm';

// ✅ 已移除对 api/client 的依赖（遵循架构边界规则 A）
// API 调用现在通过 props 传入


// 单据类型选项 (《会计档案管理办法》财政部79号令 第6条)
const VOUCHER_TYPE_OPTIONS = [
    { code: 'AC01', label: '会计凭证', desc: '原始凭证（发票、收据、银行回单等）、记账凭证' },
    { code: 'AC02', label: '会计账簿', desc: '总账、明细账、日记账、固定资产卡片' },
    { code: 'AC03', label: '财务会计报告', desc: '月度/季度/半年度/年度报告' },
    { code: 'AC04', label: '其他会计资料', desc: '银行对账单、纳税申报表、会计档案鉴定意见书等' },
];

// 默认字段配置
const DEFAULT_FIELDS: MetadataFormConfig[] = [
    {
        name: 'fiscalYear',
        label: '会计年度',
        required: true,
        type: 'text',
        placeholder: '例：2025',
        pattern: '\\d{4}',
    },
    {
        name: 'voucherType',
        label: '单据类型',
        required: true,
        type: 'select',
        options: VOUCHER_TYPE_OPTIONS,
    },
    {
        name: 'creator',
        label: '责任者',
        required: true,
        type: 'text',
        placeholder: '例：财务部 张三',
    },
    {
        name: 'fondsCode',
        label: '全宗号',
        required: false,
        type: 'text',
        placeholder: '例：COMP001',
        helperText: '可选',
    },
    {
        name: 'modifyReason',
        label: '修改原因',
        required: true,
        type: 'textarea',
        placeholder: '例：补充上传发票的分类信息',
        rows: 2,
        helperText: '合规要求',
    },
];

interface FileDetail {
    id: string;
    fileName: string;
    fileType: string;
    status: string;
    fiscalYear?: string;
    voucherType?: string;
    creator?: string;
    fondsCode?: string;
}

interface MetadataUpdatePayload {
    id: string;
    fiscalYear: string;
    voucherType: string;
    creator: string;
    fondsCode?: string;
    modifyReason: string;
}

interface MetadataEditModalProps {
    isOpen: boolean;
    onClose: () => void;
    fileId: string;
    fileName: string;
    onSuccess?: () => void;
    // ✅ 新增：通过 props 传入 API 操作（遵循架构边界规则 A）
    onLoadFileDetail: (fileId: string) => Promise<FileDetail | null>;
    onUpdateMetadata: (payload: MetadataUpdatePayload) => Promise<{ success: boolean; message?: string }>;
    /** 自定义字段配置 */
    fieldConfig?: MetadataFormConfig[];
}

export const MetadataEditModal: React.FC<MetadataEditModalProps> = ({
    isOpen,
    onClose,
    fileId,
    fileName,
    onSuccess,
    onLoadFileDetail,
    onUpdateMetadata,
    fieldConfig = DEFAULT_FIELDS,
}) => {
    const [loading, setLoading] = useState(false);
    const [saving, setSaving] = useState(false);
    const [error, setError] = useState<string | null>(null);

    // Form state using unified MetadataFormData
    const [formData, setFormData] = useState<MetadataFormData>({
        fiscalYear: new Date().getFullYear().toString(),
        voucherType: 'AC01',
        creator: '',
        fondsCode: '',
        modifyReason: '',
    });

    const loadFileDetail = useCallback(async () => {
        setLoading(true);
        setError(null);
        try {
            const detail = await onLoadFileDetail(fileId);
            if (detail) {
                setFormData({
                    fiscalYear: detail.fiscalYear || new Date().getFullYear().toString(),
                    voucherType: detail.voucherType || 'AC01',
                    creator: detail.creator || '',
                    fondsCode: detail.fondsCode || '',
                    modifyReason: '',
                });
            }
        } catch (err) {
            console.error('Failed to load file detail:', err);
        } finally {
            setLoading(false);
        }
    }, [fileId, onLoadFileDetail]);

    // Load existing metadata when modal opens
    useEffect(() => {
        if (isOpen && fileId) {
            loadFileDetail();
        }
    }, [isOpen, fileId, loadFileDetail]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        // Validation
        const requiredFields = fieldConfig.filter(f => f.required);
        for (const field of requiredFields) {
            if (!formData[field.name as keyof MetadataFormData]) {
                setError(`请填写${field.label}`);
                return;
            }
        }

        setSaving(true);
        setError(null);

        try {
            const result = await onUpdateMetadata({
                id: fileId,
                fiscalYear: formData.fiscalYear,
                voucherType: formData.voucherType,
                creator: formData.creator,
                fondsCode: formData.fondsCode || undefined,
                modifyReason: formData.modifyReason,
            });

            if (result.success) {
                onSuccess?.();
                onClose();
            } else {
                setError(result.message || '更新失败');
            }
        } catch (err: any) {
            console.error('Failed to update metadata:', err);
            setError(err.message || '更新失败，请重试');
        } finally {
            setSaving(false);
        }
    };

    const header = (
        <div className="flex items-center gap-3">
            <div className="p-2 bg-blue-100 dark:bg-blue-900/30 rounded-lg">
                <FileText className="w-5 h-5 text-blue-600 dark:text-blue-400" />
            </div>
            <div>
                <h3 className="text-lg font-semibold text-slate-800 dark:text-white">元数据补录</h3>
                <p className="text-sm text-slate-500 dark:text-slate-400 truncate max-w-[280px]">{fileName}</p>
            </div>
        </div>
    );

    return (
        <FormModal
            isOpen={isOpen}
            onClose={onClose}
            onSubmit={handleSubmit}
            isSubmitting={saving}
            error={error}
            title="元数据补录"
            header={header}
            submitText="保存并重新检测"
        >
            <MetadataForm
                data={formData}
                onChange={setFormData}
                fields={fieldConfig}
                loading={loading}
                error={error}
            />
        </FormModal>
    );
};

export default MetadataEditModal;

// Input: React, lucide-react 图标
// Output: MetadataForm 组件
// Pos: 通用复用组件 - 元数据表单组件

import React, { ReactNode } from 'react';
import { RefreshCw, AlertTriangle } from 'lucide-react';
import { MetadataFormField, FieldOption } from './MetadataFormField';

export interface MetadataFormData {
  fiscalYear: string;
  voucherType: string;
  creator: string;
  fondsCode?: string;
  modifyReason: string;
}

export interface MetadataFormConfig {
  name: string;
  label: string;
  required?: boolean;
  type?: 'text' | 'select' | 'textarea' | 'number';
  placeholder?: string;
  options?: FieldOption[];
  pattern?: string;
  rows?: number;
  helperText?: string;
}

export interface MetadataFormProps {
  /** 表单数据 */
  data: MetadataFormData;
  /** 数据变化回调 */
  onChange: (data: MetadataFormData) => void;
  /** 字段配置 */
  fields: MetadataFormConfig[];
  /** 加载状态 */
  loading?: boolean;
  /** 错误信息 */
  error?: string | null;
  /** 提交处理 */
  onSubmit?: (e: React.FormEvent) => void;
  /** 额外操作按钮 */
  actions?: ReactNode;
}

export const MetadataForm: React.FC<MetadataFormProps> = ({
  data,
  onChange,
  fields,
  loading = false,
  error,
  onSubmit,
  actions,
}) => {
  const handleChange = (name: keyof MetadataFormData, value: string) => {
    onChange({ ...data, [name]: value });
  };

  const getSelectedOptionDesc = (fieldName: string): string | undefined => {
    const field = fields.find((f) => f.name === fieldName);
    if (!field?.options) return undefined;
    const option = field.options.find((o) => o.code === data[fieldName as keyof MetadataFormData]);
    return option?.desc;
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-8">
        <RefreshCw className="w-6 h-6 text-blue-500 animate-spin" />
      </div>
    );
  }

  return (
    <form onSubmit={onSubmit} className="space-y-4">
      {fields.map((field) => (
        <MetadataFormField
          key={field.name}
          name={field.name}
          label={field.label}
          required={field.required}
          type={field.type}
          value={data[field.name as keyof MetadataFormData] || ''}
          onChange={(value) => handleChange(field.name as keyof MetadataFormData, value)}
          placeholder={field.placeholder}
          options={field.options}
          selectedOptionDesc={getSelectedOptionDesc(field.name)}
          pattern={field.pattern}
          rows={field.rows}
          helperText={field.helperText}
        />
      ))}

      {error && (
        <div className="flex items-center gap-2 p-3 bg-rose-50 dark:bg-rose-900/20 text-rose-600 dark:text-rose-400 rounded-xl text-sm">
          <AlertTriangle size={16} />
          {error}
        </div>
      )}

      {actions}
    </form>
  );
};

export default MetadataForm;

// Input: React
// Output: MetadataFormField 组件
// Pos: 通用复用组件 - 元数据字段输入组件

import React from 'react';

export interface FieldOption {
  code: string;
  label: string;
  desc?: string;
}

export interface MetadataFormFieldProps {
  /** 字段名称 */
  name: string;
  /** 字段标签 */
  label: string;
  /** 是否必填 */
  required?: boolean;
  /** 字段类型 */
  type?: 'text' | 'select' | 'textarea' | 'number';
  /** 字段值 */
  value: string;
  /** 值变化回调 */
  onChange: (value: string) => void;
  /** 占位符 */
  placeholder?: string;
  /** Select 选项 */
  options?: FieldOption[];
  /** 选中选项的描述 */
  selectedOptionDesc?: string;
  /** 输入模式 */
  pattern?: string;
  /** 行数（textarea） */
  rows?: number;
  /** 辅助文本 */
  helperText?: string;
}

export const MetadataFormField: React.FC<MetadataFormFieldProps> = ({
  name,
  label,
  required = false,
  type = 'text',
  value,
  onChange,
  placeholder,
  options,
  selectedOptionDesc,
  pattern,
  rows = 2,
  helperText,
}) => {
  const baseClassName =
    'w-full px-4 py-2.5 border border-slate-200 dark:border-slate-600 rounded-xl bg-white dark:bg-slate-700 text-slate-800 dark:text-white focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all';

  const renderInput = () => {
    switch (type) {
      case 'select':
        return (
          <select
            name={name}
            value={value}
            onChange={(e) => onChange(e.target.value)}
            className={baseClassName}
          >
            {options?.map((opt) => (
              <option key={opt.code} value={opt.code}>
                {opt.code} - {opt.label}
              </option>
            ))}
          </select>
        );

      case 'textarea':
        return (
          <textarea
            name={name}
            value={value}
            onChange={(e) => onChange(e.target.value)}
            placeholder={placeholder}
            rows={rows}
            className={`${baseClassName} resize-none`}
          />
        );

      case 'number':
        return (
          <input
            type="number"
            name={name}
            value={value}
            onChange={(e) => onChange(e.target.value)}
            placeholder={placeholder}
            className={baseClassName}
          />
        );

      default:
        return (
          <input
            type="text"
            name={name}
            value={value}
            onChange={(e) => onChange(e.target.value)}
            placeholder={placeholder}
            pattern={pattern}
            className={baseClassName}
          />
        );
    }
  };

  return (
    <div>
      <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
        {label} {required && <span className="text-rose-500">*</span>}
        {helperText && <span className="ml-2 text-xs text-slate-400">({helperText})</span>}
      </label>
      {renderInput()}
      {selectedOptionDesc && (
        <p className="mt-1 text-xs text-slate-500 dark:text-slate-400">
          {selectedOptionDesc}
        </p>
      )}
    </div>
  );
};

export default MetadataFormField;

// Input: React、本地模块 utils/storage
// Output: React 组件 OfdViewer
// Pos: 通用复用组件
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useEffect, useState } from 'react'

interface FileViewerProps {
    fileUrl: string
    fileType?: string  // 'pdf', 'ofd', etc.
    fileName?: string
    className?: string
    style?: React.CSSProperties
    token?: string  // Auth token for fetching files (avoid store coupling)
}

export function FileViewer({ fileUrl, fileType, fileName, className, style, token }: FileViewerProps) {
    const [loading, setLoading] = useState(true)
    const [error, setError] = useState<string | null>(null)
    const [blobUrl, setBlobUrl] = useState<string | null>(null)
    const [detectedType, setDetectedType] = useState<string>('')

    useEffect(() => {
        let mounted = true
        let objectUrl: string | null = null
        setLoading(true)
        setError(null)

        async function loadFile() {
            try {
                // Use token from props instead of store (avoid shared component coupling)
                const headers: Record<string, string> = {}
                if (token) {
                    headers['Authorization'] = `Bearer ${token}`
                }

                const response = await fetch(fileUrl, { headers })
                if (!response.ok) {
                    throw new Error(`Failed to fetch file: ${response.statusText}`)
                }

                const contentType = response.headers.get('content-type') || ''
                const blob = await response.blob()
                const url = URL.createObjectURL(blob)
                objectUrl = url

                // Detect file type from content-type or file extension
                let type = ''
                const inputType = fileType?.toLowerCase() || ''

                // First check input fileType
                if (inputType.includes('pdf') || inputType === 'pdf') {
                    type = 'pdf'
                } else if (inputType.includes('ofd') || inputType === 'ofd') {
                    type = 'ofd'
                }

                // Fallback to content-type detection
                if (!type) {
                    if (contentType.includes('pdf')) {
                        type = 'pdf'
                    } else if (contentType.includes('ofd')) {
                        type = 'ofd'
                    } else if (contentType.includes('image')) {
                        type = 'image'
                    } else if (fileName?.toLowerCase().endsWith('.pdf')) {
                        type = 'pdf'
                    } else if (fileName?.toLowerCase().endsWith('.ofd')) {
                        type = 'ofd'
                    } else if (fileName?.toLowerCase().match(/\.(jpg|jpeg|png|gif|bmp|webp)$/)) {
                        type = 'image'
                    }
                }

                if (mounted) {
                    setBlobUrl(url)
                    setDetectedType(type)
                }
            } catch (err: any) {
                console.error("File load error:", err)
                if (mounted) {
                    setError(err.message || 'Failed to load file')
                }
            } finally {
                if (mounted) {
                    setLoading(false)
                }
            }
        }

        loadFile()

        return () => {
            mounted = false
            if (objectUrl) {
                URL.revokeObjectURL(objectUrl)
            }
        }
    }, [fileUrl, fileType, fileName])

    const handleDownload = () => {
        if (blobUrl) {
            const link = document.createElement('a')
            link.href = blobUrl
            link.download = fileName || `document.${detectedType || 'file'}`
            link.click()
        }
    }

    if (loading) {
        return (
            <div className={`file-viewer-wrapper ${className || ''}`} style={style}>
                <div className="p-8 text-center text-gray-500 h-full flex flex-col items-center justify-center">
                    <div className="animate-spin inline-block w-8 h-8 border-4 border-blue-500 border-t-transparent rounded-full mb-4"></div>
                    <p>正在加载文件...</p>
                </div>
            </div>
        )
    }

    if (error) {
        return (
            <div className={`file-viewer-wrapper ${className || ''}`} style={style}>
                <div className="p-8 text-center text-red-500 h-full flex items-center justify-center">
                    <p>加载失败: {error}</p>
                </div>
            </div>
        )
    }

    // PDF - Use browser's built-in viewer
    if (detectedType === 'pdf' && blobUrl) {
        return (
            <div className={`file-viewer-wrapper ${className || ''}`} style={style}>
                <iframe
                    src={blobUrl}
                    className="w-full h-full min-h-[500px] border-0"
                    title="PDF文件预览"
                />
            </div>
        )
    }

    // Image Preview
    if (detectedType === 'image' && blobUrl) {
        return (
            <div className={`file-viewer-wrapper ${className || ''} flex items-center justify-center bg-gray-100 overflow-auto`} style={style}>
                <img
                    src={blobUrl}
                    alt={fileName || 'Preview'}
                    className="max-w-full max-h-full object-contain shadow-lg"
                />
            </div>
        )
    }

    // OFD and other formats - Show download UI
    return (
        <div className={`file-viewer-wrapper ${className || ''}`} style={style}>
            <div className="flex flex-col items-center justify-center h-full min-h-[400px] bg-slate-50 rounded-lg p-8">
                <div className="text-6xl mb-4">{detectedType === 'ofd' ? '📄' : '📁'}</div>
                <h3 className="text-xl font-bold text-slate-700 mb-2">
                    {detectedType === 'ofd' ? 'OFD 电子凭证' : '文件预览'}
                </h3>
                <p className="text-slate-500 mb-6 text-center">
                    {detectedType === 'ofd' ? (
                        <>OFD 是国家标准版式文档格式<br />请下载后使用专业阅读器查看</>
                    ) : (
                        <>此文件类型暂不支持在线预览<br />请下载后查看</>
                    )}
                </p>
                <button
                    onClick={handleDownload}
                    className="px-6 py-3 bg-blue-600 text-white font-medium rounded-lg hover:bg-blue-700 transition-colors shadow-lg shadow-blue-500/30 flex items-center gap-2"
                >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
