// Pos: src/components/operations/BatchResultModal.tsx

import React, { useMemo } from 'react';
import { CheckCircle, XCircle, RotateCcw, Download } from 'lucide-react';
import { BaseModal } from '../modals/BaseModal';

/**
 * 常量定义
 */
const ERROR_LIST_MAX_HEIGHT = 'max-h-60';
const ICON_SIZE_SM = 16;
const ICON_SIZE_MD = 20;
const ICON_SIZE_LG = 24;

/**
 * 批量操作错误项
 */
export interface BatchError {
  /** 记录 ID */
  id: number;
  /** 失败原因 */
  reason: string;
}

/**
 * 批量操作结果弹窗 Props
 */
export interface BatchResultModalProps {
  /** 是否显示对话框 */
  visible: boolean;
  /** 成功数量 */
  successCount: number;
  /** 失败数量 */
  failedCount: number;
  /** 错误列表 */
  errors?: BatchError[];
  /** 重试回调（传入失败的 ID 列表） */
  onRetry?: (failedIds: number[]) => void | Promise<void>;
  /** 关闭回调 */
  onClose: () => void;
  /** 操作类型（用于标题显示） */
  operationType?: 'approval' | 'operation';
  /** 导出失败报告回调 */
  onExportReport?: () => void | Promise<void>;
  /** 重试中状态 */
  isRetrying?: boolean;
}

/**
 * 批量操作结果弹窗组件
 *
 * 展示批量操作的成功/失败统计和失败详情，支持：
 * - 成功/失败数量统计摘要
 * - 失败项明细列表（可滚动）
 * - 重试失败项功能
 * - 导出失败报告功能
 *
 * @example
 * ```tsx
 * <BatchResultModal
 *   visible={open}
 *   successCount={95}
 *   failedCount={5}
 *   errors={[{ id: 1, reason: '状态不允许审批' }]}
 *   onRetry={handleRetry}
 *   onClose={() => setOpen(false)}
 *   operationType="approval"
 * />
 * ```
 */
export const BatchResultModal: React.FC<BatchResultModalProps> = ({
  visible,
  successCount,
  failedCount,
  errors = [],
  onRetry,
  onClose,
  operationType = 'operation',
  onExportReport,
  isRetrying = false,
}) => {
  /**
   * 处理重试
   */
  const handleRetry = async () => {
    if (onRetry && errors.length > 0) {
      const failedIds = errors.map((e) => e.id);
      await onRetry(failedIds);
    }
  };

  /**
   * 处理导出报告
   */
  const handleExportReport = async () => {
    if (onExportReport) {
      await onExportReport();
    }
  };

  /**
   * 计算总体状态
   */
  const totalStatus = failedCount === 0 ? 'success' : successCount === 0 ? 'error' : 'partial';

  /**
   * 状态配置（使用 useMemo 优化性能）
   */
  const statusConfig = useMemo(() => {
    switch (totalStatus) {
      case 'success':
        return {
          icon: CheckCircle,
          iconBg: 'bg-emerald-100 dark:bg-emerald-900/30',
          iconColor: 'text-emerald-600 dark:text-emerald-400',
          title: '全部成功',
          description: '所有记录均已成功处理',
        };
      case 'error':
        return {
          icon: XCircle,
          iconBg: 'bg-rose-100 dark:bg-rose-900/30',
          iconColor: 'text-rose-600 dark:text-rose-400',
          title: '全部失败',
          description: '所有记录处理失败，请检查失败详情',
        };
      case 'partial':
      default:
        return {
          icon: CheckCircle,
          iconBg: 'bg-amber-100 dark:bg-amber-900/30',
          iconColor: 'text-amber-600 dark:text-amber-400',
          title: '部分成功',
          description: '部分记录处理成功，请检查失败详情',
        };
    }
  }, [totalStatus]);

  /**
   * 获取标题
   */
  const getTitle = () => {
    return operationType === 'approval' ? '批量审批完成' : '批量操作完成';
  };

  const StatusIcon = statusConfig.icon;

  /**
   * 渲染页脚按钮
   */
  const renderFooter = () => {
    return (
      <>
        {/* 关闭按钮 */}
        <button
          type="button"
          onClick={onClose}
          disabled={isRetrying}
          className="px-4 py-2 text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-xl transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
        >
          关闭
        </button>

        {/* 导出报告按钮（有失败时显示） */}
        {failedCount > 0 && onExportReport && (
          <button
            type="button"
            onClick={handleExportReport}
            disabled={isRetrying}
            className="px-4 py-2 text-slate-700 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-xl transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
          >
            <Download size={ICON_SIZE_SM} />
            导出报告
          </button>
        )}

        {/* 重试按钮（有失败且提供了回调时显示） */}
        {failedCount > 0 && onRetry && (
          <button
            type="button"
            onClick={handleRetry}
            disabled={isRetrying}
            className="px-4 py-2 text-white bg-primary-600 hover:bg-primary-700 rounded-xl transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
          >
            {isRetrying ? (
              <>
                <RotateCcw size={ICON_SIZE_SM} className="animate-spin" />
                重试中...
              </>
            ) : (
              <>
                <RotateCcw size={ICON_SIZE_SM} />
                重试失败项
              </>
            )}
          </button>
        )}
      </>
    );
  };

  return (
    <BaseModal
      isOpen={visible}
      onClose={onClose}
      maxWidth="lg"
      closeOnBackdropClick={!isRetrying}
      footer={renderFooter()}
      showCloseButton={!isRetrying}
    >
      {/* 状态图标和标题 */}
      <div className="flex items-start gap-4 mb-6">
        <div className={`p-3 rounded-lg ${statusConfig.iconBg} ${statusConfig.iconColor} shrink-0`}>
          <StatusIcon size={ICON_SIZE_LG} />
        </div>
        <div className="flex-1">
          <h3 className="text-lg font-semibold text-slate-800 dark:text-white">
            {getTitle()}
          </h3>
          <p className="text-sm text-slate-600 dark:text-slate-400 mt-1">
            {statusConfig.description}
          </p>
        </div>
      </div>

      {/* 统计摘要 */}
      <div className="grid grid-cols-2 gap-4 mb-6" role="status" aria-live="polite">
        {/* 成功统计 */}
        <div className="p-4 bg-emerald-50 dark:bg-emerald-900/20 border border-emerald-200 dark:border-emerald-800 rounded-xl">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 rounded-lg">
              <CheckCircle size={ICON_SIZE_MD} className="text-emerald-600 dark:text-emerald-400" />
            </div>
            <div>
              <p className="text-2xl font-bold text-emerald-700 dark:text-emerald-300">
                {successCount}
              </p>
              <p className="text-sm text-emerald-600 dark:text-emerald-400">
                成功处理
              </p>
            </div>
          </div>
        </div>

        {/* 失败统计 */}
        <div className={`p-4 rounded-xl border ${
          failedCount > 0
            ? 'bg-rose-50 dark:bg-rose-900/20 border-rose-200 dark:border-rose-800'
            : 'bg-slate-50 dark:bg-slate-800 border-slate-200 dark:border-slate-700'
        }`}>
          <div className="flex items-center gap-3">
            <div className={`p-2 rounded-lg ${
              failedCount > 0
                ? 'bg-rose-100 dark:bg-rose-900/30'
                : 'bg-slate-100 dark:bg-slate-700'
            }`}>
              <XCircle
                size={ICON_SIZE_MD}
                className={
                  failedCount > 0
                    ? 'text-rose-600 dark:text-rose-400'
                    : 'text-slate-400 dark:text-slate-500'
                }
              />
            </div>
            <div>
              <p
                className={`text-2xl font-bold ${
                  failedCount > 0
                    ? 'text-rose-700 dark:text-rose-300'
                    : 'text-slate-500 dark:text-slate-400'
                }`}
              >
                {failedCount}
              </p>
              <p
                className={`text-sm ${
                  failedCount > 0
                    ? 'text-rose-600 dark:text-rose-400'
                    : 'text-slate-400 dark:text-slate-500'
                }`}
              >
                处理失败
              </p>
            </div>
          </div>
        </div>
      </div>

      {/* 失败详情列表 */}
      {failedCount > 0 && errors.length > 0 && (
        <div role="region" aria-label="失败详情区域">
          <div className="flex items-center justify-between mb-3">
            <h4 className="text-sm font-semibold text-slate-700 dark:text-slate-300">
              失败详情
            </h4>
            <span className="text-xs text-slate-500 dark:text-slate-400">
              共 {errors.length} 条
            </span>
          </div>

          <div
            className={`${ERROR_LIST_MAX_HEIGHT} overflow-y-auto border border-slate-200 dark:border-slate-700 rounded-lg divide-y divide-slate-200 dark:divide-slate-700`}
            role="list"
            aria-label="失败详情列表"
          >
            {errors.map((error) => (
              <div
                key={error.id}
                role="listitem"
                className="flex items-start gap-3 p-3 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors"
              >
                <div className="p-1.5 bg-rose-100 dark:bg-rose-900/30 rounded-lg shrink-0">
                  <XCircle size={ICON_SIZE_SM} className="text-rose-600 dark:text-rose-400" />
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-slate-800 dark:text-white">
                    档案 #{error.id}
                  </p>
                  <p className="text-xs text-rose-600 dark:text-rose-400 mt-0.5">
                    {error.reason}
                  </p>
                </div>
              </div>
            ))}
          </div>

          {/* 失败提示 */}
          <div className="mt-3 p-3 bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-800 rounded-lg">
            <p className="text-xs text-amber-800 dark:text-amber-300">
              <span className="font-semibold">提示：</span>
              可以点击「重试失败项」重新处理这些记录，或导出失败报告进行排查
            </p>
          </div>
        </div>
      )}

      {/* 全部成功时的提示 */}
      {totalStatus === 'success' && (
        <div className="p-4 bg-emerald-50 dark:bg-emerald-900/20 border border-emerald-200 dark:border-emerald-800 rounded-lg">
          <p className="text-sm text-emerald-800 dark:text-emerald-300">
            所有记录均已成功处理完成！
          </p>
        </div>
      )}
    </BaseModal>
  );
};

/**
 * 默认导出
 */
export default BatchResultModal;

// Input: Test suite for BatchApprovalDialog component
// Output: Vitest test coverage for approve/reject functionality, validation, skip feature, threshold warnings, and loading states
// Pos: src/components/operations/__tests__/BatchApprovalDialog.test.tsx

import { describe, it, expect, vi } from 'vitest';
import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import { BatchApprovalDialog, ApprovalRecord, CONFIRM_THRESHOLD, MAX_COMMENT_LENGTH } from '../BatchApprovalDialog';

describe('BatchApprovalDialog', () => {
  const mockOnConfirm = vi.fn();
  const mockOnCancel = vi.fn();

  const mockRecords: ApprovalRecord[] = [
    { id: 1, title: '记录1', code: 'CODE001' },
    { id: 2, title: '记录2', code: 'CODE002' },
    { id: 3, title: '记录3', code: 'CODE003' },
  ];

  beforeEach(() => {
    mockOnConfirm.mockClear();
    mockOnCancel.mockClear();
  });

  describe('Configuration: Approve Action', () => {
    it('should display approve configuration', () => {
      render(
        <BatchApprovalDialog
          visible={true}
          selectedCount={3}
          action="approve"
          onConfirm={mockOnConfirm}
          onCancel={mockOnCancel}
          selectedRecords={mockRecords}
        />
      );

      expect(screen.getByText('批量审批 (已选 3 条)')).toBeInTheDocument();
      expect(screen.getByPlaceholderText('审批意见（可选）')).toBeInTheDocument();
      expect(screen.getByText('确认审批')).toBeInTheDocument();
    });

    it('should not require comment for approve action', () => {
      render(
        <BatchApprovalDialog
          visible={true}
          selectedCount={3}
          action="approve"
          onConfirm={mockOnConfirm}
          onCancel={mockOnCancel}
          selectedRecords={mockRecords}
        />
      );

      const confirmButton = screen.getByText('确认审批');
      expect(confirmButton).not.toBeDisabled();
    });
  });

  describe('Configuration: Reject Action', () => {
    it('should display reject configuration', () => {
      render(
        <BatchApprovalDialog
          visible={true}
          selectedCount={3}
          action="reject"
          onConfirm={mockOnConfirm}
          onCancel={mockOnCancel}
          selectedRecords={mockRecords}
        />
      );

      expect(screen.getByText('批量驳回 (已选 3 条)')).toBeInTheDocument();
      expect(screen.getByPlaceholderText('驳回原因（必填）')).toBeInTheDocument();
      expect(screen.getByText('确认驳回')).toBeInTheDocument();
    });

    it('should show required asterisk for reject action', () => {
      render(
        <BatchApprovalDialog
          visible={true}
          selectedCount={3}
          action="reject"
          onConfirm={mockOnConfirm}
          onCancel={mockOnCancel}
          selectedRecords={mockRecords}
        />
      );

      // Check for asterisk indicator
      const label = screen.getByText('审批意见');
      expect(label.innerHTML).toContain('*');
    });
  });

  describe('Comment Validation', () => {
    it('should prevent reject without comment', async () => {
      render(
        <BatchApprovalDialog
          visible={true}
          selectedCount={3}
          action="reject"
          onConfirm={mockOnConfirm}
          onCancel={mockOnCancel}
          selectedRecords={mockRecords}
        />
      );

      const confirmButton = screen.getByText('确认驳回');
      fireEvent.click(confirmButton);

      // Should not call onConfirm
      expect(mockOnConfirm).not.toHaveBeenCalled();
    });

    it('should allow reject with comment', async () => {
      render(
        <BatchApprovalDialog
          visible={true}
          selectedCount={3}
          action="reject"
          onConfirm={mockOnConfirm}
          onCancel={mockOnCancel}
          selectedRecords={mockRecords}
        />
      );

      const textarea = screen.getByPlaceholderText('驳回原因（必填）');
      fireEvent.change(textarea, { target: { value: '不符合要求' } });

      const confirmButton = screen.getByText('确认驳回');
      fireEvent.click(confirmButton);

      await waitFor(() => {
        expect(mockOnConfirm).toHaveBeenCalledWith('不符合要求', []);
      });
    });

    it('should enforce max comment length', () => {
      render(
        <BatchApprovalDialog
          visible={true}
          selectedCount={3}
          action="approve"
          onConfirm={mockOnConfirm}
          onCancel={mockOnCancel}
          selectedRecords={mockRecords}
        />
      );

      const textarea = screen.getByPlaceholderText('审批意见（可选）');
      expect(textarea).toHaveAttribute('maxLength', String(MAX_COMMENT_LENGTH));
    });

    it('should display character count', () => {
      render(
        <BatchApprovalDialog
          visible={true}
          selectedCount={3}
          action="approve"
          onConfirm={mockOnConfirm}
          onCancel={mockOnCancel}
          selectedRecords={mockRecords}
        />
      );

      const textarea = screen.getByPlaceholderText('审批意见（可选）');
      fireEvent.change(textarea, { target: { value: '测试评论' } });

      expect(screen.getByText('4/500 字符')).toBeInTheDocument();
    });
  });

  describe('Skip Feature', () => {
    it('should expand skip section when checkbox clicked', () => {
      render(
        <BatchApprovalDialog
          visible={true}
          selectedCount={3}
          action="approve"
          onConfirm={mockOnConfirm}
          onCancel={mockOnCancel}
          selectedRecords={mockRecords}
        />
      );

      const skipCheckbox = screen.getByRole('button', { name: /跳过部分记录单独处理/ });
      fireEvent.click(skipCheckbox);

      expect(screen.getByText('记录1')).toBeInTheDocument();
      expect(screen.getByText('编号: CODE001')).toBeInTheDocument();
    });

    it('should skip selected records', async () => {
      render(
        <BatchApprovalDialog
          visible={true}
          selectedCount={3}
          action="approve"
          onConfirm={mockOnConfirm}
          onCancel={mockOnCancel}
          selectedRecords={mockRecords}
        />
      );

      // Expand skip section
      const skipCheckbox = screen.getByRole('button', { name: /跳过部分记录单独处理/ });
      fireEvent.click(skipCheckbox);

      // Uncheck record 1 (mark as skipped)
      const checkboxes = screen.getAllByRole('checkbox');
      const record1Checkbox = checkboxes[1]; // Second checkbox is record 1
      fireEvent.click(record1Checkbox);

      // Add comment and confirm
      const textarea = screen.getByPlaceholderText('审批意见（可选）');
      fireEvent.change(textarea, { target: { value: '批量审批' } });

      const confirmButton = screen.getByText('确认审批');
      fireEvent.click(confirmButton);

      await waitFor(() => {
        expect(mockOnConfirm).toHaveBeenCalledWith('批量审批', [1]);
      });
    });

    it('should display skip count badge', () => {
      render(
        <BatchApprovalDialog
          visible={true}
          selectedCount={3}
          action="approve"
          onConfirm={mockOnConfirm}
          onCancel={mockOnCancel}
          selectedRecords={mockRecords}
        />
      );

      const skipCheckbox = screen.getByRole('button', { name: /跳过部分记录单独处理/ });
      fireEvent.click(skipCheckbox);

      const checkboxes = screen.getAllByRole('checkbox');
      const record1Checkbox = checkboxes[1];
      fireEvent.click(record1Checkbox);

      expect(screen.getByText('已跳过 1 条')).toBeInTheDocument();
    });

    it('should show actual processing count when records are skipped', () => {
      render(
        <BatchApprovalDialog
          visible={true}
          selectedCount={3}
          action="approve"
          onConfirm={mockOnConfirm}
          onCancel={mockOnCancel}
          selectedRecords={mockRecords}
        />
      );

      const skipCheckbox = screen.getByRole('button', { name: /跳过部分记录单独处理/ });
      fireEvent.click(skipCheckbox);

      const checkboxes = screen.getAllByRole('checkbox');
      const record1Checkbox = checkboxes[1];
      fireEvent.click(record1Checkbox);

      // The skip count badge should be visible
      expect(screen.getByText('已跳过 1 条')).toBeInTheDocument();

      // Check that the checkbox shows proper state
      expect(record1Checkbox).not.toBeChecked();
    });
  });

  describe('Threshold Warning', () => {
    it('should show warning when count exceeds threshold', () => {
      const largeRecords = Array.from({ length: CONFIRM_THRESHOLD + 1 }, (_, i) => ({
        id: i + 1,
        title: `记录${i + 1}`,
      }));

      render(
        <BatchApprovalDialog
          visible={true}
          selectedCount={CONFIRM_THRESHOLD + 1}
          action="approve"
          onConfirm={mockOnConfirm}
          onCancel={mockOnCancel}
          selectedRecords={largeRecords}
        />
      );

      // Check that the count number appears in the document (in title and in warning)
      const countElements = screen.getAllByText(String(CONFIRM_THRESHOLD + 1));
      expect(countElements.length).toBeGreaterThan(0);
    });

    it('should display record list preview (max 5 records)', () => {
      const largeRecords = Array.from({ length: CONFIRM_THRESHOLD + 1 }, (_, i) => ({
        id: i + 1,
        title: `记录${i + 1}`,
      }));

      render(
        <BatchApprovalDialog
          visible={true}
          selectedCount={CONFIRM_THRESHOLD + 1}
          action="approve"
          onConfirm={mockOnConfirm}
          onCancel={mockOnCancel}
          selectedRecords={largeRecords}
        />
      );

      // Should show first 5 records
      expect(screen.getByText('• 记录1')).toBeInTheDocument();
      expect(screen.getByText('• 记录5')).toBeInTheDocument();

      // Should show "等共 X 条" message
      expect(screen.getByText(/\.\.\. 等共 .* 条/)).toBeInTheDocument();
    });

    it('should not show warning when count is below threshold', () => {
      render(
        <BatchApprovalDialog
          visible={true}
          selectedCount={5}
          action="approve"
          onConfirm={mockOnConfirm}
          onCancel={mockOnCancel}
          selectedRecords={mockRecords}
        />
      );

      expect(screen.queryByText(/即将处理 .* 条记录，请确认操作无误/)).not.toBeInTheDocument();
    });
  });

  describe('Loading State', () => {
    it('should disable buttons when loading', () => {
      render(
        <BatchApprovalDialog
          visible={true}
          selectedCount={3}
          action="approve"
          onConfirm={mockOnConfirm}
          onCancel={mockOnCancel}
          selectedRecords={mockRecords}
          loading={true}
        />
      );

      const cancelButton = screen.getByText('取消');
      const confirmButton = screen.getByText('处理中...');

      expect(cancelButton).toBeDisabled();
      expect(confirmButton).toBeDisabled();
    });

    it('should show loading spinner', () => {
      render(
        <BatchApprovalDialog
          visible={true}
          selectedCount={3}
          action="approve"
          onConfirm={mockOnConfirm}
          onCancel={mockOnCancel}
          selectedRecords={mockRecords}
          loading={true}
        />
      );

      expect(screen.getByText('处理中...')).toBeInTheDocument();
    });

    it('should disable textarea when loading', () => {
      render(
        <BatchApprovalDialog
          visible={true}
          selectedCount={3}
          action="approve"
          onConfirm={mockOnConfirm}
          onCancel={mockOnCancel}
          selectedRecords={mockRecords}
          loading={true}
        />
      );

      const textarea = screen.getByPlaceholderText('审批意见（可选）');
      expect(textarea).toBeDisabled();
    });
  });

  describe('Cancel Behavior', () => {
    it('should call onCancel when cancel button clicked', () => {
      render(
        <BatchApprovalDialog
          visible={true}
          selectedCount={3}
          action="approve"
          onConfirm={mockOnConfirm}
          onCancel={mockOnCancel}
          selectedRecords={mockRecords}
        />
      );

      const cancelButton = screen.getByText('取消');
      fireEvent.click(cancelButton);

      expect(mockOnCancel).toHaveBeenCalledTimes(1);
    });

    it('should reset state on cancel', () => {
      const { rerender } = render(
        <BatchApprovalDialog
          visible={true}
          selectedCount={3}
          action="approve"
          onConfirm={mockOnConfirm}
          onCancel={mockOnCancel}
          selectedRecords={mockRecords}
        />
      );

      // Add comment
      const textarea = screen.getByPlaceholderText('审批意见（可选）');
      fireEvent.change(textarea, { target: { value: '测试评论' } });

      // Cancel
      const cancelButton = screen.getByText('取消');
      fireEvent.click(cancelButton);

      // Re-render and verify state is reset
      rerender(
        <BatchApprovalDialog
          visible={true}
          selectedCount={3}
          action="approve"
          onConfirm={mockOnConfirm}
          onCancel={mockOnCancel}
          selectedRecords={mockRecords}
        />
      );

      expect(screen.getByPlaceholderText('审批意见（可选）')).toHaveValue('');
    });
  });

  describe('Edge Cases', () => {
    it('should handle empty selectedRecords gracefully', () => {
      render(
