// Input: React、组织树数据、Tree组件
// Output: OrgSelector 组织选择器组件（可复用）
// Pos: 组织架构组件 - 独立模块，不影响其他功能
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useEffect, useState, useMemo } from 'react';
import { TreeNode } from './Tree';
import { OrgNode } from '../../types';
import { ChevronRight, ChevronDown, Folder, File, Check } from 'lucide-react';

/**
 * 组织选择器组件（可复用）
 * 
 * 功能：
 * - 支持单选或多选组织
 * - 显示组织树结构
 * - 可搜索过滤
 * - 独立模块，组织架构变更不影响其他功能
 */
export interface OrgSelectorProps {
    /**
     * 组织树数据
     */
    orgTree: OrgNode[];

    /**
     * 是否多选
     */
    multiple?: boolean;

    /**
     * 当前选中的组织ID（单选时为string，多选时为string[]）
     */
    value?: string | string[];

    /**
     * 选择变化回调
     */
    onChange?: (value: string | string[]) => void;

    /**
     * 是否禁用
     */
    disabled?: boolean;

    /**
     * 占位符文本
     */
    placeholder?: string;

    /**
     * 是否显示搜索框
     */
    showSearch?: boolean;

    /**
     * 自定义样式类名
     */
    className?: string;
}

/**
 * 组织选择器组件
 */
export const OrgSelector: React.FC<OrgSelectorProps> = ({
    orgTree,
    multiple = false,
    value,
    onChange,
    disabled = false,
    placeholder: _placeholder = '请选择组织',
    showSearch = true,
    className = '',
}) => {
    const [searchText, setSearchText] = useState('');
    const [expandedKeys, setExpandedKeys] = useState<string[]>([]);
    const [selectedKeys, setSelectedKeys] = useState<string[]>(() => {
        if (!value) return [];
        return Array.isArray(value) ? value : [value];
    });

    // 转换组织树数据为Tree组件格式
    const treeData = useMemo<TreeNode[]>(() => {
        const mapNodes = (nodes: OrgNode[]): TreeNode[] => nodes.map((node) => ({
            id: node.id,
            label: node.name,
            type: node.type,
            parentId: node.parentId,
            children: node.children ? mapNodes(node.children) : [],
        }));
        return mapNodes(orgTree);
    }, [orgTree]);

    // 过滤树数据（根据搜索文本）
    const filteredTreeData = useMemo<TreeNode[]>(() => {
        if (!searchText.trim()) return treeData;

        const filterNode = (node: TreeNode): TreeNode | null => {
            const matchesSearch = node.label.toLowerCase().includes(searchText.toLowerCase());
            const filteredChildren = node.children
                ? node.children.map(filterNode).filter((n): n is TreeNode => n !== null)
                : [];

            if (matchesSearch || filteredChildren.length > 0) {
                return {
                    ...node,
                    children: filteredChildren,
                };
            }
            return null;
        };

        return treeData.map(filterNode).filter((n): n is TreeNode => n !== null);
    }, [treeData, searchText]);

    // 展开所有节点（当搜索时）
    useEffect(() => {
        if (searchText.trim() && filteredTreeData.length > 0) {
            const getAllKeys = (nodes: TreeNode[]): string[] => {
                const keys: string[] = [];
                nodes.forEach(node => {
                    keys.push(node.id);
                    if (node.children && node.children.length > 0) {
                        keys.push(...getAllKeys(node.children));
                    }
                });
                return keys;
            };
            // eslint-disable-next-line react-hooks/set-state-in-effect
            setExpandedKeys(getAllKeys(filteredTreeData));
        }
    }, [searchText, filteredTreeData]);

    // 同步外部value变化
    useEffect(() => {
        if (value !== undefined) {
            const newSelectedKeys = Array.isArray(value) ? value : (value ? [value] : []);
            // eslint-disable-next-line react-hooks/set-state-in-effect
            setSelectedKeys(newSelectedKeys);
        }
    }, [value]);

    // 处理节点选择
    const handleSelect = (nodeId: string) => {
        if (disabled) return;

        let newSelectedKeys: string[];
        if (multiple) {
            // 多选模式：切换选中状态
            if (selectedKeys.includes(nodeId)) {
                newSelectedKeys = selectedKeys.filter(id => id !== nodeId);
            } else {
                newSelectedKeys = [...selectedKeys, nodeId];
            }
        } else {
            // 单选模式：直接替换
            newSelectedKeys = [nodeId];
        }

        setSelectedKeys(newSelectedKeys);

        // 触发onChange回调
        if (onChange) {
            onChange(multiple ? newSelectedKeys : (newSelectedKeys[0] || ''));
        }
    };

    // 清除选择
    const handleClear = () => {
        if (disabled) return;
        setSelectedKeys([]);
        if (onChange) {
            onChange(multiple ? [] : '');
        }
    };

    return (
        <div className={`org-selector ${className}`}>
            {/* 搜索框 */}
            {showSearch && (
                <div className="mb-3">
                    <input
                        type="text"
                        value={searchText}
                        onChange={(e) => setSearchText(e.target.value)}
                        placeholder="搜索组织..."
                        disabled={disabled}
                        className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500 disabled:bg-slate-100 disabled:cursor-not-allowed"
                    />
                </div>
            )}

            {/* 已选择的组织显示 */}
            {selectedKeys.length > 0 && (
                <div className="mb-3 flex flex-wrap gap-2">
                    {selectedKeys.map(orgId => {
                        // 查找组织名称
                        const findOrgName = (nodes: OrgNode[], id: string): string | null => {
                            for (const node of nodes) {
                                if (node.id === id) return node.name;
                                if (node.children) {
                                    const found = findOrgName(node.children, id);
                                    if (found) return found;
                                }
                            }
                            return null;
                        };
                        const orgName = findOrgName(orgTree, orgId) || orgId;

                        return (
                            <span
                                key={orgId}
                                className="inline-flex items-center gap-1 px-2 py-1 bg-primary-100 text-primary-800 rounded text-sm"
                            >
                                {orgName}
                                {!disabled && (
                                    <button
                                        onClick={() => handleSelect(orgId)}
                                        className="text-primary-600 hover:text-primary-800"
                                    >
                                        ×
                                    </button>
                                )}
                            </span>
                        );
                    })}
                    {!disabled && (
                        <button
                            onClick={handleClear}
                            className="text-sm text-slate-500 hover:text-slate-700"
                        >
                            清除全部
                        </button>
                    )}
                </div>
            )}

            {/* 组织树 */}
            <div className="border border-slate-200 rounded-lg p-3 max-h-96 overflow-auto">
                {filteredTreeData.length === 0 ? (
                    <div className="text-center py-8 text-slate-500 text-sm">
                        {searchText ? '未找到匹配的组织' : '暂无组织数据'}
                    </div>
                ) : (
                    <OrgTreeView
                        data={filteredTreeData}
                        selectedKeys={selectedKeys}
                        expandedKeys={expandedKeys}
                        onSelect={handleSelect}
                        onExpand={(keys) => setExpandedKeys(keys)}
                        multiple={multiple}
                        disabled={disabled}
                    />
                )}
            </div>
        </div>
    );
};

/**
 * 组织树视图组件（内部使用）
 */
interface OrgTreeViewProps {
    data: TreeNode[];
    selectedKeys: string[];
    expandedKeys: string[];
    onSelect: (nodeId: string) => void;
    onExpand: (keys: string[]) => void;
    multiple: boolean;
    disabled: boolean;
}

const OrgTreeView: React.FC<OrgTreeViewProps> = ({
    data,
    selectedKeys,
    expandedKeys,
    onSelect,
    onExpand,
    multiple,
    disabled,
}) => {
    const toggleExpand = (nodeId: string, e: React.MouseEvent) => {
        e.stopPropagation();
        if (disabled) return;
        const newExpanded = expandedKeys.includes(nodeId)
            ? expandedKeys.filter(id => id !== nodeId)
            : [...expandedKeys, nodeId];
        onExpand(newExpanded);
    };

    const renderNode = (node: TreeNode, depth: number) => {
        const hasChildren = node.children && node.children.length > 0;
        const isExpanded = expandedKeys.includes(node.id);
        const isSelected = selectedKeys.includes(node.id);

        return (
            <div key={node.id} style={{ marginLeft: depth * 16 }} className="py-1">
                <div
                    className={`flex items-center group rounded px-2 py-1.5 transition-colors ${
                        isSelected
                            ? 'bg-primary-50 text-primary-700'
                            : 'hover:bg-slate-50 text-slate-800'
                    } ${disabled ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'}`}
                    onClick={() => !disabled && onSelect(node.id)}
                >
                    {/* Expand/Collapse Icon */}
                    <span
                        className={`text-slate-400 hover:text-slate-600 mr-1 ${
                            !hasChildren ? 'invisible' : ''
                        }`}
                        onClick={(e) => toggleExpand(node.id, e)}
                    >
                        {isExpanded ? <ChevronDown size={16} /> : <ChevronRight size={16} />}
                    </span>

                    {/* Type Icon */}
                    <span className="text-slate-500 mr-2">
                        {node.type === 'COMPANY' ? (
                            <Folder size={16} className="fill-blue-50 text-blue-500" />
                        ) : (
                            <File size={14} />
                        )}
                    </span>

                    {/* Checkbox (多选模式) */}
                    {multiple && (
                        <span className="mr-2">
                            {isSelected ? (
                                <Check size={16} className="text-primary-600" />
                            ) : (
                                <div className="w-4 h-4 border border-slate-300 rounded" />
                            )}
                        </span>
                    )}

                    {/* Label */}
                    <div className="text-sm flex-1">
                        {node.label}
                        {node.type && (
                            <span className="ml-2 text-[10px] text-slate-400 uppercase border border-slate-100 rounded px-1">
                                {node.type}
                            </span>
                        )}
                    </div>
                </div>

                {/* Children */}
                {hasChildren && isExpanded && (
                    <div className="mt-1 border-l border-slate-100 ml-4 pl-1">
                        {node.children!.map((child) => renderNode(child, depth + 1))}
                    </div>
                )}
            </div>
        );
    };

    return <div>{data.map((n) => renderNode(n, 0))}</div>;
};

// Input: React, lucide-react
// Output: OrgTreePicker 组件
// Pos: 通用复用组件 - 组织树选择器弹窗

import React, { useState, useMemo } from 'react';
import { Search, Folder, File, ChevronRight, ChevronDown, Check } from 'lucide-react';
import { BaseModal } from '../modals/BaseModal';
import { OrgNode } from '../../types';

export interface OrgTreePickerProps {
  isOpen: boolean;
  onClose: () => void;
  orgTree: OrgNode[];
  title?: string;
  multiple?: boolean;
  value?: string | string[];
  onChange: (value: string | string[]) => void;
}

/**
 * 组织树选择弹窗
 * <p>
 * 用于在弹窗中选择组织，支持搜索和多选
 * </p>
 */
export function OrgTreePicker({
  isOpen,
  onClose,
  orgTree,
  title = '选择组织',
  multiple = false,
  value,
  onChange,
}: OrgTreePickerProps) {
  const [searchText, setSearchText] = useState('');
  const [expandedKeys, setExpandedKeys] = useState<string[]>(() => {
    // 默认展开所有节点
    const getAllKeys = (nodes: OrgNode[]): string[] => {
      const keys: string[] = [];
      nodes.forEach(node => {
        keys.push(node.id);
        if (node.children) {
          keys.push(...getAllKeys(node.children));
        }
      });
      return keys;
    };
    return getAllKeys(orgTree);
  });

  const selectedKeys = useMemo(() => {
    if (!value) return [];
    return Array.isArray(value) ? value : [value];
  }, [value]);

  // 过滤树数据
  const filteredTreeData = useMemo(() => {
    if (!searchText.trim()) return orgTree;

    const filterNode = (node: OrgNode): OrgNode | null => {
      const matchesSearch = node.name.toLowerCase().includes(searchText.toLowerCase());
      const filteredChildren = node.children
        ? node.children.map(filterNode).filter((n): n is OrgNode => n !== null)
        : [];

      if (matchesSearch || filteredChildren.length > 0) {
        return {
          ...node,
          children: filteredChildren,
        };
      }
      return null;
    };

    return orgTree.map(filterNode).filter((n): n is OrgNode => n !== null);
  }, [orgTree, searchText]);

  const handleSelect = (nodeId: string) => {
    let newSelectedKeys: string[];
    if (multiple) {
      if (selectedKeys.includes(nodeId)) {
        newSelectedKeys = selectedKeys.filter(id => id !== nodeId);
      } else {
        newSelectedKeys = [...selectedKeys, nodeId];
      }
    } else {
      newSelectedKeys = [nodeId];
      onChange(multiple ? newSelectedKeys : newSelectedKeys[0]);
      onClose();
      return;
    }

    onChange(multiple ? newSelectedKeys : newSelectedKeys[0] || '');
  };

  const handleConfirm = () => {
    onChange(multiple ? selectedKeys : (selectedKeys[0] || ''));
    onClose();
  };

  const TreeNode: React.FC<{
    node: OrgNode;
    depth: number;
  }> = ({ node, depth }) => {
    const hasChildren = node.children && node.children.length > 0;
    const isExpanded = expandedKeys.includes(node.id);
    const isSelected = selectedKeys.includes(node.id);

    return (
      <div>
        <div
          className={`flex items-center py-2 px-3 rounded-lg cursor-pointer transition-colors ${
            isSelected
              ? 'bg-blue-50 text-blue-700'
              : 'hover:bg-slate-50 text-slate-700'
          }`}
          style={{ paddingLeft: `${depth * 16 + 12}px` }}
          onClick={() => handleSelect(node.id)}
        >
          {/* Expand/Collapse */}
          <span
            className="text-slate-400 mr-2"
            onClick={(e) => {
              e.stopPropagation();
              setExpandedKeys(prev =>
                prev.includes(node.id)
                  ? prev.filter(id => id !== node.id)
                  : [...prev, node.id]
              );
            }}
          >
            {hasChildren ? (
              isExpanded ? <ChevronDown size={16} /> : <ChevronRight size={16} />
            ) : (
              <span className="w-4" />
            )}
          </span>

          {/* Type Icon */}
          <span className="mr-2 text-slate-500">
            {node.type === 'COMPANY' ? (
              <Folder size={16} className="fill-blue-50 text-blue-500" />
            ) : (
              <File size={14} />
            )}
          </span>

          {/* Checkbox (multi-select) */}
          {multiple && (
            <span className="mr-2 flex items-center justify-center w-4 h-4 border rounded">
              {isSelected && <Check size={12} className="text-blue-600" />}
            </span>
          )}

          {/* Name */}
          <span className="text-sm flex-1">{node.name}</span>

          {/* Type Badge */}
          {node.type && (
            <span className="ml-2 text-[10px] text-slate-400 uppercase border border-slate-100 rounded px-1.5 py-0.5">
              {node.type}
            </span>
          )}
        </div>

        {/* Children */}
        {hasChildren && isExpanded && (
          <div>
            {node.children!.map(child => (
              <TreeNode key={child.id} node={child} depth={depth + 1} />
            ))}
          </div>
        )}
      </div>
    );
  };

  const selectedOrgNames = useMemo(() => {
    const names: string[] = [];
    selectedKeys.forEach(key => {
      const findName = (nodes: OrgNode[], id: string): string | null => {
        for (const node of nodes) {
          if (node.id === id) return node.name;
          if (node.children) {
            const found = findName(node.children, id);
            if (found) return found;
          }
        }
        return null;
      };
      const name = findName(orgTree, key);
      if (name) names.push(name);
    });
    return names;
  }, [selectedKeys, orgTree]);

  return (
    <BaseModal
      isOpen={isOpen}
      onClose={onClose}
      title={title}
      maxWidth="2xl"
    >
      {/* Search */}
      <div className="mb-4">
        <div className="relative">
          <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
          <input
            type="text"
            value={searchText}
            onChange={(e) => setSearchText(e.target.value)}
            placeholder="搜索组织..."
            className="w-full pl-10 pr-4 py-2 border border-slate-200 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-700 text-slate-800 dark:text-white focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          />
        </div>
      </div>

      {/* Selected */}
      {selectedKeys.length > 0 && (
        <div className="mb-4 p-3 bg-slate-50 dark:bg-slate-700 rounded-lg">
          <p className="text-xs text-slate-500 dark:text-slate-400 mb-2">已选择:</p>
          <div className="flex flex-wrap gap-2">
            {selectedOrgNames.map((name, i) => (
              <span
                key={i}
                className="inline-flex items-center gap-1 px-2 py-1 bg-blue-100 text-blue-700 rounded text-sm"
              >
                {name}
                <button
                  onClick={() => handleSelect(selectedKeys[i])}
                  className="text-blue-600 hover:text-blue-800"
                >
                  ×
                </button>
              </span>
            ))}
          </div>
        </div>
      )}

      {/* Tree */}
      <div className="border border-slate-200 dark:border-slate-600 rounded-lg p-2 max-h-80 overflow-auto">
        {filteredTreeData.length === 0 ? (
          <div className="text-center py-8 text-slate-500 text-sm">
            未找到匹配的组织
          </div>
        ) : (
          filteredTreeData.map(node => <TreeNode key={node.id} node={node} depth={0} />)
        )}
      </div>

      {/* Footer Actions */}
      <div className="flex items-center justify-end gap-3 mt-4 pt-4 border-t border-slate-200 dark:border-slate-600">
        <button
          onClick={onClose}
          className="px-4 py-2 text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg transition-colors"
        >
          取消
        </button>
        <button
          onClick={handleConfirm}
          disabled={selectedKeys.length === 0}
          className="px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
        >
          确定
        </button>
      </div>
    </BaseModal>
  );
}

export default OrgTreePicker;

// Input: React
// Output: useOrg Hook
// Pos: 通用复用组件 - 组织数据管理 Hook

import { useState, useCallback, useEffect } from 'react';
import { OrgNode } from '../../types';

export interface UseOrgOptions {
  fetchOrgTree?: () => Promise<OrgNode[]>;
  defaultOrgId?: string;
  autoFetch?: boolean;
}

export interface UseOrgReturn {
  orgTree: OrgNode[];
  selectedOrgId: string | null;
  selectedOrg: OrgNode | null;
  selectedOrgPath: OrgNode[];
  loading: boolean;
  error: string | null;
  selectOrg: (orgId: string) => void;
  clearSelection: () => void;
  reload: () => Promise<void>;
  findOrgById: (id: string) => OrgNode | null;
  findOrgByName: (name: string) => OrgNode | null;
  getChildren: (orgId: string) => OrgNode[];
  getParent: (orgId: string) => OrgNode | null;
}

/**
 * 组织数据管理 Hook
 * <p>
 * 封装组织树数据的加载、选择、查找等操作
 * </p>
 */
export function useOrg({
  fetchOrgTree,
  defaultOrgId,
  autoFetch = true,
}: UseOrgOptions = {}): UseOrgReturn {
  const [orgTree, setOrgTree] = useState<OrgNode[]>([]);
  const [selectedOrgId, setSelectedOrgId] = useState<string | null>(defaultOrgId || null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // 加载组织树
  const loadOrgTree = useCallback(async () => {
    if (!fetchOrgTree) {
      return;
    }

    setLoading(true);
    setError(null);
    try {
      const tree = await fetchOrgTree();
      setOrgTree(tree);
    } catch (err) {
      const message = err instanceof Error ? err.message : '加载组织树失败';
      setError(message);
      console.error('Failed to load org tree:', err);
    } finally {
      setLoading(false);
    }
  }, [fetchOrgTree]);

  // 自动加载
  useEffect(() => {
    if (autoFetch && fetchOrgTree) {
      loadOrgTree();
    }
  }, [autoFetch, fetchOrgTree, loadOrgTree]);

  // 查找组织
  const findOrgById = useCallback((id: string): OrgNode | null => {
    const search = (nodes: OrgNode[]): OrgNode | null => {
      for (const node of nodes) {
        if (node.id === id) return node;
        if (node.children) {
          const found = search(node.children);
          if (found) return found;
        }
      }
      return null;
    };
    return search(orgTree);
  }, [orgTree]);

  const findOrgByName = useCallback((name: string): OrgNode | null => {
    const search = (nodes: OrgNode[]): OrgNode | null => {
      for (const node of nodes) {
        if (node.name === name) return node;
        if (node.children) {
          const found = search(node.children);
          if (found) return found;
        }
      }
      return null;
    };
    return search(orgTree);
  }, [orgTree]);

  // 查找路径
  const findPath = useCallback((targetId: string): OrgNode[] => {
    const search = (nodes: OrgNode[], id: string, path: OrgNode[] = []): OrgNode[] | null => {
      for (const node of nodes) {
        const currentPath = [...path, node];
        if (node.id === id) {
          return currentPath;
        }
        if (node.children) {
          const result = search(node.children, id, currentPath);
          if (result) return result;
        }
      }
      return null;
    };
    return search(orgTree, targetId) || [];
  }, [orgTree]);

  // 获取选中的组织
  const selectedOrg = selectedOrgId ? findOrgById(selectedOrgId) : null;

  // 获取选中组织的路径
  const selectedOrgPath = selectedOrgId ? findPath(selectedOrgId) : [];

  // 选择组织
  const selectOrg = useCallback((orgId: string) => {
    setSelectedOrgId(orgId);
  }, []);

  // 清除选择
  const clearSelection = useCallback(() => {
    setSelectedOrgId(null);
  }, []);

  // 获取子组织
  const getChildren = useCallback((orgId: string): OrgNode[] => {
    const org = findOrgById(orgId);
    return org?.children || [];
  }, [findOrgById]);

  // 获取父组织
  const getParent = useCallback((orgId: string): OrgNode | null => {
    const search = (nodes: OrgNode[], id: string, parent: OrgNode | null = null): OrgNode | null => {
      for (const node of nodes) {
        if (node.id === id) {
          return parent;
        }
        if (node.children) {
          const found = search(node.children, id, node);
          if (found) return found;
        }
      }
      return null;
    };
    return search(orgTree, orgId);
  }, [orgTree]);

  return {
    orgTree,
    selectedOrgId,
    selectedOrg,
    selectedOrgPath,
    loading,
    error,
    selectOrg,
    clearSelection,
    reload: loadOrgTree,
    findOrgById,
    findOrgByName,
    getChildren,
    getParent,
  };
}

export default useOrg;

// Input: React, lucide-react
// Output: FilePreview 组件
// Pos: 通用复用组件 - 文件预览器

import React, { useState, useCallback } from 'react';
import {
  FileText, File, Loader2, AlertCircle
} from 'lucide-react';
import { PdfViewer } from './PdfViewer';
import { ImageViewer } from './ImageViewer';
import { PreviewToolbar } from './PreviewToolbar';

export type FileType = 'pdf' | 'image' | 'ofd' | 'unknown';

export interface FilePreviewProps {
  url: string;
  fileName?: string;
  fileType?: FileType;
  onClose?: () => void;
  onDownload?: () => void;
  className?: string;
  showToolbar?: boolean;
  initialPage?: number;
}

/**
 * 统一的文件预览组件
 * <p>
 * 支持 PDF、图片、OFD 等多种文件格式的预览
 * </p>
 */
export function FilePreview({
  url,
  fileName,
  fileType: propFileType,
  onClose,
  onDownload,
  className = '',
  showToolbar = true,
  initialPage = 1,
}: FilePreviewProps) {
  const [scale, setScale] = useState(1);
  const [rotation, setRotation] = useState(0);
  const [currentPage, setCurrentPage] = useState(initialPage);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isFullscreen, setIsFullscreen] = useState(false);

  // 检测文件类型
  const detectFileType = useCallback((): FileType => {
    if (propFileType) return propFileType;

    const ext = url.split('.').pop()?.toLowerCase();
    if (ext === 'pdf') return 'pdf';
    if (['jpg', 'jpeg', 'png', 'gif', 'bmp', 'webp'].includes(ext || '')) return 'image';
    if (ext === 'ofd') return 'ofd';
    return 'unknown';
  }, [url, propFileType]);

  const fileType = detectFileType();

  // 缩放操作
  const handleZoomIn = () => setScale(prev => Math.min(prev + 0.25, 3));
  const handleZoomOut = () => setScale(prev => Math.max(prev - 0.25, 0.5));
  const handleResetZoom = () => setScale(1);

  // 旋转操作
  const handleRotate = () => setRotation(prev => (prev + 90) % 360);

  // 全屏操作
  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen();
      setIsFullscreen(true);
    } else {
      document.exitFullscreen();
      setIsFullscreen(false);
    }
  };

  // 监听全屏变化
  React.useEffect(() => {
    const handleFullscreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => {
      document.removeEventListener('fullscreenchange', handleFullscreenChange);
    };
  }, []);

  // 渲染预览内容
  const renderPreview = () => {
    switch (fileType) {
      case 'pdf':
        return (
          <PdfViewer
            url={url}
            scale={scale}
            rotation={rotation}
            currentPage={currentPage}
            onPageChange={setCurrentPage}
            onLoad={() => setLoading(false)}
            onError={(err) => {
              setError(err);
              setLoading(false);
            }}
          />
        );

      case 'image':
        return (
          <ImageViewer
            url={url}
            scale={scale}
            rotation={rotation}
            onLoad={() => setLoading(false)}
            onError={(err) => {
              setError(err);
              setLoading(false);
            }}
          />
        );

      case 'ofd':
        return (
          <div className="flex items-center justify-center h-full text-slate-500">
            <div className="text-center">
              <FileText size={48} className="mx-auto mb-4 opacity-50" />
              <p>OFD 文件预览需要专用组件</p>
              <p className="text-sm mt-2">请使用 OfdViewer 组件</p>
            </div>
          </div>
        );

      default:
        return (
          <div className="flex items-center justify-center h-full text-slate-500">
            <div className="text-center">
              <File size={48} className="mx-auto mb-4 opacity-50" />
              <p>不支持的文件格式</p>
              <p className="text-sm mt-2">{fileName || url}</p>
            </div>
          </div>
        );
    }
  };

  return (
    <div className={`file-preview relative bg-slate-900 dark:bg-black ${className} ${isFullscreen ? 'fixed inset-0 z-50' : ''}`}>
      {/* Toolbar */}
      {showToolbar && (
        <PreviewToolbar
          fileName={fileName}
          fileType={fileType}
          scale={scale}
          rotation={rotation}
          currentPage={currentPage}
          onZoomIn={handleZoomIn}
          onZoomOut={handleZoomOut}
          onResetZoom={handleResetZoom}
          onRotate={handleRotate}
          onDownload={onDownload}
          onClose={onClose}
          onFullscreen={toggleFullscreen}
          isFullscreen={isFullscreen}
        />
      )}

      {/* Preview Content */}
      <div className="flex items-center justify-center h-full overflow-auto p-4">
        {loading && (
          <div className="absolute inset-0 flex items-center justify-center bg-slate-900/50">
            <Loader2 size={32} className="animate-spin text-blue-500" />
          </div>
        )}

        {error && (
          <div className="text-center text-slate-400">
            <AlertCircle size={48} className="mx-auto mb-4 text-rose-500" />
            <p>加载失败</p>
            <p className="text-sm mt-2">{error}</p>
          </div>
        )}

        {!loading && !error && renderPreview()}
      </div>
    </div>
  );
}

export default FilePreview;

// Input: React
// Output: ImageViewer 组件
// Pos: 通用复用组件 - 图片查看器

import React, { useState, useRef, useEffect } from 'react';

export interface ImageViewerProps {
  url: string;
  scale: number;
  rotation: number;
  onLoad?: () => void;
  onError?: (error: string) => void;
  className?: string;
}

/**
 * 图片查看器组件
 * <p>
 * 支持缩放、旋转、拖拽平移
 * </p>
 */
export function ImageViewer({
  url,
  scale,
  rotation,
  onLoad,
  onError,
  className = '',
}: ImageViewerProps) {
  const [isDragging, setIsDragging] = useState(false);
  const [position, setPosition] = useState({ x: 0, y: 0 });
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });
  const imgRef = useRef<HTMLImageElement>(null);

  const handleMouseDown = (e: React.MouseEvent) => {
    if (scale > 1) {
      setIsDragging(true);
      setDragStart({ x: e.clientX - position.x, y: e.clientY - position.y });
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (isDragging) {
      setPosition({
        x: e.clientX - dragStart.x,
        y: e.clientY - dragStart.y,
      });
    }
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  const handleLoad = () => {
    onLoad?.();
  };

  const handleError = () => {
    onError?.('图片加载失败');
  };

  // 重置位置当缩放变为1时
  useEffect(() => {
    if (scale === 1) {
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setPosition({ x: 0, y: 0 });
    }
  }, [scale]);

  return (
    <div
      className={`image-viewer flex items-center justify-center overflow-hidden ${className}`}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseUp}
    >
      <img
        ref={imgRef}
        src={url}
        alt="Preview"
        onLoad={handleLoad}
        onError={handleError}
        onMouseDown={handleMouseDown}
        className={`max-w-full max-h-full object-contain transition-transform cursor-${scale > 1 ? 'grab' : 'default'}`}
        style={{
          transform: `translate(${position.x}px, ${position.y}px) scale(${scale}) rotate(${rotation}deg)`,
          cursor: isDragging ? 'grabbing' : scale > 1 ? 'grab' : 'default',
        }}
        draggable={false}
      />
    </div>
  );
}

export default ImageViewer;

// Input: React
// Output: PdfViewer 组件
// Pos: 通用复用组件 - PDF 查看器

import React, { useRef, useState } from 'react';
import { Page, Document, pdfjs } from 'react-pdf';

// 配置 PDF.js worker
pdfjs.GlobalWorkerOptions.workerSrc = `//cdnjs.cloudflare.com/ajax/libs/pdf.js/${pdfjs.version}/pdf.worker.min.js`;

export interface PdfViewerProps {
  url: string;
  scale: number;
  rotation: number;
  currentPage: number;
  onPageChange: (page: number) => void;
  onPageCountChange?: (count: number) => void;
  onLoad?: () => void;
  onError?: (error: string) => void;
  className?: string;
}

/**
 * PDF 查看器组件
 * <p>
 * 基于 react-pdf，支持缩放、旋转、翻页
 * </p>
 */
export function PdfViewer({
  url,
  scale,
  rotation,
  currentPage,
  onPageChange: _onPageChange,
  onPageCountChange,
  onLoad,
  onError,
  className = '',
}: PdfViewerProps) {
  const [_numPages, setNumPages] = useState(0);
  const [pdfError, setPdfError] = useState<string | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  const handleLoadSuccess = ({ numPages }: { numPages: number }) => {
    setNumPages(numPages);
    onPageCountChange?.(numPages);
    onLoad?.();
  };

  const handleLoadError = (error: Error) => {
    const errorMsg = error.message || 'PDF 加载失败';
    setPdfError(errorMsg);
    onError?.(errorMsg);
  };

  return (
    <div
      ref={containerRef}
      className={`pdf-viewer flex items-center justify-center ${className}`}
      style={{
        transform: `scale(${scale}) rotate(${rotation}deg)`,
        transition: 'transform 0.3s ease',
      }}
    >
      <Document
        file={url}
        onLoadSuccess={handleLoadSuccess}
        onLoadError={handleLoadError}
        loading={
          <div className="flex items-center justify-center p-8">
            <div className="text-slate-400">加载中...</div>
          </div>
        }
        error={
          <div className="text-center text-slate-400">
            <p>PDF 加载失败</p>
            {pdfError && <p className="text-sm mt-2 text-rose-400">{pdfError}</p>}
          </div>
        }
      >
        <Page
          pageNumber={currentPage}
          renderTextLayer={false}
          renderAnnotationLayer={false}
          className="shadow-lg"
        />
      </Document>
    </div>
  );
}

export default PdfViewer;

