// Input: React, useFilePreview, FilePreview components
// Output: SmartFilePreview 组件
// Pos: 通用复用组件 - 智能文件预览器（使用 previewApi）

import React, { useState, useCallback } from 'react';
import {
  Loader2,
  AlertCircle,
  RefreshCw,
  ZoomIn,
  ZoomOut,
  RotateCw,
  Download,
  ChevronLeft,
  ChevronRight,
  FileText,
} from 'lucide-react';
import { useFilePreview, UseFilePreviewParams } from './useFilePreview';
import { PdfViewer } from './PdfViewer';
import { ImageViewer } from './ImageViewer';

export interface FileItem {
  id: string;
  fileName: string;
  fileType?: string;
}

export interface SmartFilePreviewProps extends Omit<UseFilePreviewParams, 'autoLoad'> {
  /** 文件列表（用于多文件切换） */
  files?: FileItem[];
  /** 当前选中的文件ID */
  currentFileId?: string;
  /** 文件切换回调 */
  onFileChange?: (fileId: string) => void;
  /** 显示工具栏 */
  showToolbar?: boolean;
  /** 显示文件切换按钮 */
  showFileNav?: boolean;
  /** 自定义类名 */
  className?: string;
}

/**
 * 智能文件预览组件
 * <p>
 * 自动调用 previewApi 获取文件内容，支持权限验证、水印、错误处理
 * 支持多文件切换、缩放、旋转等操作
 * </p>
 */
export function SmartFilePreview({
  files,
  currentFileId,
  onFileChange,
  showToolbar = true,
  showFileNav = true,
  className = '',
  ...previewParams
}: SmartFilePreviewProps) {
  const [scale, setScale] = useState(1);
  const [rotation, setRotation] = useState(0);
  const [currentPage, setCurrentPage] = useState(1);

  // 使用 useFilePreview 获取数据
  const { blobUrl, presignedUrl, loading, error, retry } = useFilePreview({
    ...previewParams,
    autoLoad: true,
  });

  // 当前文件信息
  const currentFile = files?.find(f => f.id === currentFileId);
  const fileName = currentFile?.fileName || previewParams.fileId || '预览';

  // 文件索引
  const currentIndex = files?.findIndex(f => f.id === currentFileId) ?? -1;
  const hasPrev = currentIndex > 0;
  const hasNext = currentIndex < (files?.length ?? 0) - 1;

  // 文件类型检测
  const fileType = currentFile?.fileType || detectFileType(fileName);

  // 缩放操作
  const handleZoomIn = () => setScale(prev => Math.min(prev + 0.25, 3));
  const handleZoomOut = () => setScale(prev => Math.max(prev - 0.25, 0.5));
  const handleResetZoom = () => setScale(1);

  // 旋转操作
  const handleRotate = () => setRotation(prev => (prev + 90) % 360);

  // 文件切换
  const handlePrev = useCallback(() => {
    if (hasPrev && files && onFileChange) {
      onFileChange(files[currentIndex - 1].id);
    }
  }, [hasPrev, files, currentIndex, onFileChange]);

  const handleNext = useCallback(() => {
    if (hasNext && files && onFileChange) {
      onFileChange(files[currentIndex + 1].id);
    }
  }, [hasNext, files, currentIndex, onFileChange]);

  // 下载
  const handleDownload = useCallback(() => {
    if (blobUrl) {
      const link = document.createElement('a');
      link.href = blobUrl;
      link.download = fileName;
      link.click();
    }
  }, [blobUrl, fileName]);

  // 渲染内容
  const renderContent = () => {
    // Loading
    if (loading) {
      return (
        <div className="flex items-center justify-center h-full">
          <Loader2 size={32} className="animate-spin text-blue-500" />
        </div>
      );
    }

    // Error
    if (error) {
      return (
        <div className="flex flex-col items-center justify-center h-full text-slate-500">
          <AlertCircle size={48} className="mb-4 text-rose-500" />
          <p className="font-medium text-slate-700">{error}</p>
          <button
            onClick={retry}
            className="mt-4 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors flex items-center gap-2"
          >
            <RefreshCw size={16} />
            重新加载
          </button>
        </div>
      );
    }

    // No content
    if (!blobUrl && !presignedUrl) {
      return (
        <div className="flex items-center justify-center h-full text-slate-500">
          <p>暂无预览内容</p>
        </div>
      );
    }

    const url = blobUrl || presignedUrl || '';

    // 根据文件类型渲染
    if (fileType === 'pdf') {
      return (
        <PdfViewer
          url={url}
          scale={scale}
          rotation={rotation}
          currentPage={currentPage}
          onPageChange={setCurrentPage}
        />
      );
    }

    if (fileType === 'image') {
      return (
        <ImageViewer
          url={url}
          scale={scale}
          rotation={rotation}
        />
      );
    }

    // OFD 或其他格式
    return (
      <div className="flex flex-col items-center justify-center h-full bg-slate-100">
        <FileText size={48} className="mb-4 text-slate-400" />
        <p className="text-slate-600 font-medium">
          {fileType === 'ofd' ? 'OFD 电子凭证' : '文件预览'}
        </p>
        <p className="text-sm text-slate-500 mt-2">
          {fileType === 'ofd' ? '请下载后使用专业阅读器查看' : '此文件类型暂不支持在线预览'}
        </p>
        {blobUrl && (
          <button
            onClick={handleDownload}
            className="mt-4 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors flex items-center gap-2"
          >
            <Download size={16} />
            下载文件
          </button>
        )}
      </div>
    );
  };

  return (
    <div className={`smart-file-preview relative bg-white dark:bg-slate-800 ${className}`}>
      {/* 悬浮工具栏 */}
      {showToolbar && !loading && !error && (
        <div className="preview-toolbar absolute top-0 left-0 right-0 z-10 flex items-center justify-between px-4 py-2 bg-white/90 dark:bg-slate-800/90 backdrop-blur-sm border-b border-slate-200 dark:border-slate-700">
          {/* 左侧：文件名 */}
          <div className="flex items-center gap-2 flex-1 min-w-0">
            <FileText size={16} />
            <span className="text-sm font-medium text-slate-800 dark:text-white truncate">
              {fileName}
            </span>
            {files && files.length > 1 && (
              <>
                <span className="text-slate-400">•</span>
                <span className="text-xs text-slate-500">
                  {currentIndex + 1} / {files.length}
                </span>
              </>
            )}
          </div>

          {/* 中间：工具按钮 */}
          <div className="flex items-center gap-1">
            {/* 缩放 */}
            <button
              onClick={handleZoomOut}
              disabled={scale <= 0.5}
              className="p-1.5 text-slate-600 hover:bg-slate-100 dark:text-slate-300 dark:hover:bg-slate-700 rounded disabled:opacity-40"
              title="缩小"
            >
              <ZoomOut size={16} />
            </button>
            <span className="text-xs text-slate-600 px-2">{Math.round(scale * 100)}%</span>
            <button
              onClick={handleZoomIn}
              disabled={scale >= 3}
              className="p-1.5 text-slate-600 hover:bg-slate-100 dark:text-slate-300 dark:hover:bg-slate-700 rounded disabled:opacity-40"
              title="放大"
            >
              <ZoomIn size={16} />
            </button>
            {scale !== 1 && (
              <button
                onClick={handleResetZoom}
                className="px-2 py-1 text-xs text-slate-600 hover:bg-slate-100 dark:text-slate-300 dark:hover:bg-slate-700 rounded"
              >
                重置
              </button>
            )}

            {/* 旋转 */}
            <button
              onClick={handleRotate}
              className="p-1.5 text-slate-600 hover:bg-slate-100 dark:text-slate-300 dark:hover:bg-slate-700 rounded"
              title="旋转"
            >
              <RotateCw size={16} />
            </button>

            {/* 下载 */}
            {blobUrl && (
              <button
                onClick={handleDownload}
                className="p-1.5 text-slate-600 hover:bg-slate-100 dark:text-slate-300 dark:hover:bg-slate-700 rounded"
                title="下载"
              >
                <Download size={16} />
              </button>
            )}
          </div>

          {/* 右侧：文件切换 */}
          {showFileNav && files && files.length > 1 && (
            <div className="flex items-center gap-1">
              <button
                onClick={handlePrev}
                disabled={!hasPrev}
                className="p-1.5 text-slate-600 hover:bg-slate-100 dark:text-slate-300 dark:hover:bg-slate-700 rounded disabled:opacity-40"
                title="上一张"
              >
                <ChevronLeft size={16} />
              </button>
              <button
                onClick={handleNext}
                disabled={!hasNext}
                className="p-1.5 text-slate-600 hover:bg-slate-100 dark:text-slate-300 dark:hover:bg-slate-700 rounded disabled:opacity-40"
                title="下一张"
              >
                <ChevronRight size={16} />
              </button>
            </div>
          )}
        </div>
      )}

      {/* 预览内容 */}
      <div className="preview-content flex items-center justify-center h-full min-h-[400px]">
        {renderContent()}
      </div>
    </div>
  );
}

// 辅助函数：检测文件类型
function detectFileType(fileName: string): 'pdf' | 'image' | 'ofd' | 'unknown' {
  const ext = fileName.split('.').pop()?.toLowerCase();
  if (ext === 'pdf') return 'pdf';
  if (['jpg', 'jpeg', 'png', 'gif', 'bmp', 'webp'].includes(ext || '')) return 'image';
  if (ext === 'ofd') return 'ofd';
  return 'unknown';
}

export default SmartFilePreview;

// Input: React, previewApi
// Output: useFilePreview Hook
// Pos: 通用复用组件 - 预览数据获取 Hook

import { useState, useEffect, useCallback, useRef } from 'react';
import { previewApi, PreviewRequest, WatermarkMetadata } from '../../api/preview';

export interface UseFilePreviewParams {
  /** 档案ID（已归档档案使用） */
  archiveId?: string;
  /** 文件ID（电子凭证池或附件使用） */
  fileId?: string;
  /** 是否为电子凭证池模式（未归档） */
  isPool?: boolean;
  /** 预览模式 */
  mode?: 'stream' | 'presigned' | 'rendered';
  /** 是否自动加载（默认 true） */
  autoLoad?: boolean;
}

export interface UseFilePreviewReturn {
  /** Blob URL（用于 iframe/img src） */
  blobUrl: string | null;
  /** 预签名 URL（presigned 模式） */
  presignedUrl: string | null;
  /** 水印元数据 */
  watermark: WatermarkMetadata | null;
  /** 追踪ID */
  traceId: string | null;
  /** 加载状态 */
  loading: boolean;
  /** 错误信息 */
  error: string | null;
  /** 重试加载 */
  retry: () => void;
}

/**
 * 文件预览 Hook
 * <p>
 * 统一的预览数据获取逻辑，支持 stream/presigned/rendered 三种模式
 * 自动处理权限、水印、错误等
 * </p>
 */
export function useFilePreview(params: UseFilePreviewParams): UseFilePreviewReturn {
  const { archiveId, fileId, isPool = false, mode = 'stream', autoLoad = true } = params;

  const [blobUrl, setBlobUrl] = useState<string | null>(null);
  const [presignedUrl, setPresignedUrl] = useState<string | null>(null);
  const [watermark, setWatermark] = useState<WatermarkMetadata | null>(null);
  const [traceId, setTraceId] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // 用于存储 blob URL，避免重复创建
  const blobUrlRef = useRef<string | null>(null);

  // 清理 blob URL
  useEffect(() => {
    return () => {
      if (blobUrlRef.current) {
        URL.revokeObjectURL(blobUrlRef.current);
        blobUrlRef.current = null;
      }
    };
  }, []);

  // 提取错误信息
  const getErrorMessage = useCallback((err: any): string => {
    if (err?.response?.status === 404) {
      return '文件不存在或已被删除';
    }
    if (err?.response?.status === 403) {
      return '您没有权限访问此文件';
    }
    if (err?.response?.status === 410) {
      return '文件已过期';
    }
    if (err?.response?.status === 503) {
      return '预览服务暂时不可用，请稍后重试';
    }
    return err?.message || '加载失败，请重试';
  }, []);

  // 加载预览
  const loadPreview = useCallback(async () => {
    // Pool 模式需要 fileId
    if (isPool && !fileId) {
      setError('缺少文件ID');
      return;
    }
    // Archive 模式需要 archiveId
    if (!isPool && !archiveId) {
      setError('缺少档案ID');
      return;
    }

    setLoading(true);
    setError(null);

    try {
      let result;

      if (isPool) {
        // 电子凭证池模式：使用 fileId 调用 pool preview API
        result = await previewApi.getPoolPreview(fileId!);
      } else {
        // 已归档档案模式：使用 archiveId 调用 archive preview API
        const requestParams: PreviewRequest = {
          archiveId: archiveId!,
          fileId,
          mode,
        };
        result = await previewApi.getPreview(requestParams);
      }

      // 清理旧的 blob URL
      if (blobUrlRef.current) {
        URL.revokeObjectURL(blobUrlRef.current);
        blobUrlRef.current = null;
      }

      if (result.mode === 'presigned') {
        // Presigned 模式
        setPresignedUrl(result.presignedUrl || null);
        setBlobUrl(null);
      } else {
        // Stream/Rendered 模式
        const url = URL.createObjectURL(result.blob);
        blobUrlRef.current = url;
        setBlobUrl(url);
        setPresignedUrl(null);
      }

      // 设置水印和追踪信息
      setWatermark(result.watermark || null);
      setTraceId(result.traceId || null);

    } catch (err: any) {
      console.error('Preview load error:', err);
      setError(getErrorMessage(err));
    } finally {
      setLoading(false);
    }
  }, [archiveId, fileId, isPool, mode, getErrorMessage]);

  // 自动加载
  useEffect(() => {
    if (autoLoad) {
      loadPreview();
    }
  }, [autoLoad, loadPreview]);

  // 重试
  const retry = useCallback(() => {
    loadPreview();
  }, [loadPreview]);

  return {
    blobUrl,
    presignedUrl,
    watermark,
    traceId,
    loading,
    error,
    retry,
  };
}

export default useFilePreview;

// Input: React、lucide-react、scanApi
// Output: FolderMonitorDialog 组件 - 监控文件夹设置对话框
// Pos: src/components/scan/FolderMonitorDialog.tsx

import React, { useState, useEffect } from 'react';
import { X, FolderOpen, Plus, Trash2, CheckCircle, Loader2, AlertCircle } from 'lucide-react';
import { toast } from '../../utils/notificationService';
import { scanApi } from '@api/scan';

/**
 * 文件夹监控配置接口（组件内部使用）
 */
export interface FolderMonitor {
  id?: number;
  folderPath: string;
  isActive: boolean;
  fileFilter: string;
  autoDelete: boolean;
  moveToPath?: string;
}

interface FolderMonitorDialogProps {
  open: boolean;
  onClose: () => void;
  onSuccess?: () => void;
}

/**
 * 监控文件夹设置对话框
 *
 * 允许用户配置服务器端文件夹监控，扫描仪将文件保存到指定文件夹后，
 * 系统会自动检测并导入到工作区。
 */
export const FolderMonitorDialog: React.FC<FolderMonitorDialogProps> = ({ open, onClose, onSuccess }) => {
  const [monitors, setMonitors] = useState<FolderMonitor[]>([]);
  const [newPath, setNewPath] = useState('');
  const [fileFilter, setFileFilter] = useState('*.pdf;*.jpg;*.jpeg;*.png');
  const [autoDelete, setAutoDelete] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (open) {
      loadMonitors();
    }
  }, [open]);

  const loadMonitors = async () => {
    setIsLoading(true);
    setError(null);
    try {
      const response = await scanApi.getFolderMonitors();
      // Transform API response to component format
      setMonitors(
        response.map(m => ({
          id: m.id,
          folderPath: m.folderPath,
          isActive: m.isActive ?? true,
          fileFilter: m.fileFilter || '*.pdf;*.jpg;*.jpeg;*.png',
          autoDelete: m.autoDelete ?? false,
          moveToPath: m.moveToPath,
        }))
      );
    } catch (err) {
      console.error('Failed to load folder monitors:', err);
      setError('加载监控配置失败');
      toast.error('加载监控配置失败');
    } finally {
      setIsLoading(false);
    }
  };

  const handleAdd = async () => {
    if (!newPath.trim()) {
      toast.error('请输入文件夹路径');
      return;
    }

    setIsSaving(true);
    setError(null);
    try {
      const response = await scanApi.addFolderMonitor({
        folderPath: newPath,
        fileFilter,
        autoDelete,
      });

      setMonitors(prev => [
        ...prev,
        {
          id: response.id,
          folderPath: response.folderPath,
          isActive: response.isActive ?? true,
          fileFilter: response.fileFilter || '*.pdf;*.jpg;*.jpeg;*.png',
          autoDelete: response.autoDelete ?? false,
          moveToPath: response.moveToPath,
        },
      ]);
      setNewPath('');
      setFileFilter('*.pdf;*.jpg;*.jpeg;*.png');
      setAutoDelete(false);
      toast.success('监控文件夹已添加');
    } catch (err) {
      console.error('Failed to add folder monitor:', err);
      setError('添加监控文件夹失败');
      toast.error('添加监控文件夹失败');
    } finally {
      setIsSaving(false);
    }
  };

  const handleDelete = async (id: number) => {
    try {
      await scanApi.deleteFolderMonitor(id);
      setMonitors(prev => prev.filter(m => m.id !== id));
      toast.success('监控文件夹已删除');
    } catch (err) {
      console.error('Failed to delete folder monitor:', err);
      toast.error('删除失败');
    }
  };

  const handleToggleActive = async (id: number, isActive: boolean) => {
    try {
      const response = await scanApi.toggleFolderMonitor(id);
      setMonitors(prev =>
        prev.map(m =>
          m.id === id
            ? {
                ...m,
                isActive: response.isActive ?? !isActive,
              }
            : m
        )
      );
      toast.success(response.isActive ?? !isActive ? '监控已启用' : '监控已暂停');
    } catch (err) {
      console.error('Failed to toggle folder monitor:', err);
      toast.error('切换状态失败');
    }
  };

  const handleClose = () => {
    setNewPath('');
    setFileFilter('*.pdf;*.jpg;*.jpeg;*.png');
    setAutoDelete(false);
    setError(null);
    onClose();
    onSuccess?.();
  };

  if (!open) return null;

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 animate-in fade-in duration-200">
      <div className="bg-white rounded-2xl w-full max-w-2xl mx-4 max-h-[85vh] overflow-hidden flex flex-col animate-in zoom-in-95 duration-200">
        {/* Header */}
        <div className="p-6 border-b border-slate-200 flex justify-between items-center">
          <h2 className="text-xl font-bold flex items-center gap-2 text-slate-800">
            <FolderOpen className="text-primary-600" size={24} />
            监控文件夹设置
          </h2>
          <button
            onClick={handleClose}
            className="p-2 hover:bg-slate-100 rounded-lg transition-colors"
          >
            <X size={20} className="text-slate-400" />
          </button>
        </div>

        {/* Content */}
        <div className="p-6 flex-1 overflow-y-auto">
          {error && (
            <div className="mb-4 p-3 bg-rose-50 border border-rose-200 rounded-lg flex items-start gap-2">
              <AlertCircle size={18} className="text-rose-500 shrink-0 mt-0.5" />
              <p className="text-sm text-rose-700">{error}</p>
            </div>
          )}

          {/* Add New Monitor */}
          <div className="mb-6 p-4 bg-slate-50 rounded-xl border border-slate-200">
            <h3 className="text-sm font-bold text-slate-700 mb-4 flex items-center gap-2">
              <Plus size={16} className="text-primary-600" />
              添加新监控
            </h3>

            <div className="space-y-4">
              {/* 文件夹路径 */}
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">
                  文件夹路径 <span className="text-rose-500">*</span>
                </label>
                <input
                  type="text"
                  value={newPath}
                  onChange={e => setNewPath(e.target.value)}
                  placeholder="例如: /home/user/Documents/Scan 或 C:\Users\user\Documents\Scan"
                  className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary-500/20 focus:border-primary-500 outline-none transition-all"
                />
                <p className="text-xs text-slate-500 mt-1">
                  这是服务器上的文件系统路径，请确保后端服务有访问权限
                </p>
              </div>

              {/* 文件类型过滤 */}
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">
                  文件类型过滤
                </label>
                <input
                  type="text"
                  value={fileFilter}
                  onChange={e => setFileFilter(e.target.value)}
                  placeholder="*.pdf;*.jpg;*.png"
                  className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary-500/20 focus:border-primary-500 outline-none transition-all"
                />
                <p className="text-xs text-slate-500 mt-1">
                  使用分号分隔多个文件类型，支持通配符 *
                </p>
              </div>

              {/* 选项 */}
              <div className="flex items-center gap-6">
                <label className="flex items-center gap-2 cursor-pointer">
                  <input
                    type="checkbox"
                    checked={autoDelete}
                    onChange={e => setAutoDelete(e.target.checked)}
                    className="w-4 h-4 text-primary-600 border-slate-300 rounded focus:ring-primary-500"
                  />
                  <span className="text-sm text-slate-700">导入后删除源文件</span>
                </label>
              </div>

              {/* 添加按钮 */}
              <button
                onClick={handleAdd}
                disabled={isSaving || !newPath.trim()}
                className="w-full py-2.5 bg-primary-600 text-white rounded-lg font-medium hover:bg-primary-700 active:scale-[0.98] transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
              >
                {isSaving ? (
                  <>
                    <Loader2 size={18} className="animate-spin" />
                    添加中...
                  </>
                ) : (
                  <>
                    <Plus size={18} />
                    添加监控
                  </>
                )}
              </button>
            </div>
          </div>

          {/* 监控列表 */}
          <div>
            <h3 className="text-sm font-bold text-slate-700 mb-3">当前监控列表</h3>

            {isLoading ? (
              <div className="flex items-center justify-center py-8">
                <Loader2 size={24} className="animate-spin text-slate-300" />
              </div>
            ) : monitors.length === 0 ? (
              <div className="text-center py-8 bg-slate-50 rounded-xl border border-dashed border-slate-300">
                <FolderOpen size={48} className="mx-auto mb-3 text-slate-300" />
                <p className="text-slate-400">暂无监控文件夹</p>
                <p className="text-xs text-slate-400 mt-1">添加监控后，扫描仪保存的文件将自动导入</p>
              </div>
            ) : (
              <div className="space-y-3">
                {monitors.map(monitor => (
                  <div
                    key={monitor.id}
                    className="flex items-center justify-between p-4 bg-white border border-slate-200 rounded-xl hover:border-slate-300 transition-all"
                  >
                    <div className="flex items-center gap-3 flex-1 min-w-0">
                      <button
                        onClick={() => handleToggleActive(monitor.id!, !monitor.isActive)}
                        className={`shrink-0 p-1 rounded-full transition-colors ${
                          monitor.isActive
                            ? 'text-emerald-500 hover:bg-emerald-50'
                            : 'text-slate-300 hover:bg-slate-100'
                        }`}
                      >
                        {monitor.isActive ? (
                          <CheckCircle size={20} />
                        ) : (
                          <div className="w-5 h-5 rounded-full border-2 border-current" />
                        )}
                      </button>
                      <div className="flex-1 min-w-0">
                        <p className="font-medium text-slate-800 truncate">{monitor.folderPath}</p>
                        <p className="text-xs text-slate-500">
                          过滤: {monitor.fileFilter}
                          {monitor.autoDelete && ' · 导入后删除'}
                        </p>
                      </div>
                    </div>
                    <button
                      onClick={() => handleDelete(monitor.id!)}
                      className="p-2 text-slate-400 hover:text-rose-500 hover:bg-rose-50 rounded-lg transition-colors"
                      title="删除监控"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* 说明信息 */}
          <div className="mt-6 p-3 bg-blue-50 border border-blue-100 rounded-lg">
            <p className="text-xs text-blue-700">
              <span className="font-bold">使用说明：</span>
            </p>
            <ol className="text-xs text-blue-600 mt-2 space-y-1 list-decimal list-inside">
              <li>配置扫描仪软件，将扫描文件保存到指定文件夹</li>
              <li>系统会自动检测新文件并导入到工作区</li>
              <li>支持 Linux/Windows 路径格式</li>
              <li>请确保后端服务对监控路径有读取权限</li>
            </ol>
          </div>
        </div>

        {/* Footer */}
        <div className="p-4 border-t border-slate-200 bg-slate-50 flex justify-end gap-3 rounded-b-2xl">
          <button
            onClick={handleClose}
            className="px-6 py-2 text-slate-600 hover:bg-slate-200 rounded-lg font-medium transition-colors"
          >
            关闭
          </button>
        </div>
      </div>
    </div>
  );
};

export default FolderMonitorDialog;

// Input: React、lucide-react 图标、AdminSettingsApi
// Output: React 组件 BasicSettings
// Pos: 系统设置组件
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useEffect, useState } from 'react';
import { Save, Loader2 } from 'lucide-react';
import { AdminSettingsApi } from './types';
import { AdminSettingItem, AdminSettingUpdate } from '../../types';
import { toast } from '../../utils/notificationService';

/**
 * 基础设置页面
 * 
 * 包含系统名称、存储配置、默认保管期限等基础参数
 */
interface BasicSettingsProps {
    adminApi: AdminSettingsApi;
}

export const BasicSettings: React.FC<BasicSettingsProps> = ({ adminApi }) => {
    const [settings, setSettings] = useState<Record<string, string>>({});
    const [loading, setLoading] = useState(false);
    const [saving, setSaving] = useState(false);

    useEffect(() => {
        const loadSettings = async () => {
            setLoading(true);
            try {
                const res = await adminApi.getSettings();
                if (res.code === 200 && res.data) {
                    const map: Record<string, string> = {};
                    res.data.forEach((item: AdminSettingItem) => {
                        map[item.configKey] = item.configValue;
                    });
                    setSettings(map);
                }
            } finally {
                setLoading(false);
            }
        };
        loadSettings();
    }, [adminApi]);

    const handleSave = async () => {
        setSaving(true);
        try {
            const payload: AdminSettingUpdate[] = [
                { configKey: 'system.name', configValue: settings['system.name'], category: 'system' },
                { configKey: 'archive.prefix', configValue: settings['archive.prefix'], category: 'archive' },
                { configKey: 'storage.type', configValue: settings['storage.type'], category: 'storage' },
                { configKey: 'storage.path', configValue: settings['storage.path'], category: 'storage' },
                { configKey: 'retention.default', configValue: settings['retention.default'], category: 'archive' },
            ];
            const res = await adminApi.updateSettings(payload);
            if (res.code === 200) {
                toast.success('保存成功');
            } else {
                toast.error(res.message || '保存失败');
            }
        } catch (e: any) {
            toast.error(e?.response?.data?.message || '保存失败');
        } finally {
            setSaving(false);
        }
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center py-12 text-slate-500">
                <Loader2 className="animate-spin mr-2" size={20} />
                加载设置中...
            </div>
        );
    }

    return (
        <div className="space-y-6">
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                <div className="flex items-center justify-between mb-6">
                    <div>
                        <h3 className="text-lg font-bold text-slate-800">基础配置</h3>
                        <p className="text-sm text-slate-500">系统名称、归档参数等基础设置</p>
                    </div>
                    <button
                        onClick={handleSave}
                        disabled={saving}
                        className="px-4 py-2 bg-primary-600 text-white rounded-lg text-sm font-medium hover:bg-primary-700 flex items-center shadow-lg shadow-primary-500/30 transition-all disabled:opacity-60"
                    >
                        <Save size={16} className="mr-2" />
                        {saving ? '保存中...' : '保存更改'}
                    </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="flex flex-col">
                        <label className="text-sm font-medium text-slate-700 mb-2">系统名称</label>
                        <input
                            type="text"
                            value={settings['system.name'] || ''}
                            onChange={(e) => setSettings({ ...settings, 'system.name': e.target.value })}
                            placeholder="例如：XX公司电子会计档案系统"
                            className="border border-slate-300 rounded-lg p-3 text-sm focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition-all"
                        />
                    </div>

                    <div className="flex flex-col">
                        <label className="text-sm font-medium text-slate-700 mb-2">归档全宗号前缀</label>
                        <input
                            type="text"
                            value={settings['archive.prefix'] || ''}
                            onChange={(e) => setSettings({ ...settings, 'archive.prefix': e.target.value })}
                            placeholder="例如：QZ-2024"
                            className="border border-slate-300 rounded-lg p-3 text-sm focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition-all"
                        />
                    </div>

                    <div className="flex flex-col">
                        <label className="text-sm font-medium text-slate-700 mb-2">存储类型</label>
                        <select
                            className="border border-slate-300 rounded-lg p-3 text-sm focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition-all"
                            value={settings['storage.type'] || 'local'}
                            onChange={(e) => setSettings({ ...settings, 'storage.type': e.target.value })}
                        >
                            <option value="local">本地/NAS</option>
                            <option value="oss">对象存储 (OSS/S3)</option>
                            <option value="minio">MinIO</option>
                        </select>
                    </div>

                    <div className="flex flex-col">
                        <label className="text-sm font-medium text-slate-700 mb-2">存储路径/桶名</label>
                        <input
                            type="text"
                            value={settings['storage.path'] || ''}
                            onChange={(e) => setSettings({ ...settings, 'storage.path': e.target.value })}
                            placeholder="例如：/data/archives 或 nexusarchive-bucket"
                            className="border border-slate-300 rounded-lg p-3 text-sm focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition-all"
                        />
                    </div>

                    <div className="flex flex-col">
                        <label className="text-sm font-medium text-slate-700 mb-2">默认保管期限</label>
                        <select
                            className="border border-slate-300 rounded-lg p-3 text-sm focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none transition-all"
                            value={settings['retention.default'] || '30Y'}
                            onChange={(e) => setSettings({ ...settings, 'retention.default': e.target.value })}
                        >
                            <option value="10Y">10年</option>
                            <option value="30Y">30年</option>
                            <option value="PERMANENT">永久</option>
                        </select>
                        <p className="text-xs text-slate-500 mt-1">
                            依据《会计档案管理办法》（财政部79号令）设置
                        </p>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default BasicSettings;

// Input: React、lucide-react 图标、LicenseSettingsApi
// Output: React 组件 LicenseSettings
// Pos: 系统设置组件
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useState, useEffect, useCallback } from 'react';
import { ShieldCheck, Upload, AlertTriangle, CheckCircle2 } from 'lucide-react';
import { LicenseSettingsApi } from './types';
import { LicenseInfo } from '../../types';

interface LicenseSettingsProps {
    licenseApi: LicenseSettingsApi;
}

export const LicenseSettings: React.FC<LicenseSettingsProps> = ({ licenseApi }) => {
    const [license, setLicense] = useState<LicenseInfo | null>(null);
    const [loading, setLoading] = useState(false);
    const [importText, setImportText] = useState('');
    const [error, setError] = useState<string | null>(null);
    const [success, setSuccess] = useState(false);

    const loadLicense = useCallback(async () => {
        try {
            const res = await licenseApi.getCurrent();
            if (res.code === 200 && res.data) {
                setLicense(res.data);
            }
        } catch (e) {
            console.error(e);
        }
    }, [licenseApi]);

    useEffect(() => {
        loadLicense();
    }, [loadLicense]);

    const handleImport = async () => {
        if (!importText.trim()) return;
        setLoading(true);
        setError(null);
        try {
            const res = await licenseApi.load(importText.trim());
            if (res.code === 200) {
                setSuccess(true);
                setLicense(res.data);
                setImportText('');
                // 导入成功后1.5秒刷新页面，让路由守卫重新检测 License 状态
                setTimeout(() => {
                    window.location.href = '/system';
                }, 1500);
            } else {
                setError(res.message || '导入失败');
            }
        } catch (e: any) {
            setError(e?.response?.data?.message || e?.message || '导入异常');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <div className="flex items-center justify-between mb-4">
                <div>
                    <h3 className="text-lg font-bold text-slate-800 mb-1">License 授权管理</h3>
                    <p className="text-xs text-slate-500">查看系统授权状态或导入新的 License 证书。</p>
                </div>
                {success && (
                    <span className="inline-flex items-center text-xs text-emerald-600 bg-emerald-50 border border-emerald-100 rounded px-2 py-1 animate-in fade-in">
                        <CheckCircle2 size={14} className="mr-1" /> 授权更新成功
                    </span>
                )}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {/* 左侧：当前状态 */}
                <div className="border border-slate-100 bg-slate-50 rounded-xl p-4">
                    <h4 className="flex items-center gap-2 font-semibold text-slate-700 mb-4">
                        <ShieldCheck className={`w-5 h-5 ${license ? 'text-emerald-500' : 'text-slate-400'}`} />
                        当前状态
                    </h4>

                    {!license ? (
                        <div className="flex flex-col items-center justify-center py-8 text-slate-400">
                            <AlertTriangle className="w-8 h-8 mb-2 opacity-50" />
                            <span className="text-sm">暂无有效授权</span>
                        </div>
                    ) : (
                        <div className="space-y-3 text-sm">
                            <div className="flex justify-between border-b border-slate-200 pb-2">
                                <span className="text-slate-500">到期时间</span>
                                <span className="font-mono font-medium text-slate-900">{license.expireAt}</span>
                            </div>
                            <div className="flex justify-between border-b border-slate-200 pb-2">
                                <span className="text-slate-500">最大用户数</span>
                                <span className="font-mono font-medium text-slate-900">{license.maxUsers} 人</span>
                            </div>
                            <div className="flex justify-between border-b border-slate-200 pb-2">
                                <span className="text-slate-500">节点限制</span>
                                <span className="font-mono font-medium text-slate-900">{license.nodeLimit} 节点</span>
                            </div>
                            <div className="pt-2 text-xs text-slate-400 break-all">
                                证书指纹: {license.raw?.substring(0, 20)}...
                            </div>
                        </div>
                    )}
                </div>

                {/* 右侧：导入区域 */}
                <div>
                    <h4 className="flex items-center gap-2 font-semibold text-slate-700 mb-2">
                        <Upload className="w-4 h-4 text-slate-500" />
                        导入证书
                    </h4>
                    <textarea
                        className="w-full h-32 border border-slate-300 rounded-lg p-3 text-xs font-mono focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none resize-none"
                        placeholder="在此粘贴 License JSON 字符串..."
                        value={importText}
                        onChange={(e) => setImportText(e.target.value)}
                    />

                    {error && (
                        <div className="mt-2 text-xs text-red-500 flex items-center gap-1">
                            <AlertTriangle size={12} />
                            {error}
                        </div>
                    )}

                    <div className="mt-3 flex justify-end">
                        <button
                            onClick={handleImport}
                            disabled={loading || !importText.trim()}
                            className="px-4 py-2 bg-primary-600 text-white text-sm rounded-lg hover:bg-primary-700 disabled:opacity-50 transition-colors flex items-center gap-2"
                        >
                            {loading ? '验证中...' : '验证并导入'}
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

// Input: React、lucide-react 图标、AdminSettingsApi、org/Tree
// Output: React 组件 OrgSettings
// Pos: 系统设置组件
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useEffect, useMemo, useState } from 'react';
import { Plus, Loader2, Upload } from 'lucide-react';
import { AdminSettingsApi } from './types';
import { Tree, TreeNode } from '../org/Tree';
import { OrgImportResult, OrgNode } from '../../types';
import { toast } from '../../utils/notificationService';

/**
 * 组织架构管理页面
 * 
 * 包含组织创建、树结构展示、列表管理、批量导入
 */
interface OrgSettingsProps {
    adminApi: AdminSettingsApi;
}

export const OrgSettings: React.FC<OrgSettingsProps> = ({ adminApi }) => {
    const [orgs, setOrgs] = useState<OrgNode[]>([]);
    const [orgTree, setOrgTree] = useState<OrgNode[]>([]);
    const [orgLoading, setOrgLoading] = useState(false);
    const [orgForm, setOrgForm] = useState({ name: '', code: '', parentId: '', type: 'COMPANY', orderNum: 0 });
    const [orgImportText, setOrgImportText] = useState('');
    const [orgImportResult, setOrgImportResult] = useState<OrgImportResult | null>(null);

    const treeData = useMemo<TreeNode[]>(() => {
        const mapNodes = (nodes: OrgNode[]): TreeNode[] => nodes.map((node) => ({
            id: node.id,
            label: node.name,
            type: node.type,
            parentId: node.parentId,
            children: node.children ? mapNodes(node.children) : []
        }));
        return mapNodes(orgTree);
    }, [orgTree]);

    useEffect(() => {
        const loadOrgs = async () => {
            setOrgLoading(true);
            try {
                const [listRes, treeRes] = await Promise.all([adminApi.listOrg(), adminApi.getOrgTree()]);
                if (listRes.code === 200 && listRes.data) setOrgs(listRes.data);
                if (treeRes.code === 200 && treeRes.data) setOrgTree(treeRes.data);
            } finally {
                setOrgLoading(false);
            }
        };
        loadOrgs();
    }, [adminApi]);

    const handleCreateOrg = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!orgForm.name) {
            toast.warning('组织名称必填');
            return;
        }
        setOrgLoading(true);
        try {
            const res = await adminApi.createOrg({
                name: orgForm.name,
                code: orgForm.code,
                parentId: orgForm.parentId || undefined,
                type: 'COMPANY', // 强制为 COMPANY
                orderNum: orgForm.orderNum
            });
            if (res.code === 200) {
                setOrgForm({ name: '', code: '', parentId: '', type: 'COMPANY', orderNum: 0 });
                const [listRes, treeRes] = await Promise.all([adminApi.listOrg(), adminApi.getOrgTree()]);
                if (listRes.code === 200 && listRes.data) setOrgs(listRes.data);
                if (treeRes.code === 200 && treeRes.data) setOrgTree(treeRes.data);
            } else {
                toast.error(res.message || '创建失败');
            }
        } catch (e: any) {
            toast.error(e?.response?.data?.message || '创建失败');
        } finally {
            setOrgLoading(false);
        }
    };

    const handleDeleteOrg = async (id: string) => {
        if (!window.confirm('确认删除子公司吗？')) return;
        setOrgLoading(true);
        try {
            await adminApi.deleteOrg(id);
            const [listRes, treeRes] = await Promise.all([adminApi.listOrg(), adminApi.getOrgTree()]);
            if (listRes.code === 200 && listRes.data) setOrgs(listRes.data);
            if (treeRes.code === 200 && treeRes.data) setOrgTree(treeRes.data);
        } finally {
            setOrgLoading(false);
        }
    };

    const handleOrgReorder = async (id: string, direction: 'up' | 'down') => {
        const target = orgs.find((o) => o.id === id);
        if (!target) return;
        const delta = direction === 'up' ? -1 : 1;
        const newOrder = (target.orderNum || 0) + delta;
        setOrgLoading(true);
        try {
            await adminApi.updateOrgOrder(id, newOrder);
            const [listRes, treeRes] = await Promise.all([adminApi.listOrg(), adminApi.getOrgTree()]);
            if (listRes.code === 200 && listRes.data) setOrgs(listRes.data);
            if (treeRes.code === 200 && treeRes.data) setOrgTree(treeRes.data);
        } finally {
            setOrgLoading(false);
        }
    };

    const handleOrgBulkImport = async () => {
        if (!orgImportText.trim()) return;
        let payload: Array<Partial<OrgNode>> = [];
        try {
            const parsed = JSON.parse(orgImportText) as unknown;
            if (!Array.isArray(parsed)) throw new Error();
            payload = parsed as Array<Partial<OrgNode>>;
        } catch {
            toast.warning('请输入合法的 JSON 数组，例如 [{"name":"财务部","code":"FIN"}]');
            return;
        }
        setOrgLoading(true);
        try {
            const res = await adminApi.bulkOrg(payload);
            if (res.code === 200) {
                setOrgImportText('');
                setOrgImportResult(null);
                const [listRes, treeRes] = await Promise.all([adminApi.listOrg(), adminApi.getOrgTree()]);
                if (listRes.code === 200 && listRes.data) setOrgs(listRes.data);
                if (treeRes.code === 200 && treeRes.data) setOrgTree(treeRes.data);
            } else {
                toast.error(res.message || '导入失败');
            }
        } catch (e: any) {
            toast.error(e?.response?.data?.message || '导入失败');
        } finally {
            setOrgLoading(false);
        }
    };

    const handleOrgFileImport = async (file?: File) => {
        if (!file) return;
        setOrgLoading(true);
        setOrgImportResult(null);
        try {
            const res = await adminApi.importOrg(file);
            if (res.code === 200 && res.data) {
                setOrgImportResult(res.data);
                const [listRes, treeRes] = await Promise.all([adminApi.listOrg(), adminApi.getOrgTree()]);
                if (listRes.code === 200 && listRes.data) setOrgs(listRes.data);
                if (treeRes.code === 200 && treeRes.data) setOrgTree(treeRes.data);
            } else {
                toast.error(res.message || '导入失败');
            }
        } catch (e: any) {
            toast.error(e?.response?.data?.message || '导入失败');
        } finally {
            setOrgLoading(false);
        }
    };

    return (
        <div className="space-y-6">
            {/* 创建组织 */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                <div className="flex items-center justify-center mb-4">
                    <div>
                        <h3 className="text-lg font-bold text-slate-800 mb-1">公司管理</h3>
                        <p className="text-xs text-slate-500">创建、查看公司层级</p>
                    </div>
                </div>
                <form className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-4" onSubmit={handleCreateOrg}>
                    <div className="flex flex-col">
                        <label className="text-sm font-medium text-slate-700 mb-1">名称 *</label>
                        <input
                            className="border border-slate-300 rounded-lg p-2 text-sm"
                            value={orgForm.name}
                            onChange={(e) => setOrgForm({ ...orgForm, name: e.target.value })}
                            required
                        />
                    </div>
                    <div className="flex flex-col">
                        <label className="text-sm font-medium text-slate-700 mb-1">编码</label>
                        <input
                            className="border border-slate-300 rounded-lg p-2 text-sm"
                            value={orgForm.code}
                            onChange={(e) => setOrgForm({ ...orgForm, code: e.target.value })}
                        />
                    </div>
                    <div className="flex flex-col">
                        <label className="text-sm font-medium text-slate-700 mb-1">上级 ID</label>
                        <input
                            className="border border-slate-300 rounded-lg p-2 text-sm"
                            value={orgForm.parentId}
                            onChange={(e) => setOrgForm({ ...orgForm, parentId: e.target.value })}
                            placeholder="留空为顶级"
                        />
                    </div>
                    {/* 类型固定为 COMPANY，隐藏选择框 */}
                    <input type="hidden" value="COMPANY" />
                    <div className="flex flex-col">
                        <label className="text-sm font-medium text-slate-700 mb-1">排序</label>
                        <input
                            type="number"
                            className="border border-slate-300 rounded-lg p-2 text-sm"
                            value={orgForm.orderNum}
                            onChange={(e) => setOrgForm({ ...orgForm, orderNum: Number(e.target.value) })}
                        />
                    </div>
                    <div className="md:col-span-3 flex justify-end">
                        <button
                            type="submit"
                            disabled={orgLoading}
                            className="inline-flex items-center px-4 py-2 bg-primary-600 text-white text-sm rounded-lg hover:bg-primary-700 disabled:opacity-60"
                        >
                            <Plus size={16} className="mr-2" />
                            {orgLoading ? '保存中...' : '创建公司'}
                        </button>
                    </div>
                </form>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                    <h4 className="text-sm font-semibold text-slate-800 mb-3">公司架构树</h4>
                    {orgLoading ? (
                        <div className="text-xs text-slate-500 flex items-center">
                            <Loader2 size={14} className="animate-spin mr-1" /> 加载中...
                        </div>
                    ) : (
                        <Tree data={treeData} />
                    )}
                </div>

                <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                    <h4 className="text-sm font-semibold text-slate-800 mb-3">公司列表</h4>
                    <div className="max-h-64 overflow-y-auto text-sm">
                        {orgs.map((org) => (
                            <div key={org.id} className="flex items-center justify-between py-2 border-b last:border-0">
                                <div>
                                    <div className="text-slate-800">{org.name}</div>
                                    <div className="text-xs text-slate-500">
                                        {org.type} · {org.code || '-'} · parent: {org.parentId || '根'}
                                    </div>
                                </div>
                                <button
                                    className="text-red-500 text-xs hover:underline"
                                    onClick={() => handleDeleteOrg(org.id)}
                                    disabled={orgLoading}
                                >
                                    删除
                                </button>
                            </div>
                        ))}
                        {orgs.length === 0 && <div className="text-xs text-slate-500">暂无数据</div>}
                    </div>

                    {/* 排序 */}
                    <div className="mt-4 space-y-2">
                        <div className="text-xs text-slate-600">
                            <span className="font-semibold">排序</span>：点击上/下调整排序号
                        </div>
                        <div className="max-h-32 overflow-y-auto text-xs space-y-1">
                            {orgs.map((org) => (
                                <div key={org.id} className="flex items-center justify-between">
                                    <span>{org.name}（{org.orderNum || 0}）</span>
                                    <span className="space-x-1">
                                        <button
                                            className="px-2 py-0.5 border rounded disabled:opacity-40"
                                            disabled={orgLoading}
                                            onClick={() => handleOrgReorder(org.id, 'up')}
                                        >
                                            上
                                        </button>
                                        <button
                                            className="px-2 py-0.5 border rounded disabled:opacity-40"
                                            disabled={orgLoading}
                                            onClick={() => handleOrgReorder(org.id, 'down')}
                                        >
                                            下
                                        </button>
                                    </span>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* 批量导入 */}
                    <div className="mt-4 pt-4 border-t border-slate-100">
                        <h5 className="text-sm font-semibold text-slate-800 mb-2">批量导入 (JSON 数组)</h5>
                        <textarea
                            className="w-full border border-slate-200 rounded p-2 text-xs"
                            rows={3}
                            placeholder='例如: [{"name":"子公司A","code":"SUB_A"},{"name":"子公司B","code":"SUB_B","parentId":"<上级ID>"}]'
                            value={orgImportText}
                            onChange={(e) => setOrgImportText(e.target.value)}
                        />
                        <div className="flex justify-end mt-2">
                            <button
                                className="px-3 py-1.5 text-xs bg-primary-600 text-white rounded hover:bg-primary-700 disabled:opacity-50"
                                disabled={orgLoading}
                                onClick={handleOrgBulkImport}
                            >
                                批量导入
                            </button>
                        </div>
                    </div>

                    {/* CSV 导入 */}
                    <div className="mt-4 pt-4 border-t border-slate-100">
                        <h5 className="text-sm font-semibold text-slate-800 mb-2">CSV/Excel 导入</h5>
                        <div className="flex items-center space-x-2">
                            <label className="px-3 py-1.5 text-xs border rounded cursor-pointer hover:bg-slate-50 inline-flex items-center space-x-2">
                                <Upload size={14} />
                                <span>选择文件</span>
                                <input
                                    type="file"
                                    accept=".csv,application/vnd.ms-excel,application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
                                    className="hidden"
                                    onChange={(e) => handleOrgFileImport(e.target.files?.[0])}
                                />
                            </label>
                            <button
                                className="text-xs text-blue-600 hover:underline"
                                onClick={async () => {
                                    const tpl = await adminApi.downloadOrgTemplate();
                                    toast.info(`模板示例：\n${tpl.data?.csvHeader}\n${tpl.data?.example}`);
                                }}
                                type="button"
                            >
                                查看模板说明
                            </button>
                        </div>
                        {orgImportResult && (
                            <div className="text-xs text-slate-600 mt-2">
                                <div>成功 {orgImportResult.successCount} 条，失败 {orgImportResult.failCount} 条</div>
                                {orgImportResult.errors && orgImportResult.errors.length > 0 && (
                                    <div className="mt-1 text-red-500">
                                        {orgImportResult.errors.slice(0, 5).map((err, idx) => (
                                            <div key={idx}>{err}</div>
                                        ))}
                                        {orgImportResult.errors.length > 5 && <div>...更多错误请查看日志</div>}
                                    </div>
                                )}
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default OrgSettings;

// Input: React、lucide-react 图标、AdminSettingsApi
// Output: React 组件 RoleSettings
// Pos: 系统设置组件
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useEffect, useState } from 'react';
import { Plus, Edit3, Trash2, Loader2 } from 'lucide-react';
import { AdminSettingsApi } from './types';
import { Role } from '../../types';
import { toast } from '../../utils/notificationService';

interface RoleForm {
    id?: string;
    name: string;
    code: string;
    roleCategory: string;
    type: string;
    description: string;
    permissions: string[];
}

const EXCLUSIVE_ROLE_CODES = ['system_admin', 'security_admin', 'audit_admin'];

/**
 * 角色权限管理页面
 * 
 * 包含角色 CRUD 和权限分配
 */
interface RoleSettingsProps {
    adminApi: AdminSettingsApi;
}

export const RoleSettings: React.FC<RoleSettingsProps> = ({ adminApi }) => {
    const [roles, setRoles] = useState<Role[]>([]);
    const [roleLoading, setRoleLoading] = useState(false);
    const [roleSaving, setRoleSaving] = useState(false);
    const [permissionOptions, setPermissionOptions] = useState<{ key: string; label: string; group: string }[]>([]);

    const [roleForm, setRoleForm] = useState<RoleForm>({
        name: '',
        code: '',
        roleCategory: 'business_user',
        type: 'custom',
        description: '',
        permissions: []
    });

    useEffect(() => {
        const loadRoles = async () => {
            setRoleLoading(true);
            try {
                const res = await adminApi.getRoles({ page: 1, limit: 100 });
                if (res.code === 200 && res.data) {
                    setRoles(res.data.records || []);
                }
            } finally {
                setRoleLoading(false);
            }
        };
        const loadPerms = async () => {
            try {
                const res = await adminApi.getPermissions();
                if (res.code === 200 && res.data) {
                    // 后端返回 { permKey, label, groupName }，需要映射为 { key, label, group }
                    const mapped = (res.data as any[]).map((p: any) => ({
                        key: p.permKey || p.key,
                        label: p.label,
                        group: p.groupName || p.group || '其他'
                    }));
                    setPermissionOptions(mapped);
                }
            } catch {
                // ignore
            }
        };
        loadRoles();
        loadPerms();
    }, [adminApi]);

    const togglePermissionSelection = (perm: string) => {
        setRoleForm((prev) => {
            const exists = prev.permissions.includes(perm);
            return { ...prev, permissions: exists ? prev.permissions.filter((p) => p !== perm) : [...prev.permissions, perm] };
        });
    };

    const handleRoleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!roleForm.name || !roleForm.code) {
            toast.warning('角色名称和编码必填');
            return;
        }
        if (EXCLUSIVE_ROLE_CODES.includes(roleForm.code) && roleForm.roleCategory !== 'system_admin' && roleForm.roleCategory !== 'security_admin' && roleForm.roleCategory !== 'audit_admin') {
            toast.warning('三员互斥：系统/安全/审计角色的类别应与其编码一致');
            return;
        }
        setRoleSaving(true);
        try {
            const payload = {
                name: roleForm.name,
                code: roleForm.code,
                roleCategory: roleForm.roleCategory,
                type: roleForm.type,
                description: roleForm.description,
                permissions: JSON.stringify(roleForm.permissions)
            };
            const res = roleForm.id
                ? await adminApi.updateRole(roleForm.id, payload)
                : await adminApi.createRole(payload);

            if (res.code === 200) {
                setRoleForm({
                    id: undefined,
                    name: '',
                    code: '',
                    roleCategory: 'business_user',
                    type: 'custom',
                    description: '',
                    permissions: []
                });
                const reload = await adminApi.getRoles({ page: 1, limit: 100 });
                if (reload.code === 200 && reload.data) setRoles(reload.data.records || []);
            } else {
                toast.error(res.message || '保存失败');
            }
        } catch (e: any) {
            toast.error(e?.response?.data?.message || '保存失败');
        } finally {
            setRoleSaving(false);
        }
    };

    const handleRoleEdit = (role: Role) => {
        let perms: string[] = [];
        if (role.permissions) {
            try {
                const parsed = JSON.parse(role.permissions);
                if (Array.isArray(parsed)) perms = parsed;
            } catch {
                perms = [];
            }
        }

        if (EXCLUSIVE_ROLE_CODES.includes(role.code)) {
            toast.info('提示：系统/安全/审计三员角色互斥，请勿同时分配给同一用户。');
        }

        setRoleForm({
            id: role.id,
            name: role.name,
            code: role.code,
            roleCategory: role.roleCategory || 'business_user',
            type: role.type || 'custom',
            description: role.description || '',
            permissions: perms
        });
    };

    const handleRoleDelete = async (id: string) => {
        if (!window.confirm('确认删除该角色？')) return;
        setRoleSaving(true);
        try {
            const res = await adminApi.deleteRole(id);
            if (res.code === 200) {
                const reload = await adminApi.getRoles({ page: 1, limit: 100 });
                if (reload.code === 200 && reload.data) setRoles(reload.data.records || []);
            } else {
                toast.error(res.message || '删除失败');
            }
        } catch (e: any) {
            toast.error(e?.response?.data?.message || '删除失败');
        } finally {
            setRoleSaving(false);
        }
    };

    // 按组分类权限
    const groupedPermissions = permissionOptions.reduce((acc, curr) => {
        const g = curr.group || '其他';
        if (!acc[g]) acc[g] = [];
        acc[g].push(curr);
        return acc;
    }, {} as Record<string, typeof permissionOptions>);

    return (
        <div className="space-y-6">
            {/* 角色表单 */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                <div className="flex items-center justify-between mb-4">
                    <div>
                        <h3 className="text-lg font-bold text-slate-800 mb-1">
                            {roleForm.id ? '编辑角色' : '创建角色'}
                        </h3>
                        <p className="text-xs text-slate-500">配置角色信息和权限分配</p>
                    </div>
                </div>

                <form className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4" onSubmit={handleRoleSave}>
                    <div className="flex flex-col">
                        <label className="text-sm font-medium text-slate-700 mb-1">角色名称 *</label>
                        <input
                            className="border border-slate-300 rounded-lg p-2 text-sm"
                            value={roleForm.name}
                            onChange={(e) => setRoleForm({ ...roleForm, name: e.target.value })}
                            required
                        />
                    </div>
                    <div className="flex flex-col">
                        <label className="text-sm font-medium text-slate-700 mb-1">角色编码 *</label>
                        <input
                            className="border border-slate-300 rounded-lg p-2 text-sm"
                            value={roleForm.code}
                            onChange={(e) => setRoleForm({ ...roleForm, code: e.target.value })}
                            required
                        />
                    </div>
                    <div className="flex flex-col">
                        <label className="text-sm font-medium text-slate-700 mb-1">角色类别</label>
                        <select
                            className="border border-slate-300 rounded-lg p-2 text-sm"
                            value={roleForm.roleCategory}
                            onChange={(e) => setRoleForm({ ...roleForm, roleCategory: e.target.value })}
                        >
                            <option value="business_user">业务操作员</option>
                            <option value="system_admin">系统管理员</option>
                            <option value="security_admin">安全保密员</option>
                            <option value="audit_admin">安全审计员</option>
                        </select>
                    </div>
                    <div className="flex flex-col">
                        <label className="text-sm font-medium text-slate-700 mb-1">类型</label>
                        <select
                            className="border border-slate-300 rounded-lg p-2 text-sm"
                            value={roleForm.type}
                            onChange={(e) => setRoleForm({ ...roleForm, type: e.target.value })}
                        >
                            <option value="custom">自定义</option>
                            <option value="system">系统</option>
                        </select>
                    </div>
                    <div className="flex flex-col md:col-span-2">
                        <label className="text-sm font-medium text-slate-700 mb-1">描述</label>
                        <textarea
                            className="border border-slate-300 rounded-lg p-2 text-sm"
                            value={roleForm.description}
                            onChange={(e) => setRoleForm({ ...roleForm, description: e.target.value })}
                        />
                    </div>
                    <div className="flex flex-col md:col-span-2">
                        <label className="text-sm font-medium text-slate-700 mb-2">分配权限</label>
                        <div className="space-y-3 max-h-60 overflow-y-auto border border-slate-200 rounded p-3">
                            {(Object.entries(groupedPermissions) as [string, { key: string; label: string; group: string }[]][]).map(([group, perms]) => (
                                <div key={group}>
                                    <div className="text-xs font-bold text-slate-500 mb-1 bg-slate-50 px-1">{group}</div>
                                    <div className="flex flex-wrap gap-2">
                                        {perms.map((perm) => (
                                            <label
                                                key={perm.key}
                                                className="inline-flex items-center space-x-1 px-2 py-1 border border-slate-200 rounded text-xs cursor-pointer hover:bg-slate-50"
                                            >
                                                <input
                                                    type="checkbox"
                                                    checked={roleForm.permissions.includes(perm.key)}
                                                    onChange={() => togglePermissionSelection(perm.key)}
                                                />
                                                <span>{perm.label}</span>
                                            </label>
                                        ))}
                                    </div>
                                </div>
                            ))}
                            {permissionOptions.length === 0 && <span className="text-xs text-slate-500">暂无权限定义</span>}
                        </div>
                    </div>
                    <div className="md:col-span-2 flex justify-end space-x-2">
                        {roleForm.id && (
                            <button
                                type="button"
                                className="px-3 py-2 text-xs border rounded"
                                onClick={() =>
                                    setRoleForm({
                                        id: undefined,
                                        name: '',
                                        code: '',
                                        roleCategory: 'business_user',
                                        type: 'custom',
                                        description: '',
                                        permissions: []
                                    })
                                }
                            >
                                取消编辑
                            </button>
                        )}
                        <button
                            type="submit"
                            disabled={roleSaving}
                            className="inline-flex items-center px-4 py-2 bg-primary-600 text-white text-sm rounded-lg hover:bg-primary-700 disabled:opacity-60"
                        >
                            <Plus size={16} className="mr-2" />
                            {roleSaving ? '保存中...' : roleForm.id ? '更新角色' : '创建角色'}
                        </button>
                    </div>
                </form>
            </div>

            {/* 角色列表 */}
            <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                <h3 className="text-lg font-bold text-slate-800 mb-4">角色列表</h3>
                <div className="overflow-x-auto">
                    <table className="min-w-full text-sm text-left">
                        <thead>
                            <tr className="text-slate-500 border-b">
                                <th className="py-2 pr-4">角色名称</th>
                                <th className="py-2 pr-4">编码</th>
                                <th className="py-2 pr-4">类别</th>
                                <th className="py-2 pr-4">类型</th>
                                <th className="py-2 pr-4">描述</th>
                                <th className="py-2 pr-4">操作</th>
                            </tr>
                        </thead>
                        <tbody>
                            {roleLoading ? (
                                <tr>
                                    <td colSpan={6} className="py-4 text-center text-slate-500">
                                        <Loader2 className="animate-spin inline-block mr-2" size={16} />
                                        加载中...
                                    </td>
                                </tr>
                            ) : roles.length === 0 ? (
                                <tr>
                                    <td colSpan={6} className="py-4 text-center text-slate-500">
                                        暂无角色
                                    </td>
                                </tr>
                            ) : (
                                roles.map((role) => (
                                    <tr key={role.id} className="border-b last:border-0">
                                        <td className="py-2 pr-4">{role.name}</td>
                                        <td className="py-2 pr-4">{role.code}</td>
                                        <td className="py-2 pr-4">{role.roleCategory || '-'}</td>
                                        <td className="py-2 pr-4">{role.type || '-'}</td>
                                        <td className="py-2 pr-4 max-w-xs truncate">{role.description || '-'}</td>
                                        <td className="py-2 pr-4 space-x-2 text-xs">
                                            <button
                                                className="text-blue-600 hover:underline inline-flex items-center"
                                                onClick={() => handleRoleEdit(role)}
                                            >
                                                <Edit3 size={14} className="mr-1" /> 编辑
                                            </button>
                                            {role.type !== 'system' && (
                                                <button
                                                    className="text-red-500 hover:underline inline-flex items-center"
                                                    onClick={() => handleRoleDelete(role.id)}
                                                    disabled={roleSaving}
                                                >
                                                    <Trash2 size={14} className="mr-1" /> 删除
                                                </button>
                                            )}
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

export default RoleSettings;

// Input: React、lucide-react 图标、AdminSettingsApi
