              <AlertCircle size={48} className="text-gray-400" />
              <div className="text-lg font-medium">未执行诊断</div>
              <button
                onClick={actions.startDiagnosis}
                className="px-6 py-2 bg-blue-600 text-white rounded hover:bg-blue-700"
