import React, { useMemo } from 'react';
import { Table } from 'antd';
import type { ColumnsType, TablePaginationConfig } from 'antd/es/table';
import type { PaginationProps } from 'antd/es/pagination';
import { ChevronLeft, ChevronRight } from 'lucide-react';

export interface ColumnType<T = any> {
  key: string;
  title: string;
  dataIndex?: string | string[];
  render?: (value: any, record: T, index: number) => React.ReactNode;
  width?: number;
  align?: 'left' | 'center' | 'right';
  fixed?: 'left' | 'right';
  sorter?: boolean | ((a: T, b: T) => number);
  filters?: Array<{ text: string; value: any }>;
  onFilter?: (value: any, record: T) => boolean;
}

export interface DataTableProps<T = any> {
  columns: ColumnType<T>[];
  dataSource: T[];
  rowKey?: string | ((record: T) => string);
  loading?: boolean;
  pagination?: false | TablePaginationConfig;
  onRow?: (record: T, index?: number) => {
    onClick?: (e: React.MouseEvent) => void;
    onDoubleClick?: (e: React.MouseEvent) => void;
    [key: string]: any;
  };
  scroll?: { x?: number; y?: number };
  className?: string;
  size?: 'large' | 'middle' | 'small';
  bordered?: boolean;
}

/**
 * 统一的数据表格组件
 * <p>
 * 基于 Ant Design Table，提供统一的样式和分页配置
 * </p>
 */
export function DataTable<T extends Record<string, any>>({
  columns,
  dataSource,
  rowKey = 'id',
  loading = false,
  pagination = { pageSize: 10, showSizeChanger: true, showTotal: (total: number) => `共 ${total} 条` },
  onRow,
  scroll,
  className = '',
  size = 'middle',
  bordered = false,
}: DataTableProps<T>) {
  // Convert columns to Ant Design format
  const antColumns: ColumnsType<T> = useMemo(() => {
    return columns.map((col) => ({
      key: col.key,
      title: col.title,
      dataIndex: col.dataIndex,
      render: col.render,
      width: col.width,
      align: col.align || 'left',
      fixed: col.fixed,
      sorter: col.sorter,
      filters: col.filters,
      onFilter: col.onFilter,
    }));
  }, [columns]);

  // Custom pagination icons
  const itemRender: PaginationProps['itemRender'] = (
    current: number,
    type: string,
    originalElement: React.ReactNode
  ) => {
    if (type === 'prev') {
      return <ChevronLeft className="w-4 h-4" />;
    }
    if (type === 'next') {
      return <ChevronRight className="w-4 h-4" />;
    }
    if (type === 'page') {
      return <span className="px-2">{current}</span>;
    }
    return originalElement;
  };

  const mergedPagination = pagination === false ? false : {
    ...pagination,
    itemRender,
  };

  return (
    <div className={`data-table ${className}`}>
      <Table<T>
        columns={antColumns}
        dataSource={dataSource}
        rowKey={rowKey}
        loading={loading}
        pagination={mergedPagination}
        onRow={onRow}
        scroll={scroll}
        size={size}
        bordered={bordered}
        className="custom-table"
      />
    </div>
  );
}

export default DataTable;

// Input: React, lucide-react
// Output: TableActions 组件
// Pos: 通用复用组件 - 表格操作栏

import React from 'react';
import { MoreVertical, Eye, Pencil, Trash2, Download, Copy, CheckCircle, XCircle } from 'lucide-react';

export type ActionType = 'view' | 'edit' | 'delete' | 'download' | 'copy' | 'approve' | 'reject' | 'custom';

export interface ActionItem {
  key: ActionType | string;
  label: string;
  icon?: React.ReactNode;
  onClick: (record: any) => void;
  disabled?: boolean | ((record: any) => boolean);
  danger?: boolean;
  show?: boolean | ((record: any) => boolean);
}

export interface TableActionsProps {
  actions: ActionItem[];
  record: any;
  maxVisible?: number;
  className?: string;
}

/**
 * 统一的表格操作组件
 * <p>
 * 提供下拉菜单形式的操作按钮，支持自定义图标和样式
 * </p>
 */
export function TableActions({ actions, record, maxVisible = 3, className = '' }: TableActionsProps) {
  const [isOpen, setIsOpen] = React.useState(false);
  const dropdownRef = React.useRef<HTMLDivElement>(null);

  // Close dropdown when clicking outside
  React.useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  // Filter visible actions
  const visibleActions = actions.filter(action => {
    if (typeof action.show === 'function') {
      return action.show(record);
    }
    return action.show !== false;
  });

  const primaryActions = visibleActions.slice(0, maxVisible);
  const moreActions = visibleActions.slice(maxVisible);

  const isDisabled = (action: ActionItem) => {
    if (typeof action.disabled === 'function') {
      return action.disabled(record);
    }
    return action.disabled || false;
  };

  const getDefaultIcon = (key: ActionType | string) => {
    switch (key) {
      case 'view': return <Eye size={16} />;
      case 'edit': return <Pencil size={16} />;
      case 'delete': return <Trash2 size={16} />;
      case 'download': return <Download size={16} />;
      case 'copy': return <Copy size={16} />;
      case 'approve': return <CheckCircle size={16} />;
      case 'reject': return <XCircle size={16} />;
      default: return null;
    }
  };

  const renderButton = (action: ActionItem) => {
    const disabled = isDisabled(action);

    return (
      <button
        key={action.key}
        onClick={() => !disabled && action.onClick(record)}
        disabled={disabled}
        className={`
          p-1.5 rounded-lg transition-colors
          ${action.danger
            ? 'text-rose-600 hover:bg-rose-50 dark:hover:bg-rose-900/20'
            : 'text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-700'
          }
          ${disabled ? 'opacity-40 cursor-not-allowed' : ''}
        `}
        title={action.label}
      >
        {action.icon || getDefaultIcon(action.key)}
      </button>
    );
  };

  return (
    <div ref={dropdownRef} className={`table-actions flex items-center gap-1 ${className}`}>
      {/* Primary Actions */}
      {primaryActions.map(renderButton)}

      {/* More Actions Dropdown */}
      {moreActions.length > 0 && (
        <div className="relative">
          <button
            onClick={() => setIsOpen(!isOpen)}
            className="p-1.5 text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg transition-colors"
            title="更多操作"
          >
            <MoreVertical size={16} />
          </button>

          {isOpen && (
            <div className="absolute right-0 z-10 mt-1 w-48 bg-white dark:bg-slate-700 rounded-lg shadow-lg border border-slate-200 dark:border-slate-600 py-1">
              {moreActions.map(action => {
                const disabled = isDisabled(action);
                return (
                  <button
                    key={action.key}
                    onClick={() => {
                      if (!disabled) {
                        setIsOpen(false);
                        action.onClick(record);
                      }
                    }}
                    disabled={disabled}
                    className={`
                      w-full px-4 py-2 text-left text-sm flex items-center gap-2 transition-colors
                      ${action.danger
                        ? 'text-rose-600 hover:bg-rose-50 dark:hover:bg-rose-900/20'
                        : 'text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-600'
                      }
                      ${disabled ? 'opacity-40 cursor-not-allowed' : ''}
                    `}
                  >
                    {action.icon || getDefaultIcon(action.key)}
                    {action.label}
                  </button>
                );
              })}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

export default TableActions;

// Input: React, lucide-react
// Output: TableFilters 组件
// Pos: 通用复用组件 - 表格筛选器

import React, { useState } from 'react';
import { Search, X, Filter, SlidersHorizontal } from 'lucide-react';

export interface FilterField {
  key: string;
  label: string;
  type: 'text' | 'select' | 'date' | 'dateRange';
  placeholder?: string;
  options?: Array<{ label: string; value: string | number }>;
}

export interface TableFiltersProps {
  fields: FilterField[];
  values: Record<string, any>;
  onChange: (values: Record<string, any>) => void;
  onSearch?: () => void;
  onReset?: () => void;
  className?: string;
  collapsible?: boolean;
}

/**
 * 统一的表格筛选组件
 * <p>
 * 支持多种筛选字段类型，可折叠
 * </p>
 */
export function TableFilters({
  fields,
  values,
  onChange,
  onSearch,
  onReset,
  className = '',
  collapsible = true,
}: TableFiltersProps) {
  const [isExpanded, setIsExpanded] = useState(!collapsible);
  const hasActiveFilters = Object.values(values).some(v => v !== '' && v !== undefined && v !== null);

  const handleChange = (key: string, value: any) => {
    onChange({ ...values, [key]: value });
  };

  const handleReset = () => {
    const resetValues: Record<string, any> = {};
    fields.forEach(field => {
      resetValues[field.key] = undefined;
    });
    onChange(resetValues);
    onReset?.();
  };

  const renderField = (field: FilterField) => {
    const value = values[field.key];

    switch (field.type) {
      case 'text':
        return (
          <input
            type="text"
            value={value || ''}
            onChange={(e) => handleChange(field.key, e.target.value)}
            placeholder={field.placeholder || `搜索${field.label}`}
            className="px-3 py-2 border border-slate-200 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-700 text-slate-800 dark:text-white text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          />
        );

      case 'select':
        return (
          <select
            value={value || ''}
            onChange={(e) => handleChange(field.key, e.target.value)}
            className="px-3 py-2 border border-slate-200 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-700 text-slate-800 dark:text-white text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          >
            <option value="">全部</option>
            {field.options?.map(opt => (
              <option key={opt.value} value={opt.value}>
                {opt.label}
              </option>
            ))}
          </select>
        );

      case 'date':
        return (
          <input
            type="date"
            value={value || ''}
            onChange={(e) => handleChange(field.key, e.target.value)}
            className="px-3 py-2 border border-slate-200 dark:border-slate-600 rounded-lg bg-white dark:bg-slate-700 text-slate-800 dark:text-white text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          />
        );

      default:
        return null;
    }
  };

  return (
    <div className={`table-filters ${className}`}>
      {/* Filter Toggle */}
      {collapsible && (
        <button
          onClick={() => setIsExpanded(!isExpanded)}
          className="flex items-center gap-2 px-3 py-2 text-sm text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg transition-colors mb-2"
        >
          <SlidersHorizontal size={16} />
          <span>筛选条件</span>
          {hasActiveFilters && (
            <span className="px-2 py-0.5 bg-blue-100 text-blue-600 rounded-full text-xs">
              {Object.values(values).filter(v => v !== '' && v !== undefined && v !== null).length}
            </span>
          )}
        </button>
      )}

      {/* Filter Fields */}
      {isExpanded && (
        <div className="p-4 bg-slate-50 dark:bg-slate-800 rounded-xl space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            {fields.map(field => (
              <div key={field.key} className="flex flex-col gap-1.5">
                <label className="text-sm font-medium text-slate-700 dark:text-slate-300">
                  {field.label}
                </label>
                {renderField(field)}
              </div>
            ))}
          </div>

          {/* Actions */}
          <div className="flex items-center justify-end gap-2 pt-2 border-t border-slate-200 dark:border-slate-600">
            {hasActiveFilters && (
              <button
                onClick={handleReset}
                className="flex items-center gap-1.5 px-4 py-2 text-sm text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg transition-colors"
              >
                <X size={16} />
                重置
              </button>
            )}
            <button
              onClick={onSearch}
              className="flex items-center gap-1.5 px-4 py-2 text-sm text-white bg-blue-600 hover:bg-blue-700 rounded-lg transition-colors"
            >
              <Search size={16} />
              搜索
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

export default TableFilters;

