 * - 悬停状态切换
 * - 预览回调触发
 * - 删除按钮显示/隐藏
 * - 自定义预览标签
 * - 事件冒泡阻止
 */

import { describe, it, expect, vi } from 'vitest';
import { render, screen, fireEvent } from '@testing-library/react';
import { TablePreviewAction } from '../TablePreviewAction';

describe('TablePreviewAction', () => {
  // Mock 回调函数
  const mockOnPreview = vi.fn();
  const mockOnDelete = vi.fn();

  beforeEach(() => {
    // 每个测试前清除 mock 调用记录
    mockOnPreview.mockClear();
    mockOnDelete.mockClear();
  });

  describe('基础渲染', () => {
    it('应该成功渲染组件', () => {
      expect(() => (
        <TablePreviewAction
          hovered={false}
          onPreview={mockOnPreview}
        />
      )).toBeTruthy();
    });

    it('应该渲染预览按钮', () => {
      render(
        <TablePreviewAction
          hovered={false}
          onPreview={mockOnPreview}
        />
      );

      // 检查是否有"查看"文字
      expect(screen.getByText('查看')).toBeInTheDocument();
    });

    it('应该渲染默认预览标签', () => {
      render(
        <TablePreviewAction
          hovered={false}
          onPreview={mockOnPreview}
        />
      );

      expect(screen.getByText('查看')).toBeInTheDocument();
    });

    it('应该渲染自定义预览标签', () => {
      render(
        <TablePreviewAction
          hovered={false}
          onPreview={mockOnPreview}
          previewLabel="预览详情"
        />
      );

      expect(screen.getByText('预览详情')).toBeInTheDocument();
      expect(screen.queryByText('查看')).not.toBeInTheDocument();
    });
  });

  describe('悬停状态', () => {
    it('未悬停时应该显示灰色背景样式', () => {
      const { container } = render(
        <TablePreviewAction
          hovered={false}
          onPreview={mockOnPreview}
        />
      );

      const button = container.querySelector('button');
      expect(button).toBeInTheDocument();
      expect(button?.className).toContain('bg-gray-100');
      expect(button?.className).toContain('text-gray-600');
    });

    it('悬停时应该显示蓝色背景样式', () => {
      const { container } = render(
        <TablePreviewAction
          hovered={true}
          onPreview={mockOnPreview}
        />
      );

      const button = container.querySelector('button');
      expect(button).toBeInTheDocument();
      expect(button?.className).toContain('bg-blue-600');
      expect(button?.className).toContain('text-white');
      expect(button?.className).toContain('shadow-md');
    });

    it('悬停样式应该包含过渡动画类', () => {
      const { container } = render(
        <TablePreviewAction
          hovered={true}
          onPreview={mockOnPreview}
        />
      );

      const button = container.querySelector('button');
      expect(button?.className).toContain('transition-all');
      expect(button?.className).toContain('duration-200');
    });
  });

  describe('预览功能', () => {
    it('点击预览按钮应该触发 onPreview 回调', () => {
      render(
        <TablePreviewAction
          hovered={false}
          onPreview={mockOnPreview}
        />
      );

      const previewButton = screen.getByText('查看');
      fireEvent.click(previewButton);

      expect(mockOnPreview).toHaveBeenCalledTimes(1);
    });

    it('应该阻止事件冒泡', () => {
      const mockParentClick = vi.fn();

      const { container } = render(
        <div onClick={mockParentClick}>
          <TablePreviewAction
            hovered={false}
            onPreview={mockOnPreview}
          />
        </div>
      );

      const button = container.querySelector('button');
      fireEvent.click(button!);

      // 预览回调应该被触发
      expect(mockOnPreview).toHaveBeenCalledTimes(1);

      // 父元素的点击不应该被触发（因为 stopPropagation）
      expect(mockParentClick).not.toHaveBeenCalled();
    });

    it('预览按钮应该有正确的 title 属性', () => {
      const { container } = render(
        <TablePreviewAction
          hovered={false}
          onPreview={mockOnPreview}
        />
      );

      const button = container.querySelector('button');
      expect(button?.getAttribute('title')).toBe('点击预览详情');
    });
  });

  describe('删除功能', () => {
    it('showDelete=false 时不应该显示删除按钮', () => {
      const { container } = render(
        <TablePreviewAction
          hovered={false}
          onPreview={mockOnPreview}
          showDelete={false}
          onDelete={mockOnDelete}
        />
      );

      const buttons = container.querySelectorAll('button');
      expect(buttons.length).toBe(1); // 只有预览按钮
    });

    it('showDelete=true 且有 onDelete 时应该显示删除按钮', () => {
      const { container } = render(
        <TablePreviewAction
          hovered={false}
          onPreview={mockOnPreview}
          showDelete={true}
          onDelete={mockOnDelete}
        />
      );

      const buttons = container.querySelectorAll('button');
      expect(buttons.length).toBe(2); // 预览按钮 + 删除按钮
    });

    it('showDelete=true 但没有 onDelete 时不应该显示删除按钮', () => {
      const { container } = render(
        <TablePreviewAction
          hovered={false}
          onPreview={mockOnPreview}
          showDelete={true}
        />
      );

      const buttons = container.querySelectorAll('button');
      expect(buttons.length).toBe(1); // 只有预览按钮
    });

    it('点击删除按钮应该触发 onDelete 回调', () => {
      render(
        <TablePreviewAction
          hovered={false}
          onPreview={mockOnPreview}
          showDelete={true}
          onDelete={mockOnDelete}
        />
      );

      const { container } = render(
        <TablePreviewAction
          hovered={false}
          onPreview={mockOnPreview}
          showDelete={true}
          onDelete={mockOnDelete}
        />
      );

      // 获取第二个按钮（删除按钮）
      const buttons = container.querySelectorAll('button');
      const deleteButton = buttons[1];

      fireEvent.click(deleteButton);

      expect(mockOnDelete).toHaveBeenCalledTimes(1);
    });

    it('删除按钮应该有正确的样式类', () => {
      const { container } = render(
        <TablePreviewAction
          hovered={false}
          onPreview={mockOnPreview}
          showDelete={true}
          onDelete={mockOnDelete}
        />
      );

      const buttons = container.querySelectorAll('button');
      const deleteButton = buttons[1];

      expect(deleteButton.className).toContain('text-rose-600');
      expect(deleteButton.className).toContain('hover:bg-rose-50');
      expect(deleteButton.className).toContain('rounded-lg');
      expect(deleteButton.className).toContain('transition-colors');
    });

    it('删除按钮应该有正确的 title 属性', () => {
      const { container } = render(
        <TablePreviewAction
          hovered={false}
          onPreview={mockOnPreview}
          showDelete={true}
          onDelete={mockOnDelete}
        />
      );

      const buttons = container.querySelectorAll('button');
      const deleteButton = buttons[1];

      expect(deleteButton.getAttribute('title')).toBe('删除');
    });
  });

  describe('布局和样式', () => {
    it('应该使用 flex 布局并且右对齐', () => {
      const { container } = render(
        <TablePreviewAction
          hovered={false}
          onPreview={mockOnPreview}
        />
      );

      const wrapper = container.firstChild as HTMLElement;
      expect(wrapper.className).toContain('flex');
      expect(wrapper.className).toContain('items-center');
      expect(wrapper.className).toContain('justify-end');
      expect(wrapper.className).toContain('gap-2');
    });

    it('预览按钮应该包含图标和文字', () => {
      const { container } = render(
        <TablePreviewAction
          hovered={false}
          onPreview={mockOnPreview}
        />
      );

      const button = container.querySelector('button');
      expect(button?.className).toContain('flex');
      expect(button?.className).toContain('items-center');
      expect(button?.className).toContain('gap-1.5');
    });
  });

  describe('可访问性', () => {
    it('预览按钮应该是 button 元素', () => {
      const { container } = render(
        <TablePreviewAction
          hovered={false}
          onPreview={mockOnPreview}
        />
      );

      const button = container.querySelector('button');
      expect(button?.tagName).toBe('BUTTON');
    });

    it('删除按钮应该是 button 元素', () => {
      const { container } = render(
        <TablePreviewAction
          hovered={false}
          onPreview={mockOnPreview}
          showDelete={true}
          onDelete={mockOnDelete}
        />
      );

      const buttons = container.querySelectorAll('button');
      const deleteButton = buttons[1];
      expect(deleteButton.tagName).toBe('BUTTON');
    });
  });

  describe('边界情况', () => {
    it('应该正确处理 undefined 的 hovered 属性', () => {
      expect(() => {
        render(
          <TablePreviewAction
            hovered={undefined}
            onPreview={mockOnPreview}
          />
        );
      }).toBeTruthy();
    });

    it('应该正确处理空的 previewLabel', () => {
      const { container } = render(
        <TablePreviewAction
          hovered={false}
          onPreview={mockOnPreview}
          previewLabel=""
        />
      );

      const button = container.querySelector('button');
      expect(button).toBeInTheDocument();
      expect(button?.textContent).toBe('');
    });

    it('应该正确处理特殊字符的 previewLabel', () => {
      const { container } = render(
        <TablePreviewAction
          hovered={false}
          onPreview={mockOnPreview}
          previewLabel="查看详情 & 编辑"
        />
      );

      const button = container.querySelector('button');
      expect(button?.textContent).toBe('查看详情 & 编辑');
    });
  });
});

// Input: React
// Output: useDataTable Hook
// Pos: 通用复用组件 - 表格数据管理 Hook

import { useState, useCallback, useEffect } from 'react';

export interface PaginationConfig {
  current: number;
  pageSize: number;
  total: number;
}

export interface UseDataTableOptions<T> {
  fetchFn: (page: number, pageSize: number, filters?: Record<string, any>) => Promise<{
    data: T[];
    total: number;
  }>;
  defaultPageSize?: number;
  defaultFilters?: Record<string, any>;
  autoFetch?: boolean;
}

export interface UseDataTableReturn<T> {
  data: T[];
  loading: boolean;
  pagination: PaginationConfig;
  filters: Record<string, any>;
  fetchData: () => Promise<void>;
  handlePageChange: (page: number, pageSize: number) => void;
  handleFilterChange: (filters: Record<string, any>) => void;
  handleReset: () => void;
  refresh: () => Promise<void>;
}

/**
 * 统一的表格数据管理 Hook
 * <p>
 * 封装分页、筛选、数据获取逻辑
 * </p>
 */
export function useDataTable<T extends Record<string, any>>({
  fetchFn,
  defaultPageSize = 10,
  defaultFilters = {},
  autoFetch = true,
}: UseDataTableOptions<T>): UseDataTableReturn<T> {
  const [data, setData] = useState<T[]>([]);
  const [loading, setLoading] = useState(false);
  const [pagination, setPagination] = useState<PaginationConfig>({
    current: 1,
    pageSize: defaultPageSize,
    total: 0,
  });
  const [filters, setFilters] = useState<Record<string, any>>(defaultFilters);

  // Fetch data
  const fetchData = useCallback(async () => {
    setLoading(true);
    try {
      const result = await fetchFn(pagination.current, pagination.pageSize, filters);
      setData(result.data);
      setPagination(prev => ({
        ...prev,
        total: result.total,
      }));
    } catch (error) {
      console.error('Failed to fetch data:', error);
      setData([]);
    } finally {
      setLoading(false);
    }
  }, [fetchFn, pagination.current, pagination.pageSize, filters]);

  // Handle page change
  const handlePageChange = useCallback((page: number, pageSize: number) => {
    setPagination(prev => ({
      ...prev,
      current: page,
      pageSize,
    }));
  }, []);

  // Handle filter change
  const handleFilterChange = useCallback((newFilters: Record<string, any>) => {
    setFilters(newFilters);
    setPagination(prev => ({
      ...prev,
      current: 1, // Reset to first page when filters change
    }));
  }, []);

  // Reset filters and pagination
  const handleReset = useCallback(() => {
    setFilters(defaultFilters);
    setPagination({
      current: 1,
      pageSize: defaultPageSize,
      total: 0,
    });
  }, [defaultFilters, defaultPageSize]);

  // Refresh current page
  const refresh = useCallback(async () => {
    await fetchData();
  }, [fetchData]);

  // Auto fetch on mount or when filters/pagination change
  useEffect(() => {
    if (autoFetch) {
      fetchData();
    }
  }, [fetchData, autoFetch]);

  return {
    data,
    loading,
    pagination,
    filters,
    fetchData,
    handlePageChange,
    handleFilterChange,
    handleReset,
    refresh,
  };
}

export default useDataTable;

// src/components/voucher/OriginalDocumentPreview.tsx
import React, { useState, useMemo } from 'react';
import { FileText, Download } from 'lucide-react';

interface AttachmentDTO {
  id: string;
  fileName?: string;
  name?: string;
  fileUrl?: string;
  type?: string;
}

interface OriginalDocumentPreviewProps {
  files: AttachmentDTO[];
  defaultFileIndex?: number;
}

export const OriginalDocumentPreview: React.FC<OriginalDocumentPreviewProps> = ({
  files,
  defaultFileIndex = 0,
}) => {
  const [selectedIndex, setSelectedIndex] = useState(
    files.length > 0 ? Math.min(defaultFileIndex, files.length - 1) : -1
  );

  const selectedFile = useMemo(() => {
    return selectedIndex >= 0 ? files[selectedIndex] : null;
  }, [selectedIndex, files]);

  // 如果没有文件
  if (files.length === 0) {
    return (
      <div className="h-full flex flex-col items-center justify-center text-slate-400 bg-slate-50">
        <FileText size={48} className="mb-4 opacity-20" />
        <p>暂无关联附件</p>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col">
      {/* 文件列表 */}
      {files.length > 1 && (
        <div className="border-b border-slate-200 p-2 bg-slate-50">
          <div className="flex gap-2 overflow-x-auto">
            {files.map((file, index) => (
              <button
                key={file.id}
                onClick={() => setSelectedIndex(index)}
                className={`px-3 py-1.5 text-sm rounded whitespace-nowrap transition-colors ${
                  selectedIndex === index
                    ? 'bg-blue-50 text-blue-700 border border-blue-200'
                    : 'bg-white text-slate-600 border border-slate-200 hover:bg-slate-50'
                }`}
              >
                {file.fileName || file.name || `文件${index + 1}`}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* 预览区域 */}
      <div className="flex-1 overflow-auto bg-slate-100 p-4">
        {selectedFile?.fileUrl ? (
          <div className="h-full flex flex-col">
            {/* iframe PDF 预览 */}
            <iframe
              src={selectedFile.fileUrl}
              title={selectedFile.fileName || selectedFile.name}
              className="flex-1 w-full rounded border-0 bg-white shadow-sm"
            />
          </div>
        ) : (
          <div className="h-full flex flex-col items-center justify-center text-slate-400">
            <FileText size={48} className="mb-4 opacity-20" />
            <p>该文件无法预览</p>
            <a
              href={selectedFile?.fileUrl || '#'}
              download={selectedFile?.fileName || selectedFile?.name}
              className="mt-4 flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700"
            >
              <Download size={16} />
              下载文件
            </a>
          </div>
        )}
      </div>
    </div>
  );
};

// src/components/voucher/VoucherMetadata.tsx
import React from 'react';
import { formatCurrency, formatDate } from './styles';
import type { VoucherDTO } from './types';

interface MetadataField {
  label: string;
  value: string | number | React.ReactNode;
  type?: 'text' | 'amount' | 'date' | 'link';
}

interface VoucherMetadataProps {
  data: VoucherDTO;
  compact?: boolean;
  fields?: string[];
}

// 默认显示字段配置
const DEFAULT_FIELDS: string[] = [
  'voucherNo',
  'debitTotal',
  'voucherDate',
  'invoiceCount',
  'contract',
  'matchScore',
  'matchMethod',
  'createdTime',
  'storageId',
];

export const VoucherMetadata: React.FC<VoucherMetadataProps> = ({
  data,
  compact = false,
  fields,
}) => {
  // 构建字段列表
  const metadataFields: MetadataField[] = React.useMemo(() => {
    const result: MetadataField[] = [];

    // 记账凭证号
    if (shouldIncludeField('voucherNo')) {
      const voucherNumber = data.voucherWord && data.voucherNo
        ? `${data.voucherWord}-${data.voucherNo}`
        : (data.voucherNo || '-');
      result.push({
        label: '记账凭证号',
        value: voucherNumber,
        type: 'text',
      });
    }

    // 金额
    if (shouldIncludeField('debitTotal')) {
      result.push({
        label: '金额',
        value: formatCurrency(data.debitTotal),
        type: 'amount',
      });
    }

    // 业务日期
    if (shouldIncludeField('voucherDate')) {
      result.push({
        label: '业务日期',
        value: formatDate(data.voucherDate),
        type: 'date',
      });
    }

    // 关联发票数
    if (shouldIncludeField('invoiceCount')) {
      const invoiceCount = data.attachments?.filter(a =>
        a.type?.toLowerCase().includes('invoice') ||
        (a.name && a.name.toLowerCase().includes('发票'))
      ).length || 0;
      result.push({
        label: '关联发票数',
        value: invoiceCount,
        type: 'text',
      });
    }

    // 关联合同（暂时显示占位）
    if (shouldIncludeField('contract')) {
      result.push({
        label: '关联合同',
        value: '-',
        type: 'link',
      });
    }

    // 匹配度（外部注入，暂时显示占位）
    if (shouldIncludeField('matchScore')) {
      result.push({
        label: '匹配度',
        value: '-',
        type: 'text',
      });
    }

    // 关联方式（外部注入，暂时显示占位）
    if (shouldIncludeField('matchMethod')) {
      result.push({
        label: '关联方式',
        value: '-',
        type: 'text',
      });
    }

    // 入池时间
    if (shouldIncludeField('createdTime')) {
      result.push({
        label: '入池时间',
        value: formatDate(data.createdTime),
        type: 'date',
      });
    }

    // 存储ID
    if (shouldIncludeField('storageId')) {
      const storageId = data.id || data.voucherId || '-';
      result.push({
        label: '存储ID',
        value: storageId.length > 20 ? `${storageId.slice(0, 20)}...` : storageId,
        type: 'text',
      });
    }

    return result;

    function shouldIncludeField(fieldName: string): boolean {
      if (!fields) return DEFAULT_FIELDS.includes(fieldName as any);
      return fields.includes(fieldName);
    }
  }, [data, fields]);

  return (
    <div data-testid="voucher-metadata" className="bg-white border border-slate-200 rounded-lg overflow-hidden">
      <div className={`px-4 py-3 border-b border-slate-100 bg-slate-50 ${compact ? 'py-2' : ''}`}>
        <h3 className="font-semibold text-slate-700 text-sm">业务元数据</h3>
      </div>
      <div className={`divide-y divide-slate-100 ${compact ? 'text-sm' : ''}`}>
        {metadataFields.map((field, index) => (
          <div
            key={index}
            className={`flex justify-between items-center px-4 ${compact ? 'py-2' : 'py-3'}`}
          >
            <span className="text-slate-500 text-xs uppercase tracking-wide">{field.label}</span>
            <span className={`font-medium ${
              field.type === 'amount' ? 'font-mono text-slate-800' : 'text-slate-700'
            }`}>
              {field.value}
            </span>
          </div>
        ))}
      </div>

      {/* 凭证分录列表 */}
      {data.entries && data.entries.length > 0 && (() => {
        const entries = data.entries;
        return (
          <div className="border-t-2 border-slate-200 mt-2">
            <div className={`px-4 py-3 bg-slate-100 border-b border-slate-200 ${compact ? 'py-2' : ''}`}>
              <h3 className="font-semibold text-slate-800 text-sm">
                凭证分录 ({entries.length}条)
              </h3>
            </div>
            <div className={`bg-white ${compact ? 'text-sm' : ''}`}>
              {entries.map((entry, index) => (
                <div
                  key={entry.lineNo || index}
                  className={`px-4 ${compact ? 'py-2' : 'py-3'} ${
                    index < entries.length - 1 ? 'border-b border-slate-100' : ''
                  }`}
                >
                {/* 分录头部 - 摘要 */}
                <div className="mb-2">
                  <span className="inline-block px-2 py-0.5 bg-blue-100 text-blue-700 text-xs font-medium rounded mr-2">
                    {entry.lineNo || index + 1}
                  </span>
                  <span className="font-medium text-slate-800">
                    {entry.summary || '-'}
                  </span>
                </div>

                {/* 分录详情 - 科目和金额 */}
                <div className="flex items-center justify-between text-sm">
                  <div className="flex-1 min-w-0">
                    <div className="text-slate-800 font-medium truncate">
                      {entry.accountName || '-'}
                    </div>
                    {entry.accountCode && (
                      <div className="text-xs text-slate-500 font-mono truncate">
                        {entry.accountCode}
                      </div>
                    )}
                  </div>

                  <div className="flex gap-6 font-mono text-sm">
                    <div className="text-right">
                      <div className="text-xs text-slate-500 mb-0.5">借方</div>
                      <div className={`font-semibold ${Number(entry.debit || 0) > 0 ? 'text-green-700' : 'text-slate-400'}`}>
                        {entry.debit ? formatCurrency(entry.debit) : '-'}
                      </div>
                    </div>
                    <div className="text-right">
                      <div className="text-xs text-slate-500 mb-0.5">贷方</div>
                      <div className={`font-semibold ${Number(entry.credit || 0) > 0 ? 'text-red-700' : 'text-slate-400'}`}>
                        {entry.credit ? formatCurrency(entry.credit) : '-'}
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
        );
      })()}
    </div>
  );
};

