/**
 * useArchiveDataLoader - Data Loading Logic Hook
 *
 * Handles data fetching for archives and pool items
 */
import { useCallback, useRef, useEffect } from 'react';
import { poolApi } from '../../../api/pool';
import { archivesApi } from '../../../api/archives';
import { UseArchiveDataLoadOptions, ControllerDataInternal, PoolStatusFilter } from './types';
import { mapArchiveToRow } from './utils';

interface UseArchiveDataLoaderOptions extends UseArchiveDataLoadOptions {
    data: ControllerDataInternal;
    showToast: (message: string, type?: 'success' | 'error') => void;
    onSelectionClear?: () => void;
}

export function useArchiveDataLoader(options: UseArchiveDataLoaderOptions) {
    const {
        mode,
        query,
        page,
        isPoolView,
        poolStatusFilter,
        data,
        showToast,
        onSelectionClear,
    } = options;

    const { setRows, setIsLoading, setErrorMessage, setPageInfo, setCurrentPage } = data;
    const isInitialLoadRef = useRef(true);
    const prevDepsRef = useRef({
        subTitle: mode.subTitle,
        searchTerm: query.searchTerm,
        statusFilter: query.statusFilter,
        orgFilter: query.orgFilter,
        subTypeFilter: query.subTypeFilter,
        poolStatusFilter,
    });

    // Load pool data
    const loadPoolData = useCallback(async (pageNum = page.currentPage, filterOverride?: PoolStatusFilter) => {
        setIsLoading(true);
        setErrorMessage(null);
        onSelectionClear?.();
        try {
            const activeFilter = filterOverride !== undefined ? filterOverride : poolStatusFilter;

            let poolItems = [];
            // 如果指定了状态，调用特定的状态过滤接口（后端过滤）
            if (activeFilter && activeFilter !== 'all') {
                poolItems = await poolApi.getListByStatus(activeFilter);
            } else {
                poolItems = await poolApi.getList();
            }

            // 移除不安全的前端模糊搜索和状态过滤，改为直接展示后端结果
            // 注意：由于后端列表接口暂时不支持搜索参数，搜索逻辑建议后续在后端 PoolController 完善
            // 目前至少保证了状态层面的后端过滤

            const total = poolItems.length;
            const start = (pageNum - 1) * page.pageInfo.pageSize;
            const paged = poolItems.slice(start, start + page.pageInfo.pageSize);
            const mappedPaged = paged.map((item: any) => ({
                ...item,
                rawStatus: item.status
            }));

            setRows(mappedPaged);
            setPageInfo({ total, page: pageNum, pageSize: page.pageInfo.pageSize });
        } catch (error) {
            console.error('Failed to load pool data:', error);
            setErrorMessage('加载数据失败');
            showToast('加载数据失败', 'error');
        } finally {
            setIsLoading(false);
        }
    }, [page.currentPage, page.pageInfo.pageSize, poolStatusFilter, setRows, setIsLoading, setErrorMessage, setPageInfo, showToast, onSelectionClear]);

    // Load archive list
    const loadArchiveList = useCallback(async (pageNum = page.currentPage) => {
        setIsLoading(true);
        setErrorMessage(null);
        onSelectionClear?.();
        try {
            const result = await archivesApi.getArchives({
                page: pageNum,
                limit: page.pageInfo.pageSize,
                search: query.searchTerm || undefined,
                status: query.statusFilter || mode.defaultStatus,
                categoryCode: mode.categoryCode,
                orgId: query.orgFilter || undefined,
                subType: query.subTypeFilter || undefined
            });

            if (result.code !== 200 || !result.data) {
                throw new Error(result.message || '加载档案数据失败');
            }

            const pageResult: any = result.data;
            const { records = [], total = 0, size = page.pageInfo.pageSize, current = pageNum } = pageResult;
            const mappedItems = (records as any[]).map((item) => mapArchiveToRow(item, mode.subTitle));

            setRows(mappedItems);
            setPageInfo({ total, page: current || pageNum, pageSize: size || page.pageInfo.pageSize });
            setCurrentPage(current || pageNum);
        } catch (error) {
            console.error('Failed to load archives:', error);
            setErrorMessage(error instanceof Error ? error.message : '加载档案数据失败');
            showToast('加载档案数据失败', 'error');
        } finally {
            setIsLoading(false);
        }
    }, [page.currentPage, page.pageInfo.pageSize, query.searchTerm, query.statusFilter, mode.defaultStatus, mode.categoryCode, mode.subTitle, query.orgFilter, query.subTypeFilter, setRows, setIsLoading, setErrorMessage, setPageInfo, setCurrentPage, showToast, onSelectionClear]);

    // Load current view based on mode
    const loadCurrentView = useCallback((pageNum = page.currentPage, poolFilter?: PoolStatusFilter) => {
        if (isPoolView) {
            return loadPoolData(pageNum, poolFilter);
        }
        return loadArchiveList(pageNum);
    }, [isPoolView, loadPoolData, loadArchiveList, page.currentPage]);

    // Initial load
    useEffect(() => {
        if (isInitialLoadRef.current) {
            isInitialLoadRef.current = false;
            if (isPoolView) {
                loadPoolData(1, poolStatusFilter);
            } else {
                loadArchiveList(1);
            }
        }
    }, [isPoolView, poolStatusFilter, loadPoolData, loadArchiveList]);

    // Monitor poolStatusFilter changes
    useEffect(() => {
        if (isInitialLoadRef.current) return;
        const prevFilter = prevDepsRef.current.poolStatusFilter;
        if (prevFilter !== poolStatusFilter) {
            prevDepsRef.current = { ...prevDepsRef.current, poolStatusFilter };
            if (isPoolView) {
                setCurrentPage(1);
                loadPoolData(1, poolStatusFilter);
            }
        }
    }, [poolStatusFilter, isPoolView, loadPoolData, setCurrentPage]);

    // Monitor other filter changes
    useEffect(() => {
        if (isInitialLoadRef.current) return;
        const prevDeps = prevDepsRef.current;
        const depsChanged =
            prevDeps.subTitle !== mode.subTitle ||
            prevDeps.searchTerm !== query.searchTerm ||
            prevDeps.statusFilter !== query.statusFilter ||
            prevDeps.orgFilter !== query.orgFilter ||
            prevDeps.subTypeFilter !== query.subTypeFilter;

        if (depsChanged) {
            prevDepsRef.current = {
                ...prevDepsRef.current,
                subTitle: mode.subTitle,
                searchTerm: query.searchTerm,
                statusFilter: query.statusFilter,
                orgFilter: query.orgFilter,
                subTypeFilter: query.subTypeFilter,
            };
            setCurrentPage(1);
            if (isPoolView) {
                loadPoolData(1, poolStatusFilter);
            } else {
                loadArchiveList(1);
            }
        }
    }, [mode.subTitle, query.searchTerm, query.statusFilter, query.orgFilter, query.subTypeFilter, isPoolView, poolStatusFilter, loadPoolData, loadArchiveList, setCurrentPage]);

    // Monitor page changes
    const isPageChangeFromFilterRef = useRef(false);
    useEffect(() => {
        if (isInitialLoadRef.current) return;
        if (isPageChangeFromFilterRef.current) {
            isPageChangeFromFilterRef.current = false;
            return;
        }
        loadCurrentView(page.currentPage, poolStatusFilter);
    }, [page.currentPage, poolStatusFilter, loadCurrentView]);

    return {
        loadCurrentView,
        markPageChangeFromFilter: () => {
            isPageChangeFromFilterRef.current = true;
        },
    };
}

/**
 * useArchiveMode - Mode Resolution Hook
 *
 * Handles route mode resolution and configuration
 */
import { useCallback } from 'react';
import { resolveRouteConfig, DEFAULT_ROUTE_CONFIG, ArchiveRouteMode } from '../routeConfigs';
import { ControllerMode, UseArchiveModeOptions } from './types';
import type { ModuleConfig } from '../../../types';

export function useArchiveMode(options: UseArchiveModeOptions): ControllerMode {
    const { routeConfig, title: propTitle, subTitle: propSubTitle, config: propConfig } = options;

    // Resolve configuration
    const resolvedConfig = routeConfig ? resolveRouteConfig(routeConfig as ArchiveRouteMode) : undefined;
    const title = resolvedConfig?.title || propTitle || DEFAULT_ROUTE_CONFIG.title;
    const subTitle = resolvedConfig?.subTitle || propSubTitle || DEFAULT_ROUTE_CONFIG.subTitle;
    const config: ModuleConfig = resolvedConfig?.config || propConfig || DEFAULT_ROUTE_CONFIG.config;

    const isPoolView = subTitle === '电子凭证池';
    const isLinkingView = subTitle === '凭证关联';

    const resolveCategoryCode = useCallback((): 'AC01' | 'AC02' | 'AC03' | 'AC04' | undefined => {
        switch (subTitle) {
            case '会计凭证':
            case '原始凭证':
            case '记账凭证':
            case '凭证关联':
                return 'AC01';
            case '会计账簿':
                return 'AC02';
            case '财务报告':
                return 'AC03';
            case '其他会计资料':
                return 'AC04';
            default:
                return undefined;
        }
    }, [subTitle]);

    const resolveDefaultStatus = useCallback(() => {
        if (subTitle === '凭证关联') return 'draft,MATCH_PENDING,MATCHED';
        if (['会计凭证', '会计账簿', '财务报告', '其他会计资料'].includes(subTitle || '')) {
            return 'archived';
        }
        return undefined;
    }, [subTitle]);

    return {
        routeKey: routeConfig as ArchiveRouteMode | undefined,
        title,
        subTitle,
        config,
        isPoolView,
        isLinkingView,
        categoryCode: resolveCategoryCode(),
        defaultStatus: resolveDefaultStatus(),
    };
}

/**
 * Archive Controllers - Utility Functions
 */

import { GenericRow } from '../../../types';

const CATEGORY_LABELS: Record<string, string> = {
    AC01: '会计凭证',
    AC02: '会计账簿',
    AC03: '财务报告',
    AC04: '其他会计资料'
};

const STATUS_LABELS: Record<string, string> = {
    draft: '草稿',
    MATCH_PENDING: '待匹配',
    MATCHED: '匹配成功',
    pending: '准备归档',
    archived: '已归档'
};

const PRE_ARCHIVE_STATUS_LABELS: Record<string, { label: string }> = {
    PENDING_CHECK: { label: '待检测' },
    CHECK_FAILED: { label: '检测失败' },
    PENDING_METADATA: { label: '待补录' },
    MATCH_PENDING: { label: '待匹配' },
    MATCHED: { label: '匹配成功' },
    PENDING_ARCHIVE: { label: '准备归档' },
    PENDING_APPROVAL: { label: '归档审批中' },
    ARCHIVING: { label: '归档中' },
    ARCHIVED: { label: '已归档' },
};

export const resolveCategoryLabel = (code?: string) => {
    if (!code) return '档案';
    return CATEGORY_LABELS[code] || code;
};

export const formatStatus = (status?: string) => {
    if (!status) return '-';
    return STATUS_LABELS[status] || PRE_ARCHIVE_STATUS_LABELS[status]?.label || status;
};

export const getSafeDisplayValue = (text: string | undefined | null) => {
    if (!text) return '-';
    const isHash = text.length > 30 && !text.includes(' ') && /^[a-fA-F0-9]+$/.test(text);
    if (isHash) return '密级文档(标题加密)';
    return text;
};

export const mapArchiveToRow = (archive: any, subTitle: string): GenericRow => {
    const categoryLabel = resolveCategoryLabel(archive?.categoryCode);
    const baseDate = archive?.docDate || archive?.createdTime || '';
    const date = baseDate ? String(baseDate).split('T')[0] : '';
    const statusText = formatStatus(archive?.status);

    if (subTitle === '会计凭证' || subTitle === '凭证关联') {
        const amountValue = archive?.amount;
        const amount = typeof amountValue === 'number'
            ? `¥ ${amountValue.toFixed(2)}`
            : amountValue || '-';

        let subjectName = '-';
        try {
            if (archive?.customMetadata) {
                const meta = typeof archive.customMetadata === 'string'
                    ? JSON.parse(archive.customMetadata)
                    : archive.customMetadata;
                if (Array.isArray(meta) && meta.length > 0) {
                    const entry = meta.find((m: any) => m.accsubject && (m.debit_org > 0 || m.debitLocal > 0)) || meta[0];
                    if (entry?.accsubject?.name) {
                        subjectName = entry.accsubject.name;
                    } else if (entry?.description) {
                        subjectName = entry.description;
                    }
                }
            }
            if (subjectName === '-' && archive?.title) {
                subjectName = archive.title;
            }
            subjectName = getSafeDisplayValue(subjectName);
        } catch (e) {
            console.warn('Failed to parse custom metadata for subject', e);
        }

        return {
            id: archive?.id,
            code: archive?.archiveCode,
            voucherNo: archive?.archiveCode,
            archivalCode: archive?.archiveCode,
            entity: archive?.orgName,
            period: archive?.fiscalPeriod || archive?.fiscalYear || '',
            subject: subjectName,
            type: categoryLabel,
            amount,
            date,
            status: statusText,
            matchScore: archive?.matchScore || 0,
            autoLink: archive?.matchMethod || '-',
            rawStatus: archive?.status
        };
    }

    if (subTitle === '会计账簿') {
        return {
            id: archive?.id,
            code: archive?.archiveCode,
            ledgerNo: archive?.archiveCode,
            archivalCode: archive?.archiveCode,
            type: categoryLabel,
            entity: archive?.orgName,
            year: archive?.fiscalYear,
            period: archive?.fiscalPeriod || '全年',
            subject: getSafeDisplayValue(archive?.title),
            pageCount: archive?.pageCount || '-',
            status: statusText,
            rawStatus: archive?.preArchiveStatus || archive?.status
        };
    }

    if (subTitle === '财务报告') {
        return {
            id: archive?.id,
            code: archive?.archiveCode,
            reportNo: archive?.archiveCode,
            archivalCode: archive?.archiveCode,
            type: categoryLabel,
            year: archive?.fiscalYear,
            unit: archive?.orgName,
            title: getSafeDisplayValue(archive?.title),
            period: archive?.fiscalPeriod || '',
            date,
            status: statusText,
            rawStatus: archive?.preArchiveStatus || archive?.status
        };
    }

    return {
        id: archive?.id,
        code: archive?.archiveCode,
        archiveNo: archive?.fondsNo,
        archivalCode: archive?.archiveCode,
        category: categoryLabel,
        year: archive?.fiscalYear,
        period: archive?.retentionPeriod || archive?.fiscalPeriod,
        title: getSafeDisplayValue(archive?.title),
        security: archive?.securityLevel || '-',
        status: statusText,
        orgName: archive?.orgName,
        date,
        rawStatus: archive?.preArchiveStatus || archive?.status
    };
};

// Input: Controller Hook
// Output: useArchiveActions Hook
// Pos: src/features/archives/useArchiveActions.ts
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

/**
 * Archive Actions Hook
 * 
 * 封装档案管理相关的具体操作逻辑，包括增删改查、归档、导出等。
 * 进一步为 ArchiveListView 瘦身。
 */
import { useState, useCallback } from 'react';
import { GenericRow } from '../../types';
import { poolApi } from '../../api/pool';
import { archivesApi } from '../../api/archives';
import { client } from '../../api/client';
import { ArchiveListController } from './useArchiveListController';

interface UseArchiveActionsResult {
    // States
    isUploading: boolean;
    isArchiving: boolean;
    isExporting: string | null; // ID of item being exported

    // Handlers
    handleDelete: (id: string) => Promise<void>;
    handleBatchDelete: () => Promise<void>;
    handleAipExport: (row: GenericRow) => Promise<void>;
    handleUpload: (file: File) => Promise<void>;
    handleMetadataUpdate: (fileId: string, payload: any) => Promise<{ success: boolean; message?: string }>;
    handlePoolCheck: (mode: 'all' | 'failed') => Promise<void>;

    // Archiving Flow (Confirmation handled by View/Page for now, or exposed here)
    executeArchiving: () => Promise<void>;
}

export function useArchiveActions(controller: ArchiveListController): UseArchiveActionsResult {
    const { ui, selection, actions, pool, mode } = controller;

    const [isUploading, setIsUploading] = useState(false);
    const [isArchiving, setIsArchiving] = useState(false);
    const [isExporting, setIsExporting] = useState<string | null>(null);

    // 删除单条
    const handleDelete = useCallback(async (id: string) => {
        if (!window.confirm('确定要删除这条记录吗？')) return;

        try {
            if (mode.isPoolView) {
                await poolApi.delete(id);
            } else {
                await archivesApi.deleteArchive(id);
            }
            ui.showToast('删除成功', 'success');
            actions.reload();
        } catch (error: any) {
            ui.showToast('删除失败: ' + (error.message || '未知错误'), 'error');
        }
    }, [mode.isPoolView, ui, actions]);

    // 批量删除
    const handleBatchDelete = useCallback(async () => {
        if (selection.selectedIds.length === 0) return;
        if (!window.confirm(`确定要删除选中的 ${selection.selectedIds.length} 条记录吗？`)) return;

        try {
            if (mode.isPoolView) {
                // Pool API might implement batch delete in future, loop for now or specific endpoint
                // Assuming loop for safety if no batch endpoint confirmed
                await Promise.all(selection.selectedIds.map(id => poolApi.delete(id)));
            } else {
                // Archives API might have batch delete
                await Promise.all(selection.selectedIds.map(id => archivesApi.deleteArchive(id)));
            }
            ui.showToast('批量删除成功', 'success');
            selection.clear();
            actions.reload();
        } catch (error: any) {
            ui.showToast('批量删除失败: ' + (error.message || '部分删除失败'), 'error');
        }
    }, [selection, mode.isPoolView, ui, actions]);

    // AIP 导出
    const handleAipExport = useCallback(async (row: GenericRow) => {
        const exportCode = row.archivalCode || row.code;
        if (!exportCode) {
            ui.showToast('无法导出: 缺少归档号', 'error');
            return;
        }

        setIsExporting(exportCode);
        try {
            const response = await client.get(`/archives/export/aip/${row.id}`, {
                responseType: 'blob'
            });

            const url = window.URL.createObjectURL(new Blob([response.data]));
            const link = document.createElement('a');
            link.href = url;
            link.setAttribute('download', `${exportCode}.aip`);
            document.body.appendChild(link);
            link.click();
            link.remove();
            window.URL.revokeObjectURL(url);

            ui.showToast('AIP 导出成功', 'success');
        } catch (error) {
            console.error('Export failed:', error);
            ui.showToast('AIP 导出失败', 'error');
        } finally {
            setIsExporting(null);
        }
    }, [ui]);

    // 上传 (Pool)
    const handleUpload = useCallback(async (file: File) => {
        if (!mode.isPoolView) return;

        const formData = new FormData();
        formData.append('file', file);

        setIsUploading(true);
        try {
            ui.showToast('正在上传...', 'success');
            const response = await client.post('/ingest/upload', formData, {
                headers: { 'Content-Type': 'multipart/form-data' }
            });

            if (response.status === 200 && response.data.code === 200) {
                ui.showToast(`✅ 上传成功: ${response.data.data.fileName}`, 'success');
                actions.reload();
            } else {
                throw new Error(response.data.message || '服务器错误');
            }
        } catch (error: any) {
            console.error('Upload error:', error);
            ui.showToast('上传出错: ' + error.message, 'error');
        } finally {
            setIsUploading(false);
        }
    }, [mode.isPoolView, ui, actions]);

    // 元数据更新
    const handleMetadataUpdate = useCallback(async (fileId: string, payload: any) => {
        try {
            const response = await client.post('/pool/metadata/update', payload);
            if (response.data?.code === 200) {
                actions.reload();
                // 如果是 Pool View，也刷新统计
                if (mode.isPoolView) pool.refreshStats();
                return { success: true, message: response.data.message };
            } else {
                return { success: false, message: response.data?.message || '更新失败' };
            }
        } catch (err: any) {
            return { success: false, message: err.response?.data?.message || '更新失败' };
        }
    }, [actions, pool, mode.isPoolView]);

    // Pool 检测
    const handlePoolCheck = useCallback(async (checkMode: 'all' | 'failed') => {
        const endpoint = checkMode === 'all' ? '/pool/check/all-pending' : '/pool/check/failed';

        // 使用 controller.data.isLoading 可能会冲突，这里可以用 toast 提示
        ui.showToast(checkMode === 'all' ? '正在执行全量检测...' : '正在重试失败项...', 'success');

        try {
            const response = await client.get(endpoint);
            if (response.data.code === 200) {
                const reports = response.data.data || [];
                const passCount = reports.filter((r: any) => r.status === 'PASS').length;
                const failCount = reports.filter((r: any) => r.status === 'FAIL').length;
                const warnCount = reports.filter((r: any) => r.status === 'WARNING').length;

                ui.showToast(`检测完成: 通过 ${passCount}, 失败 ${failCount}, 警告 ${warnCount}`, passCount > 0 ? 'success' : 'error');
                actions.reload();
                pool.refreshStats();
            }
        } catch (error: any) {
            ui.showToast('检测失败: ' + (error.message || '未知错误'), 'error');
        }
    }, [ui, actions, pool]);

    // 归档提交
    const executeArchiving = useCallback(async () => {
        if (selection.selectedIds.length === 0) return;

        setIsArchiving(true);
        try {
            const response = await client.post('/archives/batch-archive', {
                ids: selection.selectedIds
            });

            if (response.data.code === 200) {
                const result = response.data.data;
                const successCount = result.successItems ? result.successItems.length : (Array.isArray(result) ? result.length : 0);
                const failureCount = result.failures ? Object.keys(result.failures).length : 0;

                if (failureCount === 0 && successCount > 0) {
                    ui.showToast(`已提交 ${successCount} 个归档申请`, 'success');
                } else if (successCount > 0) {
                    ui.showToast(`部分成功: ${successCount}条, 失败 ${failureCount}条`, 'error');
                } else {
                    ui.showToast(`提交失败 (${failureCount})`, 'error');
                }

                if (successCount > 0) {
                    selection.clear();
                    actions.reload();
                    pool.refreshStats();
                }
            }
        } catch (error: any) {
            ui.showToast('提交归档失败: ' + (error.response?.data?.message || error.message), 'error');
        } finally {
            setIsArchiving(false);
        }
    }, [selection, ui, actions, pool]);

    return {
        isUploading,
        isArchiving,
        isExporting,
        handleDelete,
        handleBatchDelete,
        handleAipExport,
        handleUpload,
        handleMetadataUpdate,
        handlePoolCheck,
        executeArchiving
    };
}

// Input: matchingApi, MatchPreviewRow 类型
// Output: useSmartMatching Hook
// Pos: src/features/archives/useSmartMatching.ts
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import { useState, useCallback } from 'react';
import { matchingApi } from '../../api/matching';
import { toast } from 'react-hot-toast';

// 适配 MatchPreviewModal 的数据结构
export interface MatchPreviewRow {
    voucherId: string; // 增加 voucherId 以便确认
    voucherNo?: string;
    date?: string;
    amount?: string;
    matchScore?: number;
    _previewStatus?: 'high' | 'medium';
    _proposedLinks?: Array<{ code: string; docId: string; evidenceRole: string; linkType: string }>;
}

export const useSmartMatching = (onRefresh?: () => void) => {
    const [isMatchPreviewOpen, setIsMatchPreviewOpen] = useState(false);
    const [matchPreviewData, setMatchPreviewData] = useState<MatchPreviewRow[]>([]);
    const [isMatching, setIsMatching] = useState(false);
    const [isConfirming, setIsConfirming] = useState(false);

    // 执行智能匹配
    const handleAutoMatch = useCallback(async (selectedIds: string[]) => {
        if (!selectedIds.length) {
            toast.error('请先选择要匹配的凭证');
            return;
        }

        setIsMatching(true);
        const toastId = toast.loading('正在执行智能匹配...');

        try {
            // 1. 提交批量任务
            await matchingApi.executeBatchMatch(selectedIds);

            // 2. 获取每个凭证的详细结果 (这里简化为并行获取，实际生产可能需要轮询任务状态)
            // 既然是"修复"，我们先假设后端返回得很快，或者我们直接获取 Mock/Real 结果
            const tasks = selectedIds.map(id => matchingApi.getMatchResult(id));
            const results = await Promise.all(tasks);

            // 3. 转换为预览数据
            const previewRows: MatchPreviewRow[] = results
                .filter(Boolean)
                .map(res => {
                    if (!res) return {} as MatchPreviewRow;

                    const topLink = res.links?.[0]; // 取分数最高的一个
                    const score = res.confidence || topLink?.score || 0;
                    const previewStatus: MatchPreviewRow['_previewStatus'] =
                        score >= 90 ? 'high' : (score > 60 ? 'medium' : undefined);

                    return {
                        voucherId: res.voucherId,
                        voucherNo: res.voucherNo,
                        // 暂无日期金额等元数据，需从列表获取或 API 返回。
                        // 由于 API 返回可能不全，这里仅依赖 API 返回的 minimal info
                        amount: '待获取',
                        date: res.createdTime?.substring(0, 10),
                        matchScore: score,
                        _previewStatus: previewStatus,
                        _proposedLinks: res.links?.map(l => ({
                            code: l.matchedDocNo || '未知单据',
                            docId: l.matchedDocId || '',
                            evidenceRole: l.evidenceRole,
                            linkType: l.linkType
                        })) || []
                    };
                })
                .filter(row => row._previewStatus); // 过滤掉无匹配建议的

            if (previewRows.length === 0) {
                toast.success('未发现新的高置信度匹配项', { id: toastId });
                return;
            }

            setMatchPreviewData(previewRows);
            setIsMatchPreviewOpen(true);
            toast.dismiss(toastId);

        } catch (error) {
            console.error('Auto match failed:', error);
            toast.error('智能匹配执行失败', { id: toastId });
        } finally {
            setIsMatching(false);
        }
    }, []);

    // 确认并应用关联
    const handleConfirmLinks = useCallback(async () => {
        setIsConfirming(true);
        const toastId = toast.loading('正在建立关联...');

        try {
            // 过滤出需要确认的行
            const rowsToConfirm = matchPreviewData.filter(r => r._previewStatus);

            // 并行提交确认
            const tasks = rowsToConfirm.map(row => {
                if (!row._proposedLinks?.length) return Promise.resolve();

                // 构建 links payload
                // 假设每个凭证取所有 proposed links
                const linksPayload = row._proposedLinks.map(link => ({
                    sourceDocId: link.docId,
                    evidenceRole: link.evidenceRole,
                    linkType: link.linkType
                }));

                return matchingApi.confirmMatch(row.voucherId, linksPayload);
            });

            await Promise.all(tasks);

            toast.success(`成功关联 ${rowsToConfirm.length} 份凭证`, { id: toastId });
            setIsMatchPreviewOpen(false);

            // 刷新列表
            onRefresh?.();

        } catch (error) {
            console.error('Confirm match failed:', error);
            toast.error('关联确认失败', { id: toastId });
        } finally {
            setIsConfirming(false);
        }
    }, [matchPreviewData, onRefresh]);

    const closeMatchPreview = useCallback(() => {
        setIsMatchPreviewOpen(false);
        setMatchPreviewData([]);
    }, []);

    return {
        isMatchPreviewOpen,
        matchPreviewData,
        isMatching,
        isConfirming,
        handleAutoMatch,
        handleConfirmLinks,
        closeMatchPreview
    };
};

