import { useState, useEffect, useCallback, useRef } from 'react';

/**
 * 目录文档映射关系
 * key: 文件路径模式（支持通配符 *）
 * value: 对应的文档路径
 */
interface DocMapping {
  pattern: string;
  docPath: string;
  description: string;
}

/**
 * 文档守卫状态
 */
interface DocGuardState {
  /** 是否有未更新的文档 */
  hasPendingDocs: boolean;
  /** 待更新的文档列表 */
  pendingDocs: Array<{
    docPath: string;
    description: string;
    relatedFile?: string;
  }>;
  /** 是否正在检查 */
  checking: boolean;
}

/**
 * 文档守卫操作
 */
interface DocGuardActions {
  /** 检查文档状态 */
  checkDocs: () => Promise<void>;
  /** 标记文档已更新 */
  markUpdated: (docPath: string) => void;
  /** 获取文档更新模板 */
  getDocTemplate: (docPath: string) => string;
  /** 重置状态 */
  reset: () => void;
}

/**
 * 默认文档映射配置
 */
const DEFAULT_DOC_MAPPINGS: DocMapping[] = [
  // hooks 目录 -> src/hooks/README.md
  { pattern: 'src/hooks/**/*.ts', docPath: 'src/hooks/README.md', description: 'Hooks 目录文档' },
  // 组件 hooks -> 组件目录/hooks/README.md
  { pattern: 'src/components/**/hooks/*.ts', docPath: 'src/components/$DIR/hooks/README.md', description: '组件 Hooks 文档' },
  // API 层 -> src/api/README.md
  { pattern: 'src/api/**/*.ts', docPath: 'src/api/README.md', description: 'API 层文档' },
  // Store -> src/store/README.md
  { pattern: 'src/store/**/*.ts', docPath: 'src/store/README.md', description: '状态管理文档' },
  // Components -> 各组件目录/README.md
  { pattern: 'src/components/**/*.tsx', docPath: 'src/components/$DIR/README.md', description: '组件文档' },
  // Services -> src/services/README.md
  { pattern: 'src/services/**/*.ts', docPath: 'src/services/README.md', description: '服务层文档' },
];

/**
 * 生成目录文档的标准模板
 */
function generateDocTemplate(docPath: string, description: string): string {
  const today = new Date().toISOString().split('T')[0];
  return `<!-- 一旦我所属的文件夹有所变化，请更新我。-->
<!-- 本目录 ${description} -->
<!-- 最后更新: ${today} -->

## 用途

[请描述此目录的作用，1-3 行]

## 文件清单

| 文件 | 地位 | 功能 |
| --- | --- | --- |
| \`xxx.ts\` | Hook/Component/Util | [功能描述] |
| \`index.ts\` | 聚合入口 | 统一导出 |

## 设计说明

[可选] 描述目录的设计决策、依赖关系等

---
*此文档由 useDocumentationGuard 生成，请根据实际情况完善*
`;
}

/**
 * 提取目录路径（用于 $DIR 替换）
 */
function extractDirPath(filePath: string, pattern: string): string | null {
  // 简单实现：从 pattern 中提取目录结构
  // 例如: 'src/components/**/hooks/*.ts' -> 提取中间的目录
  const parts = pattern.split('/');
  const fileIndex = parts.findIndex(p => p.includes('*'));

  if (fileIndex === -1) return null;

  const filePathParts = filePath.split('/');
  return filePathParts.slice(0, fileIndex + 1).join('/');
}

/**
 * 文档守卫 Hook
 *
 * @param options - 配置选项
 * @returns 文档守卫状态和操作
 *
 * @example
 * ```tsx
 * const { state, actions } = useDocumentationGuard({
 *   watchedFiles: ['src/hooks/useMyHook.ts'],
 *   autoCheck: true,
 * });
 *
 * if (state.hasPendingDocs) {
 *   state.pendingDocs.forEach(doc => {
 *     console.warn(`需要更新文档: ${doc.docPath}`);
 *   });
 * }
 * ```
 */
export function useDocumentationGuard(options?: {
  /** 需要监控的文件列表（默认：当前 git 变更文件） */
  watchedFiles?: string[];
  /** 自定义文档映射 */
  docMappings?: DocMapping[];
  /** 是否自动检查（默认：true） */
  autoCheck?: boolean;
  /** 检查间隔（毫秒，默认：30000） */
  checkInterval?: number;
}): { state: DocGuardState; actions: DocGuardActions } {
  const {
    watchedFiles,
    docMappings = DEFAULT_DOC_MAPPINGS,
    autoCheck = true,
    checkInterval = 30000,
  } = options || {};

  const [state, setState] = useState<DocGuardState>({
    hasPendingDocs: false,
    pendingDocs: [],
    checking: false,
  });

  const lastCheckRef = useRef<number>(0);

  /**
   * 检查文档状态
   */
  const checkDocs = useCallback(async () => {
    const now = Date.now();
    if (now - lastCheckRef.current < 1000) {
      return; // 防止频繁检查
    }
    lastCheckRef.current = now;

    setState(prev => ({ ...prev, checking: true }));

    try {
      const filesToCheck = watchedFiles || await getChangedFiles();
      const pendingDocs: DocGuardState['pendingDocs'] = [];

      for (const file of filesToCheck) {
        for (const mapping of docMappings) {
          if (matchPattern(file, mapping.pattern)) {
            let docPath = mapping.docPath;

            // 处理 $DIR 替换
            if (docPath.includes('$DIR')) {
              const dirPath = extractDirPath(file, mapping.pattern);
              if (dirPath) {
                docPath = docPath.replace('$DIR', dirPath.split('/').pop() || '');
              }
            }

            pendingDocs.push({
              docPath,
              description: mapping.description,
              relatedFile: file,
            });
          }
        }
      }

      setState({
        hasPendingDocs: pendingDocs.length > 0,
        pendingDocs: Array.from(
          new Map(pendingDocs.map(d => [d.docPath, d])).values()
        ),
        checking: false,
      });
    } catch (error) {
      console.error('Documentation check failed:', error);
      setState(prev => ({ ...prev, checking: false }));
    }
  }, [watchedFiles, docMappings]);

  /**
   * 标记文档已更新
   */
  const markUpdated = useCallback((docPath: string) => {
    setState(prev => ({
      ...prev,
      pendingDocs: prev.pendingDocs.filter(d => d.docPath !== docPath),
      hasPendingDocs: false,
    }));
  }, []);

  /**
   * 获取文档更新模板
   */
  const getDocTemplate = useCallback((docPath: string): string => {
    const pending = state.pendingDocs.find(d => d.docPath === docPath);
    return generateDocTemplate(docPath, pending?.description || '文档');
  }, [state.pendingDocs]);

  /**
   * 重置状态
   */
  const reset = useCallback(() => {
    setState({
      hasPendingDocs: false,
      pendingDocs: [],
      checking: false,
    });
  }, []);

  // 自动检查
  useEffect(() => {
    if (!autoCheck) return;

    checkDocs();

    const interval = setInterval(checkDocs, checkInterval);
    return () => clearInterval(interval);
  }, [autoCheck, checkInterval, checkDocs]);

  const actions: DocGuardActions = {
    checkDocs,
    markUpdated,
    getDocTemplate,
    reset,
  };

  return { state, actions };
}

/**
 * 获取 Git 变更文件
 */
async function getChangedFiles(): Promise<string[]> {
  if (typeof window !== 'undefined') {
    // 浏览器环境：返回空（需要后端支持）
    return [];
  }

  try {
    const { execSync } = await import('child_process');
    const output = execSync('git status --porcelain', { encoding: 'utf-8' });
    return output
      .split('\n')
      .filter(line => line.trim())
      .map(line => line.substring(3)); // 跳过状态标识
  } catch {
    return [];
  }
}

/**
 * 简单的通配符匹配
 */
function matchPattern(filePath: string, pattern: string): boolean {
  const regex = new RegExp(
    '^' +
    pattern
      .replace(/\./g, '\\.')
      .replace(/\*\*/g, '.*')
      .replace(/\*/g, '[^/]*') +
    '$'
  );
  return regex.test(filePath);
}

/**
 * 便捷 hook：在开发环境自动提示文档更新
 *
 * @example
 * ```tsx
 * function MyComponent() {
 *   useDocReminder('src/hooks/useMyHook.ts');
 *   return <div>...</div>;
 * }
 * ```
 */
export function useDocReminder(filePath: string) {
  const { state, actions } = useDocumentationGuard({
    watchedFiles: [filePath],
    autoCheck: true,
  });

  useEffect(() => {
    if (state.hasPendingDocs && state.pendingDocs.length > 0) {
      const docPath = state.pendingDocs[0].docPath;
      console.warn(
        `%c📄 文档提醒: 代码已变更，请更新 ${docPath}`,
        'color: #f5222d; font-weight: bold; font-size: 14px;'
      );
      console.log(
        `%c使用 actions.getDocTemplate('${docPath}') 获取文档模板`,
        'color: #1890ff;'
      );
    }
  }, [state.hasPendingDocs, state.pendingDocs]);
}

// Input: React
// Output: useSettings Hook
// Pos: 通用复用组件 - 设置管理 Hook

import { useState, useCallback } from 'react';

export interface SettingsValue<T = any> {
  value: T;
  defaultValue: T;
  category: string;
  key: string;
  label: string;
  description?: string;
  type: 'text' | 'number' | 'boolean' | 'select' | 'multiselect';
  options?: Array<{ label: string; value: any }>;
  required?: boolean;
  validator?: (value: T) => string | null;
}

export interface UseSettingsOptions<T = any> {
  initialValues?: Record<string, T>;
  onSave?: (values: Record<string, T>) => Promise<void>;
  autoSave?: boolean;
}

export interface UseSettingsReturn<T = any> {
  values: Record<string, T>;
  errors: Record<string, string>;
  isDirty: boolean;
  isSaving: boolean;
  setValue: (key: string, value: T) => void;
  setValues: (values: Record<string, T>) => void;
  resetValue: (key: string) => void;
  resetAll: () => void;
  save: () => Promise<void>;
  validate: () => boolean;
}

/**
 * 设置管理 Hook
 * <p>
 * 封装设置页面的状态管理、验证和保存逻辑
 * </p>
 */
export function useSettings<T = any>({
  initialValues = {} as Record<string, T>,
  onSave,
  autoSave = false,
}: UseSettingsOptions<T> = {}): UseSettingsReturn<T> {
  const [values, setValues] = useState<Record<string, T>>(initialValues);
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isDirty, setIsDirty] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  const setValue = useCallback((key: string, value: T) => {
    setValues(prev => ({ ...prev, [key]: value }));
    setErrors(prev => ({ ...prev, [key]: '' }));
    setIsDirty(true);
  }, []);

  const setValuesMultiple = useCallback((newValues: Record<string, T>) => {
    setValues(prev => ({ ...prev, ...newValues }));
    setIsDirty(true);
  }, []);

  const resetValue = useCallback((key: string) => {
    const defaultValue = initialValues[key];
    setValues(prev => ({ ...prev, [key]: defaultValue }));
    setErrors(prev => ({ ...prev, [key]: '' }));
  }, [initialValues]);

  const resetAll = useCallback(() => {
    setValues(initialValues);
    setErrors({});
    setIsDirty(false);
  }, [initialValues]);

  const validate = useCallback((): boolean => {
    const newErrors: Record<string, string> = {};
    let isValid = true;

    // TODO: Add validation logic based on settings config
    for (const [key, value] of Object.entries(values)) {
      if (value === null || value === undefined || value === '') {
        newErrors[key] = '此字段不能为空';
        isValid = false;
      }
    }

    setErrors(newErrors);
    return isValid;
  }, [values]);

  const save = useCallback(async () => {
    if (!validate()) {
      return;
    }

    setIsSaving(true);
    try {
      await onSave?.(values);
      setIsDirty(false);
    } catch (error) {
      console.error('Failed to save settings:', error);
      throw error;
    } finally {
      setIsSaving(false);
    }
  }, [values, validate, onSave]);

  return {
    values,
    errors,
    isDirty,
    isSaving,
    setValue,
    setValues: setValuesMultiple,
    resetValue,
    resetAll,
    save,
    validate,
  };
}

export default useSettings;

// Input: LoginCard 展示组件
// Output: Login 页面容器（Page 层）
// Pos: src/pages/Auth/Login/index.tsx

/**
 * Login Page Container
 * 
 * 职责：路由集成、认证状态处理、AuthStore 调用。
 * 渲染委托给 LoginCard 展示组件（Presenter）。
 */
import React, { useState } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { authApi } from '../../../api/auth';
import { triggerAuditRefresh } from '../../../utils/audit';
import { useAuthStore } from '../../../store';
import { LoginCard } from '../../../components/auth';

interface LocationState {
    from?: { pathname: string };
}

const LoginPage: React.FC = () => {
    const [error, setError] = useState<string | null>(null);
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();
    const location = useLocation();
    const { login } = useAuthStore();

    const state = location.state as LocationState;
    const from = state?.from?.pathname || '/system';

    const handleLogin = async (username: string, password: string) => {
        setLoading(true);
        setError(null);
        try {
            const res = await authApi.login({ username: username.trim(), password: password.trim() });
            if (res.code === 200) {
                // 存储完整的用户数据
                const { user } = res.data;
                login(res.data.token, {
                    id: user.id,
                    username: user.username,
                    fullName: user.fullName,
                    email: user.email,
                    avatar: user.avatar,
                    departmentId: user.departmentId,
                    status: user.status,
                    roles: user.roles || [],
                    permissions: user.permissions || [],
                    // 新增字段：个人资料展示
                    phone: user.phone,
                    employeeId: user.employeeId,
                    jobTitle: user.jobTitle,
                    orgCode: user.orgCode,
                    lastLoginAt: user.lastLoginAt,
                    createdTime: user.createdTime,
                    roleNames: user.roleNames,
                });
                window.dispatchEvent(new Event('login'));
                triggerAuditRefresh();
                navigate(from, { replace: true });
            } else {
                setError(res.message || '登录失败');
            }
        } catch (err: any) {
            const serverMessage = err?.response?.data?.message;
            const rawMessage = err?.message;
            let message = serverMessage || rawMessage || '网络错误';
            if (err?.code === 'ERR_NETWORK' || rawMessage === 'Network Error') {
                message = '网络错误';
            }
            setError(message);
        }
        setLoading(false);
    };

    const handleVisitLanding = () => {
        navigate('/');
    };

    return (
        <LoginCard
            error={error}
            loading={loading}
            redirectHint={from !== '/system' ? from : undefined}
            onLogin={handleLogin}
            onVisitLanding={handleVisitLanding}
        />
    );
};

export default LoginPage;

// Input: React、react-router-dom 路由、本地模块 api/auth、utils/audit、store
// Output: React 组件 LoginView
// Pos: src/pages/Auth/LoginView.tsx

import React, { useState } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { authApi } from '../../api/auth';
import { triggerAuditRefresh } from '../../utils/audit';
import { useAuthStore } from '../../store';

interface LoginViewProps {
    // 保留可选 props 用于向后兼容（如用于嵌入式登录场景）
    onLoginSuccess?: (user: any) => void;
    onVisitLanding?: () => void;
}

interface LocationState {
    from?: { pathname: string };
}

export const LoginView: React.FC<LoginViewProps> = ({ onLoginSuccess, onVisitLanding }) => {
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState<string | null>(null);
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();
    const location = useLocation();

    // 使用 AuthStore
    const { login } = useAuthStore();

    // 获取登录后的跳转目标（登录后跳转回原页面）
    const state = location.state as LocationState;
    const from = state?.from?.pathname || '/system';

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError(null);

        try {
            console.log('[LoginView] Attempting login for:', username.trim());
            const res = await authApi.login({ username: username.trim(), password: password.trim() });
            console.log('[LoginView] Login response:', res);
            if (res.code === 200) {
                // 存储完整的用户数据
                const { user } = res.data;
                login(res.data.token, {
                    id: user.id,
                    username: user.username,
                    fullName: user.fullName,
                    email: user.email,
                    avatar: user.avatar,
                    departmentId: user.departmentId,
                    status: user.status,
                    roles: user.roles || [],
                    permissions: user.permissions || [],
                    // 新增字段：个人资料展示
                    phone: user.phone,
                    employeeId: user.employeeId,
                    jobTitle: user.jobTitle,
                    orgCode: user.orgCode,
                    lastLoginAt: user.lastLoginAt,
                    createdTime: user.createdTime,
                    roleNames: user.roleNames,
                });

                // Dispatch login event for other components
                window.dispatchEvent(new Event('login'));

                // 如果有回调则调用（向后兼容）
                if (onLoginSuccess) {
                    onLoginSuccess(res.data.user);
                }
                triggerAuditRefresh();

                // 跳转到原页面或默认门户
                console.log('[LoginView] Login success, navigating to:', from);
                navigate(from, { replace: true });
            } else {
                console.error('[LoginView] Login failed with code:', res.code, res.message);
                setError(res.message || '登录失败');
            }
        } catch (err: any) {
            console.error('[LoginView] Login error exception:', err);
            const serverMessage = err?.response?.data?.message;
            const rawMessage = err?.message;
            let message = serverMessage || rawMessage || '网络错误';
            if (err?.code === 'ERR_NETWORK' || rawMessage === 'Network Error') {
                message = '网络错误';
            }
            setError(message);
        }
        setLoading(false);
    };

    const handleVisitLanding = () => {
        if (onVisitLanding) {
            onVisitLanding();
        }
        // 产品首页现在在应用内的 '/' 路径
        navigate('/');
    };

    return (
        <div className="flex items-center justify-center h-screen bg-gray-100">
            <form onSubmit={handleSubmit} className="bg-white p-6 rounded shadow-md w-80">
                <h2 className="text-xl mb-4 text-center">登录</h2>

                {/* 显示跳转来源提示 */}
                {from !== '/system' && (
                    <p className="text-xs text-slate-500 mb-3 text-center">
                        登录后将跳转到: {from}
                    </p>
                )}

                {error && <p className="text-red-500 text-sm mb-2" data-testid="login-error">{error}</p>}
                <div className="mb-3">
                    <label className="block text-sm mb-1">用户名</label>
                    <input
                        type="text"
                        value={username}
                        onChange={e => setUsername(e.target.value)}
                        className="w-full border rounded px-2 py-1"
                        required
                        data-testid="login-username"
                    />
                </div>
                <div className="mb-3">
                    <label className="block text-sm mb-1">密码</label>
                    <input
                        type="password"
                        value={password}
                        onChange={e => setPassword(e.target.value)}
                        className="w-full border rounded px-2 py-1"
                        required
                        data-testid="login-password"
                    />
                </div>
                <button
                    type="submit"
                    disabled={loading}
                    className="w-full bg-blue-600 text-white py-2 rounded hover:bg-blue-700 mb-4 disabled:opacity-50"
                    data-testid="login-submit"
                >
                    {loading ? '登录中...' : '登录'}
                </button>
                <button
                    type="button"
                    onClick={handleVisitLanding}
                    className="w-full border border-blue-600 text-blue-600 py-2 rounded hover:bg-blue-50"
                >
                    访问产品官网
                </button>
            </form>
        </div>
    );
};

export default LoginView;

// Input: React、lucide-react、mfaApi
// Output: MfaVerifyPage 组件
// Pos: MFA 验证页面（登录后验证）
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useState } from 'react';
import { Shield, Loader2, CheckCircle2, XCircle, Key, AlertCircle } from 'lucide-react';
import { mfaApi } from '../../api/mfa';
import { useNavigate } from 'react-router-dom';

/**
 * MFA 验证页面
 * 
 * 功能：
 * 1. TOTP 码输入框
 * 2. 备用码输入选项
 * 3. 验证失败提示
 * 
 * PRD 来源: Section 5.3 - 多因素认证
 */
export const MfaVerifyPage: React.FC = () => {
    const navigate = useNavigate();
    const [code, setCode] = useState('');
    const [useBackupCode, setUseBackupCode] = useState(false);
    const [verifying, setVerifying] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const handleVerify = async () => {
        if (!code.trim()) {
            setError('请输入验证码');
            return;
        }

        setVerifying(true);
        setError(null);

        try {
            const res = useBackupCode
                ? await mfaApi.verifyBackup(code.trim())
                : await mfaApi.verify(code.trim());

            if (res.code === 200) {
                // 验证成功，跳转到首页
                navigate('/system');
            } else {
                setError(res.message || '验证失败，请检查验证码是否正确');
            }
        } catch (error: any) {
            setError(error?.response?.data?.message || '验证失败，请重试');
        } finally {
            setVerifying(false);
        }
    };

    const handleKeyPress = (e: React.KeyboardEvent<HTMLInputElement>) => {
        if (e.key === 'Enter') {
            handleVerify();
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-slate-50 p-4">
            <div className="max-w-md w-full bg-white rounded-lg shadow-lg p-8">
                <div className="text-center mb-8">
                    <div className="mx-auto w-16 h-16 bg-primary-100 rounded-full flex items-center justify-center mb-4">
                        <Shield className="text-primary-600" size={32} />
                    </div>
                    <h1 className="text-2xl font-bold text-slate-800 mb-2">多因素认证</h1>
                    <p className="text-slate-600">
                        请输入您的{useBackupCode ? '备用码' : '验证码'}以继续
                    </p>
                </div>

                {error && (
                    <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg flex items-start gap-3">
                        <XCircle className="text-red-600 flex-shrink-0 mt-0.5" size={20} />
                        <div className="text-sm text-red-800">{error}</div>
                    </div>
                )}

                <div className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-2">
                            {useBackupCode ? '备用码' : '6位验证码'}
                        </label>
                        <div className="relative">
                            <Key className="absolute left-3 top-1/2 transform -translate-y-1/2 text-slate-400" size={20} />
                            <input
                                type="text"
                                value={code}
                                onChange={(e) => {
                                    const value = useBackupCode 
                                        ? e.target.value 
                                        : e.target.value.replace(/\D/g, '').slice(0, 6);
                                    setCode(value);
                                    setError(null);
                                }}
                                onKeyPress={handleKeyPress}
                                placeholder={useBackupCode ? '输入备用码' : '000000'}
                                maxLength={useBackupCode ? undefined : 6}
                                className="w-full pl-10 pr-4 py-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500 text-center text-xl tracking-widest font-mono"
                                autoFocus
                            />
                        </div>
                        {!useBackupCode && (
                            <p className="text-xs text-slate-500 mt-1">
                                输入验证器应用中显示的6位数字
                            </p>
                        )}
                    </div>

                    <div className="flex items-center">
                        <input
                            type="checkbox"
                            id="useBackupCode"
                            checked={useBackupCode}
                            onChange={(e) => {
                                setUseBackupCode(e.target.checked);
                                setCode('');
                                setError(null);
                            }}
                            className="w-4 h-4 text-primary-600 border-slate-300 rounded focus:ring-primary-500"
                        />
                        <label htmlFor="useBackupCode" className="ml-2 text-sm text-slate-700">
                            使用备用码
                        </label>
                    </div>

                    {useBackupCode && (
                        <div className="p-3 bg-blue-50 border border-blue-200 rounded-lg flex items-start gap-2">
                            <AlertCircle className="text-blue-600 flex-shrink-0 mt-0.5" size={16} />
                            <p className="text-xs text-blue-800">
                                每个备用码只能使用一次。使用后该备用码将失效。
                            </p>
                        </div>
                    )}

                    <button
                        onClick={handleVerify}
                        disabled={verifying || !code.trim() || (!useBackupCode && code.length !== 6)}
                        className="w-full px-4 py-3 bg-primary-600 text-white rounded-lg hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2 font-medium"
                    >
                        {verifying ? (
                            <>
                                <Loader2 className="animate-spin" size={20} />
                                验证中...
                            </>
                        ) : (
                            <>
                                <CheckCircle2 size={20} />
                                验证
                            </>
                        )}
                    </button>

                    <div className="text-center">
                        <button
                            onClick={() => navigate(-1)}
                            className="text-sm text-slate-500 hover:text-slate-700"
                        >
                            返回
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default MfaVerifyPage;

// Input: React、lucide-react、userLifecycleApi
// Output: AccessReviewPage 组件
// Pos: 定期复核（Access Review）页面
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useState, useEffect } from 'react';
import { ShieldCheck, Loader2, CheckCircle2, XCircle, Eye, Clock, User, MessageSquare } from 'lucide-react';
import { userLifecycleApi, AccessReviewTask, ExecuteReviewRequest } from '../../api/userLifecycle';
import { toast } from '../../utils/notificationService';

/**
 * 定期复核（Access Review）页面
 * 
 * 功能：
 * 1. 复核任务列表
 * 2. 复核执行：查看用户权限、确认/撤销权限
 * 3. 复核历史记录
 * 
 * PRD 来源: Section 4.2 - 用户生命周期管理
 */
export const AccessReviewPage: React.FC = () => {
    const [tasks, setTasks] = useState<AccessReviewTask[]>([]);
    const [loading, setLoading] = useState(false);
    const [page, setPage] = useState(1);
    const [total, setTotal] = useState(0);
    const pageSize = 20;
    const [statusFilter, setStatusFilter] = useState<string>('');
    const [selectedTask, setSelectedTask] = useState<AccessReviewTask | null>(null);
    const [showReviewModal, setShowReviewModal] = useState(false);
    const [reviewForm, setReviewForm] = useState<ExecuteReviewRequest>({
        taskId: '',
        result: 'APPROVED',
        comment: '',
        revokeRoleIds: [],
    });
    const [submitting, setSubmitting] = useState(false);

    const loadTasks = async () => {
        setLoading(true);
        try {
            const params: any = { page, size: pageSize };
            if (statusFilter) params.status = statusFilter;

            const res = await userLifecycleApi.getReviewTasks(params);
            if (res.code === 200 && res.data) {
                setTasks(res.data.records || []);
                setTotal(res.data.total || 0);
            }
        } catch (error) {
            console.error('加载复核任务失败', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadTasks();
    }, [page, statusFilter]);

    const handleReview = (task: AccessReviewTask) => {
        setSelectedTask(task);
        setReviewForm({
            taskId: task.id,
            result: 'APPROVED',
            comment: '',
            revokeRoleIds: [],
        });
        setShowReviewModal(true);
    };

    const handleSubmitReview = async () => {
        if (!selectedTask) return;

        setSubmitting(true);
        try {
            const res = await userLifecycleApi.executeReview(reviewForm);
            if (res.code === 200) {
                toast.success('复核完成');
                setShowReviewModal(false);
                loadTasks();
            } else {
                toast.error(res.message || '复核失败');
            }
        } catch (error: any) {
            toast.error(error?.response?.data?.message || '复核失败');
        } finally {
            setSubmitting(false);
        }
    };

    const getStatusBadge = (status: string) => {
        const configs: Record<string, { label: string; color: string }> = {
            'PENDING': { label: '待复核', color: 'bg-yellow-100 text-yellow-700' },
            'IN_PROGRESS': { label: '复核中', color: 'bg-blue-100 text-blue-700' },
            'COMPLETED': { label: '已完成', color: 'bg-green-100 text-green-700' },
        };
        const config = configs[status] || { label: status, color: 'bg-slate-100 text-slate-700' };
        return (
            <span className={`px-3 py-1 rounded-full text-xs font-medium ${config.color}`}>
                {config.label}
            </span>
        );
    };

    return (
        <div className="p-6 space-y-4">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-2xl font-bold text-slate-800 flex items-center">
                        <ShieldCheck className="mr-2" size={28} />
                        权限定期复核
                    </h2>
                    <p className="text-slate-500 text-sm mt-1">定期复核用户权限，确保权限的合理性和安全性</p>
                </div>
            </div>

            {/* 筛选条件 */}
            <div className="bg-white border border-slate-200 rounded-lg p-4">
                <div className="flex items-center gap-4">
                    <label className="text-sm font-medium text-slate-700">状态筛选:</label>
                    <select
                        value={statusFilter}
                        onChange={(e) => { setStatusFilter(e.target.value); setPage(1); }}
                        className="px-3 py-2 border border-slate-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-primary-500"
                    >
                        <option value="">全部</option>
                        <option value="PENDING">待复核</option>
                        <option value="IN_PROGRESS">复核中</option>
                        <option value="COMPLETED">已完成</option>
                    </select>
                    <button
                        onClick={loadTasks}
                        className="px-4 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 text-sm"
                    >
                        刷新
                    </button>
                </div>
            </div>

            {/* 任务列表 */}
            <div className="bg-white border border-slate-200 rounded-lg overflow-hidden">
                {loading ? (
                    <div className="flex items-center justify-center h-64">
                        <Loader2 className="animate-spin text-slate-400" size={32} />
                    </div>
                ) : tasks.length === 0 ? (
                    <div className="flex flex-col items-center justify-center h-64 text-slate-400">
                        <ShieldCheck size={48} className="mb-4" />
                        <p>暂无复核任务</p>
                    </div>
                ) : (
                    <>
                        <table className="w-full text-left text-sm">
                            <thead className="bg-slate-50 border-b">
                                <tr>
                                    <th className="px-4 py-3">用户</th>
                                    <th className="px-4 py-3">角色</th>
                                    <th className="px-4 py-3">复核日期</th>
                                    <th className="px-4 py-3">状态</th>
                                    <th className="px-4 py-3">复核人</th>
                                    <th className="px-4 py-3">复核结果</th>
                                    <th className="px-4 py-3">操作</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y">
                                {tasks.map(task => (
                                    <tr key={task.id} className="hover:bg-slate-50">
                                        <td className="px-4 py-3">
                                            <div className="flex items-center gap-2">
                                                <User size={16} className="text-slate-400" />
                                                <span>{task.userName}</span>
                                            </div>
                                        </td>
                                        <td className="px-4 py-3">
                                            <div className="flex flex-wrap gap-1">
                                                {task.roleNames.map((role, idx) => (
                                                    <span key={idx} className="px-2 py-1 bg-slate-100 text-slate-700 rounded text-xs">
                                                        {role}
                                                    </span>
                                                ))}
                                            </div>
                                        </td>
                                        <td className="px-4 py-3 text-slate-600">
                                            {new Date(task.reviewDate).toLocaleDateString('zh-CN')}
                                        </td>
                                        <td className="px-4 py-3">{getStatusBadge(task.status)}</td>
                                        <td className="px-4 py-3">{task.reviewerName || '-'}</td>
                                        <td className="px-4 py-3">
                                            {task.reviewResult ? (
                                                task.reviewResult === 'APPROVED' ? (
                                                    <span className="text-green-600">已批准</span>
                                                ) : (
                                                    <span className="text-red-600">已撤销</span>
                                                )
                                            ) : (
                                                <span className="text-slate-400">-</span>
                                            )}
                                        </td>
                                        <td className="px-4 py-3">
                                            {task.status === 'PENDING' && (
                                                <button
                                                    onClick={() => handleReview(task)}
                                                    className="px-3 py-1 bg-primary-600 text-white rounded text-sm hover:bg-primary-700 flex items-center gap-1"
                                                >
                                                    <ShieldCheck size={14} />
                                                    复核
                                                </button>
                                            )}
                                            {task.status === 'COMPLETED' && (
                                                <button
                                                    onClick={() => handleReview(task)}
                                                    className="px-3 py-1 text-slate-600 hover:bg-slate-100 rounded text-sm flex items-center gap-1"
                                                >
                                                    <Eye size={14} />
                                                    查看
                                                </button>
                                            )}
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                        {/* 分页 */}
                        <div className="px-4 py-3 border-t flex items-center justify-between">
                            <div className="text-sm text-slate-600">
                                共 {total} 条，第 {page} / {Math.ceil(total / pageSize)} 页
                            </div>
                            <div className="flex gap-2">
                                <button
                                    onClick={() => setPage(p => Math.max(1, p - 1))}
                                    disabled={page <= 1}
                                    className="px-3 py-1 border rounded text-sm disabled:opacity-50"
                                >
                                    上一页
                                </button>
                                <button
                                    onClick={() => setPage(p => Math.min(Math.ceil(total / pageSize), p + 1))}
                                    disabled={page >= Math.ceil(total / pageSize)}
                                    className="px-3 py-1 border rounded text-sm disabled:opacity-50"
                                >
                                    下一页
                                </button>
                            </div>
                        </div>
                    </>
                )}
            </div>

            {/* 复核模态框 */}
            {showReviewModal && selectedTask && (
                <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
                    <div className="bg-white rounded-lg shadow-xl max-w-2xl w-full mx-4 max-h-[90vh] overflow-y-auto">
                        <div className="px-6 py-4 border-b border-slate-200 flex items-center justify-between">
                            <h2 className="text-lg font-semibold">权限复核</h2>
                            <button
                                onClick={() => setShowReviewModal(false)}
                                className="text-slate-400 hover:text-slate-600"
                            >
                                ×
                            </button>
                        </div>
                        <div className="p-6 space-y-4">
                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <span className="text-sm text-slate-500">用户:</span>
                                    <p className="font-medium">{selectedTask.userName}</p>
                                </div>
                                <div>
                                    <span className="text-sm text-slate-500">复核日期:</span>
                                    <p className="font-medium">{new Date(selectedTask.reviewDate).toLocaleDateString('zh-CN')}</p>
                                </div>
                            </div>
                            <div>
                                <span className="text-sm text-slate-500">当前角色:</span>
                                <div className="mt-2 flex flex-wrap gap-2">
                                    {selectedTask.roleNames.map((role, idx) => (
                                        <span key={idx} className="px-3 py-1 bg-slate-100 text-slate-700 rounded-full text-sm">
                                            {role}
                                        </span>
                                    ))}
                                </div>
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-2">
                                    复核结果
                                </label>
                                <div className="space-y-2">
                                    <label className="flex items-center gap-2 p-3 border border-slate-200 rounded-lg cursor-pointer hover:bg-slate-50">
                                        <input
                                            type="radio"
                                            name="reviewResult"
                                            checked={reviewForm.result === 'APPROVED'}
                                            onChange={() => setReviewForm({ ...reviewForm, result: 'APPROVED' })}
                                            className="w-4 h-4 text-primary-600 border-slate-300 focus:ring-primary-500"
                                        />
                                        <CheckCircle2 className="text-green-600" size={20} />
                                        <span>批准（保持权限）</span>
                                    </label>
                                    <label className="flex items-center gap-2 p-3 border border-slate-200 rounded-lg cursor-pointer hover:bg-slate-50">
                                        <input
                                            type="radio"
                                            name="reviewResult"
                                            checked={reviewForm.result === 'REVOKED'}
                                            onChange={() => setReviewForm({ ...reviewForm, result: 'REVOKED' })}
                                            className="w-4 h-4 text-primary-600 border-slate-300 focus:ring-primary-500"
                                        />
                                        <XCircle className="text-red-600" size={20} />
                                        <span>撤销权限</span>
                                    </label>
                                </div>
                            </div>
                            {reviewForm.result === 'REVOKED' && (
                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-2">
                                        撤销角色（可选，留空则撤销所有角色）
                                    </label>
                                    <div className="space-y-2">
                                        {selectedTask.roleNames.map((roleName, idx) => {
                                            const roleId = `role-${idx}`; // 模拟角色ID
                                            return (
                                                <label key={idx} className="flex items-center gap-2 p-2 border border-slate-200 rounded cursor-pointer hover:bg-slate-50">
                                                    <input
                                                        type="checkbox"
                                                        checked={reviewForm.revokeRoleIds?.includes(roleId) || false}
                                                        onChange={(e) => {
                                                            const ids = reviewForm.revokeRoleIds || [];
                                                            if (e.target.checked) {
                                                                setReviewForm({ ...reviewForm, revokeRoleIds: [...ids, roleId] });
                                                            } else {
                                                                setReviewForm({ ...reviewForm, revokeRoleIds: ids.filter(id => id !== roleId) });
                                                            }
                                                        }}
                                                        className="w-4 h-4 text-primary-600 border-slate-300 rounded focus:ring-primary-500"
                                                    />
                                                    <span>{roleName}</span>
                                                </label>
                                            );
                                        })}
                                    </div>
                                </div>
                            )}
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-2">
                                    复核意见
                                </label>
                                <textarea
                                    value={reviewForm.comment}
                                    onChange={(e) => setReviewForm({ ...reviewForm, comment: e.target.value })}
                                    rows={4}
                                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                                    placeholder="请输入复核意见..."
                                />
                            </div>
                            <div className="flex gap-3 pt-4 border-t">
                                <button
                                    onClick={handleSubmitReview}
                                    disabled={submitting}
                                    className="flex-1 px-4 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                                >
                                    {submitting ? (
                                        <Loader2 className="animate-spin" size={16} />
                                    ) : (
                                        <ShieldCheck size={16} />
                                    )}
                                    提交复核
                                </button>
                                <button
                                    onClick={() => setShowReviewModal(false)}
                                    className="px-4 py-2 border border-slate-300 rounded-lg text-slate-700 hover:bg-slate-50"
                                >
                                    取消
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default AccessReviewPage;

