                setMessage({ type: 'success', text: `全宗分立成功，历史记录ID: ${res.data?.historyIds?.join(', ')}` });
                setSplitForm({
                    sourceFondsNo: '',
                    newFondsNos: [''],
                    effectiveDate: new Date().toISOString().split('T')[0],
                    reason: '',
