    const [fondsList, setFondsList] = useState<BasFonds[]>([]);
    const [orgList, setOrgList] = useState<Org[]>([]);
    const [loading, setLoading] = useState(false);
    const [saving, setSaving] = useState(false);
    const [showModal, setShowModal] = useState(false);
    const [canModifyFondsCode, setCanModifyFondsCode] = useState(true);

    // Form State
    const [form, setForm] = useState<FondsForm>({
        fondsCode: '',
        fondsName: '',
        companyName: '',
        description: ''
    });

    const loadData = async () => {
        setLoading(true);
        try {
            const [fondsRes, orgRes] = await Promise.all([
                fondsApi.list(),
                adminApi.listOrg()
            ]);
            if (fondsRes.code === 200 && fondsRes.data) {
                setFondsList(fondsRes.data);
            }
            if (orgRes.code === 200 && orgRes.data) {
                // 过滤只保留公司级别 (COMPANY)
                setOrgList(orgRes.data.filter((o: Org) => o.type === 'COMPANY' || !o.type));
            }
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadData();
    }, []);

    const handleEdit = async (item: BasFonds) => {
        // 检查是否可以修改全宗号
        try {
            const canModifyRes = await fondsApi.canModify(item.id);
            setCanModifyFondsCode(canModifyRes.code === 200 && canModifyRes.data === true);
        } catch {
            setCanModifyFondsCode(false);
        }

        setForm({
            id: item.id,
            fondsCode: item.fondsCode,
            fondsName: item.fondsName,
            companyName: item.companyName || '',
            description: item.description || ''
        });
        setShowModal(true);
    };

    const handleDelete = async (id: string) => {
        if (!window.confirm('确定删除该全宗吗？删除后关联的档案将失去全宗引用。')) return;
        setLoading(true);
        try {
            await fondsApi.remove(id);
            loadData();
        } finally {
            setLoading(false);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setSaving(true);
        try {
            if (form.id) {
                await fondsApi.update(form);
                toast.success('全宗更新成功');
            } else {
                await fondsApi.save(form);
                toast.success('全宗创建成功');
            }
            setShowModal(false);
            loadData();
        } catch {
            toast.error('保存失败，请检查全宗号是否重复');
        } finally {
            setSaving(false);
        }
    };

    const openCreate = () => {
        setForm({ fondsCode: '', fondsName: '', companyName: '', description: '' });
        setCanModifyFondsCode(true); // 新建时可以编辑全宗号
        setShowModal(true);
    };

    // 选择组织时自动填充全宗号和名称
    const handleOrgChange = (orgId: string) => {
        const org = orgList.find(o => o.id === orgId);
        if (org) {
            setForm(prev => ({
                ...prev,
                orgId: orgId,
                fondsCode: prev.fondsCode || org.code || '', // 只有为空时才填充
                fondsName: prev.fondsName || org.name || '',
                companyName: org.name || ''
            }));
        }
    };

    return (
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <div className="flex items-center justify-between mb-6">
                <div>
                    <h3 className="text-lg font-bold text-slate-800 mb-1">全宗管理 (Fonds)</h3>
                    <p className="text-xs text-slate-500">管理档案系统的顶层全宗实体，符合 DA/T 94 标准。</p>
                </div>
                <button
                    onClick={openCreate}
                    className="inline-flex items-center px-4 py-2 bg-primary-600 text-white text-sm rounded-lg hover:bg-primary-700"
                >
                    <Plus size={16} className="mr-2" />
                    新建全宗
                </button>
            </div>

            <div className="overflow-x-auto">
                <table className="w-full text-sm text-left">
                    <thead className="bg-slate-50 text-slate-500 font-medium">
                        <tr>
                            <th className="px-4 py-3 rounded-l-lg">全宗号</th>
                            <th className="px-4 py-3">全宗名称</th>
                            <th className="px-4 py-3">所属法人</th>
                            <th className="px-4 py-3">立档单位</th>
                            <th className="px-4 py-3">描述</th>
                            <th className="px-4 py-3 rounded-r-lg text-right">操作</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                        {loading ? (
                            <tr>
                                <td colSpan={6} className="py-8 text-center text-slate-500">
                                    <div className="flex items-center justify-center">
                                        <Loader2 size={20} className="animate-spin mr-2" /> 加载中...
                                    </div>
                                </td>
                            </tr>
                        ) : fondsList.length === 0 ? (
                            <tr>
                                <td colSpan={6} className="py-8 text-center text-slate-400">暂无全宗数据，请新建。</td>
                            </tr>
                        ) : (
                            fondsList.map((item) => {
                                const entity = orgList.find((e: Org) => e.id === (item as any).entityId);
                                return (
                                <tr key={item.id} className="hover:bg-slate-50 group transition-colors">
                                    <td className="px-4 py-3 font-mono text-primary-600 font-medium">{item.fondsCode}</td>
                                    <td className="px-4 py-3 font-medium text-slate-800">{item.fondsName}</td>
                                    <td className="px-4 py-3 text-slate-600">
                                        {entity ? (
                                            <span className="font-medium">{entity.name}</span>
                                        ) : (
                                            <span className="text-slate-400">-</span>
                                        )}
                                    </td>
                                    <td className="px-4 py-3 text-slate-600">{item.companyName || '-'}</td>
                                    <td className="px-4 py-3 text-slate-500 truncate max-w-xs">{item.description || '-'}</td>
                                    <td className="px-4 py-3 text-right space-x-2">
                                        <button
                                            onClick={() => handleEdit(item)}
                                            className="p-1 text-slate-400 hover:text-blue-600 transition-colors"
                                            title="编辑"
                                        >
                                            <Edit3 size={16} />
                                        </button>
                                        <button
                                            onClick={() => handleDelete(item.id)}
                                            className="p-1 text-slate-400 hover:text-red-600 transition-colors"
                                            title="删除"
                                        >
                                            <Trash2 size={16} />
                                        </button>
                                    </td>
                                </tr>
                                );
                            })
                        )}
                    </tbody>
                </table>
            </div>

            {/* Modal */}
            {showModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/20 backdrop-blur-sm p-4 animate-in fade-in duration-200">
                    <div className="bg-white rounded-xl shadow-2xl w-full max-w-md overflow-hidden animate-in zoom-in-95 duration-200">
                        <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                            <h3 className="font-bold text-slate-800">{form.id ? '编辑全宗' : '新建全宗'}</h3>
                            <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600">×</button>
                        </div>
                        <form onSubmit={handleSubmit} className="p-6 space-y-4">
                            {/* 组织选择器 */}
                            {!form.id && orgList.length > 0 && (
                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-1">
                                        <Building2 size={14} className="inline mr-1" />
                                        从组织快速创建
                                    </label>
                                    <select
                                        className="w-full border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-primary-500 outline-none"
                                        value={form.orgId || ''}
                                        onChange={e => handleOrgChange(e.target.value)}
                                    >
                                        <option value="">-- 选择组织自动填充 --</option>
                                        {orgList.map(org => (
                                            <option key={org.id} value={org.id}>
                                                {org.name} ({org.code || '无编码'})
                                            </option>
                                        ))}
                                    </select>
                                    <p className="text-xs text-slate-400 mt-1">选择后自动填充全宗号和名称</p>
                                </div>
                            )}

                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">
                                    全宗号 *
                                    {!canModifyFondsCode && form.id && (
                                        <span className="ml-2 text-xs text-amber-600">
                                            <Lock size={12} className="inline" /> 已有归档档案，不可修改
                                        </span>
                                    )}
                                </label>
                                <input
                                    className={`w-full border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-primary-500 outline-none ${!canModifyFondsCode && form.id ? 'bg-slate-100 cursor-not-allowed' : ''
                                        }`}
                                    placeholder="例如: Z001"
                                    value={form.fondsCode}
                                    onChange={e => setForm({ ...form, fondsCode: e.target.value })}
                                    disabled={!canModifyFondsCode && !!form.id}
                                    required
                                />
                                <p className="text-xs text-slate-400 mt-1">全局唯一，用于生成档号前缀。</p>
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">全宗名称 *</label>
                                <input
                                    className="w-full border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-primary-500 outline-none"
                                    placeholder="例如: 集团总公司全宗"
                                    value={form.fondsName}
                                    onChange={e => setForm({ ...form, fondsName: e.target.value })}
                                    required
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">立档单位名称</label>
                                <input
                                    className="w-full border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-primary-500 outline-none"
                                    placeholder="例如: XX集团有限公司"
                                    value={form.companyName}
                                    onChange={e => setForm({ ...form, companyName: e.target.value })}
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">描述</label>
                                <textarea
                                    className="w-full border border-slate-300 rounded-lg p-2 text-sm focus:ring-2 focus:ring-primary-500 outline-none"
                                    rows={3}
                                    value={form.description}
                                    onChange={e => setForm({ ...form, description: e.target.value })}
                                />
                            </div>

                            <div className="pt-2 flex justify-end space-x-3">
                                <button
                                    type="button"
                                    onClick={() => setShowModal(false)}
                                    className="px-4 py-2 border border-slate-300 rounded-lg text-sm text-slate-700 hover:bg-slate-50"
                                >
                                    取消
                                </button>
                                <button
                                    type="submit"
                                    disabled={saving}
                                    className="px-4 py-2 bg-primary-600 text-white rounded-lg text-sm font-medium hover:bg-primary-700 disabled:opacity-70 flex items-center"
                                >
                                    {saving && <Loader2 size={16} className="animate-spin mr-2" />}
                                    保存
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

export default FondsManagement;

// Input: React、lucide-react、legacyImportApi、Tailwind CSS
// Output: LegacyImportPage 组件
// Pos: src/pages/admin/LegacyImportPage.tsx
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useState, useEffect } from 'react';
import {
    Upload,
    FileText,
    CheckCircle2,
    XCircle,
    AlertCircle,
    Loader2,
    Download,
    History,
    Eye,
    RefreshCw,
    X,
    HelpCircle,
    Info,
    FileSpreadsheet,
    ChevronDown,
    ChevronUp,
} from 'lucide-react';
import {
    legacyImportApi,
    ImportPreviewResult,
    ImportResult,
    LegacyImportTask,
    ImportError,
} from '../../api/legacyImport';
import { toast } from '../../utils/notificationService';

/**
 * 历史数据导入页面
 * 
 * OpenSpec 来源: openspec-legacy-data-import.md
 * 
 * 功能：
 * 1. 文件上传（支持拖拽）
 * 2. 导入预览（显示解析结果和验证错误）
 * 3. 执行导入（显示进度）
 * 4. 导入历史查询
 * 5. 错误报告下载
 */
export const LegacyImportPage: React.FC = () => {
    // 状态管理
    const [activeTab, setActiveTab] = useState<'import' | 'history'>('import');
    const [file, setFile] = useState<File | null>(null);
    const [previewResult, setPreviewResult] = useState<ImportPreviewResult | null>(null);
    const [importResult, setImportResult] = useState<ImportResult | null>(null);
    const [loading, setLoading] = useState(false);
    const [importing, setImporting] = useState(false);
    const [historyLoading, setHistoryLoading] = useState(false);
    const [tasks, setTasks] = useState<LegacyImportTask[]>([]);
    const [currentPage, setCurrentPage] = useState(1);
    const [total, setTotal] = useState(0);
    const [statusFilter, setStatusFilter] = useState<string>('');
    const [showGuideDetail, setShowGuideDetail] = useState(false);

    useEffect(() => {
        if (activeTab === 'history') {
            loadHistory();
        }
    }, [activeTab, currentPage, statusFilter]);

    // 加载导入历史
    const loadHistory = async () => {
        setHistoryLoading(true);
        try {
            const res = await legacyImportApi.getTasks(currentPage, 20, statusFilter || undefined);
            if (res.code === 200 && res.data) {
                setTasks(res.data.records || []);
                setTotal(res.data.total || 0);
            }
        } catch (error) {
            console.error('加载导入历史失败', error);
        } finally {
            setHistoryLoading(false);
        }
    };

    // 处理文件选择
    const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = e.target.files?.[0];
        if (selectedFile) {
            // 文件大小检查（100MB = 100 * 1024 * 1024 bytes）
            const maxSize = 100 * 1024 * 1024;
            if (selectedFile.size > maxSize) {
                toast.warning(`文件大小超过限制！最大允许 100MB，当前文件：${(selectedFile.size / 1024 / 1024).toFixed(2)} MB`);
                e.target.value = '';
                return;
            }
            setFile(selectedFile);
            setPreviewResult(null);
            setImportResult(null);
        }
    };

    // 处理文件拖拽
    const handleDrop = (e: React.DragEvent<HTMLDivElement>) => {
        e.preventDefault();
        const droppedFile = e.dataTransfer.files[0];
        if (droppedFile) {
            // 文件大小检查（100MB = 100 * 1024 * 1024 bytes）
            const maxSize = 100 * 1024 * 1024;
            if (droppedFile.size > maxSize) {
                toast.warning(`文件大小超过限制！最大允许 100MB，当前文件：${(droppedFile.size / 1024 / 1024).toFixed(2)} MB`);
                return;
            }
            setFile(droppedFile);
            setPreviewResult(null);
            setImportResult(null);
        }
    };

    const handleDragOver = (e: React.DragEvent<HTMLDivElement>) => {
        e.preventDefault();
    };

    // 预览导入数据
    const handlePreview = async () => {
        if (!file) {
            toast.warning('请先选择文件');
            return;
        }

        setLoading(true);
        try {
            const res = await legacyImportApi.preview(file);
            if (res.code === 200 && res.data) {
                setPreviewResult(res.data);
                toast.success('预览成功');
            } else {
                toast.error(res.message || '预览失败');
            }
        } catch (error: any) {
            toast.error(error?.response?.data?.message || '预览失败');
        } finally {
            setLoading(false);
        }
    };

    // 执行导入
    const handleImport = async () => {
        if (!file) {
            toast.warning('请先选择文件');
            return;
        }

        if (!previewResult) {
            toast.warning('请先预览数据');
            return;
        }

        if (!window.confirm('确认导入数据吗？导入过程可能需要较长时间。')) {
            return;
        }

        setImporting(true);
        try {
            const res = await legacyImportApi.import(file);
            if (res.code === 200 && res.data) {
                setImportResult(res.data);
                toast.success('导入成功');
                // 导入成功后，刷新历史列表
                if (activeTab === 'history') {
                    loadHistory();
                }
            } else {
                toast.error(res.message || '导入失败');
            }
        } catch (error: any) {
            toast.error(error?.response?.data?.message || '导入失败');
        } finally {
            setImporting(false);
        }
    };

    // 下载错误报告
    const handleDownloadErrorReport = async (importId: string) => {
        try {
            const blob = await legacyImportApi.downloadErrorReport(importId);
            const url = window.URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `error_report_${importId}.xlsx`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            window.URL.revokeObjectURL(url);
            toast.success('错误报告下载成功');
        } catch (error) {
            toast.error('下载错误报告失败');
        }
    };

    // 下载CSV模板
    const handleDownloadCsvTemplate = async () => {
        try {
            const blob = await legacyImportApi.downloadCsvTemplate();
            const url = window.URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = 'legacy-import-template.csv';
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            window.URL.revokeObjectURL(url);
            toast.success('CSV模板下载成功');
        } catch (error) {
            toast.error('下载CSV模板失败');
        }
    };

    // 下载Excel模板
    const handleDownloadExcelTemplate = async () => {
        try {
            const blob = await legacyImportApi.downloadExcelTemplate();
            const url = window.URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = 'legacy-import-template.xlsx';
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            window.URL.revokeObjectURL(url);
            toast.success('Excel模板下载成功');
        } catch (error) {
            toast.error('下载Excel模板失败');
        }
    };

    // 获取状态标签样式
    const getStatusBadge = (status: string) => {
        const styles = {
            SUCCESS: 'bg-green-100 text-green-800',
            PARTIAL_SUCCESS: 'bg-yellow-100 text-yellow-800',
            FAILED: 'bg-red-100 text-red-800',
            PENDING: 'bg-gray-100 text-gray-800',
            PROCESSING: 'bg-blue-100 text-blue-800',
        };
        return styles[status as keyof typeof styles] || styles.PENDING;
    };

    return (
        <div className="h-full flex flex-col bg-slate-50">
            {/* Header */}
            <div className="bg-white border-b border-slate-200 px-6 py-4">
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <FileText className="w-6 h-6 text-primary-600" />
                        <h1 className="text-xl font-semibold text-slate-900">历史数据导入</h1>
                    </div>
                </div>

                {/* Tabs */}
                <div className="mt-4 flex gap-4 border-b border-slate-200">
                    <button
                        onClick={() => setActiveTab('import')}
                        className={`px-4 py-2 font-medium ${
                            activeTab === 'import'
                                ? 'text-primary-600 border-b-2 border-primary-600'
                                : 'text-slate-600 hover:text-slate-900'
                        }`}
                    >
                        数据导入
                    </button>
                    <button
                        onClick={() => setActiveTab('history')}
                        className={`px-4 py-2 font-medium ${
                            activeTab === 'history'
                                ? 'text-primary-600 border-b-2 border-primary-600'
                                : 'text-slate-600 hover:text-slate-900'
                        }`}
                    >
                        <History className="w-4 h-4 inline-block mr-2" />
                        导入历史
                    </button>
                </div>
            </div>

            {/* Content */}
            <div className="flex-1 overflow-auto p-6">
                {activeTab === 'import' ? (
                    <div className="max-w-6xl mx-auto space-y-6">
                        {/* 合规警告提示 - P0级别 */}
                        <div className="bg-amber-50 border-2 border-amber-300 rounded-lg p-4">
                            <div className="flex items-start gap-3">
                                <AlertCircle className="w-6 h-6 text-amber-600 mt-0.5 flex-shrink-0" />
                                <div className="flex-1">
                                    <h3 className="font-semibold text-amber-900 mb-2">
                                        ⚠️ 合规说明（重要）
                                    </h3>
                                    <div className="text-sm text-amber-800 space-y-2">
                                        <p className="font-medium">
                                            本功能<strong>仅适用于历史数据迁移场景</strong>，不适用于新档案的正式归档。
                                        </p>
                                        <div className="bg-white rounded p-3 border border-amber-200">
                                            <p className="mb-2"><strong>适用范围：</strong></p>
                                            <ul className="list-disc list-inside space-y-1 ml-2 text-xs">
                                                <li>✅ 系统迁移：从旧系统迁移历史数据到新系统</li>
                                                <li>✅ 历史元数据补录：电子文件已通过其他方式完成归档和四性检测</li>
                                                <li>❌ 新档案归档：请使用标准归档流程（包含四性检测）</li>
                                            </ul>
                                        </div>
                                        <p className="text-xs text-amber-700 mt-2">
                                            <strong>合规要求：</strong>根据GB/T 39362-2020，电子会计档案归档时必须进行四性检测（完整性、真实性、可用性、安全性）。
                                            通过本功能导入的数据<strong>仅包含元数据</strong>，如需归档电子文件，请使用标准归档流程或后续补充文件关联。
                                        </p>
                                    </div>
                                </div>
                            </div>
                        </div>

                        {/* 导入指南说明 */}
                        <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
                            <div className="flex items-start gap-3">
                                <Info className="w-5 h-5 text-blue-600 mt-0.5 flex-shrink-0" />
                                <div className="flex-1">
                                    <div className="flex items-center justify-between mb-2">
                                        <h3 className="font-medium text-blue-900">导入说明</h3>
                                        <button
                                            onClick={() => setShowGuideDetail(!showGuideDetail)}
                                            className="text-blue-600 hover:text-blue-800 flex items-center gap-1 text-sm"
                                        >
                                            {showGuideDetail ? (
                                                <>
