// Input: React、lucide-react 图标、本地模块 api/admin
// Output: React 组件 PositionManagement
// Pos: src/pages/admin/PositionManagement.tsx
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useEffect, useState } from 'react';
import { adminApi } from '../../api/admin';
import { AlertTriangle, Loader2, Plus, Trash2, Edit3 } from 'lucide-react';

interface Position {
  id: string;
  name: string;
  code: string;
  departmentId?: string;
  description?: string;
  status?: string;
  createdAt?: string;
}

export const PositionManagement: React.FC = () => {
  const [positions, setPositions] = useState<Position[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<Position | null>(null);
  const [form, setForm] = useState<Partial<Position>>({
    name: '',
    code: '',
    departmentId: '',
    description: '',
    status: 'active'
  });

  const loadData = async () => {
    setLoading(true);
    setError(null);
    try {
      const res = await adminApi.getPositions({ page: 1, limit: 50 });
      if (res.code === 200 && res.data) {
        setPositions((res.data as any).records || []);
      } else {
        setError(res.message || '加载岗位数据失败');
      }
    } catch {
      setError('加载岗位数据失败');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const openCreate = () => {
    setEditing(null);
    setForm({ name: '', code: '', departmentId: '', description: '', status: 'active' });
    setModalOpen(true);
  };

  const openEdit = (p: Position) => {
    setEditing(p);
    setForm(p);
    setModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.name || !form.code) {
      setError('名称和编码必填');
      return;
    }
    try {
      if (editing) {
        await adminApi.updatePosition({ ...form, id: editing.id });
      } else {
        await adminApi.createPosition(form);
      }
      setModalOpen(false);
      loadData();
    } catch (err: any) {
      setError(err?.response?.data?.message || '保存失败');
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm('确定删除该岗位？')) return;
    try {
      await adminApi.deletePosition(id);
      loadData();
    } catch (err: any) {
      setError(err?.response?.data?.message || '删除失败');
    }
  };

  return (
    <div className="bg-white rounded-2xl border border-slate-200 shadow-sm p-6 space-y-4">
      <div className="flex items-center justify-between">
        <div>
          <h3 className="text-xl font-bold text-slate-800">岗位管理</h3>
          <p className="text-sm text-slate-500">维护部门岗位，辅助角色与人员管理</p>
        </div>
        <button
          onClick={openCreate}
          className="px-3 py-2 bg-primary-600 text-white rounded-lg text-sm font-semibold hover:bg-primary-700 flex items-center gap-2"
        >
          <Plus size={16} /> 新建岗位
        </button>
      </div>

      {error && (
        <div className="bg-rose-50 border border-rose-200 text-rose-700 px-4 py-2 rounded-lg text-sm flex items-center gap-2">
          <AlertTriangle size={16} /> {error}
        </div>
      )}

      {loading ? (
        <div className="flex items-center gap-2 text-slate-500 text-sm">
          <Loader2 className="animate-spin" size={16} /> 加载中...
        </div>
      ) : positions.length === 0 ? (
        <div className="text-slate-400 text-sm">暂无岗位，请新建。</div>
      ) : (
        <div className="overflow-x-auto">
          <table className="min-w-full text-sm text-slate-700">
            <thead className="bg-slate-50 text-xs text-slate-500 uppercase">
              <tr>
                <th className="px-3 py-2 text-left">名称</th>
                <th className="px-3 py-2 text-left">编码</th>
                <th className="px-3 py-2 text-left">所属部门</th>
                <th className="px-3 py-2 text-left">状态</th>
                <th className="px-3 py-2 text-left">描述</th>
                <th className="px-3 py-2 text-right">操作</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {positions.map((p) => (
                <tr key={p.id} className="hover:bg-slate-50">
                  <td className="px-3 py-2 font-medium text-slate-800">{p.name}</td>
                  <td className="px-3 py-2 font-mono text-slate-600">{p.code}</td>
                  <td className="px-3 py-2 text-slate-600">{p.departmentId || '-'}</td>
                  <td className="px-3 py-2">
                    <span className={`px-2 py-1 text-xs rounded-full border ${p.status === 'disabled'
                      ? 'bg-slate-100 text-slate-500 border-slate-200'
                      : 'bg-emerald-50 text-emerald-700 border-emerald-100'}`}>
                      {p.status === 'disabled' ? '禁用' : '启用'}
                    </span>
                  </td>
                  <td className="px-3 py-2 text-slate-500">{p.description || '-'}</td>
                  <td className="px-3 py-2 text-right space-x-2">
                    <button onClick={() => openEdit(p)} className="text-primary-600 hover:text-primary-700 text-xs inline-flex items-center gap-1">
                      <Edit3 size={14} /> 编辑
                    </button>
                    <button onClick={() => handleDelete(p.id)} className="text-rose-600 hover:text-rose-700 text-xs inline-flex items-center gap-1">
                      <Trash2 size={14} /> 删除
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {modalOpen && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg border border-slate-100">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center">
              <h4 className="text-lg font-bold text-slate-800">{editing ? '编辑岗位' : '新建岗位'}</h4>
              <button onClick={() => setModalOpen(false)} className="text-slate-400 hover:text-slate-600">✕</button>
            </div>
            <form onSubmit={handleSubmit} className="p-5 space-y-4">
              <div>
                <label className="text-sm font-medium text-slate-700">名称</label>
                <input
                  className="w-full border border-slate-300 rounded-lg px-3 py-2 text-sm"
                  value={form.name || ''}
                  onChange={(e) => setForm({ ...form, name: e.target.value })}
                  required
                />
              </div>
              <div>
                <label className="text-sm font-medium text-slate-700">编码</label>
                <input
                  className="w-full border border-slate-300 rounded-lg px-3 py-2 text-sm"
                  value={form.code || ''}
                  onChange={(e) => setForm({ ...form, code: e.target.value })}
                  required
                />
              </div>
              <div>
                <label className="text-sm font-medium text-slate-700">所属部门 ID</label>
                <input
                  className="w-full border border-slate-300 rounded-lg px-3 py-2 text-sm"
                  value={form.departmentId || ''}
                  onChange={(e) => setForm({ ...form, departmentId: e.target.value })}
                  placeholder="可选"
                />
              </div>
              <div>
                <label className="text-sm font-medium text-slate-700">描述</label>
                <textarea
                  className="w-full border border-slate-300 rounded-lg px-3 py-2 text-sm"
                  value={form.description || ''}
                  onChange={(e) => setForm({ ...form, description: e.target.value })}
                  rows={2}
                />
              </div>
              <div>
                <label className="text-sm font-medium text-slate-700">状态</label>
                <select
                  className="w-full border border-slate-300 rounded-lg px-3 py-2 text-sm"
                  value={form.status || 'active'}
                  onChange={(e) => setForm({ ...form, status: e.target.value })}
                >
                  <option value="active">启用</option>
                  <option value="disabled">禁用</option>
                </select>
              </div>
              <div className="flex justify-end gap-2 pt-2">
                <button type="button" onClick={() => setModalOpen(false)} className="px-4 py-2 text-slate-600">取消</button>
                <button type="submit" className="px-4 py-2 bg-primary-600 text-white rounded-lg">{editing ? '保存' : '创建'}</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

// Input: React、lucide-react、userLifecycleApi
// Output: UserLifecyclePage 组件
// Pos: 用户生命周期管理页面
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useState, useEffect } from 'react';
import { Users, Loader2, CheckCircle2, XCircle, UserPlus, UserMinus, UserCog, AlertCircle } from 'lucide-react';
import { userLifecycleApi, OnboardRequest, OffboardRequest, TransferRequest } from '../../api/userLifecycle';
import { OrgSelector } from '../../components/org';
import { OrgNode } from '../../types';
import { useAdminSettingsApi } from '../../features/settings';

/**
 * 用户生命周期管理页面
 * 
 * 功能：
 * 1. 入职触发：选择员工、自动创建账号、分配角色
 * 2. 离职触发：选择员工、停用账号、回收权限
 * 3. 调岗触发：选择员工、调整角色和权限
 * 
 * PRD 来源: Section 4.2 - 用户生命周期管理
 */
export const UserLifecyclePage: React.FC = () => {
    const { adminApi } = useAdminSettingsApi();
    const [activeTab, setActiveTab] = useState<'onboard' | 'offboard' | 'transfer'>('onboard');
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

    // 组织架构数据
    const [orgTree, setOrgTree] = useState<OrgNode[]>([]);
    const [orgLoading, setOrgLoading] = useState(false);

    // 入职表单
    const [onboardForm, setOnboardForm] = useState<OnboardRequest>({
        employeeId: '',
        roleIds: [],
        organizationId: '', // 新增：组织ID
    });

    // 离职表单
    const [offboardForm, setOffboardForm] = useState<OffboardRequest>({
        employeeId: '',
        reason: '',
    });

    // 调岗表单
    const [transferForm, setTransferForm] = useState<TransferRequest>({
        employeeId: '',
        newRoleIds: [],
        reason: '',
        toOrganizationId: '', // 新增：目标组织ID
    });

    // 加载组织架构数据
    useEffect(() => {
        const loadOrgTree = async () => {
            setOrgLoading(true);
            try {
                const res = await adminApi.getOrgTree();
                if (res.code === 200 && res.data) {
                    setOrgTree(res.data);
                }
            } catch (error) {
                console.error('加载组织架构失败', error);
            } finally {
                setOrgLoading(false);
            }
        };
        loadOrgTree();
    }, [adminApi]);

    // 注意：这里需要集成员工选择器和角色选择器
    // 由于没有现成的API，这里使用模拟数据
    const mockEmployees = [
        { id: '1', name: '张三' },
        { id: '2', name: '李四' },
        { id: '3', name: '王五' },
    ];

    const mockRoles = [
        { id: '1', name: '档案管理员' },
        { id: '2', name: '财务人员' },
        { id: '3', name: '审计人员' },
    ];

    const handleOnboard = async () => {
        if (!onboardForm.employeeId || onboardForm.roleIds.length === 0) {
            setMessage({ type: 'error', text: '请选择员工和至少一个角色' });
            return;
        }

        if (!onboardForm.organizationId) {
            setMessage({ type: 'error', text: '请选择目标组织' });
            return;
        }

        setLoading(true);
        try {
            const res = await userLifecycleApi.onboard(onboardForm);
            if (res.code === 200) {
                setMessage({ type: 'success', text: `账号创建成功：${res.data?.username || ''}` });
                setOnboardForm({ employeeId: '', roleIds: [], organizationId: '' });
            } else {
                setMessage({ type: 'error', text: res.message || '入职处理失败' });
            }
        } catch (error: any) {
            setMessage({ type: 'error', text: error?.response?.data?.message || '入职处理失败' });
        } finally {
            setLoading(false);
        }
    };

    const handleOffboard = async () => {
        if (!offboardForm.employeeId) {
            setMessage({ type: 'error', text: '请选择员工' });
            return;
        }

        if (!window.confirm('确认执行离职处理吗？账号将被停用，权限将被回收。')) {
            return;
        }

        setLoading(true);
        try {
            const res = await userLifecycleApi.offboard(offboardForm);
            if (res.code === 200) {
                setMessage({ type: 'success', text: '离职处理成功' });
                setOffboardForm({ employeeId: '', reason: '' });
            } else {
                setMessage({ type: 'error', text: res.message || '离职处理失败' });
            }
        } catch (error: any) {
            setMessage({ type: 'error', text: error?.response?.data?.message || '离职处理失败' });
        } finally {
            setLoading(false);
        }
    };

    const handleTransfer = async () => {
        if (!transferForm.employeeId || transferForm.newRoleIds.length === 0) {
            setMessage({ type: 'error', text: '请选择员工和至少一个角色' });
            return;
        }

        if (!transferForm.toOrganizationId) {
            setMessage({ type: 'error', text: '请选择目标组织' });
            return;
        }

        setLoading(true);
        try {
            const res = await userLifecycleApi.transfer(transferForm);
            if (res.code === 200) {
                setMessage({ type: 'success', text: '调岗处理成功' });
                setTransferForm({ employeeId: '', newRoleIds: [], reason: '', toOrganizationId: '' });
            } else {
                setMessage({ type: 'error', text: res.message || '调岗处理失败' });
            }
        } catch (error: any) {
            setMessage({ type: 'error', text: error?.response?.data?.message || '调岗处理失败' });
        } finally {
            setLoading(false);
        }
    };

    const toggleRole = (roleId: string, roleIds: string[], setRoleIds: (ids: string[]) => void) => {
        if (roleIds.includes(roleId)) {
            setRoleIds(roleIds.filter(id => id !== roleId));
        } else {
            setRoleIds([...roleIds, roleId]);
        }
    };

    return (
        <div className="p-6 space-y-6">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-2xl font-bold text-slate-800 flex items-center">
                        <Users className="mr-2" size={28} />
                        用户生命周期管理
                    </h2>
                    <p className="text-slate-500 text-sm mt-1">管理用户入职、离职和调岗流程</p>
                </div>
            </div>

            {/* 消息提示 */}
            {message && (
                <div className={`p-4 rounded-lg flex items-center gap-2 ${
                    message.type === 'success' 
                        ? 'bg-green-50 text-green-800 border border-green-200' 
                        : 'bg-red-50 text-red-800 border border-red-200'
                }`}>
                    {message.type === 'success' ? (
                        <CheckCircle2 size={20} />
                    ) : (
                        <XCircle size={20} />
                    )}
                    <span>{message.text}</span>
                    <button
                        onClick={() => setMessage(null)}
                        className="ml-auto text-slate-400 hover:text-slate-600"
                    >
                        ×
                    </button>
                </div>
            )}

            {/* 标签页 */}
            <div className="bg-white border border-slate-200 rounded-lg">
                <div className="flex border-b border-slate-200">
                    <button
                        onClick={() => setActiveTab('onboard')}
                        className={`px-6 py-3 font-medium ${
                            activeTab === 'onboard'
                                ? 'text-primary-600 border-b-2 border-primary-600'
                                : 'text-slate-600 hover:text-slate-900'
                        }`}
                    >
                        <UserPlus className="inline mr-2" size={18} />
                        入职
                    </button>
                    <button
                        onClick={() => setActiveTab('offboard')}
                        className={`px-6 py-3 font-medium ${
                            activeTab === 'offboard'
                                ? 'text-primary-600 border-b-2 border-primary-600'
                                : 'text-slate-600 hover:text-slate-900'
                        }`}
                    >
                        <UserMinus className="inline mr-2" size={18} />
                        离职
                    </button>
                    <button
                        onClick={() => setActiveTab('transfer')}
                        className={`px-6 py-3 font-medium ${
                            activeTab === 'transfer'
                                ? 'text-primary-600 border-b-2 border-primary-600'
                                : 'text-slate-600 hover:text-slate-900'
                        }`}
                    >
                        <UserCog className="inline mr-2" size={18} />
                        调岗
                    </button>
                </div>

                <div className="p-6">
                    {/* 入职表单 */}
                    {activeTab === 'onboard' && (
                        <div className="space-y-6 max-w-2xl">
                            <div>
                                <h3 className="text-lg font-semibold mb-4">员工入职</h3>
                                <p className="text-sm text-slate-600 mb-4">
                                    选择员工后，系统将自动创建用户账号并分配指定角色
                                </p>
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-2">
                                    选择员工 <span className="text-red-500">*</span>
                                </label>
                                <select
                                    value={onboardForm.employeeId}
                                    onChange={(e) => setOnboardForm({ ...onboardForm, employeeId: e.target.value })}
                                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                                >
                                    <option value="">请选择员工</option>
                                    {mockEmployees.map(emp => (
                                        <option key={emp.id} value={emp.id}>{emp.name}</option>
                                    ))}
                                </select>
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-2">
                                    选择组织 <span className="text-red-500">*</span>
                                </label>
                                {orgLoading ? (
                                    <div className="flex items-center justify-center py-8 text-slate-500">
                                        <Loader2 className="animate-spin mr-2" size={16} />
                                        加载组织架构...
                                    </div>
                                ) : (
                                    <OrgSelector
                                        orgTree={orgTree}
                                        value={onboardForm.organizationId}
                                        onChange={(value) => setOnboardForm({ ...onboardForm, organizationId: value as string })}
                                        multiple={false}
                                        placeholder="请选择目标组织"
                                        className="mb-4"
                                    />
                                )}
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-2">
                                    分配角色 <span className="text-red-500">*</span>
                                </label>
                                <div className="space-y-2">
                                    {mockRoles.map(role => (
                                        <label key={role.id} className="flex items-center gap-2 p-3 border border-slate-200 rounded-lg hover:bg-slate-50 cursor-pointer">
                                            <input
                                                type="checkbox"
                                                checked={onboardForm.roleIds.includes(role.id)}
                                                onChange={() => toggleRole(role.id, onboardForm.roleIds, (ids) => setOnboardForm({ ...onboardForm, roleIds: ids }))}
                                                className="w-4 h-4 text-primary-600 border-slate-300 rounded focus:ring-primary-500"
                                            />
                                            <span>{role.name}</span>
                                        </label>
                                    ))}
                                </div>
                            </div>
                            <button
                                onClick={handleOnboard}
                                disabled={loading}
                                className="px-6 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
                            >
                                {loading ? <Loader2 className="animate-spin" size={16} /> : <UserPlus size={16} />}
                                执行入职
                            </button>
                        </div>
                    )}

                    {/* 离职表单 */}
                    {activeTab === 'offboard' && (
                        <div className="space-y-6 max-w-2xl">
                            <div>
                                <h3 className="text-lg font-semibold mb-4">员工离职</h3>
                                <div className="p-4 bg-yellow-50 border border-yellow-200 rounded-lg flex items-start gap-3 mb-4">
                                    <AlertCircle className="text-yellow-600 flex-shrink-0 mt-0.5" size={20} />
                                    <div className="text-sm text-yellow-800">
                                        <div className="font-semibold mb-1">注意</div>
                                        <div>执行离职后，用户账号将被停用，所有权限将被回收，此操作不可逆。</div>
                                    </div>
                                </div>
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-2">
                                    选择员工 <span className="text-red-500">*</span>
                                </label>
                                <select
                                    value={offboardForm.employeeId}
                                    onChange={(e) => setOffboardForm({ ...offboardForm, employeeId: e.target.value })}
                                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                                >
                                    <option value="">请选择员工</option>
                                    {mockEmployees.map(emp => (
                                        <option key={emp.id} value={emp.id}>{emp.name}</option>
                                    ))}
                                </select>
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-2">
                                    离职原因
                                </label>
                                <textarea
                                    value={offboardForm.reason}
                                    onChange={(e) => setOffboardForm({ ...offboardForm, reason: e.target.value })}
                                    rows={4}
                                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                                    placeholder="请输入离职原因..."
                                />
                            </div>
                            <button
                                onClick={handleOffboard}
                                disabled={loading}
                                className="px-6 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
                            >
                                {loading ? <Loader2 className="animate-spin" size={16} /> : <UserMinus size={16} />}
                                执行离职
                            </button>
                        </div>
                    )}

                    {/* 调岗表单 */}
                    {activeTab === 'transfer' && (
                        <div className="space-y-6 max-w-2xl">
                            <div>
                                <h3 className="text-lg font-semibold mb-4">员工调岗</h3>
                                <p className="text-sm text-slate-600 mb-4">
                                    调整员工角色和权限，旧角色将被替换为新角色
                                </p>
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-2">
                                    选择员工 <span className="text-red-500">*</span>
                                </label>
                                <select
                                    value={transferForm.employeeId}
                                    onChange={(e) => setTransferForm({ ...transferForm, employeeId: e.target.value })}
                                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                                >
                                    <option value="">请选择员工</option>
                                    {mockEmployees.map(emp => (
                                        <option key={emp.id} value={emp.id}>{emp.name}</option>
                                    ))}
                                </select>
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-2">
                                    选择目标组织 <span className="text-red-500">*</span>
                                </label>
                                {orgLoading ? (
                                    <div className="flex items-center justify-center py-8 text-slate-500">
                                        <Loader2 className="animate-spin mr-2" size={16} />
                                        加载组织架构...
                                    </div>
                                ) : (
                                    <OrgSelector
                                        orgTree={orgTree}
                                        value={transferForm.toOrganizationId}
                                        onChange={(value) => setTransferForm({ ...transferForm, toOrganizationId: value as string })}
                                        multiple={false}
                                        placeholder="请选择目标组织"
                                        className="mb-4"
                                    />
                                )}
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-2">
                                    新角色 <span className="text-red-500">*</span>
                                </label>
                                <div className="space-y-2">
                                    {mockRoles.map(role => (
                                        <label key={role.id} className="flex items-center gap-2 p-3 border border-slate-200 rounded-lg hover:bg-slate-50 cursor-pointer">
                                            <input
                                                type="checkbox"
                                                checked={transferForm.newRoleIds.includes(role.id)}
                                                onChange={() => toggleRole(role.id, transferForm.newRoleIds, (ids) => setTransferForm({ ...transferForm, newRoleIds: ids }))}
                                                className="w-4 h-4 text-primary-600 border-slate-300 rounded focus:ring-primary-500"
                                            />
                                            <span>{role.name}</span>
                                        </label>
                                    ))}
                                </div>
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-2">
                                    调岗原因
                                </label>
                                <textarea
                                    value={transferForm.reason}
                                    onChange={(e) => setTransferForm({ ...transferForm, reason: e.target.value })}
                                    rows={4}
                                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                                    placeholder="请输入调岗原因..."
                                />
                            </div>
                            <button
                                onClick={handleTransfer}
                                disabled={loading}
                                className="px-6 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
                            >
                                {loading ? <Loader2 className="animate-spin" size={16} /> : <UserCog size={16} />}
                                执行调岗
                            </button>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

