        <div className="flex items-center justify-center h-64 text-slate-400">
          <p>{isLoading ? '加载中...' : '暂无凭证数据'}</p>
        </div>
      ),
    },
    {
      key: 'attachments',
      label: `关联附件${archiveAttachments.length > 0 ? ` (${archiveAttachments.length})` : ''}`,
      children: (
        <div className="p-6">
          {attachmentsLoading ? (
            <div className="flex items-center justify-center h-64 text-slate-400">
