          ) : (
            <div className="flex items-center justify-center h-64 text-slate-400">
              <p>暂无附件</p>
            </div>
          )}
        </div>
      ),
    },
  ];

  return (
    <div className="min-h-screen bg-slate-50" data-archive-id={id}>
      {/* Header */}
      <div className="bg-white border-b border-slate-200 sticky top-0 z-10">
