import React, { useState, useEffect, useCallback } from 'react';
import {
    ShieldCheck,
    ShieldAlert,
    ShieldX,
    FileText,
    Download,
    ChevronLeft,
    CheckCircle2,
    AlertTriangle,
    XCircle,
    Hash
} from 'lucide-react';
import { ApiResponse } from '../../types';
import { client } from '../../api/client';

interface ComplianceReportViewProps {
    archiveId: string;
    onBack: () => void;
}

interface ComplianceResult {
    archiveId: string;
    archiveCode: string;
    complianceLevel: '完全合规' | '合规但有警告' | '不合规';
    violationCount: number;
    warningCount: number;
    violations: string[];
    warnings: string[];
}

export const ComplianceReportView: React.FC<ComplianceReportViewProps> = ({ archiveId, onBack }) => {
    const [loading, setLoading] = useState(true);
    const [result, setResult] = useState<ComplianceResult | null>(null);
    const [error, setError] = useState<string | null>(null);

    const fetchData = useCallback(async () => {
        try {
            setLoading(true);
            // Fetch compliance result
            const response = await client.get<ApiResponse<ComplianceResult>>(`/compliance/archives/${archiveId}`);
            const res = response.data;

            if (res && res.code === 200) {
                setResult(res.data);
            } else {
                setError(res.message || 'Unknown error');
            }

            // Fetch archive info (optional, for display)
            // For now we might just use what is in the report or fetch separately if needed
            // const archiveRes = await get(`/api/archives/${archiveId}`);

        } catch (err: any) {
            setError(err.message || '获取合规性报告失败');
        } finally {
            setLoading(false);
        }
    }, [archiveId]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const handleExport = async (format: 'xml' | 'json') => {
        try {
            const response = await client.get<ApiResponse<string>>(`/compliance/archives/${archiveId}/report?format=${format}`);
            const res = response.data;
            if (res && res.code === 200) {
                // Trigger download
                const blob = new Blob([res.data], { type: format === 'json' ? 'application/json' : 'text/xml' });
                const url = window.URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = `compliance_report_${archiveId}.${format}`;
                document.body.appendChild(a);
                a.click();
                window.URL.revokeObjectURL(url);
                document.body.removeChild(a);
            }
        } catch (err) {
            console.error('Export failed', err);
        }
    };

    const getStatusColor = (level?: string) => {
        if (level === '完全合规') return 'text-green-600 bg-green-50 border-green-200';
        if (level === '合规但有警告') return 'text-yellow-600 bg-yellow-50 border-yellow-200';
        return 'text-red-600 bg-red-50 border-red-200';
    };

    const getStatusIcon = (level?: string) => {
        if (level === '完全合规') return <ShieldCheck className="w-16 h-16 text-green-500" />;
        if (level === '合规但有警告') return <ShieldAlert className="w-16 h-16 text-yellow-500" />;
        return <ShieldX className="w-16 h-16 text-red-500" />;
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center h-full">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600"></div>
            </div>
        );
    }

    if (error) {
        return (
            <div className="p-8 text-center text-red-600">
                <AlertTriangle className="w-12 h-12 mx-auto mb-4" />
                <p>{error}</p>
                <button onClick={onBack} className="mt-4 text-indigo-600 hover:underline">返回</button>
            </div>
        );
    }

    if (!result) return null;

    return (
        <div className="p-6 max-w-7xl mx-auto space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div className="flex items-center space-x-4">
                    <button
                        onClick={onBack}
                        className="p-2 hover:bg-slate-100 rounded-lg transition-colors"
                    >
                        <ChevronLeft className="w-6 h-6 text-slate-600" />
                    </button>
                    <div>
                        <h1 className="text-2xl font-bold text-slate-900">《会计档案管理办法》符合性检查报告</h1>
                        <p className="text-slate-500 mt-1">检测依据：DA/T 94-2022 电子会计档案管理规范</p>
                    </div>
                </div>
                <div className="flex space-x-3">
                    <button
                        onClick={() => handleExport('xml')}
                        className="flex items-center px-4 py-2 bg-white border border-slate-200 rounded-lg text-slate-700 hover:bg-slate-50"
                    >
                        <FileText className="w-4 h-4 mr-2" />
                        导出 XML
                    </button>
                    <button
                        onClick={() => handleExport('json')}
                        className="flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700"
                    >
                        <Download className="w-4 h-4 mr-2" />
                        导出 JSON
                    </button>
                </div>
            </div>

            {/* Overview Card */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-8">
                <div className="flex items-start justify-between">
                    <div className="flex-1">
                        <div className="flex items-center space-x-2 mb-6">
                            <span className={`px-4 py-1.5 rounded-full text-sm font-semibold border ${getStatusColor(result.complianceLevel)}`}>
                                {result.complianceLevel}
                            </span>
                            <span className="text-sm text-slate-500">检测时间：{new Date().toLocaleString()}</span>
                        </div>

                        <div className="grid grid-cols-2 gap-8">
                            <div>
                                <h3 className="text-sm font-medium text-slate-500 mb-4">档案信息</h3>
                                <div className="space-y-3">
                                    <div className="flex items-center text-slate-700">
                                        <Hash className="w-4 h-4 mr-2 text-slate-400" />
                                        <span className="font-mono">{result.archiveCode || '未生成档号'}</span>
                                    </div>
                                </div>
                            </div>
                            <div>
                                <h3 className="text-sm font-medium text-slate-500 mb-4">检测统计</h3>
                                <div className="flex space-x-8">
                                    <div className="text-center">
                                        <div className="text-2xl font-bold text-red-600">{result.violationCount}</div>
                                        <div className="text-xs text-slate-500">违规项</div>
                                    </div>
                                    <div className="text-center">
                                        <div className="text-2xl font-bold text-yellow-600">{result.warningCount}</div>
                                        <div className="text-xs text-slate-500">警告项</div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="ml-12">
                        {getStatusIcon(result.complianceLevel)}
                    </div>
                </div>
            </div>

            {/* Violations */}
            {result.violations.length > 0 && (
                <div className="bg-white rounded-xl shadow-sm border border-red-200 overflow-hidden">
                    <div className="px-6 py-4 bg-red-50 border-b border-red-100 flex items-center">
                        <XCircle className="w-5 h-5 text-red-600 mr-2" />
                        <h3 className="font-semibold text-red-900">违规项 (必须修复)</h3>
                    </div>
                    <div className="divide-y divide-red-100">
                        {result.violations.map((v, i) => (
                            <div key={i} className="px-6 py-4 text-slate-700 flex items-start">
                                <span className="text-red-500 font-mono mr-3">{i + 1}.</span>
                                {v}
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* Warnings */}
            {result.warnings.length > 0 && (
                <div className="bg-white rounded-xl shadow-sm border border-yellow-200 overflow-hidden">
                    <div className="px-6 py-4 bg-yellow-50 border-b border-yellow-100 flex items-center">
                        <AlertTriangle className="w-5 h-5 text-yellow-600 mr-2" />
                        <h3 className="font-semibold text-yellow-900">警告项 (建议优化)</h3>
                    </div>
                    <div className="divide-y divide-yellow-100">
                        {result.warnings.map((w, i) => (
                            <div key={i} className="px-6 py-4 text-slate-700 flex items-start">
                                <span className="text-yellow-500 font-mono mr-3">{i + 1}.</span>
                                {w}
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* Safe Items (Mock) */}
            <div className="bg-white rounded-xl shadow-sm border border-green-200 overflow-hidden">
                <div className="px-6 py-4 bg-green-50 border-b border-green-100 flex items-center">
                    <CheckCircle2 className="w-5 h-5 text-green-600 mr-2" />
                    <h3 className="font-semibold text-green-900">已通过检测项</h3>
                </div>
                <div className="p-6 grid grid-cols-2 gap-4 text-sm text-slate-600">
                    <div className="flex items-center"><CheckCircle2 className="w-4 h-4 text-green-500 mr-2" /> 档案四性检测 (真实性、完整性、可用性、安全性)</div>
                    <div className="flex items-center"><CheckCircle2 className="w-4 h-4 text-green-500 mr-2" /> 数据来源可靠性验证</div>
                    <div className="flex items-center"><CheckCircle2 className="w-4 h-4 text-green-500 mr-2" /> 电子会计凭证元数据结构</div>
                    <div className="flex items-center"><CheckCircle2 className="w-4 h-4 text-green-500 mr-2" /> 关联文件数量一致性</div>
                </div>
            </div>
        </div>
    );
};

export default ComplianceReportView;

// Input: React, Lucide Icons, originalVoucher API
// Output: CreateOriginalVoucherDialog 组件
// Pos: src/pages/archives/CreateOriginalVoucherDialog.tsx
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useState, useRef } from 'react';
import { X, Upload, FileText, AlertCircle, Loader2 } from 'lucide-react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { useNavigate } from 'react-router-dom';
import { createOriginalVoucher, addOriginalVoucherFile, getOriginalVoucherTypes } from '../../api/originalVoucher';
import { useFondsStore } from '../../store/useFondsStore';

interface CreateOriginalVoucherDialogProps {
    isOpen: boolean;
    onClose: () => void;
    onSuccess?: () => void;
    initialType?: string;
    category?: string;
}

export const CreateOriginalVoucherDialog: React.FC<CreateOriginalVoucherDialogProps> = ({
    isOpen,
    onClose,
    onSuccess,
    initialType,
    category
}) => {
    const navigate = useNavigate();
    const queryClient = useQueryClient();
    const fileInputRef = useRef<HTMLInputElement>(null);
    const currentFonds = useFondsStore((state) => state.currentFonds);

    // Form State
    const [voucherType, setVoucherType] = useState(initialType || '');
    const [amount, setAmount] = useState('');
    const [summary, setSummary] = useState('');
    const [file, setFile] = useState<File | null>(null);
    const [error, setError] = useState('');

    // Fetch types
    const { data: voucherTypes = [] } = useQuery({
        queryKey: ['originalVoucherTypes'],
        queryFn: getOriginalVoucherTypes,
        enabled: isOpen
    });

    const createMutation = useMutation({
        mutationFn: async () => {
            // 1. Create Voucher
            // Find category from selected type
            const selectedTypeObj = voucherTypes.find(t => t.typeCode === voucherType);
            const derivedCategory = selectedTypeObj?.categoryCode;

            const newVoucher = await createOriginalVoucher({
                voucherType,
                amount: amount ? parseFloat(amount) : undefined,
                summary,
                // Use prop category if present, otherwise use derived category, finally fallback to OTHER
                // Note: If both exist but mismatch, backend will catch it, but usually UI filters types if category is fixed.
                voucherCategory: category || derivedCategory || 'OTHER',
                currency: 'CNY',
                fondsCode: currentFonds?.fondsCode ?? '001',
                fiscalYear: new Date().getFullYear().toString()
            });

            // 2. Upload File if selected
            if (file && newVoucher.id) {
                await addOriginalVoucherFile(newVoucher.id, file, 'ORIGINAL');
            }
            return newVoucher;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['originalVouchers'] });
            if (onSuccess) onSuccess();
            onClose();
        },
        onError: (err: any) => {
            setError(err.message || '创建失败');
        }
    });

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!voucherType) {
            setError('请选择凭证类型');
            return;
        }
        createMutation.mutate();
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            setFile(e.target.files[0]);
        }
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-4 animate-in fade-in duration-200">
            <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-2xl w-full max-w-lg border border-slate-100 dark:border-gray-700">
                {/* Header */}
                <div className="p-6 border-b border-slate-100 dark:border-gray-700 flex justify-between items-center bg-slate-50/50 dark:bg-gray-800/50 rounded-t-2xl">
                    <div>
                        <h3 className="text-lg font-bold text-slate-800 dark:text-white">新建原始凭证</h3>
                        <p className="text-sm text-slate-500 dark:text-gray-400 mt-1">手动录入凭证元数据并上传扫描件</p>
                    </div>
                    <button onClick={onClose}><X size={20} className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200" /></button>
                </div>

                {/* Body */}
                <form onSubmit={handleSubmit} className="p-6 space-y-5">
                    {error && (
                        <div className="bg-red-50 text-red-600 p-3 rounded-lg text-sm flex items-center gap-2">
                            <AlertCircle size={16} />
                            {error}
                        </div>
                    )}

                    {/* Type Selection */}
                    <div>
                        <label className="block text-sm font-medium text-slate-700 dark:text-gray-300 mb-1">凭证类型 <span className="text-red-500">*</span></label>
                        <select
                            className="w-full border border-slate-300 dark:border-gray-600 rounded-lg px-3 py-2 text-sm bg-white dark:bg-gray-700 text-slate-900 dark:text-white focus:ring-2 focus:ring-blue-500 outline-none"
                            value={voucherType}
                            onChange={(e) => setVoucherType(e.target.value)}
                        >
                            <option value="">请选择类型</option>
                            {voucherTypes.map(type => (
                                <option key={type.typeCode} value={type.typeCode}>{type.typeName}</option>
                            ))}
                        </select>
                    </div>

                    {/* Amount */}
                    <div>
                        <label className="block text-sm font-medium text-slate-700 dark:text-gray-300 mb-1">金额 (元)</label>
                        <input
                            type="number"
                            step="0.01"
                            className="w-full border border-slate-300 dark:border-gray-600 rounded-lg px-3 py-2 text-sm bg-white dark:bg-gray-700 text-slate-900 dark:text-white focus:ring-2 focus:ring-blue-500 outline-none"
                            placeholder="0.00"
                            value={amount}
                            onChange={(e) => setAmount(e.target.value)}
                        />
                    </div>

                    {/* Summary */}
                    <div>
                        <label className="block text-sm font-medium text-slate-700 dark:text-gray-300 mb-1">摘要 / 说明</label>
                        <textarea
                            className="w-full border border-slate-300 dark:border-gray-600 rounded-lg px-3 py-2 text-sm bg-white dark:bg-gray-700 text-slate-900 dark:text-white focus:ring-2 focus:ring-blue-500 outline-none resize-none"
                            rows={3}
                            placeholder="请输入业务摘要..."
                            value={summary}
                            onChange={(e) => setSummary(e.target.value)}
                        />
                    </div>

                    {/* File Upload Area */}
                    <div>
                        <label className="block text-sm font-medium text-slate-700 dark:text-gray-300 mb-1">附件上传</label>
                        <div
                            className={`border-2 border-dashed rounded-xl p-6 flex flex-col items-center justify-center text-center cursor-pointer transition-colors ${file ? 'border-blue-500 bg-blue-50 dark:bg-blue-900/20' : 'border-slate-300 dark:border-gray-600 hover:border-blue-400'}`}
                            onClick={() => fileInputRef.current?.click()}
                        >
                            <input
                                type="file"
                                ref={fileInputRef}
                                className="hidden"
                                onChange={handleFileChange}
                                accept=".pdf,.ofd,.jpg,.jpeg,.png"
                            />

                            {file ? (
                                <div className="flex items-center gap-3 text-blue-600 dark:text-blue-400">
                                    <FileText size={24} />
                                    <span className="font-medium text-sm truncate max-w-[200px]">{file.name}</span>
                                    <button
                                        type="button"
                                        onClick={(e) => { e.stopPropagation(); setFile(null); }}
                                        className="text-slate-400 hover:text-red-500 ml-2"
                                    >
                                        <X size={16} />
                                    </button>
                                </div>
                            ) : (
                                <>
                                    <div className="w-10 h-10 rounded-full bg-slate-100 dark:bg-gray-700 flex items-center justify-center mb-2 text-slate-500 dark:text-gray-400">
                                        <Upload size={20} />
                                    </div>
                                    <p className="text-sm font-medium text-slate-700 dark:text-gray-300">点击上传或是拖拽文件</p>
                                    <p className="text-xs text-slate-500 dark:text-gray-500 mt-1">支持 PDF, OFD, JPG, PNG</p>
                                </>
                            )}
                        </div>
                    </div>

                    {/* Footer / Actions */}
                    <div className="pt-2 flex items-center justify-between">
                        <button
                            type="button"
                            onClick={() => { onClose(); navigate('/system/collection/upload'); }}
                            className="text-sm text-blue-600 hover:text-blue-700 hover:underline"
                        >
                            去批量上传 &rarr;
                        </button>

                        <div className="flex gap-3">
                            <button
                                type="button"
                                onClick={onClose}
                                className="px-4 py-2 text-sm text-slate-600 dark:text-gray-300 hover:bg-slate-100 dark:hover:bg-gray-700 rounded-lg transition"
                            >
                                取消
                            </button>
                            <button
                                type="submit"
                                disabled={createMutation.isPending}
                                className="px-4 py-2 text-sm bg-blue-600 hover:bg-blue-700 text-white rounded-lg shadow-sm shadow-blue-200 dark:shadow-none transition flex items-center gap-2 disabled:opacity-70 disabled:cursor-not-allowed"
                            >
                                {createMutation.isPending && <Loader2 size={16} className="animate-spin" />}
                                立即创建
                            </button>
                        </div>
                    </div>
                </form>
            </div>
        </div>
    );
};

// Input: React, Lucide Icons, Pool API
// Output: LinkModal 组件
// Pos: src/pages/archives/LinkModal.tsx
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useState, useEffect, useCallback } from 'react';
import { X, Search, Filter, Calendar, DollarSign, Loader2, Link as LinkIcon, FileText, User } from 'lucide-react';
import { poolApi, PoolItem } from '../../api/pool';

interface LinkModalProps {
    isOpen: boolean;
    onClose: () => void;
    selectedIds: string[];
    onToggleSelection: (id: string) => void;
    onConfirm: () => void;
    /** 当前正在关联的凭证对象，用于智能推荐 */
    linkingRow?: any;
}

const DEFAULT_SEARCH_FILTERS = {
    keyword: '',
    minAmount: '',
    maxAmount: '',
    startDate: '',
    endDate: '',
    invoiceNumber: ''
};

/**
 * 高级手动凭证关联模态框
 * 支持按金额、日期、发票号、供应商等维度进行精准搜索
 */
export const LinkModal: React.FC<LinkModalProps> = ({
    isOpen,
    onClose,
    selectedIds,
    onToggleSelection,
    onConfirm,
    linkingRow
}) => {
    const [candidates, setCandidates] = useState<PoolItem[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [showFilters, setShowFilters] = useState(false);

    // 搜索表单状态
    const [searchFilters, setSearchFilters] = useState(DEFAULT_SEARCH_FILTERS);

    const handleSearch = useCallback(async (filters: typeof DEFAULT_SEARCH_FILTERS) => {
        setIsLoading(true);
        // 清理空值，防止后端 Jackson 反序列化失败（特别是日期和金额）
        const sanitizedFilters = Object.keys(filters).reduce((acc: any, key) => {
            const val = filters[key as keyof typeof filters];
            if (val === '' || val === undefined || val === null) {
                acc[key] = null;
            } else if (key === 'minAmount' || key === 'maxAmount') {
                const parsed = parseFloat(val as string);
                acc[key] = isNaN(parsed) ? null : parsed;
            } else {
                acc[key] = val;
            }
            return acc;
        }, {});

        try {
            const results = await poolApi.searchCandidates(sanitizedFilters);
            setCandidates(results);
        } catch (error) {
            console.error('Search failed', error);
        } finally {
            setIsLoading(false);
        }
    }, []);

    // 自动根据 linkingRow 初始化搜索条件 (智能推荐逻辑)
    useEffect(() => {
        if (!isOpen) return;
        if (linkingRow) {
            const rawAmount = typeof linkingRow.amount === 'string'
                ? parseFloat(linkingRow.amount.replace(/[¥,\s]/g, ''))
                : linkingRow.amount;

            const rawDate = linkingRow.date ? linkingRow.date.split(' ')[0] : '';

            const nextFilters = {
                ...DEFAULT_SEARCH_FILTERS,
                minAmount: !isNaN(rawAmount) ? (rawAmount - 1).toFixed(2) : '',
                maxAmount: !isNaN(rawAmount) ? (rawAmount + 1).toFixed(2) : '',
                startDate: rawDate, // 默认当天或范围
                endDate: rawDate
            };

            setSearchFilters(nextFilters);
            handleSearch(nextFilters);
        } else if (isOpen) {
            // 没有任何上下文时，加载最近 20 条
            setSearchFilters(DEFAULT_SEARCH_FILTERS);
            handleSearch(DEFAULT_SEARCH_FILTERS);
        }
    }, [isOpen, linkingRow, handleSearch]);

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4 animate-in fade-in duration-200">
            <div className="bg-white rounded-3xl shadow-2xl w-full max-w-4xl border border-slate-100 flex flex-col max-h-[90vh] overflow-hidden">
                {/* Header */}
                <div className="px-8 py-6 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                    <div>
                        <h3 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                            <LinkIcon className="text-primary-600" size={24} />
                            手动凭证关联
                        </h3>
                        <p className="text-sm text-slate-400 mt-1">查找并关联原始电子凭证到当前会计记录</p>
                    </div>
                    <button
                        onClick={onClose}
                        className="p-2 hover:bg-slate-200 rounded-full transition-colors"
                    >
                        <X size={24} className="text-slate-400" />
                    </button>
                </div>

                {/* Search Bar & Filters */}
                <div className="px-8 py-4 border-b border-slate-50 space-y-4">
                    <div className="flex gap-3">
                        <div className="relative flex-1">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                            <input
                                type="text"
                                placeholder="搜索文件名、发票号或供应商..."
                                className="w-full pl-10 pr-4 py-3 bg-slate-100 border-none rounded-xl focus:ring-2 focus:ring-primary-500 transition-all text-sm"
                                value={searchFilters.keyword}
                                onChange={(e) => setSearchFilters({ ...searchFilters, keyword: e.target.value })}
                                onKeyDown={(e) => e.key === 'Enter' && handleSearch(searchFilters)}
                            />
                        </div>
                        <button
                            onClick={() => setShowFilters(!showFilters)}
                            className={`px-4 py-3 rounded-xl border flex items-center gap-2 transition-all text-sm font-medium ${showFilters ? 'bg-primary-50 border-primary-200 text-primary-600' : 'bg-white border-slate-200 text-slate-600'}`}
                        >
                            <Filter size={18} />
                            高级过滤
                        </button>
                        <button
                            onClick={() => handleSearch(searchFilters)}
                            className="px-6 py-3 bg-primary-600 text-white rounded-xl hover:bg-primary-700 shadow-lg shadow-primary-500/20 transition-all active:scale-95 font-medium"
                        >
                            查询
                        </button>
                    </div>

                    {showFilters && (
                        <div className="grid grid-cols-4 gap-4 p-4 bg-slate-50 rounded-2xl animate-in slide-in-from-top-2 duration-200">
                            <div className="space-y-1">
                                <label className="text-xs font-bold text-slate-500 flex items-center gap-1"><DollarSign size={12} /> 最低金额</label>
                                <input
                                    type="number"
                                    className="w-full px-3 py-2 border border-slate-200 rounded-lg text-sm"
                                    value={searchFilters.minAmount}
                                    onChange={(e) => setSearchFilters({ ...searchFilters, minAmount: e.target.value })}
                                />
                            </div>
                            <div className="space-y-1">
                                <label className="text-xs font-bold text-slate-500 flex items-center gap-1"><DollarSign size={12} /> 最高金额</label>
                                <input
                                    type="number"
                                    className="w-full px-3 py-2 border border-slate-200 rounded-lg text-sm"
                                    value={searchFilters.maxAmount}
                                    onChange={(e) => setSearchFilters({ ...searchFilters, maxAmount: e.target.value })}
                                />
                            </div>
                            <div className="space-y-1">
                                <label className="text-xs font-bold text-slate-500 flex items-center gap-1"><Calendar size={12} /> 开始日期</label>
                                <input
                                    type="date"
                                    className="w-full px-3 py-2 border border-slate-200 rounded-lg text-sm"
                                    value={searchFilters.startDate}
                                    onChange={(e) => setSearchFilters({ ...searchFilters, startDate: e.target.value })}
                                />
                            </div>
                            <div className="space-y-1">
                                <label className="text-xs font-bold text-slate-500 flex items-center gap-1"><Calendar size={12} /> 结束日期</label>
                                <input
                                    type="date"
                                    className="w-full px-3 py-2 border border-slate-200 rounded-lg text-sm"
                                    value={searchFilters.endDate}
                                    onChange={(e) => setSearchFilters({ ...searchFilters, endDate: e.target.value })}
                                />
                            </div>
                        </div>
                    )}
                </div>

                {/* Candidate List */}
                <div className="flex-1 overflow-y-auto px-8 py-4 bg-slate-50/30">
                    {isLoading ? (
                        <div className="flex flex-col items-center justify-center h-64 text-slate-400 gap-3">
                            <Loader2 size={40} className="animate-spin text-primary-500" />
                            <p className="text-sm font-medium">正在检索匹配的凭证...</p>
                        </div>
                    ) : candidates.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-64 text-slate-400 gap-4 opacity-60">
                            <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center">
                                <Search size={32} />
                            </div>
                            <div className="text-center">
                                <p className="font-bold text-slate-600">未找到候选凭证</p>
                                <p className="text-xs mt-1">请尝试调整金额、日期或关键字重新搜索</p>
                            </div>
                        </div>
                    ) : (
                        <div className="space-y-3">
                            <div className="flex items-center justify-between mb-2">
                                <span className="text-xs font-bold text-slate-400 tracking-wider uppercase">检索到 {candidates.length} 条记录</span>
                                <span className="text-xs text-slate-400">已选择 {selectedIds.length} 项</span>
                            </div>
                            {candidates.map(c => {
                                const isSelected = selectedIds.includes(c.id);
                                return (
                                    <div
                                        key={c.id}
                                        onClick={() => onToggleSelection(c.id)}
                                        className={`group relative flex items-center p-4 rounded-2xl border transition-all cursor-pointer ${isSelected
                                            ? 'bg-primary-50 border-primary-500 shadow-md ring-1 ring-primary-200'
                                            : 'bg-white border-slate-100 hover:border-primary-300 hover:shadow-sm'
                                            }`}
                                    >
                                        <div className={`p-3 rounded-xl mr-4 transition-colors ${isSelected ? 'bg-primary-600 text-white' : 'bg-slate-100 text-slate-500 group-hover:bg-primary-100 group-hover:text-primary-600'}`}>
                                            <FileText size={20} />
                                        </div>
                                        <div className="flex-1 min-w-0">
                                            <div className="flex items-center gap-2">
                                                <p className={`font-bold truncate ${isSelected ? 'text-primary-900' : 'text-slate-700'}`}>{c.fileName || c.code}</p>
                                                <span className="text-[10px] px-1.5 py-0.5 bg-slate-100 text-slate-500 rounded font-mono uppercase tracking-tighter">{c.type}</span>
                                            </div>
                                            <div className="flex items-center gap-4 mt-1 text-xs text-slate-400">
                                                <span className="flex items-center gap-1"><Calendar size={12} /> {c.date}</span>
                                                <span className="flex items-center gap-1"><User size={12} /> {c.source || '未知来源'}</span>
                                            </div>
                                        </div>
                                        <div className="text-right">
                                            <p className={`font-mono font-bold text-lg ${isSelected ? 'text-primary-700' : 'text-slate-800'}`}>
                                                ¥ {parseFloat(c.amount).toLocaleString(undefined, { minimumFractionDigits: 2 })}
                                            </p>
                                            <p className="text-[10px] text-slate-400 mt-0.5 font-mono">{c.code}</p>
                                        </div>

                                        {isSelected && (
                                            <div className="absolute -top-2 -right-2 w-6 h-6 bg-primary-600 text-white rounded-full flex items-center justify-center shadow-lg animate-in zoom-in duration-200">
                                                <LinkIcon size={12} />
                                            </div>
                                        )}
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </div>

                {/* Footer */}
                <div className="p-8 border-t border-slate-100 bg-slate-50/80 flex justify-between items-center">
                    <div className="text-sm text-slate-500">
                        {selectedIds.length > 0 ? (
                            <span className="flex items-center gap-1 animate-in slide-in-from-left-2 transition-all">
                                <span className="w-2 h-2 bg-primary-500 rounded-full animate-pulse" />
                                准备关联 {selectedIds.length} 个原始凭证
                            </span>
                        ) : '请从列表中选择要关联的项目'}
                    </div>
                    <div className="flex gap-3">
                        <button
                            onClick={onClose}
                            className="px-6 py-3 text-slate-600 font-bold hover:bg-slate-200 rounded-xl transition-colors"
                        >
                            取消
                        </button>
                        <button
                            onClick={onConfirm}
                            disabled={selectedIds.length === 0 || isLoading}
                            className="px-10 py-3 bg-primary-600 text-white font-bold rounded-xl disabled:opacity-50 disabled:cursor-not-allowed shadow-xl shadow-primary-500/30 hover:bg-primary-700 transition-all active:scale-95 flex items-center gap-2"
                        >
                            {isLoading ? <Loader2 size={18} className="animate-spin" /> : <LinkIcon size={18} />}
                            确认关联
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default LinkModal;

