import React, { useState } from 'react';
import { Shield, CheckCircle2, XCircle, Loader2, FileText, Calendar, Search, Shuffle, List } from 'lucide-react';
import { auditVerificationApi, VerificationResult, ChainVerificationResult, SamplingResult } from '../../api/auditVerification';
import { useFondsStore } from '../../store';

type VerifyMode = 'single' | 'batch' | 'chain' | 'sample';

/**
 * 审计证据链验真页面
 * 
 * 功能：
 * 1. 单条日志验真
 * 2. 批量日志验真
 * 3. 按条件验真（全宗、时间范围、操作类型）
 * 4. 随机抽检验真
 * 5. 验真结果展示
 * 
 * PRD 来源: Section 6.2 - 审计日志防篡改要求
 */
export const AuditVerificationPage: React.FC = () => {
    const { currentFonds } = useFondsStore();
    const [mode, setMode] = useState<VerifyMode>('single');
    const [loading, setLoading] = useState(false);
    const [result, setResult] = useState<VerificationResult | ChainVerificationResult | SamplingResult | null>(null);
    const [error, setError] = useState<string | null>(null);

    // 单条验真
    const [singleLogId, setSingleLogId] = useState('');

    // 批量验真
    const [batchLogIds, setBatchLogIds] = useState('');

    // 链路验真
    const [chainStartDate, setChainStartDate] = useState('');
    const [chainEndDate, setChainEndDate] = useState('');
    const [chainFondsNo, setChainFondsNo] = useState('');

    // 抽检验真
    const [sampleSize, setSampleSize] = useState(10);
    const [sampleStartDate, setSampleStartDate] = useState('');
    const [sampleEndDate, setSampleEndDate] = useState('');

    const handleSingleVerify = async () => {
        if (!singleLogId.trim()) {
            setError('请输入日志ID');
            return;
        }
        setLoading(true);
        setError(null);
        try {
            const res = await auditVerificationApi.verifySingle(singleLogId.trim());
            if (res.code === 200 && res.data) {
                setResult(res.data);
            } else {
                setError(res.message || '验真失败');
            }
        } catch (err: any) {
            setError(err.message || '验真失败');
        } finally {
            setLoading(false);
        }
    };

    const handleBatchVerify = async () => {
        const ids = batchLogIds.split('\n').map(id => id.trim()).filter(id => id);
        if (ids.length === 0) {
            setError('请输入至少一个日志ID');
            return;
        }
        setLoading(true);
        setError(null);
        try {
            const res = await auditVerificationApi.verifyChainByIds(ids);
            if (res.code === 200 && res.data) {
                setResult(res.data);
            } else {
                setError(res.message || '验真失败');
            }
        } catch (err: any) {
            setError(err.message || '验真失败');
        } finally {
            setLoading(false);
        }
    };

    const handleChainVerify = async () => {
        if (!chainStartDate || !chainEndDate) {
            setError('请选择开始日期和结束日期');
            return;
        }
        setLoading(true);
        setError(null);
        try {
            const res = await auditVerificationApi.verifyChain(
                chainStartDate,
                chainEndDate,
                chainFondsNo || undefined
            );
            if (res.code === 200 && res.data) {
                setResult(res.data);
            } else {
                setError(res.message || '验真失败');
            }
        } catch (err: any) {
            setError(err.message || '验真失败');
        } finally {
            setLoading(false);
        }
    };

    const handleSampleVerify = async () => {
        if (!sampleStartDate || !sampleEndDate) {
            setError('请选择开始日期和结束日期');
            return;
        }
        if (sampleSize <= 0) {
            setError('抽检数量必须大于0');
            return;
        }
        setLoading(true);
        setError(null);
        try {
            const res = await auditVerificationApi.sampleVerify(
                sampleSize,
                sampleStartDate,
                sampleEndDate
            );
            if (res.code === 200 && res.data) {
                setResult(res.data);
            } else {
                setError(res.message || '验真失败');
            }
        } catch (err: any) {
            setError(err.message || '验真失败');
        } finally {
            setLoading(false);
        }
    };

    const renderResult = () => {
        if (!result) return null;

        // 单条验真结果
        if ('logId' in result && !('totalLogs' in result)) {
            const singleResult = result as VerificationResult;
            return (
                <div className="mt-6 bg-white border border-slate-200 rounded-lg p-6">
                    <h3 className="text-lg font-semibold mb-4 flex items-center">
                        <FileText className="mr-2" size={20} />
                        验真结果
                    </h3>
                    <div className={`p-4 rounded-lg ${singleResult.valid ? 'bg-green-50 border border-green-200' : 'bg-red-50 border border-red-200'}`}>
                        <div className="flex items-center mb-2">
                            {singleResult.valid ? (
                                <CheckCircle2 className="text-green-600 mr-2" size={20} />
                            ) : (
                                <XCircle className="text-red-600 mr-2" size={20} />
                            )}
                            <span className={`font-semibold ${singleResult.valid ? 'text-green-800' : 'text-red-800'}`}>
                                {singleResult.valid ? '验证通过' : '验证失败'}
                            </span>
                        </div>
                        <div className="space-y-2 text-sm">
                            <div><span className="text-slate-600">日志ID:</span> <span className="font-mono">{singleResult.logId}</span></div>
                            {singleResult.expectedHash && (
                                <div><span className="text-slate-600">期望哈希:</span> <span className="font-mono text-xs">{singleResult.expectedHash}</span></div>
                            )}
                            {singleResult.actualHash && (
                                <div><span className="text-slate-600">实际哈希:</span> <span className="font-mono text-xs">{singleResult.actualHash}</span></div>
                            )}
                            {singleResult.reason && (
                                <div><span className="text-slate-600">失败原因:</span> <span className="text-red-600">{singleResult.reason}</span></div>
                            )}
                            {singleResult.verifiedAt && (
                                <div><span className="text-slate-600">验证时间:</span> {singleResult.verifiedAt}</div>
                            )}
                        </div>
                    </div>
                </div>
            );
        }

        // 哈希链/抽检验真结果
        if ('totalLogs' in result) {
            const chainResult = 'verificationResult' in result 
                ? (result as SamplingResult).verificationResult
                : result as ChainVerificationResult;

            const sampleInfo = 'verificationResult' in result ? result as SamplingResult : null;

            return (
                <div className="mt-6 bg-white border border-slate-200 rounded-lg p-6">
                    <h3 className="text-lg font-semibold mb-4 flex items-center">
                        <FileText className="mr-2" size={20} />
                        验真结果
                    </h3>
                    {sampleInfo && (
                        <div className="mb-4 p-4 bg-blue-50 border border-blue-200 rounded-lg">
                            <div className="text-sm space-y-1">
                                <div><span className="text-slate-600">总日志数:</span> {sampleInfo.totalLogs}</div>
                                <div><span className="text-slate-600">抽检数量:</span> {sampleInfo.sampledLogs}</div>
                                <div><span className="text-slate-600">抽检日志ID:</span> 
                                    <div className="mt-1 font-mono text-xs max-h-32 overflow-y-auto">
                                        {sampleInfo.sampledLogIds.join(', ')}
                                    </div>
                                </div>
                            </div>
                        </div>
                    )}
                    <div className={`p-4 rounded-lg ${chainResult.chainIntact ? 'bg-green-50 border border-green-200' : 'bg-red-50 border border-red-200'}`}>
                        <div className="flex items-center mb-4">
                            {chainResult.chainIntact ? (
                                <CheckCircle2 className="text-green-600 mr-2" size={20} />
                            ) : (
                                <XCircle className="text-red-600 mr-2" size={20} />
                            )}
                            <span className={`font-semibold ${chainResult.chainIntact ? 'text-green-800' : 'text-red-800'}`}>
                                {chainResult.chainIntact ? '哈希链完整' : '哈希链断裂'}
                            </span>
                        </div>
                        <div className="grid grid-cols-3 gap-4 mb-4">
                            <div className="text-center p-3 bg-white rounded">
                                <div className="text-2xl font-bold text-slate-800">{chainResult.totalLogs}</div>
                                <div className="text-xs text-slate-600 mt-1">总日志数</div>
                            </div>
                            <div className="text-center p-3 bg-white rounded">
                                <div className="text-2xl font-bold text-green-600">{chainResult.validLogs}</div>
                                <div className="text-xs text-slate-600 mt-1">有效日志</div>
                            </div>
                            <div className="text-center p-3 bg-white rounded">
                                <div className="text-2xl font-bold text-red-600">{chainResult.invalidLogs}</div>
                                <div className="text-xs text-slate-600 mt-1">无效日志</div>
                            </div>
                        </div>
                        {chainResult.invalidResults && chainResult.invalidResults.length > 0 && (
                            <div className="mt-4">
                                <div className="text-sm font-semibold text-red-800 mb-2">无效日志详情:</div>
                                <div className="space-y-2 max-h-64 overflow-y-auto">
                                    {chainResult.invalidResults.map((invalid, idx) => (
                                        <div key={idx} className="p-3 bg-white border border-red-200 rounded text-sm">
                                            <div className="font-mono text-xs mb-1">ID: {invalid.logId}</div>
                                            <div className="text-red-600">{invalid.reason}</div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                        {chainResult.verifiedAt && (
                            <div className="mt-4 text-sm text-slate-600">
                                验证时间: {chainResult.verifiedAt}
                            </div>
                        )}
                    </div>
                </div>
            );
        }

        return null;
    };

    return (
        <div className="p-6 space-y-6">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-2xl font-bold text-slate-800 flex items-center">
                        <Shield className="mr-2" size={28} />
                        审计证据链验真
                    </h2>
                    <p className="text-slate-500 text-sm mt-1">验证审计日志的完整性和真实性，确保未被篡改</p>
                </div>
            </div>

            {/* 模式选择 */}
            <div className="bg-white border border-slate-200 rounded-lg p-4">
                <div className="flex space-x-2">
                    <button
                        onClick={() => { setMode('single'); setResult(null); setError(null); }}
                        className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
                            mode === 'single' 
                                ? 'bg-primary-600 text-white' 
                                : 'bg-slate-100 text-slate-700 hover:bg-slate-200'
                        }`}
                    >
                        <Search className="inline mr-2" size={16} />
                        单条验真
                    </button>
                    <button
                        onClick={() => { setMode('batch'); setResult(null); setError(null); }}
                        className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
                            mode === 'batch' 
                                ? 'bg-primary-600 text-white' 
                                : 'bg-slate-100 text-slate-700 hover:bg-slate-200'
                        }`}
                    >
                        <List className="inline mr-2" size={16} />
                        批量验真
                    </button>
                    <button
                        onClick={() => { setMode('chain'); setResult(null); setError(null); }}
                        className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
                            mode === 'chain' 
                                ? 'bg-primary-600 text-white' 
                                : 'bg-slate-100 text-slate-700 hover:bg-slate-200'
                        }`}
                    >
                        <FileText className="inline mr-2" size={16} />
                        链路验真
                    </button>
                    <button
                        onClick={() => { setMode('sample'); setResult(null); setError(null); }}
                        className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
                            mode === 'sample' 
                                ? 'bg-primary-600 text-white' 
                                : 'bg-slate-100 text-slate-700 hover:bg-slate-200'
                        }`}
                    >
                        <Shuffle className="inline mr-2" size={16} />
                        抽检验真
                    </button>
                </div>
            </div>

            {/* 单条验真 */}
            {mode === 'single' && (
                <div className="bg-white border border-slate-200 rounded-lg p-6">
                    <h3 className="text-lg font-semibold mb-4">单条日志验真</h3>
                    <div className="space-y-4">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2">
                                日志ID
                            </label>
                            <input
                                type="text"
                                value={singleLogId}
                                onChange={(e) => setSingleLogId(e.target.value)}
                                placeholder="请输入审计日志ID"
                                className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                            />
                        </div>
                        <button
                            onClick={handleSingleVerify}
                            disabled={loading}
                            className="px-4 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center"
                        >
                            {loading ? <Loader2 className="animate-spin mr-2" size={16} /> : <Search className="mr-2" size={16} />}
                            开始验真
                        </button>
                    </div>
                </div>
            )}

            {/* 批量验真 */}
            {mode === 'batch' && (
                <div className="bg-white border border-slate-200 rounded-lg p-6">
                    <h3 className="text-lg font-semibold mb-4">批量日志验真</h3>
                    <div className="space-y-4">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2">
                                日志ID列表（每行一个）
                            </label>
                            <textarea
                                value={batchLogIds}
                                onChange={(e) => setBatchLogIds(e.target.value)}
                                placeholder="请输入日志ID，每行一个"
                                rows={8}
                                className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500 font-mono text-sm"
                            />
                        </div>
                        <button
                            onClick={handleBatchVerify}
                            disabled={loading}
                            className="px-4 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center"
                        >
                            {loading ? <Loader2 className="animate-spin mr-2" size={16} /> : <List className="mr-2" size={16} />}
                            开始验真
                        </button>
                    </div>
                </div>
            )}

            {/* 链路验真 */}
            {mode === 'chain' && (
                <div className="bg-white border border-slate-200 rounded-lg p-6">
                    <h3 className="text-lg font-semibold mb-4 flex items-center">
                        <Calendar className="mr-2" size={20} />
                        按时间范围验真
                    </h3>
                    <div className="space-y-4">
                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-2">
                                    开始日期 <span className="text-red-500">*</span>
                                </label>
                                <input
                                    type="date"
                                    value={chainStartDate}
                                    onChange={(e) => setChainStartDate(e.target.value)}
                                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-2">
                                    结束日期 <span className="text-red-500">*</span>
                                </label>
                                <input
                                    type="date"
                                    value={chainEndDate}
                                    onChange={(e) => setChainEndDate(e.target.value)}
                                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                                />
                            </div>
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-2">
                                全宗号（可选）
                            </label>
                            <input
                                type="text"
                                value={chainFondsNo}
                                onChange={(e) => setChainFondsNo(e.target.value)}
                                placeholder="留空则验证所有全宗"
                                className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                            />
                        </div>
                        <button
                            onClick={handleChainVerify}
                            disabled={loading}
                            className="px-4 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center"
                        >
                            {loading ? <Loader2 className="animate-spin mr-2" size={16} /> : <FileText className="mr-2" size={16} />}
                            开始验真
                        </button>
                    </div>
                </div>
            )}

            {/* 抽检验真 */}
            {mode === 'sample' && (
                <div className="bg-white border border-slate-200 rounded-lg p-6">
                    <h3 className="text-lg font-semibold mb-4 flex items-center">
                        <Shuffle className="mr-2" size={20} />
                        随机抽检验真
                    </h3>
                    <div className="space-y-4">
                        <div className="grid grid-cols-3 gap-4">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-2">
                                    开始日期 <span className="text-red-500">*</span>
                                </label>
                                <input
                                    type="date"
                                    value={sampleStartDate}
                                    onChange={(e) => setSampleStartDate(e.target.value)}
                                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-2">
                                    结束日期 <span className="text-red-500">*</span>
                                </label>
                                <input
                                    type="date"
                                    value={sampleEndDate}
                                    onChange={(e) => setSampleEndDate(e.target.value)}
                                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                                />
                            </div>
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-2">
                                    抽检数量 <span className="text-red-500">*</span>
                                </label>
                                <input
                                    type="number"
                                    value={sampleSize}
                                    onChange={(e) => setSampleSize(parseInt(e.target.value) || 0)}
                                    min={1}
                                    max={1000}
                                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500"
                                />
                            </div>
                        </div>
                        <button
                            onClick={handleSampleVerify}
                            disabled={loading}
                            className="px-4 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center"
                        >
                            {loading ? <Loader2 className="animate-spin mr-2" size={16} /> : <Shuffle className="mr-2" size={16} />}
                            开始抽检验真
                        </button>
                    </div>
                </div>
            )}

            {/* 错误提示 */}
            {error && (
                <div className="bg-red-50 border border-red-200 rounded-lg p-4">
                    <div className="flex items-center text-red-800">
                        <XCircle className="mr-2" size={20} />
                        <span>{error}</span>
                    </div>
                </div>
            )}

            {/* 结果显示 */}
            {renderResult()}
        </div>
    );
};

export default AuditVerificationPage;

// Input: React、lucide-react 图标、本地模块 batchUploadApi、useFondsStore
// Output: React 组件 BatchUploadView
// Pos: src/pages/collection/BatchUploadView.tsx - 批量上传页面

/**
 * 批量上传页面
 *
 * 功能：
 * 1. 创建上传批次
 * 2. 拖拽/选择文件上传
 * 3. 实时进度跟踪
 * 4. 文件列表展示
 * 5. 四性检测触发
 *
 * 符合 GB/T 39362-2020 电子会计档案管理系统建设要求
 */

import React, { useState, useCallback, useRef, useEffect } from 'react';
import {
  Upload as UploadIcon,
  FileText,
  CheckCircle2,
  XCircle,
  AlertCircle,
  Trash2,
  Pause,
  Play,
  ShieldCheck,
  ArrowLeft,
  FolderOpen,
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { useMutation, useQuery } from '@tanstack/react-query';
import { message, Upload, Modal, Progress, Button, Select, Form, Input, Card, Row, Col, Statistic, Alert } from 'antd';
import type { UploadProps, UploadFile } from 'antd';
import { batchUploadApi, ArchivalCategoryLabels } from '../../api/batchUpload';
import { useFondsStore } from '../../store/useFondsStore';
import { ComplianceAlert } from './components/ComplianceAlert';

const { Dragger } = Upload;

// ===== Types =====

interface FileUploadItem {
  uid: string;
  file: File;
  status: 'pending' | 'uploading' | 'uploaded' | 'failed' | 'duplicate';
  progress: number;
  error?: string;
  fileId?: string;
}

interface BatchFormData {
  batchName: string;
  fondsCode: string;
  fiscalYear: string;
  fiscalPeriod?: string;
  archivalCategory: 'VOUCHER' | 'LEDGER' | 'REPORT' | 'OTHER';
}

export const BatchUploadView: React.FC = () => {
  const navigate = useNavigate();
  const currentFonds = useFondsStore((state) => state.currentFonds);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // ===== State =====
  const [step, setStep] = useState<'create' | 'upload' | 'complete'>('create');
  const [batchInfo, setBatchInfo] = useState<{
    batchId: number;
    batchNo: string;
    batchName: string;
  } | null>(null);
  const [uploadQueue, setUploadQueue] = useState<FileUploadItem[]>([]);
  const [isPaused, setIsPaused] = useState(false);
  const [uploadingIndex, setUploadingIndex] = useState<number>(-1);
  const [form] = Form.useForm<BatchFormData>();

  // ===== Queries =====

  // 轮询批次状态
  const { data: batchDetail } = useQuery({
    queryKey: ['batchDetail', batchInfo?.batchId],
    queryFn: () => batchUploadApi.getBatchDetail(batchInfo!.batchId),
    enabled: !!batchInfo?.batchId && step !== 'create',
    refetchInterval: 2000,
  });

  // 获取文件列表
  const { data: batchFiles = [] } = useQuery({
    queryKey: ['batchFiles', batchInfo?.batchId],
    queryFn: () => batchUploadApi.getBatchFiles(batchInfo!.batchId),
    enabled: !!batchInfo?.batchId && step !== 'create',
    refetchInterval: 3000,
  });

  // ===== Mutations =====

  const createBatchMutation = useMutation({
    mutationFn: (data: BatchFormData) =>
      batchUploadApi.createBatch({
        ...data,
        fondsCode: currentFonds?.fondsCode || data.fondsCode,
        totalFiles: uploadQueue.length,
        autoCheck: true,
      }),
    onSuccess: (response) => {
      setBatchInfo({
        batchId: response.batchId,
        batchNo: response.batchNo,
        batchName: form.getFieldValue('batchName'),
      });
      setStep('upload');
      message.success('批次创建成功');
    },
    onError: (err: Error) => {
      message.error('批次创建失败: ' + (err.message || '未知错误'));
    },
  });

  const uploadFileMutation = useMutation({
    mutationFn: ({ file, index }: { file: File; index: number }) =>
      batchUploadApi.uploadFile(
        batchInfo!.batchId,
        file,
        (progress) => {
          setUploadQueue((prev) => {
            const updated = [...prev];
            updated[index].progress = progress;
            return updated;
          });
        }
      ),
    onSuccess: (result, variables) => {
      setUploadQueue((prev) => {
        const updated = [...prev];
        updated[variables.index].status =
          result.status === 'UPLOADED' ? 'uploaded' : 'failed';
        updated[variables.index].fileId = result.fileId;
        updated[variables.index].error = result.errorMessage;
        return updated;
      });
    },
    onError: (err: Error, variables) => {
      setUploadQueue((prev) => {
        const updated = [...prev];
        updated[variables.index].status = 'failed';
        updated[variables.index].error = err.message || '上传失败';
        return updated;
      });
    },
  });

  const completeBatchMutation = useMutation({
    mutationFn: () => batchUploadApi.completeBatch(batchInfo!.batchId),
    onSuccess: () => {
      setStep('complete');
      message.success('批次上传完成');
    },
  });

  const cancelBatchMutation = useMutation({
    mutationFn: () => batchUploadApi.cancelBatch(batchInfo!.batchId),
    onSuccess: () => {
      message.success('批次已取消');
      navigate('/system/collection');
    },
  });

  const runCheckMutation = useMutation({
    mutationFn: () => batchUploadApi.runFourNatureCheck(batchInfo!.batchId),
    onSuccess: (result) => {
      message.success(result.summary);
    },
  });

  // ===== Effects =====

  // 自动处理上传队列
  useEffect(() => {
    if (step === 'upload' && !isPaused && uploadingIndex === -1) {
      const nextIndex = uploadQueue.findIndex((item) => item.status === 'pending');
      if (nextIndex !== -1) {
        setUploadingIndex(nextIndex);
        setUploadQueue((prev) => {
          const updated = [...prev];
          updated[nextIndex].status = 'uploading';
          return updated;
        });
      }
    }
  }, [step, isPaused, uploadQueue, uploadingIndex]);

  // 执行上传
  useEffect(() => {
    if (uploadingIndex >= 0 && uploadQueue[uploadingIndex]?.status === 'uploading') {
      const item = uploadQueue[uploadingIndex];
      uploadFileMutation.mutate(
        { file: item.file, index: uploadingIndex },
        {
          onSettled: () => {
            setUploadingIndex(-1);
          },
        }
      );
    }
  }, [uploadingIndex, uploadQueue, uploadFileMutation]);

  // ===== Handlers =====

  const handleCreateBatch = useCallback(async () => {
    try {
      const values = await form.validateFields();
      createBatchMutation.mutate(values);
    } catch (error) {
      message.error('请填写完整的批次信息');
    }
  }, [form, createBatchMutation, uploadQueue]);

  const handleFileSelect: UploadProps['onChange'] = useCallback((info: { fileList: UploadFile[] }) => {
    const newFiles = info.fileList
      .filter((file: UploadFile) => file.originFileObj)
      .map((file: UploadFile) => ({
        uid: file.uid,
        file: file.originFileObj as File,
        status: 'pending' as const,
        progress: 0,
      }));

    setUploadQueue((prev) => [...prev, ...newFiles]);
  }, []);

  const handleRemoveFile = useCallback((uid: string) => {
    setUploadQueue((prev) => prev.filter((item) => item.uid !== uid));
  }, []);

  const handleRetryFile = useCallback((uid: string) => {
    setUploadQueue((prev) =>
      prev.map((item) => {
        if (item.uid === uid) {
          return { ...item, status: 'pending' as const, progress: 0, error: undefined };
        }
        return item;
      })
    );
  }, []);

  const handleCompleteBatch = useCallback(() => {
    completeBatchMutation.mutate();
  }, [completeBatchMutation]);

  const handleCancelBatch = useCallback(() => {
    Modal.confirm({
      title: '确认取消',
      content: '取消后将删除所有已上传的文件，是否继续？',
      onOk: () => cancelBatchMutation.mutate(),
    });
  }, [cancelBatchMutation]);

  const handleRunCheck = useCallback(() => {
    runCheckMutation.mutate();
  }, [runCheckMutation]);

  // ===== Render Helpers =====

  const renderFileIcon = (status: FileUploadItem['status']) => {
    switch (status) {
      case 'uploaded':
        return <CheckCircle2 className="text-green-500" size={20} />;
      case 'failed':
        return <XCircle className="text-red-500" size={20} />;
      case 'duplicate':
        return <AlertCircle className="text-amber-500" size={20} />;
      case 'uploading':
        return <UploadIcon className="text-blue-500 animate-pulse" size={20} />;
      default:
        return <FileText className="text-slate-400" size={20} />;
    }
  };

  const getStatusText = (status: FileUploadItem['status'] | string) => {
    const statusMap: Record<string, string> = {
      pending: '等待中',
      uploading: '上传中',
      uploaded: '已上传',
      failed: '上传失败',
      duplicate: '重复文件',
      UPLOADED: '已上传',
      VALIDATED: '已校验',
      FAILED: '失败',
      CHECK_FAILED: '检测失败',
      PENDING: '等待中',
    };
    return statusMap[status] || status;
  };

  const stats = React.useMemo(() => {
    const total = uploadQueue.length;
    const uploaded = uploadQueue.filter((f) => f.status === 'uploaded').length;
    const failed = uploadQueue.filter((f) => f.status === 'failed').length;
    const duplicate = uploadQueue.filter((f) => f.status === 'duplicate').length;
    return { total, uploaded, failed, duplicate };
  }, [uploadQueue]);

  // ===== Render =====

  if (step === 'create') {
    return (
      <div className="p-8 max-w-4xl mx-auto animate-in fade-in duration-300">
        {/* Header */}
        <div className="flex items-center gap-4 mb-8">
          <button
            onClick={() => navigate('/system/collection')}
            className="p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800"
          >
            <ArrowLeft size={20} />
          </button>
          <div>
            <h1 className="text-2xl font-bold text-slate-900">批量上传</h1>
            <p className="text-slate-500 text-sm">创建上传批次并上传会计档案文件</p>
          </div>
        </div>

        {/* Batch Form */}
        <Card className="mb-6">
          <Form
            form={form}
            layout="vertical"
            initialValues={{
              fondsCode: currentFonds?.fondsCode || '001',
              fiscalYear: new Date().getFullYear().toString(),
              archivalCategory: 'VOUCHER',
            }}
          >
            <Row gutter={16}>
              <Col span={12}>
                <Form.Item
                  label="批次名称"
                  name="batchName"
                  rules={[{ required: true, message: '请输入批次名称' }]}
                >
                  <Input placeholder="例如：2024年1月凭证" />
                </Form.Item>
              </Col>
              <Col span={12}>
                <Form.Item
                  label="全宗代码"
                  name="fondsCode"
                  rules={[{ required: true, message: '请输入全宗代码' }]}
                >
                  <Input placeholder="001" />
                </Form.Item>
              </Col>
            </Row>

            <Row gutter={16}>
              <Col span={8}>
                <Form.Item
                  label="会计年度"
                  name="fiscalYear"
                  rules={[{ required: true, message: '请输入会计年度' }]}
                >
                  <Input placeholder="2024" />
                </Form.Item>
              </Col>
              <Col span={8}>
                <Form.Item label="会计期间" name="fiscalPeriod">
                  <Select
                    placeholder="选择期间"
                    allowClear
                    options={[
                      { label: '1月', value: '01' },
                      { label: '2月', value: '02' },
                      { label: '3月', value: '03' },
                      { label: '4月', value: '04' },
                      { label: '5月', value: '05' },
                      { label: '6月', value: '06' },
                      { label: '7月', value: '07' },
                      { label: '8月', value: '08' },
                      { label: '9月', value: '09' },
                      { label: '10月', value: '10' },
                      { label: '11月', value: '11' },
                      { label: '12月', value: '12' },
                    ]}
                  />
                </Form.Item>
              </Col>
              <Col span={8}>
                <Form.Item
                  label="档案门类"
                  name="archivalCategory"
                  rules={[{ required: true, message: '请选择档案门类' }]}
                >
                  <Select
                    options={Object.entries(ArchivalCategoryLabels).map(
                      ([value, label]) => ({ label, value })
                    )}
                  />
                </Form.Item>
              </Col>
            </Row>
          </Form>
        </Card>

        {/* File Upload Area */}
        <Card className="mb-6">
          <Dragger
            multiple
            accept=".pdf,.ofd,.xml,.jpg,.jpeg,.png,.tif,.tiff"
            customRequest={() => {}}
            onChange={handleFileSelect}
            showUploadList={false}
          >
            <p className="ant-upload-drag-icon">
              <FolderOpen size={48} className="text-blue-500" />
            </p>
            <p className="text-lg font-medium text-slate-700">
              点击或拖拽文件到此区域上传
            </p>
            <p className="text-slate-500 text-sm mt-2">
              支持 PDF、OFD、XML、JPG、PNG、TIFF 格式，单个文件不超过 100MB
            </p>
          </Dragger>
        </Card>

        {/* File List */}
        {uploadQueue.length > 0 && (
          <Card className="mb-6">
            <div className="flex justify-between items-center mb-4">
              <h3 className="font-semibold text-slate-800">
                已选择 {uploadQueue.length} 个文件
              </h3>
              <Button
                danger
                size="small"
                onClick={() => setUploadQueue([])}
              >
                清空列表
              </Button>
            </div>

            <div className="space-y-2 max-h-64 overflow-y-auto">
              {uploadQueue.map((item) => (
                <div
                  key={item.uid}
                  className="flex items-center gap-3 p-3 bg-slate-50 dark:bg-slate-800 rounded-lg"
                >
                  {renderFileIcon(item.status)}
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium text-slate-700 truncate">
                      {item.file.name}
                    </p>
                    <p className="text-xs text-slate-500">
                      {(item.file.size / 1024 / 1024).toFixed(2)} MB
                      {item.status === 'uploading' && ` - ${item.progress}%`}
                    </p>
                    {item.error && (
                      <p className="text-xs text-red-500">{item.error}</p>
                    )}
                  </div>
                  {item.status === 'failed' && (
                    <Button size="small" onClick={() => handleRetryFile(item.uid)}>
                      重试
                    </Button>
                  )}
                  <Button
                    size="small"
                    danger
                    disabled={item.status === 'uploading'}
                    onClick={() => handleRemoveFile(item.uid)}
                  >
                    <Trash2 size={14} />
                  </Button>
                </div>
              ))}
            </div>
          </Card>
        )}

        {/* Actions */}
        <div className="flex justify-end gap-3">
          <Button onClick={() => navigate('/system/collection')}>取消</Button>
          <Button
            type="primary"
            onClick={handleCreateBatch}
            disabled={uploadQueue.length === 0}
            loading={createBatchMutation.isPending}
          >
            开始上传 ({uploadQueue.length})
          </Button>
        </div>
      </div>
    );
  }

  // Upload & Complete Steps
  return (
    <div className="p-8 max-w-6xl mx-auto animate-in fade-in duration-300">
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center gap-4">
          <button
            onClick={() => navigate('/system/collection')}
            className="p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800"
          >
            <ArrowLeft size={20} />
          </button>
          <div>
            <h1 className="text-2xl font-bold text-slate-900">
              {batchInfo?.batchName}
            </h1>
            <p className="text-slate-500 text-sm">
              批次号: {batchInfo?.batchNo} · 状态: {batchDetail?.status}
            </p>
          </div>
        </div>

        {step === 'upload' && (
          <div className="flex items-center gap-2">
            <Button
              icon={isPaused ? <Play size={16} /> : <Pause size={16} />}
              onClick={() => setIsPaused(!isPaused)}
            >
              {isPaused ? '继续' : '暂停'}
            </Button>
            <Button
              type="primary"
              onClick={handleCompleteBatch}
              disabled={stats.uploaded === 0}
            >
              完成上传
            </Button>
          </div>
        )}
      </div>

      {/* Statistics */}
      <Row gutter={16} className="mb-6">
        <Col span={6}>
          <Card>
            <Statistic title="总文件数" value={stats.total} />
          </Card>
        </Col>
        <Col span={6}>
          <Card>
            <Statistic
              title="已上传"
              value={stats.uploaded}
              valueStyle={{ color: '#3f8600' }}
            />
          </Card>
        </Col>
        <Col span={6}>
          <Card>
            <Statistic
              title="失败"
              value={stats.failed}
              valueStyle={{ color: stats.failed > 0 ? '#cf1322' : undefined }}
            />
          </Card>
        </Col>
        <Col span={6}>
          <Card>
            <Statistic
              title="重复"
              value={stats.duplicate}
              valueStyle={{ color: stats.duplicate > 0 ? '#faad14' : undefined }}
            />
          </Card>
        </Col>
      </Row>

      {/* Compliance Alert */}
      <ComplianceAlert className="mb-6" />

      {/* Overall Progress */}
      {step === 'upload' && (
        <Card className="mb-6">
          <div className="flex items-center gap-4">
            <div className="flex-1">
              <div className="flex justify-between mb-2">
                <span className="text-sm font-medium">上传进度</span>
                <span className="text-sm text-slate-500">
                  {stats.uploaded} / {stats.total}
                </span>
              </div>
              <Progress
                percent={stats.total > 0 ? Math.round((stats.uploaded / stats.total) * 100) : 0}
                status={stats.failed > 0 ? 'exception' : 'active'}
              />
            </div>
          </div>
        </Card>
      )}

      {/* File List (from server) */}
      <Card title="文件列表">
        <div className="space-y-2">
          {batchFiles.map((file) => (
            <div
              key={file.id}
              className="flex items-center gap-3 p-3 bg-slate-50 dark:bg-slate-800 rounded-lg"
            >
              {renderFileIcon(
                file.uploadStatus === 'UPLOADED' || file.uploadStatus === 'VALIDATED'
                  ? 'uploaded'
                  : file.uploadStatus === 'FAILED' || file.uploadStatus === 'CHECK_FAILED'
                  ? 'failed'
                  : 'pending'
              )}
              <div className="flex-1 min-w-0">
                <p className="text-sm font-medium text-slate-700 truncate">
                  {file.originalFilename}
                </p>
                <p className="text-xs text-slate-500">
                  {((file.fileSizeBytes || 0) / 1024 / 1024).toFixed(2)} MB
                  {' · '}{getStatusText(file.uploadStatus)}
                </p>
                {file.errorMessage && (
                  <p className="text-xs text-red-500">{file.errorMessage}</p>
                )}
              </div>
            </div>
          ))}
        </div>
      </Card>

      {/* Actions for Complete Step */}
      {step === 'complete' && (
        <div className="mt-6">
          {/* Completion Summary */}
          <Alert
            type="success"
            showIcon
            className="mb-4"
            message="上传完成！"
            description="已为您创建档案记录，请在凭证关联页面匹配原始凭证。"
          />

          {/* Action Buttons */}
          <div className="flex justify-center gap-4">
            <Button
              type="primary"
              onClick={() => navigate('/system/pre-archive/link')}
            >
              前往凭证关联
            </Button>
            <Button
              icon={<ShieldCheck size={16} />}
              onClick={handleRunCheck}
              loading={runCheckMutation.isPending}
            >
              执行四性检测
            </Button>
            <Button onClick={() => navigate('/system/collection/upload')}>
              继续上传
            </Button>
            <Button danger onClick={handleCancelBatch}>
              取消批次
            </Button>
          </div>
        </div>
      )}
    </div>
  );
};

export default BatchUploadView;

// Input: React、lucide-react 图标、API
// Output: React 组件 FourNatureReportView
// Pos: src/pages/collection/FourNatureReportView.tsx
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useEffect, useState } from 'react';
import { CheckCircle, XCircle, AlertTriangle, Shield, FileCheck, Lock, Eye, Printer, X, Loader2 } from 'lucide-react';

interface CheckItem {
    name: string;
    status: 'PASS' | 'FAIL' | 'WARNING';
    message: string;
    errors?: string[];
}

interface FourNatureReport {
    checkId: string;
    checkTime: string;
    archivalCode?: string;
    status: 'PASS' | 'FAIL' | 'WARNING';
    authenticity?: CheckItem;
    integrity?: CheckItem;
    usability?: CheckItem;
    safety?: CheckItem;
}

interface FourNatureReportViewProps {
    fileId: string;
    onClose: () => void;
}

// API 基础路径
const API_BASE = process.env.NEXT_PUBLIC_API_BASE || '/api';

export const FourNatureReportView: React.FC<FourNatureReportViewProps> = ({ fileId, onClose }) => {
    const [report, setReport] = useState<FourNatureReport | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        const fetchReport = async () => {
            try {
                setLoading(true);
                setError(null);

                const token = localStorage.getItem('token');
                const response = await fetch(`${API_BASE}/pool/check/${fileId}`, {
                    headers: {
                        'Authorization': token ? `Bearer ${token}` : '',
                        'Content-Type': 'application/json'
                    }
                });

                if (!response.ok) {
                    throw new Error(`检测请求失败: ${response.status}`);
                }

                const result = await response.json();
                if (result.code === 200 && result.data) {
                    setReport(result.data);
                } else {
                    throw new Error(result.message || '未知错误');
                }
            } catch (err) {
                setError(err instanceof Error ? err.message : '网络请求失败');
            } finally {
                setLoading(false);
            }
        };

        if (fileId) {
            fetchReport();
        }
    }, [fileId]);

    const getStatusIcon = (status?: string) => {
        switch (status) {
            case 'PASS':
                return <CheckCircle className="w-4 h-4 text-emerald-500 shrink-0" />;
            case 'FAIL':
                return <XCircle className="w-4 h-4 text-red-500 shrink-0" />;
            case 'WARNING':
                return <AlertTriangle className="w-4 h-4 text-amber-500 shrink-0" />;
            default:
                return <CheckCircle className="w-4 h-4 text-slate-400 shrink-0" />;
        }
    };

    const getOverallStatusConfig = (status?: string) => {
        switch (status) {
            case 'PASS':
                return { bg: 'bg-emerald-50', border: 'border-emerald-100', text: 'text-emerald-900', icon: CheckCircle, iconBg: 'bg-emerald-100', iconColor: 'text-emerald-600', label: '检测通过' };
            case 'FAIL':
                return { bg: 'bg-red-50', border: 'border-red-100', text: 'text-red-900', icon: XCircle, iconBg: 'bg-red-100', iconColor: 'text-red-600', label: '检测失败' };
            case 'WARNING':
                return { bg: 'bg-amber-50', border: 'border-amber-100', text: 'text-amber-900', icon: AlertTriangle, iconBg: 'bg-amber-100', iconColor: 'text-amber-600', label: '检测警告' };
            default:
                return { bg: 'bg-slate-50', border: 'border-slate-100', text: 'text-slate-900', icon: Shield, iconBg: 'bg-slate-100', iconColor: 'text-slate-600', label: '检测中' };
        }
    };

    const renderCheckCategory = (title: string, icon: React.ReactNode, item?: CheckItem) => {
        if (!item) return null;

        return (
            <div className="bg-white border border-slate-200 rounded-xl p-4 shadow-sm hover:shadow-md transition-shadow">
                <div className="flex items-center gap-2 mb-4 pb-2 border-b border-slate-100">
                    {icon}
                    <h3 className="font-bold text-slate-800">{title}</h3>
                    {getStatusIcon(item.status)}
                </div>
                <div className="space-y-3">
                    <div className="flex items-start justify-between group">
                        <div className="flex-1">
                            <div className="text-sm font-medium text-slate-700">{item.name || title}</div>
                            <div className="text-xs text-slate-500 mt-0.5">{item.message}</div>
                            {item.errors && item.errors.length > 0 && (
                                <ul className="mt-2 text-xs text-red-600 list-disc list-inside">
                                    {item.errors.map((err, i) => (
                                        <li key={i}>{err}</li>
                                    ))}
                                </ul>
                            )}
                        </div>
                        {getStatusIcon(item.status)}
                    </div>
                </div>
            </div>
        );
    };

    const statusConfig = getOverallStatusConfig(report?.status);
    const StatusIcon = statusConfig.icon;

    return (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 backdrop-blur-sm">
            <div className="bg-white rounded-xl shadow-2xl w-[800px] max-h-[90vh] overflow-hidden flex flex-col animate-in fade-in zoom-in duration-200">
                {/* Header */}
                <div className="p-6 border-b border-slate-200 flex justify-between items-center bg-slate-50">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-blue-100 rounded-lg">
                            <Shield className="w-6 h-6 text-blue-700" />
                        </div>
                        <div>
                            <h2 className="text-xl font-bold text-slate-900">四性检测报告</h2>
                            <p className="text-sm text-slate-500">依据 DA/T 92-2022 标准执行</p>
                        </div>
                    </div>
                    <button onClick={onClose} className="text-slate-400 hover:text-slate-600 transition-colors">
                        <X className="w-6 h-6" />
                    </button>
                </div>

                {/* Content */}
                <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50/30">
                    {loading ? (
                        <div className="flex flex-col items-center justify-center py-12">
                            <Loader2 className="w-10 h-10 text-blue-600 animate-spin" />
                            <p className="mt-4 text-slate-600">正在执行四性检测...</p>
                        </div>
                    ) : error ? (
                        <div className="bg-red-50 border border-red-100 rounded-xl p-4 flex items-center gap-4">
                            <div className="w-12 h-12 rounded-full bg-red-100 flex items-center justify-center">
                                <XCircle className="w-6 h-6 text-red-600" />
                            </div>
                            <div>
                                <div className="text-lg font-bold text-red-900">检测失败</div>
                                <div className="text-sm text-red-700">{error}</div>
                            </div>
                        </div>
                    ) : report ? (
                        <>
                            {/* Overall Result */}
                            <div className={`${statusConfig.bg} border ${statusConfig.border} rounded-xl p-4 flex items-center justify-between`}>
                                <div className="flex items-center gap-4">
                                    <div className={`w-12 h-12 rounded-full ${statusConfig.iconBg} flex items-center justify-center`}>
                                        <StatusIcon className={`w-6 h-6 ${statusConfig.iconColor}`} />
                                    </div>
                                    <div>
                                        <div className={`text-lg font-bold ${statusConfig.text}`}>{statusConfig.label}</div>
                                        <div className={`text-sm ${statusConfig.iconColor}`}>
                                            {report.archivalCode || '待归档文件'}
                                        </div>
                                    </div>
                                </div>
                                <div className="text-right">
                                    <div className={`text-sm ${statusConfig.iconColor}`}>检测时间</div>
                                    <div className={`font-mono font-medium ${statusConfig.text}`}>
                                        {report.checkTime ? new Date(report.checkTime).toLocaleString() : '-'}
                                    </div>
                                </div>
                            </div>

                            {/* Detailed Checks */}
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                {renderCheckCategory(
                                    '真实性 (Authenticity)',
                                    <Shield className="w-5 h-5 text-blue-600" />,
                                    report.authenticity
                                )}
                                {renderCheckCategory(
                                    '完整性 (Integrity)',
                                    <FileCheck className="w-5 h-5 text-emerald-600" />,
                                    report.integrity
                                )}
                                {renderCheckCategory(
                                    '可用性 (Usability)',
                                    <Eye className="w-5 h-5 text-purple-600" />,
                                    report.usability
                                )}
                                {renderCheckCategory(
                                    '安全性 (Safety)',
                                    <Lock className="w-5 h-5 text-orange-600" />,
                                    report.safety
                                )}
                            </div>
                        </>
                    ) : null}
                </div>

                {/* Footer */}
                <div className="p-4 border-t border-slate-200 bg-white flex justify-end gap-3">
                    <button onClick={onClose} className="px-4 py-2 text-slate-700 hover:bg-slate-100 rounded-lg font-medium transition-colors">
                        关闭
                    </button>
                    <button 
                        className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white hover:bg-blue-700 rounded-lg font-medium shadow-sm transition-colors disabled:opacity-50"
                        disabled={loading || !!error}
                        onClick={() => window.print()}
                    >
                        <Printer className="w-4 h-4" />
                        打印报告
                    </button>
                </div>
            </div>
        </div>
    );
};

// Input: React、lucide-react 图标、本地模块 FourNatureReportView、api/stats、api/erp 等
// Output: React 组件 OnlineReceptionView
// Pos: src/pages/collection/OnlineReceptionView.tsx
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useState, useEffect } from 'react';
import { RefreshCw, CheckCircle, XCircle, Eye, Trash2, Filter, Server, Clock } from 'lucide-react';
import { FourNatureReportView } from './FourNatureReportView';
import { statsApi, ErpStats } from '@api/stats';
import { integrationApi, IntegrationChannel } from '@api/erp';
import { client } from '@api/client';

// 扩展 IntegrationChannel 以支持本地状态
interface LocalChannel extends IntegrationChannel {
    localStatus?: 'normal' | 'error' | 'syncing';
}

export const OnlineReceptionView: React.FC = () => {
    const [channels, setChannels] = useState<LocalChannel[]>([]);
    const [error, setError] = useState<string | null>(null);
    const [selectedIds, setSelectedIds] = useState<Set<number>>(new Set());

    // 切换选中状态
    const toggleSelection = (id: number) => {
        setSelectedIds(prev => {
            const newSet = new Set(prev);
            if (newSet.has(id)) {
                newSet.delete(id);
            } else {
                newSet.add(id);
            }
            return newSet;
        });
    };

    const [isModalOpen, setIsModalOpen] = useState(false);
    const [isReportOpen, setIsReportOpen] = useState(false);
    const [newChannel, setNewChannel] = useState({ name: '', system: 'SAP ERP', description: '' });

    const [stats, setStats] = useState<ErpStats>({
        connectedSystems: 0,
        todayReceived: 0,
        activeInterfaces: 0,
        abnormalCount: 0
    });

    // Sync Modal State
    const [isSyncModalOpen, setIsSyncModalOpen] = useState(false);
    const [syncChannelId, setSyncChannelId] = useState<number | null>(null);
    const [syncPeriod, setSyncPeriod] = useState({ start: '2024-01', end: '2024-12' });
    // Multi-org sync: available orgs and selected orgs
    const [availableOrgs, setAvailableOrgs] = useState<{ code: string, name: string }[]>([]);
    const [selectedOrgs, setSelectedOrgs] = useState<string[]>([]);
    const [syncError, setSyncError] = useState<string | null>(null);

    // 加载集成通道数据
    useEffect(() => {
        const loadData = async () => {
            try {
                // 加载统计数据
                const statsRes = await statsApi.getErpStats();
                if (statsRes.code === 200) {
                    setStats(statsRes.data);
                }

                // 加载组织/全宗数据用于映射名称
                const fondsRes = await client.get('/bas/fonds/list');
                const fondsMap: Record<string, string> = {};
                if (fondsRes.data.code === 200 && fondsRes.data.data) {
                    fondsRes.data.data.forEach((f: any) => {
                        fondsMap[f.fondsCode] = f.fondsName;
                    });
                }

                // 加载集成通道列表
                const channelsRes = await integrationApi.getChannels();
                if (channelsRes.code === 200 && channelsRes.data) {
                    setChannels(channelsRes.data.map(ch => ({
                        ...ch,
                        localStatus: ch.status
                    })));
                }

                // 导出 fondsMap 供后续弹窗使用
                (window as any)._fondsMap = fondsMap;
            } catch (e: any) {
                console.error("Failed to load integration data", e);
                setError(e.message || String(e));
            }
        };
        loadData();
    }, []);

    // YonSuite 同步配置
    // State for Log Modal
    const [logModalOpen, setLogModalOpen] = useState(false);
    const [currentLog, setCurrentLog] = useState<{ title: string, content: string | null }>({ title: '', content: '' });

    const handleViewLog = (channel: LocalChannel) => {
        setCurrentLog({
            title: `${channel.name} - 同步日志`,
            content: channel.lastSyncMsg || '暂无日志记录'
        });
        setLogModalOpen(true);
    };

    const handleSync = async (id: number) => {
        const channel = channels.find(c => c.id === id);
        if (!channel) return;

        // 根据后端返回的多组织代码，动态构建弹窗选项
        const codes = channel.accbookCodes || (channel.accbookCode ? [channel.accbookCode] : []);
        const fondsMap = (window as any)._fondsMap || {};

        const orgs = codes.map(code => ({
            code,
            name: fondsMap[code] ? `${fondsMap[code]} (${code})` : `组织 (${code})`
        }));

        setAvailableOrgs(orgs);
        setSelectedOrgs(codes.length > 0 ? [codes[0]] : []);
        setSyncChannelId(id);
        setIsSyncModalOpen(true);
        setSyncError(null);
    };

    const executeRealSync = async () => {
        if (!syncChannelId) return;

        const channel = channels.find(c => c.id === syncChannelId);
        if (!channel) return;

        // 更新状态为同步中
        setChannels(prev => prev.map(c =>
            c.id === syncChannelId ? { ...c, status: 'syncing' as const } : c
        ));
        setSyncError(null);

        try {
            let success = false;
            if (channel.apiEndpoint) {
                // 有 apiEndpoint：使用统一 client 进行请求
                const response = await client.post(channel.apiEndpoint, {
                    accbookCode: selectedOrgs.length > 0 ? selectedOrgs[0] : (channel.accbookCode || 'BR01'),
                    accbookCodes: selectedOrgs.length > 0 ? selectedOrgs : [channel.accbookCode || 'BR01'],
                    periodStart: syncPeriod.start,
                    periodEnd: syncPeriod.end
                });
                const result = response.data;
                success = response.status === 200 && result.status === 'SUCCESS';
                if (!success) throw new Error(result.message || '同步失败');
            } else {
                // 无 apiEndpoint：使用通用触发接口
                const { erpApi } = await import('@api/erp');
                const res = await erpApi.triggerSync(syncChannelId);
                success = res && res.code === 200;
                if (!success) throw new Error(res?.message || '触发失败');
            }

            if (success) {
                // 刷新通道列表
                const channelsRes = await integrationApi.getChannels();
                if (channelsRes.code === 200 && channelsRes.data) {
                    setChannels(channelsRes.data.map(ch => ({
                        ...ch,
                        localStatus: ch.status
                    })));
                }
                setIsSyncModalOpen(false);
            }
        } catch (error: any) {
            setSyncError(error.message || '同步请求失败');
            setChannels(prev => prev.map(c =>
                c.id === syncChannelId ? { ...c, status: 'error' as const } : c
            ));
        }
    };

    const handleAddChannel = () => {
        const channel: LocalChannel = {
            id: Date.now(),
            name: newChannel.name,
            displayName: newChannel.name, // Added displayName
            configName: newChannel.system, // Added configName
            erpType: 'unknown', // Added erpType
            frequency: '每小时',
            lastSync: '-',
            receivedCount: 0,
            status: 'normal',
            description: newChannel.description,
            apiEndpoint: null,
            accbookCode: null,
            accbookCodes: null,
            lastSyncMsg: null
        };
        // Note: This local add is just for UI demo of "Add Channel" which might not be fully backed by API yet
        // casting to any to bypass strict type checks for this demo feature
        setChannels([...channels, channel as any]);
        setIsModalOpen(false);
        setNewChannel({ name: '', system: 'SAP ERP', description: '' });
    };

    return (
        <div className="p-6 max-w-[1600px] mx-auto space-y-6 relative">
            {/* Log Modal */}
            {logModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/50 backdrop-blur-sm">
                    <div className="bg-white rounded-lg shadow-xl w-[600px] max-w-[90vw] flex flex-col max-h-[80vh]">
                        <div className="p-4 border-b border-slate-100 flex justify-between items-center">
                            <h3 className="font-medium text-slate-800 flex items-center gap-2">
                                <CheckCircle size={16} className="text-blue-500" />
                                {currentLog.title}
                            </h3>
                            <button
                                onClick={() => setLogModalOpen(false)}
                                className="text-slate-400 hover:text-slate-600 transition-colors"
                            >
                                <XCircle size={20} />
                            </button>
                        </div>
                        <div className="p-6 overflow-y-auto bg-slate-50 font-mono text-sm text-slate-600 whitespace-pre-wrap">
                            {currentLog.content}
                        </div>
                        <div className="p-4 border-t border-slate-100 bg-white rounded-b-lg flex justify-end">
                            <button
                                onClick={() => setLogModalOpen(false)}
                                className="px-4 py-2 bg-slate-100 text-slate-600 rounded hover:bg-slate-200 transition-colors text-sm font-medium"
                            >
                                关闭
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* Header */}
            {error && (
                <div className="bg-red-50 border border-red-200 text-red-700 p-4 rounded-lg mb-4">
                    <strong>Error:</strong> {error}
                </div>
            )}

            <div className="flex justify-between items-start">
                <div>
                    <div className="flex items-center gap-3 mb-2">
                        <h1 className="text-2xl font-bold text-slate-900">资料收集 / 在线接收</h1>
                        <span className="px-2 py-1 bg-blue-100 text-blue-700 text-xs rounded-full font-medium">
                            集成监控
                        </span>
                    </div>
                    <p className="text-slate-500">
                        管理和监控来自外部系统 (ERP, OA, 费控) 的数据集成通道与同步状态。
                    </p>
                </div>
                <div className="flex gap-3">
                    <button className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 text-slate-700 rounded-lg hover:bg-slate-50 transition-colors">
                        <Filter className="w-4 h-4" />
                        筛选
                    </button>
                    {/* 新增接口功能已移至集成中心，以保持职责分离 */}
                </div>
            </div>

            {/* Stats Cards */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                    <div className="text-slate-500 text-sm mb-1">接入系统总数</div>
                    <div className="text-2xl font-bold text-slate-900">{stats.connectedSystems}</div>
                </div>
                <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                    <div className="text-slate-500 text-sm mb-1">今日接收数据</div>
                    <div className="text-2xl font-bold text-emerald-600">{stats.todayReceived} 条</div>
                </div>
                <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                    <div className="text-slate-500 text-sm mb-1">运行正常接口</div>
                    <div className="text-2xl font-bold text-blue-600">{stats.activeInterfaces}</div>
                </div>
                <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                    <div className="text-slate-500 text-sm mb-1">异常报警</div>
                    <div className="text-2xl font-bold text-red-600">{stats.abnormalCount}</div>
                </div>
            </div>

            {/* Main Table */}
            <div className="bg-white border border-slate-200 rounded-xl shadow-sm overflow-hidden">
                <div className="p-4 border-b border-slate-200 flex justify-between items-center bg-slate-50/50">
                    <div className="flex items-center gap-4">
                        <span className="text-sm text-slate-500">
                            已选择 <span className="font-medium text-slate-900">{selectedIds.size}</span> 项
                        </span>
                        {selectedIds.size > 0 && (
                            <button className="text-sm text-red-600 hover:text-red-700 font-medium">
                                批量删除
                            </button>
                        )}
                    </div>
                    <button className="text-sm text-slate-500 hover:text-slate-700 flex items-center gap-1">
                        <RefreshCw className="w-3 h-3" /> 重置视图
                    </button>
                </div>

                <table className="w-full text-left text-sm">
                    <thead>
                        <tr className="border-b border-slate-200 bg-slate-50 text-slate-600">
                            <th className="p-4 w-10">
                                <input type="checkbox" className="rounded border-slate-300" />
                            </th>
                            <th className="p-4 font-medium">接口名称 / 描述</th>
                            <th className="p-4 font-medium">对接系统</th>
                            <th className="p-4 font-medium">同步频率</th>
                            <th className="p-4 font-medium">最后同步</th>
                            <th className="p-4 font-medium">本次接收</th>
                            <th className="p-4 font-medium">接口状态</th>
                            <th className="p-4 font-medium text-right">操作</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                        {channels.map((channel) => (
                            <tr key={channel.id} className="hover:bg-slate-50/80 transition-colors group">
                                <td className="p-4">
                                    <input
                                        type="checkbox"
                                        checked={selectedIds.has(channel.id)}
                                        onChange={() => toggleSelection(channel.id)}
                                        className="rounded border-slate-300"
                                    />
                                </td>
                                <td className="p-4">
                                    <div className="font-medium text-slate-900">{channel.name}</div>
                                    <div className="text-slate-500 text-xs mt-0.5">{channel.description}</div>
                                </td>
                                <td className="p-4">
                                    <div className="flex items-center gap-2">
                                        <div className="w-8 h-8 rounded bg-slate-100 flex items-center justify-center text-slate-500">
                                            <Server className="w-4 h-4" />
                                        </div>
                                        <span className="font-medium text-slate-700">{channel.configName}</span>
                                    </div>
                                </td>
                                <td className="p-4">
                                    <div className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-slate-100 text-slate-600 text-xs font-medium border border-slate-200">
                                        <Clock className="w-3 h-3" />
                                        {channel.frequency}
                                    </div>
                                </td>
                                <td className="p-4 text-slate-600 font-mono text-xs">
                                    {channel.lastSync || '-'}
                                </td>
                                <td className="p-4">
                                    <span className="font-medium text-slate-900">{channel.receivedCount}</span>
                                    <span className="text-slate-500 ml-1">条</span>
                                </td>
                                <td className="p-4">
                                    {channel.status === 'syncing' ? (
                                        <div className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-blue-50 text-blue-700 text-xs font-medium border border-blue-100">
                                            <RefreshCw className="w-3 h-3 animate-spin" />
                                            同步中
                                        </div>
                                    ) : channel.status === 'normal' ? (
                                        <div className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-emerald-50 text-emerald-700 text-xs font-medium border border-emerald-100">
                                            <CheckCircle className="w-3 h-3" />
                                            正常
                                        </div>
                                    ) : (
                                        <div className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full bg-red-50 text-red-700 text-xs font-medium border border-red-100">
                                            <XCircle className="w-3 h-3" />
                                            异常
                                        </div>
                                    )}
                                </td>
                                <td className="p-4 text-right">
                                    <div className="flex items-center justify-end gap-2">
                                        <button
                                            onClick={() => handleSync(channel.id)}
                                            className="p-1.5 text-blue-600 hover:bg-blue-50 rounded-lg tooltip"
                                            title="立即同步"
                                        >
                                            <RefreshCw className="w-4 h-4" />
                                        </button>
                                        <button
                                            onClick={() => handleViewLog(channel)}
                                            className="p-1.5 text-slate-500 hover:bg-slate-100 rounded-lg"
                                            title="查看日志"
                                        >
                                            <Eye className="w-4 h-4" />
                                        </button>
                                        <button className="p-1.5 text-red-500 hover:bg-red-50 rounded-lg" title="删除配置">
                                            <Trash2 className="w-4 h-4" />
                                        </button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
            {/* Add Channel Modal */}
            {isModalOpen && (
                <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
                    <div className="bg-white rounded-xl shadow-xl w-[500px] p-6 animate-in fade-in zoom-in duration-200">
                        <div className="flex justify-between items-center mb-6">
                            <h2 className="text-xl font-bold text-slate-900">新增集成接口</h2>
                            <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600">
                                <XCircle className="w-6 h-6" />
                            </button>
                        </div>

                        <div className="space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">接口名称</label>
                                <input
                                    type="text"
                                    value={newChannel.name}
                                    onChange={e => setNewChannel({ ...newChannel, name: e.target.value })}
                                    placeholder="例如: SAP_VOUCHER_SYNC"
                                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                                />
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">对接系统</label>
                                <select
                                    value={newChannel.system}
                                    onChange={e => setNewChannel({ ...newChannel, system: e.target.value })}
                                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                                >
                                    <option>用友YonSuite</option>
                                    <option>SAP ERP</option>
                                    <option>金蝶云星空</option>
                                    <option>用友 U8</option>
                                    <option>泛微OA</option>
                                    <option>易快报</option>
                                    <option>汇联易</option>
                                </select>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">描述</label>
                                <textarea
                                    value={newChannel.description}
                                    onChange={e => setNewChannel({ ...newChannel, description: e.target.value })}
                                    placeholder="接口用途描述..."
                                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none h-24 resize-none"
                                />
                            </div>
                        </div>

                        <div className="flex justify-end gap-3 mt-8">
                            <button
                                onClick={() => setIsModalOpen(false)}
                                className="px-4 py-2 text-slate-700 hover:bg-slate-100 rounded-lg font-medium"
                            >
                                取消
                            </button>
                            <button
                                onClick={handleAddChannel}
                                className="px-4 py-2 bg-blue-600 text-white hover:bg-blue-700 rounded-lg font-medium shadow-sm"
                            >
                                确认添加
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* Four Nature Report Modal - 需要传入选中文件的 ID */}
            {isReportOpen && (
                <FourNatureReportView fileId="" onClose={() => setIsReportOpen(false)} />
            )}

            {/* YonSuite Sync Modal */}
            {isSyncModalOpen && (
                <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
                    <div className="bg-white rounded-xl shadow-xl w-[500px] p-6 animate-in fade-in zoom-in duration-200">
                        <div className="flex justify-between items-center mb-6">
                            <h2 className="text-xl font-bold text-slate-900">同步凭证数据</h2>
                            <button onClick={() => setIsSyncModalOpen(false)} className="text-slate-400 hover:text-slate-600">
                                <XCircle className="w-6 h-6" />
                            </button>
                        </div>

                        <div className="space-y-4">
                            <div className="p-4 bg-blue-50 rounded-lg border border-blue-100">
                                <p className="text-sm text-blue-800">
                                    将从用友YonSuite系统同步指定期间的会计凭证数据到本系统。
                                </p>
                            </div>

                            {/* Multi-Org Selector */}
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-2">选择同步组织</label>
                                <div className="space-y-2 p-3 border border-slate-200 rounded-lg bg-slate-50">
                                    {availableOrgs.map(org => (
                                        <label key={org.code} className="flex items-center gap-2 cursor-pointer">
                                            <input
                                                type="checkbox"
                                                checked={selectedOrgs.includes(org.code)}
                                                onChange={(e) => {
                                                    if (e.target.checked) {
                                                        setSelectedOrgs([...selectedOrgs, org.code]);
                                                    } else {
                                                        setSelectedOrgs(selectedOrgs.filter(c => c !== org.code));
                                                    }
                                                }}
                                                className="rounded border-slate-300 text-blue-600 focus:ring-blue-500"
                                            />
                                            <span className="text-sm text-slate-700">{org.name}</span>
                                        </label>
                                    ))}
                                </div>
                                <p className="text-xs text-slate-500 mt-1">可选择多个组织同时同步</p>
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-1">开始期间</label>
                                    <input
                                        type="month"
                                        value={syncPeriod.start}
                                        onChange={e => setSyncPeriod({ ...syncPeriod, start: e.target.value })}
                                        className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-slate-700 mb-1">结束期间</label>
                                    <input
                                        type="month"
                                        value={syncPeriod.end}
                                        onChange={e => setSyncPeriod({ ...syncPeriod, end: e.target.value })}
                                        className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none"
                                    />
                                </div>
                            </div>

                            {syncError && (
                                <div className="p-3 bg-red-50 border border-red-200 rounded-lg text-red-700 text-sm">
                                    ❌ {syncError}
                                </div>
                            )}
                        </div>

                        <div className="flex justify-end gap-3 mt-8">
                            <button
                                onClick={() => setIsSyncModalOpen(false)}
                                className="px-4 py-2 text-slate-700 hover:bg-slate-100 rounded-lg font-medium"
                            >
                                取消
                            </button>
                            <button
                                onClick={executeRealSync}
                                disabled={channels.find(c => c.id === syncChannelId)?.status === 'syncing'}
                                className="px-4 py-2 bg-blue-600 text-white hover:bg-blue-700 rounded-lg font-medium shadow-sm disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
                            >
                                {channels.find(c => c.id === syncChannelId)?.status === 'syncing' ? (
                                    <>
                                        <RefreshCw className="w-4 h-4 animate-spin" />
                                        同步中...
                                    </>
                                ) : (
                                    <>
                                        <RefreshCw className="w-4 h-4" />
                                        开始同步
                                    </>
                                )}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default OnlineReceptionView;

