import React, { useState } from 'react';
// Local Card Component since common/Card doesn't exist
const Card: React.FC<{ className?: string; children: React.ReactNode }> = ({ className = '', children }) => (
    <div className={`bg-white shadow rounded-lg p-6 ${className}`}>
        {children}
    </div>
);
import { client } from '../../api/client';
import { toast } from 'react-hot-toast';
import { CloudDownload, Code } from 'lucide-react';

const PaymentFileTestView: React.FC = () => {
    const [configId, setConfigId] = useState('1'); // Default to 1 (YonSuite)
    const [fileIds, setFileIds] = useState('mfdfs23421\nn95sdavdas'); // Default from doc
    const [loading, setLoading] = useState(false);
    const [result, setResult] = useState<any>(null);

    const handleTest = async () => {
        setLoading(true);
        setResult(null);
        try {
            const ids = fileIds.split('\n').map(s => s.trim()).filter(Boolean);
            if (ids.length === 0) {
                toast.error('请输入至少一个文件ID');
                return;
            }

            const response = await client.post('/api/integration/yon/payment/url/batch', {
                configId: parseInt(configId),
                fileIds: ids
            });
            setResult(response.data);
            toast.success('请求成功');
        } catch (error: any) {
            console.error(error);
            toast.error('请求失败: ' + (error.response?.data?.message || error.message));
            setResult({ error: error.message, detail: error.response?.data });
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="space-y-6 p-6">
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900">YonBIP Payment File Test</h1>
                    <p className="text-slate-500 mt-1">验证 AI 生成的资金结算文件下载接口 (Pass 2 Result Verification)</p>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                {/* Input Panel */}
                <Card>
                    <div className="space-y-4">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">
                                ERP Configuration ID
                            </label>
                            <input
                                type="number"
                                value={configId}
                                onChange={e => setConfigId(e.target.value)}
                                className="w-full px-3 py-2 border rounded-md focus:ring-2 focus:ring-indigo-500"
                            />
                            <p className="text-xs text-slate-500 mt-1">关联 sys_erp_config 表的主键 ID</p>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">
                                File IDs (每行一个)
                            </label>
                            <textarea
                                value={fileIds}
                                onChange={e => setFileIds(e.target.value)}
                                rows={8}
                                className="w-full px-3 py-2 border rounded-md font-mono text-sm focus:ring-2 focus:ring-indigo-500"
                                placeholder="输入文件ID..."
                            />
                        </div>

                        <button
                            onClick={handleTest}
                            disabled={loading}
                            className="w-full flex items-center justify-center space-x-2 bg-indigo-600 hover:bg-indigo-700 text-white py-2 px-4 rounded-md disabled:opacity-50 transition-colors"
                        >
                            {loading ? (
                                <span className="animate-spin">⌛</span>
                            ) : (
                                <CloudDownload className="w-5 h-5" />
                            )}
                            <span>发送请求 (Invoke Generated Service)</span>
                        </button>
                    </div>
                </Card>

                {/* Result Panel */}
                <Card className="bg-slate-50">
                    <div className="flex items-center space-x-2 mb-4 text-slate-700">
                        <Code className="w-5 h-5" />
                        <h3 className="font-semibold">Test Result</h3>
                    </div>

                    {result ? (
                        <pre className="bg-slate-900 text-green-400 p-4 rounded-md overflow-auto text-xs font-mono h-[300px]">
                            {JSON.stringify(result, null, 2)}
                        </pre>
                    ) : (
                        <div className="h-[300px] flex items-center justify-center text-slate-400 border-2 border-dashed rounded-md">
                            等待测试结果...
                        </div>
                    )}
                </Card>
            </div>
        </div>
    );
};

export default PaymentFileTestView;

// Input: React、Ant Design、匹配 API
// Output: ComplianceReport 组件
// Pos: src/pages/matching/ComplianceReport.tsx
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useState, useEffect, useCallback } from 'react';
import {
    Card, Table, Tag, Button, Space, Statistic, Row, Col,
    DatePicker, message, Spin, Alert
} from 'antd';
import {
    WarningOutlined, CheckCircleOutlined,
    DownloadOutlined, ReloadOutlined
} from '@ant-design/icons';
import type { ColumnsType } from 'antd/es/table';
import type { Dayjs } from 'dayjs';
import { matchingApi, ComplianceStats, MissingDocRecord } from '../../api/matching';

const { RangePicker } = DatePicker;

const ComplianceReport: React.FC = () => {
    const [loading, setLoading] = useState(false);
    const [exporting, setExporting] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [dateRange, setDateRange] = useState<[Dayjs | null, Dayjs | null] | null>(null);
    const [stats, setStats] = useState<ComplianceStats>({
        totalVouchers: 0,
        matchedVouchers: 0,
        pendingVouchers: 0,
        missingMustLink: 0,
        missingShouldLink: 0,
        complianceRate: 0
    });
    const [missingDocs, setMissingDocs] = useState<MissingDocRecord[]>([]);

    // 加载报告数据
    const loadReport = useCallback(async () => {
        setLoading(true);
        setError(null);
        try {
            const startDate = dateRange?.[0]?.format('YYYY-MM-DD');
            const endDate = dateRange?.[1]?.format('YYYY-MM-DD');
            const report = await matchingApi.getComplianceReport(startDate, endDate);
            setStats(report.stats);
            setMissingDocs(report.missingDocs);
        } catch (err) {
            const errorMessage = err instanceof Error ? err.message : '加载报告失败';
            setError(errorMessage);
        } finally {
            setLoading(false);
        }
    }, [dateRange]);

    // 初始加载
    useEffect(() => {
        loadReport();
    }, [loadReport]);

    // 日期变更时重新加载
    const handleDateChange = (dates: [Dayjs | null, Dayjs | null] | null) => {
        setDateRange(dates);
    };

    // 导出 Excel
    const handleExport = async () => {
        setExporting(true);
        try {
            const startDate = dateRange?.[0]?.format('YYYY-MM-DD');
            const endDate = dateRange?.[1]?.format('YYYY-MM-DD');
            const blob = await matchingApi.exportMissingDocs(startDate, endDate);

            // 创建下载链接
            const url = window.URL.createObjectURL(blob);
            const link = document.createElement('a');
            link.href = url;
            link.download = `合规报告_${startDate || 'all'}_${endDate || 'all'}.xlsx`;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
            window.URL.revokeObjectURL(url);

            message.success('导出成功');
        } catch {
            message.error('导出失败');
        } finally {
            setExporting(false);
        }
    };

    const columns: ColumnsType<MissingDocRecord> = [
        {
            title: '凭证号',
            dataIndex: 'voucherNo',
            key: 'voucherNo',
        },
        {
            title: '业务场景',
            dataIndex: 'scene',
            key: 'scene',
            render: (scene: string) => {
                const sceneNames: Record<string, string> = {
                    PAYMENT: '付款',
                    RECEIPT: '收款',
                    REIMBURSEMENT: '报销',
                    PURCHASE_ENTRY: '采购入库',
                    SALES_INVOICE: '销售开票',
                    SALARY_PAYMENT: '工资发放',
                    TAX_PAYMENT: '税费缴纳',
                };
                return sceneNames[scene] || scene;
            }
        },
        {
            title: '缺失单据',
            dataIndex: 'missingDocType',
            key: 'missingDocType',
        },
        {
            title: '关联类型',
            dataIndex: 'linkType',
            key: 'linkType',
            render: (type: string) => (
                <Tag color={type === 'MUST_LINK' ? 'red' : 'orange'}>
                    {type === 'MUST_LINK' ? '必关联' : '应关联'}
                </Tag>
            )
        },
        {
            title: '风险等级',
            dataIndex: 'riskLevel',
            key: 'riskLevel',
            render: (level: string) => {
                const config: Record<string, { color: string; text: string }> = {
                    HIGH: { color: 'red', text: '高' },
                    MEDIUM: { color: 'orange', text: '中' },
                    LOW: { color: 'green', text: '低' },
                };
                const cfg = config[level];
                return <Tag color={cfg?.color}>{cfg?.text}</Tag>;
            }
        },
        {
            title: '凭证日期',
            dataIndex: 'createTime',
            key: 'createTime',
        },
        {
            title: '操作',
            key: 'action',
            render: () => (
                <Button type="link" size="small">补证</Button>
            )
        }
    ];

    if (loading && missingDocs.length === 0) {
        return <Spin tip="加载报告..." />;
    }

    return (
        <div className="compliance-report">
            <Card title="凭证关联合规报告" extra={
                <Space>
                    <RangePicker
                        value={dateRange}
                        onChange={handleDateChange}
                        allowClear
                    />
                    <Button
                        icon={<ReloadOutlined spin={loading} />}
                        onClick={loadReport}
                        loading={loading}
                    >
                        刷新
                    </Button>
                    <Button
                        icon={<DownloadOutlined />}
                        onClick={handleExport}
                        loading={exporting}
                    >
                        导出 Excel
                    </Button>
                </Space>
            }>
                {error && (
                    <Alert
                        type="error"
                        message={error}
                        closable
                        onClose={() => setError(null)}
                        style={{ marginBottom: 16 }}
                    />
                )}

                {/* 统计卡片 */}
                <Row gutter={16} style={{ marginBottom: 24 }}>
                    <Col span={4}>
                        <Card>
                            <Statistic
                                title="总凭证数"
                                value={stats.totalVouchers}
                            />
                        </Card>
                    </Col>
                    <Col span={4}>
                        <Card>
                            <Statistic
                                title="已匹配"
                                value={stats.matchedVouchers}
                                valueStyle={{ color: '#3f8600' }}
                                prefix={<CheckCircleOutlined />}
                            />
                        </Card>
                    </Col>
                    <Col span={4}>
                        <Card>
                            <Statistic
                                title="待补证"
                                value={stats.pendingVouchers}
                                valueStyle={{ color: '#cf1322' }}
                                prefix={<WarningOutlined />}
                            />
                        </Card>
                    </Col>
                    <Col span={4}>
                        <Card>
                            <Statistic
                                title="缺必关联"
                                value={stats.missingMustLink}
                                valueStyle={{ color: '#cf1322' }}
                            />
                        </Card>
                    </Col>
                    <Col span={4}>
                        <Card>
                            <Statistic
                                title="缺应关联"
                                value={stats.missingShouldLink}
                                valueStyle={{ color: '#faad14' }}
                            />
                        </Card>
                    </Col>
                    <Col span={4}>
                        <Card>
                            <Statistic
                                title="合规率"
                                value={stats.complianceRate}
                                suffix="%"
                                valueStyle={{ color: stats.complianceRate >= 95 ? '#3f8600' : '#faad14' }}
                            />
                        </Card>
                    </Col>
                </Row>

                {/* 缺失清单 */}
                <Card title="待补证清单" size="small">
                    <Table
                        columns={columns}
                        dataSource={missingDocs}
                        rowKey="voucherId"
                        size="small"
                        loading={loading}
                        pagination={{ pageSize: 10 }}
                    />
                </Card>
            </Card>
        </div>
    );
};

export default ComplianceReport;

