    PENDING: { color: 'default', text: '待提交' },
    VALIDATING: { color: 'processing', text: '校验中' },
    APPROVED: { color: 'success', text: '已审批' },
    ARCHIVED: { color: 'green', text: '已归档' },
    REJECTED: { color: 'error', text: '已驳回' },
    FAILED: { color: 'error', text: '失败' },
};

const ArchiveBatchView: React.FC = () => {
    // 全宗状态
    const currentFonds = useFondsStore((state) => state.currentFonds);

    // 当前用户
    const user = useAuthStore((state) => state.user);

    // 批量选择状态
    const {
        selectedIds,
        rowSelection,
        clearSelection,
        selectAll,
        getSelectedCount
    } = useBatchSelection();

    // 状态
    const [loading, setLoading] = useState(false);
    const [batches, setBatches] = useState<ArchiveBatch[]>([]);
    const [total, setTotal] = useState(0);
    const [page, setPage] = useState(1);
    const [pageSize, setPageSize] = useState(10);
    const [statusFilter, setStatusFilter] = useState<BatchStatus | undefined>();

    // 弹窗状态
    const [createModalVisible, setCreateModalVisible] = useState(false);
    const [detailModalVisible, setDetailModalVisible] = useState(false);
    const [approvalModalVisible, setApprovalModalVisible] = useState(false);
    const [selectedBatch, setSelectedBatch] = useState<ArchiveBatch | null>(null);
    const [batchItems, setBatchItems] = useState<ArchiveBatchItem[]>([]);
    const [integrityReport, setIntegrityReport] = useState<IntegrityReport | null>(null);
    const [approvalAction, setApprovalAction] = useState<'approve' | 'reject'>('approve');
    const [approvalComment, setApprovalComment] = useState('');

    // 添加凭证弹窗
    const [addVoucherModalVisible, setAddVoucherModalVisible] = useState(false);
    const [availableVouchers, setAvailableVouchers] = useState<any[]>([]);
    const [selectedVoucherIds, setSelectedVoucherIds] = useState<number[]>([]);
    const [loadingVouchers, setLoadingVouchers] = useState(false);

    // 统计
    const [stats, setStats] = useState<{ total: number; byStatus: Record<string, number> }>({
        total: 0,
        byStatus: {}
    });

    // 批量操作状态
    const [batchDialogOpen, setBatchDialogOpen] = useState(false);
    const [batchResultOpen, setBatchResultOpen] = useState(false);
    const [batchAction, setBatchAction] = useState<'approve' | 'reject'>('approve');
    const [batchResult, setBatchResult] = useState({ success: 0, failed: 0, errors: [] as BatchError[] });
    const [batchProcessing, setBatchProcessing] = useState(false);

    const [form] = Form.useForm();

    // 加载批次列表
    const loadBatches = useCallback(async () => {
        setLoading(true);
        try {
            const result = await archiveBatchApi.listBatches(page, pageSize, undefined, statusFilter);
            setBatches(result.records);
            setTotal(result.total);
        } catch {
            message.error('加载批次列表失败');
        } finally {
            setLoading(false);
        }
    }, [page, pageSize, statusFilter]);

    // 加载统计
    const loadStats = useCallback(async () => {
        try {
            const data = await archiveBatchApi.getStats();
            setStats(data);
        } catch {
            // 忽略统计加载失败
        }
    }, []);

    useEffect(() => {
        loadBatches();
        loadStats();
    }, [loadBatches, loadStats]);

    // 创建批次
    const handleCreate = async (values: { period: [dayjs.Dayjs, dayjs.Dayjs] }) => {
        try {
            await archiveBatchApi.createBatch({
                fondsId: currentFonds?.id ? parseInt(currentFonds.id) : 1,
                periodStart: values.period[0].format('YYYY-MM-DD'),
                periodEnd: values.period[1].format('YYYY-MM-DD'),
            });
            message.success('创建成功');
            setCreateModalVisible(false);
            form.resetFields();
            loadBatches();
            loadStats();
        } catch (err: any) {
            message.error(err.message || '创建失败');
        }
    };

    // 查看详情
    const handleViewDetail = async (batch: ArchiveBatch) => {
        setSelectedBatch(batch);
        setDetailModalVisible(true);

        try {
            const items = await archiveBatchApi.getItems(batch.id);
            setBatchItems(items);

            if (batch.integrityReport) {
                setIntegrityReport(batch.integrityReport);
            }
        } catch {
            message.error('加载批次详情失败');
        }
    };

    // 提交校验
    const handleSubmit = async (batchId: number) => {
        try {
            await archiveBatchApi.submitBatch(batchId);
            message.success('提交成功，正在校验');
            loadBatches();
        } catch (err: any) {
            message.error(err.message || '提交失败');
        }
    };

    // 打开审批弹窗
    const openApprovalModal = (batch: ArchiveBatch, action: 'approve' | 'reject') => {
        setSelectedBatch(batch);
        setApprovalAction(action);
        setApprovalComment('');
        setApprovalModalVisible(true);
    };

    // 执行审批
    const handleApproval = async () => {
        if (!selectedBatch) return;

        try {
            if (approvalAction === 'approve') {
                await archiveBatchApi.approveBatch(selectedBatch.id, approvalComment);
                message.success('审批通过');
            } else {
                if (!approvalComment.trim()) {
                    message.error('请填写驳回原因');
                    return;
                }
                await archiveBatchApi.rejectBatch(selectedBatch.id, approvalComment);
                message.success('已驳回');
            }
            setApprovalModalVisible(false);
            loadBatches();
            loadStats();
        } catch (err: any) {
            message.error(err.message || '操作失败');
        }
    };

    // 执行归档
    const handleArchive = async (batchId: number) => {
        try {
            await archiveBatchApi.executeBatchArchive(batchId);
            message.success('归档完成');
            loadBatches();
            loadStats();
        } catch (err: any) {
            message.error(err.message || '归档失败');
        }
    };

    // 执行四性检测
    const handleIntegrityCheck = async (batchId: number) => {
        try {
            const report = await archiveBatchApi.runIntegrityCheck(batchId);
            setIntegrityReport(report);
            message.success('四性检测完成');
        } catch (err: any) {
            message.error(err.message || '检测失败');
        }
    };

    // 删除批次
    const handleDelete = async (batchId: number) => {
        try {
            await archiveBatchApi.deleteBatch(batchId);
            message.success('删除成功');
            loadBatches();
            loadStats();
        } catch (err: any) {
            message.error(err.message || '删除失败');
        }
    };

    // 加载可选凭证列表（预归档库中待归档的凭证）
    const loadAvailableVouchers = async () => {
        if (!selectedBatch) return;
        setLoadingVouchers(true);
        try {
            // 调用预归档库 API 获取待归档凭证
            const response = await fetch('/api/pool?page=1&size=100&status=PENDING_ARCHIVE');
            const data = await response.json();
            if (data.code === 200) {
                setAvailableVouchers(data.data?.records || data.data || []);
            }
        } catch {
            message.error('加载凭证列表失败');
        } finally {
            setLoadingVouchers(false);
        }
    };

    // 添加选中的凭证到批次
    const handleAddVouchersToBatch = async () => {
        if (!selectedBatch || selectedVoucherIds.length === 0) return;
        try {
            const added = await archiveBatchApi.addVouchers(selectedBatch.id, selectedVoucherIds);
            message.success(`已添加 ${added} 条凭证`);
            setAddVoucherModalVisible(false);
            setSelectedVoucherIds([]);
            // 刷新条目列表
            const items = await archiveBatchApi.getItems(selectedBatch.id);
            setBatchItems(items);
            // 刷新批次信息
            const updatedBatch = await archiveBatchApi.getBatch(selectedBatch.id);
            setSelectedBatch(updatedBatch);
            loadBatches();
        } catch (err: any) {
            message.error(err.message || '添加失败');
        }
    };

    // ========== 批量操作处理函数 ==========

    const handleBatchApprove = () => {
        setBatchAction('approve');
        setBatchDialogOpen(true);
    };

    const handleBatchReject = () => {
        setBatchAction('reject');
        setBatchDialogOpen(true);
    };

    const handleBatchConfirm = async (comment: string, skipIds: number[]) => {
        const selectedIdArray = Array.from(selectedIds).filter(id => !skipIds.includes(id));

        // 添加边界检查
        if (selectedIdArray.length === 0) {
            message.warning('请选择至少一条记录');
            return;
        }

        if (selectedIdArray.length > 100) {
            message.warning('单次最多 100 条，请分批操作');
            return;
        }

        try {
            setBatchProcessing(true);

            const request = {
                batchIds: selectedIdArray,
                operatorId: user?.id || '',
                operatorName: user?.realName || user?.username || '',
                comment: comment || (batchAction === 'approve' ? '批量批准' : '批量拒绝')
            };

            const result = batchAction === 'approve'
                ? await archiveBatchApi.batchApprove(request)
                : await archiveBatchApi.batchReject(request);

            setBatchResult({
                success: result.success,
                failed: result.failed,
                errors: result.errors || []
            });

            setBatchDialogOpen(false);
            setBatchResultOpen(true);
            clearSelection();
            loadBatches();
            loadStats();

            if (result.failed === 0) {
                message.success(`批量${batchAction === 'approve' ? '批准' : '拒绝'}成功`);
            } else if (result.success === 0) {
                message.error(`批量${batchAction === 'approve' ? '批准' : '拒绝'}失败`);
            } else {
                message.warning(`部分成功：${result.success}条成功，${result.failed}条失败`);
            }
        } catch (err: any) {
            message.error(err.message || `批量${batchAction === 'approve' ? '批准' : '拒绝'}失败，请重试`);
        } finally {
            setBatchProcessing(false);
        }
    };

    const handleBatchRetry = async (failedIds: number[]) => {
        try {
            setBatchProcessing(true);

            const request = {
                batchIds: failedIds,
                operatorId: user?.id || '',
                operatorName: user?.realName || user?.username || '',
                comment: batchAction === 'approve' ? '重试批量批准' : '重试批量拒绝'
            };

            const result = batchAction === 'approve'
                ? await archiveBatchApi.batchApprove(request)
                : await archiveBatchApi.batchReject(request);

            setBatchResult({
                success: result.success,
                failed: result.failed,
                errors: result.errors || []
            });

            loadBatches();
            loadStats();

            if (result.failed === 0) {
                message.success('重试成功');
                setBatchResultOpen(false);
            } else if (result.success === 0) {
                message.error('重试失败');
            } else {
                message.warning(`部分成功：${result.success}条成功，${result.failed}条失败`);
            }
        } catch (err: any) {
            message.error(err.message || '重试失败，请重试');
        } finally {
            setBatchProcessing(false);
        }
    };

    const handleSelectAll = () => {
        const allIds = batches.map(b => b.id);
        const result = selectAll(allIds);
        if (!result.success) {
            message.warning(result.reason || '全选失败');
        }
    };

    // 获取选中的记录列表
    const selectedRecords = useMemo<ApprovalRecord[]>(() => {
        return batches
            .filter(b => selectedIds.has(b.id))
            .map(b => ({
                id: b.id,
                title: b.batchNo,
                code: b.batchNo
            }));
    }, [batches, selectedIds]);

    // 表格列
    const columns: ColumnsType<ArchiveBatch> = [
        {
            title: '批次编号',
            dataIndex: 'batchNo',
            key: 'batchNo',
            width: 140,
            render: (text, record) => (
                <a onClick={() => handleViewDetail(record)}>{text}</a>
            ),
        },
        {
            title: '归档期间',
            key: 'period',
            width: 200,
            render: (_, record) => (
                <span>
                    {record.periodStart} ~ {record.periodEnd}
                </span>
            ),
        },
        {
            title: '凭证数',
            dataIndex: 'voucherCount',
            key: 'voucherCount',
            width: 80,
            align: 'center',
        },
        {
            title: '单据数',
            dataIndex: 'docCount',
            key: 'docCount',
            width: 80,
            align: 'center',
        },
        {
            title: '状态',
            dataIndex: 'status',
            key: 'status',
            width: 100,
            render: (status: BatchStatus) => {
                const config = STATUS_CONFIG[status];
                return <Tag color={config?.color}>{config?.text || status}</Tag>;
            },
        },
        {
            title: '创建时间',
            dataIndex: 'createdTime',
            key: 'createdTime',
            width: 160,
            render: (text) => dayjs(text).format('YYYY-MM-DD HH:mm'),
        },
        {
            title: '操作',
            key: 'action',
            width: 280,
            render: (_, record) => (
                <Space size="small">
                    <Tooltip title="查看详情">
                        <Button
                            type="text"
                            icon={<EyeOutlined />}
                            onClick={() => handleViewDetail(record)}
                        />
                    </Tooltip>

                    {record.status === 'PENDING' && (
                        <>
                            <Button
                                type="primary"
                                size="small"
                                onClick={() => handleSubmit(record.id)}
                            >
                                提交校验
                            </Button>
                            <Popconfirm
                                title="确定删除此批次？"
                                onConfirm={() => handleDelete(record.id)}
                            >
                                <Button type="text" danger icon={<DeleteOutlined />} />
                            </Popconfirm>
                        </>
                    )}

                    {record.status === 'VALIDATING' && (
                        <>
                            <Button
                                type="primary"
                                size="small"
                                icon={<CheckCircleOutlined />}
                                onClick={() => openApprovalModal(record, 'approve')}
                            >
                                通过
                            </Button>
                            <Button
                                size="small"
                                danger
                                icon={<CloseCircleOutlined />}
                                onClick={() => openApprovalModal(record, 'reject')}
                            >
                                驳回
                            </Button>
                        </>
                    )}

                    {record.status === 'APPROVED' && (
                        <Popconfirm
                            title="确定执行归档？归档后数据将不可修改。"
                            onConfirm={() => handleArchive(record.id)}
                        >
                            <Button
                                type="primary"
                                size="small"
                                icon={<PlayCircleOutlined />}
                            >
                                执行归档
                            </Button>
                        </Popconfirm>
                    )}
                </Space>
            ),
        },
    ];

    // 条目表格列
    const itemColumns: ColumnsType<ArchiveBatchItem> = [
        {
            title: '类型',
            dataIndex: 'itemType',
            key: 'itemType',
            width: 100,
            render: (type) => (
                <Tag color={type === 'VOUCHER' ? 'blue' : 'green'}>
                    {type === 'VOUCHER' ? '凭证' : '单据'}
                </Tag>
            ),
        },
        {
            title: '编号',
            dataIndex: 'refNo',
            key: 'refNo',
        },
        {
            title: '状态',
            dataIndex: 'status',
            key: 'status',
            width: 100,
            render: (status) => {
                const config: Record<string, { color: string; text: string }> = {
                    PENDING: { color: 'default', text: '待校验' },
                    VALIDATED: { color: 'success', text: '已校验' },
                    ARCHIVED: { color: 'green', text: '已归档' },
                    FAILED: { color: 'error', text: '失败' },
                };
                return <Tag color={config[status]?.color}>{config[status]?.text}</Tag>;
            },
        },
    ];

    return (
        <div className="p-6">
            {/* 统计卡片 */}
            <Row gutter={16} className="mb-6">
                <Col span={4}>
                    <Card>
                        <Statistic title="总批次" value={stats.total} />
                    </Card>
                </Col>
                <Col span={4}>
                    <Card>
                        <Statistic
                            title="待提交"
                            value={stats.byStatus?.PENDING || 0}
                            valueStyle={{ color: '#999' }}
                        />
                    </Card>
                </Col>
                <Col span={4}>
                    <Card>
                        <Statistic
                            title="待审批"
                            value={stats.byStatus?.VALIDATING || 0}
                            valueStyle={{ color: '#1890ff' }}
                        />
                    </Card>
                </Col>
                <Col span={4}>
                    <Card>
                        <Statistic
                            title="待归档"
                            value={stats.byStatus?.APPROVED || 0}
                            valueStyle={{ color: '#faad14' }}
                        />
                    </Card>
                </Col>
                <Col span={4}>
                    <Card>
                        <Statistic
                            title="已归档"
                            value={stats.byStatus?.ARCHIVED || 0}
                            valueStyle={{ color: '#52c41a' }}
                        />
                    </Card>
                </Col>
                <Col span={4}>
                    <Card>
                        <Statistic
                            title="已驳回"
                            value={stats.byStatus?.REJECTED || 0}
                            valueStyle={{ color: '#ff4d4f' }}
                        />
                    </Card>
                </Col>
            </Row>

            {/* 批次列表 */}
            <Card
                title="归档批次管理"
                extra={
                    <Space>
                        <Select
                            placeholder="状态筛选"
                            allowClear
                            style={{ width: 120 }}
                            value={statusFilter}
                            onChange={setStatusFilter}
                            options={Object.entries(STATUS_CONFIG).map(([value, config]) => ({
                                value,
                                label: config.text,
                            }))}
                        />
                        <Button icon={<ReloadOutlined />} onClick={loadBatches}>
                            刷新
                        </Button>
                        <Button
                            type="primary"
                            icon={<PlusOutlined />}
                            onClick={() => setCreateModalVisible(true)}
                        >
                            创建批次
                        </Button>
                    </Space>
                }
            >
                {/* 批量操作工具栏 */}
                <BatchOperationBar
                    selectedCount={getSelectedCount()}
                    totalCount={batches.length}
                    onBatchApprove={handleBatchApprove}
                    onBatchReject={handleBatchReject}
                    onSelectAll={handleSelectAll}
                    onClear={clearSelection}
                    loading={batchProcessing}
                />

                <Table
                    columns={columns}
                    dataSource={batches}
                    rowKey="id"
                    rowSelection={rowSelection}
                    loading={loading}
                    pagination={{
                        current: page,
                        pageSize,
                        total,
                        showSizeChanger: true,
                        showTotal: (t) => `共 ${t} 条`,
                        onChange: (p, s) => {
                            setPage(p);
                            setPageSize(s);
                        },
                    }}
                />
            </Card>

            {/* 创建批次弹窗 */}
            <Modal
                title="创建归档批次"
                open={createModalVisible}
                onCancel={() => setCreateModalVisible(false)}
                onOk={() => form.submit()}
            >
                <Form form={form} layout="vertical" onFinish={handleCreate}>
                    <Form.Item
                        name="period"
                        label="归档期间"
                        rules={[{ required: true, message: '请选择归档期间' }]}
                    >
                        <RangePicker style={{ width: '100%' }} />
                    </Form.Item>
                </Form>
            </Modal>

            {/* 详情弹窗 */}
            <Modal
                title={`批次详情 - ${selectedBatch?.batchNo}`}
                open={detailModalVisible}
                onCancel={() => setDetailModalVisible(false)}
                footer={null}
                width={800}
            >
                {selectedBatch && (
                    <Tabs
                        items={[
                            {
                                key: 'info',
                                label: '基本信息',
                                children: (
                                    <Descriptions column={2} bordered size="small">
                                        <Descriptions.Item label="批次编号">
                                            {selectedBatch.batchNo}
                                        </Descriptions.Item>
                                        <Descriptions.Item label="状态">
                                            <Tag color={STATUS_CONFIG[selectedBatch.status]?.color}>
                                                {STATUS_CONFIG[selectedBatch.status]?.text}
                                            </Tag>
                                        </Descriptions.Item>
                                        <Descriptions.Item label="归档期间" span={2}>
                                            {selectedBatch.periodStart} ~ {selectedBatch.periodEnd}
                                        </Descriptions.Item>
                                        <Descriptions.Item label="凭证数">
                                            {selectedBatch.voucherCount}
                                        </Descriptions.Item>
                                        <Descriptions.Item label="单据数">
                                            {selectedBatch.docCount}
                                        </Descriptions.Item>
                                        <Descriptions.Item label="创建时间" span={2}>
                                            {dayjs(selectedBatch.createdTime).format('YYYY-MM-DD HH:mm:ss')}
                                        </Descriptions.Item>
                                        {selectedBatch.archivedAt && (
                                            <Descriptions.Item label="归档时间" span={2}>
                                                {dayjs(selectedBatch.archivedAt).format('YYYY-MM-DD HH:mm:ss')}
                                            </Descriptions.Item>
                                        )}
                                        {selectedBatch.errorMessage && (
                                            <Descriptions.Item label="错误信息" span={2}>
                                                <Alert type="error" message={selectedBatch.errorMessage} />
                                            </Descriptions.Item>
                                        )}
                                    </Descriptions>
                                ),
                            },
                            {
                                key: 'items',
                                label: `条目列表 (${batchItems.length})`,
                                children: (
                                    <div>
                                        {selectedBatch?.status === 'PENDING' && (
                                            <div className="mb-4">
                                                <Button
                                                    type="primary"
                                                    icon={<PlusCircleOutlined />}
                                                    onClick={() => {
                                                        loadAvailableVouchers();
                                                        setAddVoucherModalVisible(true);
                                                    }}
                                                >
                                                    添加凭证
                                                </Button>
                                            </div>
                                        )}
                                        <Table
                                            columns={itemColumns}
                                            dataSource={batchItems}
                                            rowKey="id"
                                            size="small"
                                            pagination={{ pageSize: 10 }}
                                        />
                                    </div>
                                ),
                            },
                            {
                                key: 'integrity',
                                label: (
                                    <span>
                                        <SafetyCertificateOutlined /> 四性检测
                                    </span>
                                ),
                                children: integrityReport ? (
                                    <div>
                                        <Alert
                                            type={integrityReport.overallResult === 'PASS' ? 'success' : 'error'}
                                            message={`检测结果: ${integrityReport.overallResult === 'PASS' ? '通过' : '未通过'}`}
                                            className="mb-4"
                                        />
                                        {integrityReport.checks.map((check, idx) => (
                                            <Card key={idx} size="small" className="mb-2">
                                                <Space>
                                                    {check.result === 'PASS' ? (
                                                        <CheckCircleOutlined style={{ color: '#52c41a' }} />
                                                    ) : (
                                                        <CloseCircleOutlined style={{ color: '#ff4d4f' }} />
                                                    )}
                                                    <span>{check.name}</span>
                                                    <Tag color={check.result === 'PASS' ? 'green' : 'red'}>
                                                        {check.result}
                                                    </Tag>
                                                </Space>
                                            </Card>
                                        ))}
                                    </div>
                                ) : (
                                    <Empty description="暂无检测记录">
                                        <Button
                                            type="primary"
                                            onClick={() => handleIntegrityCheck(selectedBatch.id)}
                                        >
                                            执行四性检测
                                        </Button>
                                    </Empty>
                                ),
                            },
                        ]}
                    />
                )}
            </Modal>

            {/* 审批弹窗 */}
            <Modal
                title={approvalAction === 'approve' ? '审批通过' : '驳回批次'}
                open={approvalModalVisible}
                onCancel={() => setApprovalModalVisible(false)}
                onOk={handleApproval}
                okText={approvalAction === 'approve' ? '确认通过' : '确认驳回'}
                okButtonProps={{
                    danger: approvalAction === 'reject',
                }}
            >
                <div className="mb-4">
                    批次编号: <strong>{selectedBatch?.batchNo}</strong>
                </div>
                <Form.Item
                    label={approvalAction === 'approve' ? '审批意见（可选）' : '驳回原因'}
                    required={approvalAction === 'reject'}
                >
                    <TextArea
                        rows={4}
                        value={approvalComment}
                        onChange={(e) => setApprovalComment(e.target.value)}
                        placeholder={approvalAction === 'approve' ? '请输入审批意见...' : '请输入驳回原因...'}
                    />
                </Form.Item>
            </Modal>

            {/* 添加凭证弹窗 */}
            <Modal
                title="选择凭证添加到批次"
                open={addVoucherModalVisible}
                onCancel={() => {
                    setAddVoucherModalVisible(false);
                    setSelectedVoucherIds([]);
                }}
                onOk={handleAddVouchersToBatch}
                okText="确认添加"
                okButtonProps={{ disabled: selectedVoucherIds.length === 0 }}
                width={700}
            >
                <div className="mb-4">
                    <Alert
                        type="info"
                        message={`已选择 ${selectedVoucherIds.length} 条凭证`}
                        showIcon
                    />
                </div>
                {loadingVouchers ? (
                    <div className="text-center py-8">
                        <Spin tip="加载中..." />
                    </div>
                ) : availableVouchers.length === 0 ? (
                    <Empty description='暂无可添加的凭证（需要状态为"准备归档"的凭证）' />
                ) : (
                    <Table
                        rowSelection={{
                            type: 'checkbox',
                            selectedRowKeys: selectedVoucherIds,
                            onChange: (keys) => setSelectedVoucherIds(keys as number[]),
                        }}
                        columns={[
                            { title: '凭证号', dataIndex: 'erpVoucherNo', key: 'erpVoucherNo' },
                            { title: '摘要', dataIndex: 'summary', key: 'summary', ellipsis: true },
                            { title: '金额', dataIndex: 'amount', key: 'amount' },
                            { title: '日期', dataIndex: 'docDate', key: 'docDate' },
                        ]}
                        dataSource={availableVouchers}
                        rowKey="id"
                        size="small"
                        pagination={{ pageSize: 10 }}
                    />
                )}
            </Modal>

            {/* 批量审批弹窗 */}
            <BatchApprovalDialog
                visible={batchDialogOpen}
                selectedCount={getSelectedCount()}
                action={batchAction}
                onConfirm={handleBatchConfirm}
                onCancel={() => setBatchDialogOpen(false)}
                selectedRecords={selectedRecords}
                loading={batchProcessing}
            />

            {/* 批量操作结果弹窗 */}
            <BatchResultModal
                visible={batchResultOpen}
                successCount={batchResult.success}
                failedCount={batchResult.failed}
                errors={batchResult.errors}
                onRetry={handleBatchRetry}
                onClose={() => setBatchResultOpen(false)}
                operationType="approval"
                isRetrying={batchProcessing}
            />
        </div>
    );
};

export default ArchiveBatchView;

// Input: React、lucide-react、destructionApi、批量操作组件
// Output: DestructionApprovalPage 组件（支持批量审批）
// Pos: 销毁审批页面
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useState, useEffect, useMemo } from 'react';
import { Shield, Loader2, CheckCircle2, XCircle, Eye, Clock, User, MessageSquare, Check, Square } from 'lucide-react';
import { destructionApi, Destruction, DestructionApprovalRequest } from '../../api/destruction';
import { toast } from '../../utils/notificationService';
import {
  BatchOperationBar,
  BatchApprovalDialog,
  BatchResultModal,
  type ApprovalRecord
} from '@/components/operations';

/**
 * 批量选择限制
 */
const MAX_SELECTION_LIMIT = 100;

/**
 * 销毁审批页面
 *
 * 功能：
 * 1. 待审批销毁申请列表
 * 2. 审批表单：审批意见、批准/拒绝
 * 3. 双人审批流程展示
 * 4. 批量审批功能（支持第一/第二审批批量操作）
 *
 * PRD 来源: Section 13 - 档案销毁
 */
export const DestructionApprovalPage: React.FC = () => {
    const [destructions, setDestructions] = useState<Destruction[]>([]);
    const [loading, setLoading] = useState(false);
    const [page, setPage] = useState(1);
    const [total, setTotal] = useState(0);
    const pageSize = 20;

    // 单条审批状态
    const [selectedDestruction, setSelectedDestruction] = useState<Destruction | null>(null);
    const [showApprovalModal, setShowApprovalModal] = useState(false);
    const [approvalType, setApprovalType] = useState<'first' | 'second'>('first');
    const [approvalForm, setApprovalForm] = useState<DestructionApprovalRequest>({
        comment: '',
        approved: true,
    });
    const [submitting, setSubmitting] = useState(false);

    // 批量操作状态
    const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
    const [showBatchDialog, setShowBatchDialog] = useState(false);
    const [batchAction, setBatchAction] = useState<'approve' | 'reject'>('approve');
    const [batchApprovalType, setBatchApprovalType] = useState<'first' | 'second'>('first');
    const [batchProcessing, setBatchProcessing] = useState(false);
    const [batchResult, setBatchResult] = useState<{ success: number; failed: number; errors: Array<{ id: string; reason: string }> } | null>(null);
    const [showResultModal, setShowResultModal] = useState(false);

    const loadDestructions = async () => {
        setLoading(true);
        try {
            const res = await destructionApi.getDestructions({
                page,
                limit: pageSize,
                status: 'PENDING',
            });
            if (res.code === 200 && res.data) {
                setDestructions(res.data.records || []);
                setTotal(res.data.total || 0);
            }
        } catch (error) {
            console.error('加载销毁申请失败', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadDestructions();
    }, [page]);

    // 清空选择
    const clearSelection = () => {
        setSelectedIds(new Set());
    };

    // 切换单条选中
    const toggleSelection = (id: string) => {
        setSelectedIds(prev => {
            const newSet = new Set(prev);
            if (newSet.has(id)) {
                newSet.delete(id);
            } else {
                if (newSet.size >= MAX_SELECTION_LIMIT) {
                    toast.warning(`单次最多选择 ${MAX_SELECTION_LIMIT} 条`);
                    return prev;
                }
                newSet.add(id);
            }
            return newSet;
        });
    };

    // 全选当前页
    const selectAllCurrentPage = () => {
        if (destructions.length > MAX_SELECTION_LIMIT) {
            toast.warning(`当前页超过 ${MAX_SELECTION_LIMIT} 条，请分批选择`);
            return;
        }
        setSelectedIds(new Set(destructions.map(d => d.id)));
    };

    // 批量审批
    const handleBatchAction = (action: 'approve' | 'reject', approvalType: 'first' | 'second') => {
        if (selectedIds.size === 0) return;

        // 检查边界
        if (selectedIds.size > MAX_SELECTION_LIMIT) {
            toast.warning(`单次最多 ${MAX_SELECTION_LIMIT} 条，请分批操作`);
            return;
        }

        setBatchAction(action);
        setBatchApprovalType(approvalType);
        setShowBatchDialog(true);
    };

    // 批量确认
    const handleBatchConfirm = async (comment: string, skipIds: number[]) => {
        setBatchProcessing(true);

        // 转换 skipIds (number) 回 string IDs
        const selectedArray = Array.from(selectedIds);
        const skipIdSet = new Set(skipIds.map(id => selectedArray[id] || ''));
        const finalIds = selectedArray.filter(id => !skipIdSet.has(id));

        try {
            const res = batchAction === 'approve'
                ? await destructionApi.batchApprove({
                    ids: finalIds,
                    comment,
                    approvalType: batchApprovalType,
                })
                : await destructionApi.batchReject({
                    ids: finalIds,
                    comment,
                    approvalType: batchApprovalType,
                });

            if (res.code === 200 && res.data) {
                setBatchResult(res.data);
                setShowResultModal(true);
                setShowBatchDialog(false);
                clearSelection();
                loadDestructions();

                if (res.data.failed === 0) {
                    toast.success(`批量${batchAction === 'approve' ? '批准' : '拒绝'}成功`);
                } else if (res.data.success === 0) {
                    toast.error(`批量${batchAction === 'approve' ? '批准' : '拒绝'}失败`);
                } else {
                    toast.warning(`部分成功：${res.data.success} 条成功，${res.data.failed} 条失败`);
                }
            } else {
                toast.error(res.message || '批量操作失败');
            }
        } catch (error: any) {
            toast.error(error?.response?.data?.message || '批量操作失败');
        } finally {
            setBatchProcessing(false);
        }
    };

    // 重试失败项
    const handleBatchRetry = () => {
        if (!batchResult) return;
        const failedIds = batchResult.errors.map(e => e.id);
        setSelectedIds(new Set(failedIds));
        setShowResultModal(false);
        setBatchResult(null);
        toast.info('已重新选中失败的记录，请重试');
    };

    // 获取批量操作记录（用于弹窗显示）
    const getBatchRecords = useMemo((): ApprovalRecord[] => {
        return Array.from(selectedIds).map((id, index) => {
            const destruction = destructions.find(d => d.id === id);
            return {
                id: index,
                title: destruction ? `申请 #${destruction.id} (${destruction.applicantName})` : `申请 #${id}`,
            };
        });
    }, [selectedIds, destructions]);

    // 单条审批
    const handleApprove = (destruction: Destruction, type: 'first' | 'second') => {
        setSelectedDestruction(destruction);
        setApprovalType(type);
        setApprovalForm({ comment: '', approved: true });
        setShowApprovalModal(true);
    };

    const handleSubmitApproval = async () => {
        if (!selectedDestruction) return;

        setSubmitting(true);
        try {
            const res = await destructionApi.approveDestruction(selectedDestruction.id, approvalForm);
            if (res.code === 200) {
                toast.success('审批成功');
                setShowApprovalModal(false);
                loadDestructions();
            } else {
                toast.error(res.message || '审批失败');
            }
        } catch (error: any) {
            toast.error(error?.response?.data?.message || '审批失败');
        } finally {
            setSubmitting(false);
        }
    };

    const getStatusBadge = (status: string) => {
        const configs: Record<string, { label: string; color: string }> = {
            'PENDING': { label: '待审批', color: 'bg-yellow-100 text-yellow-700' },
            'APPROVED': { label: '已批准', color: 'bg-green-100 text-green-700' },
            'REJECTED': { label: '已拒绝', color: 'bg-red-100 text-red-700' },
        };
        const config = configs[status] || { label: status, color: 'bg-slate-100 text-slate-700' };
        return (
            <span className={`px-3 py-1 rounded-full text-xs font-medium ${config.color}`}>
                {config.label}
            </span>
        );
    };

    const canFirstApprove = (destruction: Destruction) => {
        return destruction.status === 'PENDING' && !destruction.firstApproverId;
    };

    const canSecondApprove = (destruction: Destruction) => {
        return destruction.status === 'PENDING' &&
               destruction.firstApproverId &&
               !destruction.secondApproverId;
    };

    // 判断批量操作状态
    const hasFirstApprovable = destructions.some(canFirstApprove);
    const hasSecondApprovable = destructions.some(canSecondApprove);

    return (
        <div className="p-6 space-y-4">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-2xl font-bold text-slate-800 flex items-center">
                        <Shield className="mr-2" size={28} />
                        销毁审批
                    </h2>
                    <p className="text-slate-500 text-sm mt-1">审批档案销毁申请，支持双人审批流程与批量操作</p>
                </div>
            </div>

            {/* 批量操作工具栏 */}
            {selectedIds.size > 0 && (
                <BatchOperationBar
                    selectedCount={selectedIds.size}
                    totalCount={total}
                    onBatchApprove={() => handleBatchAction('approve', hasFirstApprovable ? 'first' : 'second')}
                    onBatchReject={() => handleBatchAction('reject', hasFirstApprovable ? 'first' : 'second')}
                    onSelectAll={selectAllCurrentPage}
                    onClear={clearSelection}
                />
            )}

            {/* 审批列表 */}
            <div className="bg-white border border-slate-200 rounded-lg overflow-hidden">
                {loading ? (
                    <div className="flex items-center justify-center h-64">
                        <Loader2 className="animate-spin text-slate-400" size={32} />
                    </div>
                ) : destructions.length === 0 ? (
                    <div className="flex flex-col items-center justify-center h-64 text-slate-400">
                        <Shield size={48} className="mb-4" />
                        <p>暂无待审批的销毁申请</p>
                    </div>
                ) : (
                    <>
                        <table className="w-full text-left text-sm">
                            <thead className="bg-slate-50 border-b">
                                <tr>
                                    <th className="px-4 py-3 w-10">
                                        <button
                                            onClick={selectAllCurrentPage}
                                            className="text-slate-500 hover:text-slate-700"
                                            title="全选当前页"
                                        >
                                            {selectedIds.size === destructions.length && destructions.length > 0 ? (
                                                <Check className="text-primary-600" size={16} />
                                            ) : (
                                                <Square size={16} />
                                            )}
                                        </button>
                                    </th>
                                    <th className="px-4 py-3">申请ID</th>
                                    <th className="px-4 py-3">申请人</th>
                                    <th className="px-4 py-3">档案数量</th>
                                    <th className="px-4 py-3">状态</th>
                                    <th className="px-4 py-3">第一审批人</th>
                                    <th className="px-4 py-3">第二审批人</th>
                                    <th className="px-4 py-3">创建时间</th>
                                    <th className="px-4 py-3">操作</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y">
                                {destructions.map(destruction => {
                                    const isSelected = selectedIds.has(destruction.id);
                                    const isRowDisabled = !canFirstApprove(destruction) && !canSecondApprove(destruction);
                                    return (
                                        <tr
                                            key={destruction.id}
                                            className={`hover:bg-slate-50 ${isSelected ? 'bg-primary-50' : ''} ${isRowDisabled ? 'opacity-50' : ''}`}
                                        >
                                            <td className="px-4 py-3">
                                                {!isRowDisabled && (
                                                    <button
                                                        onClick={() => toggleSelection(destruction.id)}
                                                        className="text-slate-500 hover:text-primary-600"
                                                        title={isSelected ? '取消选择' : '选择'}
                                                    >
                                                        {isSelected ? (
                                                            <Check className="text-primary-600" size={16} />
                                                        ) : (
                                                            <Square size={16} />
                                                        )}
                                                    </button>
                                                )}
                                            </td>
                                            <td className="px-4 py-3 font-mono text-xs">{destruction.id}</td>
                                            <td className="px-4 py-3">{destruction.applicantName}</td>
                                            <td className="px-4 py-3">{destruction.archiveCount}</td>
                                            <td className="px-4 py-3">{getStatusBadge(destruction.status)}</td>
                                            <td className="px-4 py-3">
                                                {destruction.firstApproverName ? (
                                                    <div className="flex items-center gap-2">
                                                        <User size={14} className="text-slate-400" />
                                                        <span>{destruction.firstApproverName}</span>
                                                    </div>
                                                ) : (
                                                    <span className="text-slate-400">待审批</span>
                                                )}
                                            </td>
                                            <td className="px-4 py-3">
                                                {destruction.secondApproverName ? (
                                                    <div className="flex items-center gap-2">
                                                        <User size={14} className="text-slate-400" />
                                                        <span>{destruction.secondApproverName}</span>
                                                    </div>
                                                ) : (
                                                    <span className="text-slate-400">待审批</span>
                                                )}
                                            </td>
                                            <td className="px-4 py-3 text-slate-600">
                                                {new Date(destruction.createdAt).toLocaleString('zh-CN')}
                                            </td>
                                            <td className="px-4 py-3">
                                                <div className="flex items-center gap-2">
                                                    {canFirstApprove(destruction) && (
                                                        <button
                                                            onClick={() => handleApprove(destruction, 'first')}
                                                            className="px-3 py-1 bg-primary-600 text-white rounded text-sm hover:bg-primary-700"
                                                        >
                                                            第一审批
                                                        </button>
                                                    )}
                                                    {canSecondApprove(destruction) && (
                                                        <button
                                                            onClick={() => handleApprove(destruction, 'second')}
                                                            className="px-3 py-1 bg-blue-600 text-white rounded text-sm hover:bg-blue-700"
                                                        >
                                                            第二审批
                                                        </button>
                                                    )}
                                                </div>
                                            </td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                        {/* 分页 */}
                        <div className="px-4 py-3 border-t flex items-center justify-between">
                            <div className="text-sm text-slate-600">
                                共 {total} 条，第 {page} / {Math.ceil(total / pageSize)} 页
                            </div>
                            <div className="flex gap-2">
                                <button
                                    onClick={() => setPage(p => Math.max(1, p - 1))}
                                    disabled={page <= 1}
                                    className="px-3 py-1 border rounded text-sm disabled:opacity-50"
                                >
                                    上一页
                                </button>
                                <button
                                    onClick={() => setPage(p => Math.min(Math.ceil(total / pageSize), p + 1))}
                                    disabled={page >= Math.ceil(total / pageSize)}
                                    className="px-3 py-1 border rounded text-sm disabled:opacity-50"
                                >
                                    下一页
                                </button>
                            </div>
                        </div>
                    </>
                )}
            </div>

            {/* 审批模态框 */}
            {showApprovalModal && selectedDestruction && (
                <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
                    <div className="bg-white rounded-lg shadow-xl max-w-md w-full mx-4">
                        <div className="px-6 py-4 border-b border-slate-200">
                            <h2 className="text-lg font-semibold">
                                {approvalType === 'first' ? '第一审批' : '第二审批（复核）'}
                            </h2>
                        </div>
                        <div className="p-6 space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">
                                    审批意见
                                </label>
                                <textarea
                                    value={approvalForm.comment}
                                    onChange={(e) => setApprovalForm({ ...approvalForm, comment: e.target.value })}
                                    rows={4}
                                    className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-500"
                                    placeholder="请输入审批意见..."
                                />
                            </div>
                            <div>
                                <label className="flex items-center gap-2">
                                    <input
                                        type="checkbox"
                                        checked={approvalForm.approved}
                                        onChange={(e) => setApprovalForm({ ...approvalForm, approved: e.target.checked })}
                                        className="w-4 h-4 text-primary-600 border-slate-300 rounded focus:ring-primary-500"
                                    />
                                    <span className="text-sm text-slate-700">批准</span>
                                </label>
                            </div>
                            <div className="flex gap-3">
                                <button
                                    onClick={handleSubmitApproval}
                                    disabled={submitting}
                                    className="flex-1 px-4 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                                >
                                    {submitting ? (
                                        <Loader2 className="animate-spin" size={16} />
                                    ) : (
                                        <>
                                            {approvalForm.approved ? (
                                                <CheckCircle2 size={16} />
                                            ) : (
                                                <XCircle size={16} />
                                            )}
                                            提交审批
                                        </>
                                    )}
                                </button>
                                <button
                                    onClick={() => setShowApprovalModal(false)}
                                    className="px-4 py-2 border border-slate-300 rounded-lg text-slate-700 hover:bg-slate-50"
                                >
                                    取消
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}

            {/* 批量审批对话框 */}
            <BatchApprovalDialog
                visible={showBatchDialog}
                selectedCount={selectedIds.size}
                action={batchAction}
                onConfirm={handleBatchConfirm}
                onCancel={() => setShowBatchDialog(false)}
                selectedRecords={getBatchRecords}
                loading={batchProcessing}
            />

            {/* 批量结果弹窗 */}
            <BatchResultModal
                visible={showResultModal}
                successCount={batchResult?.success ?? 0}
                failedCount={batchResult?.failed ?? 0}
                errors={batchResult?.errors.map(e => ({
                    id: parseInt(e.id) || 0,
                    reason: e.reason,
                })) ?? []}
                onClose={() => setShowResultModal(false)}
                onRetry={handleBatchRetry}
            />
        </div>
    );
};

export default DestructionApprovalPage;

// Input: React、lucide-react、destructionApi
// Output: DestructionExecutionPage 组件
// Pos: 销毁执行页面
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useState, useEffect } from 'react';
import { Flame, Loader2, CheckCircle2, AlertTriangle, Play, RefreshCw } from 'lucide-react';
import { destructionApi, Destruction } from '../../api/destruction';
import { toast } from '../../utils/notificationService';

/**
 * 销毁执行页面
 * 
 * 功能：
 * 1. 已审批的销毁任务列表
 * 2. 执行销毁操作
 * 3. 销毁进度显示
 * 
 * PRD 来源: Section 13 - 档案销毁
 */
export const DestructionExecutionPage: React.FC = () => {
    const [destructions, setDestructions] = useState<Destruction[]>([]);
    const [loading, setLoading] = useState(false);
    const [page, setPage] = useState(1);
    const [total, setTotal] = useState(0);
    const pageSize = 20;
    const [executing, setExecuting] = useState<string | null>(null);

    const loadDestructions = async () => {
        setLoading(true);
        try {
            const res = await destructionApi.getDestructions({
                page,
                limit: pageSize,
                status: 'APPROVED',
            });
            if (res.code === 200 && res.data) {
                setDestructions(res.data.records || []);
                setTotal(res.data.total || 0);
            }
        } catch (error) {
            console.error('加载销毁任务失败', error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadDestructions();
    }, [page]);

    const handleExecute = async (id: string) => {
        if (!window.confirm('确认执行销毁操作吗？此操作不可逆！')) {
            return;
        }

        setExecuting(id);
        try {
            const res = await destructionApi.executeDestruction(id);
            if (res.code === 200) {
                toast.success('销毁执行成功');
                loadDestructions();
            } else {
                toast.error(res.message || '执行失败');
            }
        } catch (error: any) {
            toast.error(error?.response?.data?.message || '执行失败');
        } finally {
            setExecuting(null);
        }
    };

    const getStatusBadge = (status: string) => {
        const configs: Record<string, { label: string; color: string; icon: React.ReactNode }> = {
            'APPROVED': {
                label: '已批准',
                color: 'bg-green-100 text-green-700',
                icon: <CheckCircle2 className="w-4 h-4" />
            },
            'EXECUTING': {
                label: '执行中',
                color: 'bg-blue-100 text-blue-700',
                icon: <Loader2 className="w-4 h-4 animate-spin" />
            },
            'COMPLETED': {
                label: '已完成',
                color: 'bg-slate-100 text-slate-700',
                icon: <CheckCircle2 className="w-4 h-4" />
            },
        };
        const config = configs[status] || { label: status, color: 'bg-slate-100 text-slate-700', icon: null };
        return (
            <span className={`px-3 py-1 rounded-full text-xs font-medium flex items-center gap-1 w-fit ${config.color}`}>
                {config.icon}
                {config.label}
            </span>
        );
    };

    return (
        <div className="p-6 space-y-4">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-2xl font-bold text-slate-800 flex items-center">
                        <Flame className="mr-2" size={28} />
                        销毁执行
                    </h2>
                    <p className="text-slate-500 text-sm mt-1">执行已审批的档案销毁任务</p>
                </div>
                <button
                    onClick={loadDestructions}
                    className="px-4 py-2 border border-slate-300 rounded-lg text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                >
                    <RefreshCw size={16} />
                    刷新
                </button>
            </div>

            {/* 警告提示 */}
            <div className="bg-red-50 border border-red-200 rounded-lg p-4 flex items-start gap-3">
                <AlertTriangle className="text-red-600 flex-shrink-0 mt-0.5" size={20} />
                <div className="text-sm text-red-800">
                    <div className="font-semibold mb-1">警告：销毁操作不可逆</div>
                    <div>执行销毁后，相关档案将被永久删除，无法恢复。请确保已做好备份和确认工作。</div>
                </div>
            </div>

            {/* 销毁任务列表 */}
            <div className="bg-white border border-slate-200 rounded-lg overflow-hidden">
                {loading ? (
                    <div className="flex items-center justify-center h-64">
                        <Loader2 className="animate-spin text-slate-400" size={32} />
                    </div>
                ) : destructions.length === 0 ? (
                    <div className="flex flex-col items-center justify-center h-64 text-slate-400">
                        <Flame size={48} className="mb-4" />
                        <p>暂无待执行的销毁任务</p>
                    </div>
                ) : (
                    <>
                        <table className="w-full text-left text-sm">
                            <thead className="bg-slate-50 border-b">
                                <tr>
                                    <th className="px-4 py-3">申请ID</th>
                                    <th className="px-4 py-3">申请人</th>
                                    <th className="px-4 py-3">档案数量</th>
                                    <th className="px-4 py-3">状态</th>
                                    <th className="px-4 py-3">第一审批人</th>
                                    <th className="px-4 py-3">第二审批人</th>
                                    <th className="px-4 py-3">审批时间</th>
                                    <th className="px-4 py-3">操作</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y">
                                {destructions.map(destruction => (
                                    <tr key={destruction.id} className="hover:bg-slate-50">
                                        <td className="px-4 py-3 font-mono text-xs">{destruction.id}</td>
                                        <td className="px-4 py-3">{destruction.applicantName}</td>
                                        <td className="px-4 py-3">{destruction.archiveCount}</td>
                                        <td className="px-4 py-3">{getStatusBadge(destruction.status)}</td>
                                        <td className="px-4 py-3">{destruction.firstApproverName || '-'}</td>
                                        <td className="px-4 py-3">{destruction.secondApproverName || '-'}</td>
                                        <td className="px-4 py-3 text-slate-600">
                                            {destruction.secondApprovalTime 
                                                ? new Date(destruction.secondApprovalTime).toLocaleString('zh-CN')
                                                : '-'}
                                        </td>
                                        <td className="px-4 py-3">
                                            {destruction.status === 'APPROVED' && (
                                                <button
                                                    onClick={() => handleExecute(destruction.id)}
                                                    disabled={executing === destruction.id}
                                                    className="px-3 py-1 bg-red-600 text-white rounded text-sm hover:bg-red-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-1"
                                                >
                                                    {executing === destruction.id ? (
                                                        <Loader2 className="animate-spin" size={14} />
                                                    ) : (
                                                        <Play size={14} />
                                                    )}
                                                    执行销毁
                                                </button>
                                            )}
                                            {destruction.status === 'EXECUTING' && (
                                                <span className="text-sm text-blue-600">执行中...</span>
                                            )}
                                            {destruction.status === 'COMPLETED' && (
                                                <span className="text-sm text-slate-400">已完成</span>
                                            )}
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                        {/* 分页 */}
                        <div className="px-4 py-3 border-t flex items-center justify-between">
                            <div className="text-sm text-slate-600">
                                共 {total} 条，第 {page} / {Math.ceil(total / pageSize)} 页
                            </div>
                            <div className="flex gap-2">
                                <button
                                    onClick={() => setPage(p => Math.max(1, p - 1))}
                                    disabled={page <= 1}
                                    className="px-3 py-1 border rounded text-sm disabled:opacity-50"
                                >
                                    上一页
                                </button>
                                <button
                                    onClick={() => setPage(p => Math.min(Math.ceil(total / pageSize), p + 1))}
                                    disabled={page >= Math.ceil(total / pageSize)}
                                    className="px-3 py-1 border rounded text-sm disabled:opacity-50"
                                >
                                    下一页
                                </button>
                            </div>
                        </div>
                    </>
                )}
            </div>
        </div>
    );
};

export default DestructionExecutionPage;

