 * PRD 来源: Section 6.2 - 冻结/保全管理
 */
export const FreezeHoldDetailPage: React.FC = () => {
    const { id } = useParams<{ id: string }>();
    const navigate = useNavigate();
    const [record, setRecord] = useState<FreezeHoldRecord | null>(null);
    const [loading, setLoading] = useState(false);
    const [showReleaseModal, setShowReleaseModal] = useState(false);
    const [releaseReason, setReleaseReason] = useState('');
    const [releasing, setReleasing] = useState(false);

    useEffect(() => {
        if (id) {
            loadDetail();
        }
    }, [id]);

    const loadDetail = async () => {
        if (!id) return;
        setLoading(true);
        try {
            const res = await freezeHoldApi.getDetail(id);
            if (res.code === 200 && res.data) {
                setRecord(res.data);
            }
        } catch (error) {
            console.error('加载详情失败', error);
        } finally {
            setLoading(false);
        }
    };

    const handleRelease = async () => {
        if (!record) return;
        if (!releaseReason.trim()) {
            toast.warning('请填写解除原因');
            return;
        }

        setReleasing(true);
        try {
            const res = await freezeHoldApi.release({ id: record.id, reason: releaseReason });
            if (res.code === 200) {
                toast.success('解除成功');
                navigate(-1);
            } else {
                toast.error(res.message || '解除失败');
            }
        } catch (error: any) {
            toast.error(error?.response?.data?.message || '解除失败');
