                    </div>
                )}
            </div>

            {/* 解除模态框 */}
            {showReleaseModal && (
                <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
                    <div className="bg-white rounded-lg shadow-xl max-w-xl w-full mx-4">
