interface EvidencePreviewProps {
    voucherId: string;
    highlightField?: string | null;
    onInteract?: (fieldId: string) => void;
    sourceType?: 'ARCHIVE' | 'ORIGINAL' | null;
    simpleMode?: boolean;
}

const TAB_CONFIG = [
    { id: 'invoice', label: '原始凭证' },
    { id: 'bank_slip', label: '银行回单' },
    { id: 'contract', label: '合同文件' },
    { id: 'other', label: '附件' }
] as const;

type TabType = typeof TAB_CONFIG[number]['id'];

/**
 * 全景视图 - 证据预览组件（只读模式）
 * 
 * 【合规说明】DA/T 94-2022 第6.3条
 * 电子会计档案一经归档，不得进行修改、删除、替换原有内容。
 * 因此已归档档案的附件区只能查看，不能添加/修改。
 * 
 * 附件上传功能应在"电子凭证池"中进行（归档前阶段）。
 */
interface InvoiceOverlayProps {
    highlightField?: string | null;
    onInteract?: (fieldId: string) => void;
    highlightMeta?: string | null; // JSON string from backend
}

interface HighlightMetaData {
    width?: number;
    height?: number;
    regions?: Record<string, { x: number; y: number; w: number; h: number }>;
}

const InvoiceOverlay: React.FC<InvoiceOverlayProps> = ({ highlightField, onInteract, highlightMeta }) => {
    // 只使用后端真实解析的数据，不使用任何 Mock 数据
    // If no highlightMeta from backend, don't render any overlay
    if (!highlightMeta) {
        return null;
    }

    const regions: Record<string, React.CSSProperties> = {};

    try {
        const meta: HighlightMetaData = JSON.parse(highlightMeta);
        if (meta.regions && meta.width && meta.height) {
            const pageWidth = meta.width;
            const pageHeight = meta.height;
            // Convert to percentage-based styles for CSS overlay
            for (const [key, rect] of Object.entries(meta.regions)) {
                regions[key] = {
                    left: `${(rect.x / pageWidth) * 100}%`,
                    top: `${(rect.y / pageHeight) * 100}%`,
                    width: `${(rect.w / pageWidth) * 100}%`,
                    height: `${(rect.h / pageHeight) * 100}%`,
                    position: 'absolute',
                };
            }
        }
    } catch (e) {
        console.warn('Failed to parse highlightMeta', e);
        return null;
    }

    // If no regions parsed, don't render anything
    if (Object.keys(regions).length === 0) {
        return null;
    }

    return (
        <div className="absolute inset-0 z-10 pointer-events-none">
            {Object.entries(regions).map(([key, style]) => {
                const isActive = highlightField === key ||
                    (key.startsWith('tax_') && highlightField?.startsWith('entry_')) ||
                    (key === 'total_amount' && highlightField === 'total_amount');

                return (
                    <div
                        key={key}
                        className={`cursor-pointer transition-all duration-300 pointer-events-auto ${isActive
                            ? 'bg-yellow-400/30 border-2 border-yellow-500 shadow-[0_0_15px_rgba(234,179,8,0.5)]'
                            : 'hover:bg-yellow-400/10 hover:border-2 hover:border-yellow-300'
                            }`}
                        style={style}
                        onClick={() => onInteract?.(key)}
                        title={key === 'total_amount' ? '金额合计' : key.includes('tax') ? '税额' : key}
                    />
                );
            })}
        </div>
    );
};

export const EvidencePreview: React.FC<EvidencePreviewProps> = ({ voucherId, highlightField, onInteract, sourceType, simpleMode = false }) => {
    const [files, setFiles] = useState<AttachmentFile[]>([]);
    const [activeTab, setActiveTab] = useState<TabType>('invoice');
    const [selectedFile, setSelectedFile] = useState<AttachmentFile | null>(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    // Get auth token for FileViewer (pages can use store)
    const token = useAuthStore(state => state.token);

    // 加载附件列表
    const loadFiles = useCallback(async () => {
        if (!voucherId) return;

        setLoading(true);
        setError(null);
        try {
            if (sourceType === 'ORIGINAL') {
                const ovFiles = await originalVoucherApi.getOriginalVoucherFiles(voucherId);
                if (ovFiles && ovFiles.length > 0) {
                    const converted = ovFiles.map(f => ({
                        id: f.id,
                        fileName: f.fileName,
                        fileType: f.fileType,
                        fileSize: f.fileSize,
                        storagePath: f.storagePath,
                        docType: (f.fileRole === 'PRIMARY' || f.fileRole === 'ORIGINAL') ? 'invoice' :
                            (f.fileName?.includes('回单') ? 'bank_slip' :
                                (f.fileName?.includes('合同') ? 'contract' : 'other')),
                        highlightMeta: (f as any).highlightMeta || null
                    })) as any[];
                    setFiles(converted);
                } else {
                    setFiles([]);
                    setSelectedFile(null);
                }
            } else {
                const attachments = await attachmentsApi.getByArchive(voucherId);
                if (attachments && attachments.length > 0) {
                    setFiles(attachments);
                } else if (sourceType === null) {
                    // 降级尝试
                    const ovFiles = await originalVoucherApi.getOriginalVoucherFiles(voucherId);
                    if (ovFiles && ovFiles.length > 0) {
                        const converted = ovFiles.map(f => ({
                            id: f.id,
                            fileName: f.fileName,
                            fileType: f.fileType,
                            fileSize: f.fileSize,
                            storagePath: f.storagePath,
                            docType: (f.fileRole === 'PRIMARY' || f.fileRole === 'ORIGINAL') ? 'invoice' : 'other'
                        })) as any[];
                        setFiles(converted);
                        setSelectedFile(converted[0] || null);
                    }
                } else {
                    setFiles([]);
                    setSelectedFile(null);
                }
            }
        } catch {
            setError('加载附件失败');
        } finally {
            setLoading(false);
        }
    }, [voucherId, sourceType]);

    useEffect(() => {
        loadFiles();
    }, [loadFiles]);

    // 切换标签时更新选中文件
    useEffect(() => {
        const firstFile = files.find(f => f.docType === activeTab);
        setSelectedFile(firstFile || null);
    }, [activeTab, files]);

    // 构建文件预览 URL
    const getPreviewUrl = (file: AttachmentFile): string => {
        if (!file.id) return '';

        // 根据来源选择不同的下载接口
        if (sourceType === 'ARCHIVE') {
            return `/api/archive/files/download/${file.id}`;
        } else {
            return `/api/original-vouchers/files/download/${file.id}`;
        }
    };

    // 当前页签对应的文件
    const currentTabFiles = simpleMode ? files : files.filter(f => f.docType === activeTab);

    // 渲染空状态
    if (!voucherId) {
        return (
            <div className="h-full flex items-center justify-center text-slate-400 bg-slate-50/50 border-l border-slate-200">
                <div className="text-center">
                    <Paperclip size={48} className="mx-auto mb-4 opacity-20" />
                    <p>选择凭证以查看关联证据</p>
                </div>
            </div>
        );
    }

    return (
        <div className="h-full flex flex-col bg-white border-l border-slate-200">
            {/* 标签页 */}
            {!simpleMode && (
                <div className="flex border-b border-slate-200 bg-slate-50">
                    {TAB_CONFIG.map(tab => (
                        <button
                            key={tab.id}
                            onClick={() => setActiveTab(tab.id)}
                            className={`flex-1 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === tab.id
                                ? 'border-primary-500 text-primary-700 bg-white'
                                : 'border-transparent text-slate-500 hover:text-slate-700 hover:bg-slate-100'
                                }`}
                        >
                            {tab.label}
                            {files.filter(f => f.docType === tab.id).length > 0 && (
                                <span className="ml-1 text-xs text-slate-400">
                                    ({files.filter(f => f.docType === tab.id).length})
                                </span>
                            )}
                        </button>
                    ))}
                </div>
            )}

            {/* 工具栏 - 只读模式，已归档档案不可添加附件 */}
            <div className="flex items-center justify-between px-3 py-2 bg-slate-50 border-b border-slate-200">
                <span className="text-xs text-slate-500">
                    关联文件 {files.length} 个
                </span>
                <span className="text-xs text-slate-400 font-medium">
                    {sourceType === 'ARCHIVE' ? '已归档 · 只读' : '原始凭证 · 待归档'}
                </span>
            </div>

            {/* 错误提示 */}
            {error && (
                <div className="px-3 py-2 bg-red-50 border-b border-red-100 flex items-center gap-2 text-sm text-red-600">
                    <AlertCircle size={14} />
                    {error}
                    <button onClick={() => setError(null)} className="ml-auto text-xs underline">关闭</button>
                </div>
            )}

            {/* 文件列表（多个文件时显示） */}
            {currentTabFiles.length > 1 && (
                <div className="p-2 bg-slate-50 border-b border-slate-200 flex gap-2 overflow-x-auto">
                    {currentTabFiles.map(file => (
                        <button
                            key={file.id}
                            onClick={() => setSelectedFile(file)}
                            className={`px-3 py-1.5 rounded text-xs border whitespace-nowrap transition-colors ${selectedFile?.id === file.id
                                ? 'bg-white border-primary-200 text-primary-700 shadow-sm'
                                : 'bg-slate-100 border-transparent text-slate-600 hover:bg-white hover:border-slate-200'
                                }`}
                        >
                            {file.fileName}
                        </button>
                    ))}
                </div>
            )}

            {/* 预览区域 */}
            <div className="flex-1 overflow-hidden relative">
                {loading ? (
                    <div className="h-full flex items-center justify-center text-slate-500">
                        <div className="animate-pulse">加载关联文件中...</div>
                    </div>
                ) : selectedFile ? (
                    <div className="h-full flex flex-col relative">
                        {/* 文件信息头 */}
                        <div className="flex items-center justify-between p-3 bg-slate-100 border-b border-slate-200">
                            <div className="flex items-center gap-2 truncate">
                                <FileText size={16} className="text-slate-500" />
                                <span className="text-sm font-medium text-slate-700 truncate">
                                    {selectedFile.fileName}
                                </span>
                                <span className="text-xs text-slate-400">
                                    ({(selectedFile.fileSize / 1024).toFixed(1)} KB)
                                </span>
                            </div>
                            <div className="flex items-center gap-2">
                                <a
                                    href={getPreviewUrl(selectedFile)}
                                    target="_blank"
                                    rel="noopener noreferrer"
                                    className="p-1.5 hover:bg-white rounded text-slate-500 hover:text-primary-600 transition-colors"
                                    title="新窗口打开"
                                >
                                    <ExternalLink size={16} />
                                </a>
                                <a
                                    href={getPreviewUrl(selectedFile)}
                                    download={selectedFile.fileName}
                                    className="p-1.5 hover:bg-white rounded text-slate-500 hover:text-primary-600 transition-colors"
                                    title="下载"
                                >
                                    <Download size={16} />
                                </a>
                            </div>
                        </div>

                        {/* 真实文件预览 */}
                        <div className="flex-1 bg-slate-200 overflow-hidden relative">
                            {/* Overlay for interaction (Only for invoices in this demo) */}
                            {activeTab === 'invoice' && (
                                <InvoiceOverlay
                                    highlightField={highlightField}
                                    onInteract={onInteract}
                                    highlightMeta={selectedFile.highlightMeta}
                                />
                            )}

                            <FileViewer
                                fileUrl={getPreviewUrl(selectedFile)}
                                fileType={selectedFile.fileType?.toLowerCase()}
                                fileName={selectedFile.fileName}
                                className="h-full"
                                token={token ?? undefined}
                            />
                        </div>
                    </div>
                ) : (
                    <div className="h-full flex flex-col items-center justify-center text-slate-400 bg-slate-50 m-4 rounded-lg border border-dashed border-slate-300">
                        <Paperclip size={48} className="mb-4 opacity-20" />
                        <p>暂无该类型文件</p>
                        <p className="text-xs mt-2 text-slate-400">已归档档案不可添加附件</p>
                    </div>
                )}
            </div>
        </div>
    );
};

// Input: React、lucide-react 图标、本地模块 api/autoAssociation、api/archives
// Output: React 组件 VoucherDetailCard
// Pos: src/pages/panorama/VoucherDetailCard.tsx
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useEffect, useState } from 'react';
import { ShieldCheck, AlertTriangle, FileText, CreditCard, Calendar, Hash, Info } from 'lucide-react';
import { autoAssociationApi, ComplianceStatus } from '../../api/autoAssociation';
import { archivesApi, Archive } from '../../api/archives';
import { originalVoucherApi, OriginalVoucher } from '../../api/originalVoucher';

interface VoucherDetailCardProps {
    voucherId: string;
    compact?: boolean;
    onFieldHover?: (fieldId: string | null) => void;
    activeField?: string | null;
    sourceType?: 'ARCHIVE' | 'ORIGINAL' | null;
    hideEntries?: boolean;
}

interface VoucherEntry {
    id: string;
    summary: string;
    subjectCode: string;
    subjectName: string;
    debit: string;
    credit: string;
    auxInfo?: string; // 辅助核算信息 (客户/供应商/项目等)
}

interface VoucherData {
    id: string;
    code: string;
    summary: string;
    date: string;
    amount: string;
    creator: string;
    status: string;
    entries: VoucherEntry[];
}

// 解析 YonSuite 凭证分录数据
const parseCustomMetadata = (metadata: string | undefined): VoucherEntry[] => {
    if (!metadata) return [];

    try {
        const entries = JSON.parse(metadata);
        if (!Array.isArray(entries)) return [];

        return entries.map((entry: any, index: number) => ({
            id: entry.id || String(index + 1),
            summary: entry.description || entry.summary || '无摘要',
            subjectCode: entry.accsubject?.code || entry.subjectCode || '',
            subjectName: entry.accsubject?.name || entry.subjectName || '未知科目',
            debit: entry.debit_org > 0 ? entry.debit_org.toLocaleString() : '-',
            credit: entry.credit_org > 0 ? entry.credit_org.toLocaleString() : '-',
            auxInfo: entry.aux_info || entry.auxInfo || undefined, // 辅助核算
        }));
    } catch (e) {
        console.warn('Failed to parse custom_metadata', e);
        return [];
    }
};

// 从分录中提取摘要作为凭证标题
const extractSummaryFromEntries = (entries: VoucherEntry[], fallbackTitle: string): string => {
    // 如果标题不是哈希值，直接使用
    if (fallbackTitle && !isHash(fallbackTitle)) {
        return fallbackTitle;
    }

    // 从第一条分录摘要中提取
    const firstEntry = entries[0];
    if (firstEntry && firstEntry.summary && firstEntry.summary !== '无摘要') {
        return firstEntry.summary;
    }

    return '会计凭证';
};

// 判断字符串是否为哈希值（长度超过 32 且仅包含十六进制字符）
const isHash = (str: string): boolean => {
    if (!str || str.length < 32) return false;
    return /^[a-f0-9]+$/i.test(str);
};

// 格式化制单人显示
const formatCreator = (creator: string | undefined, orgName: string | undefined): string => {
    if (creator && !isHash(creator)) {
        return creator;
    }
    if (orgName && !isHash(orgName)) {
        return orgName;
    }
    return '系统同步';
};

// 格式化状态显示
const formatStatus = (status: string): { label: string; color: string } => {
    const statusMap: Record<string, { label: string; color: string }> = {
        'archived': { label: '已归档', color: 'bg-emerald-500' },
        'pending': { label: '待处理', color: 'bg-amber-500' },
        'rejected': { label: '已驳回', color: 'bg-red-500' },
        'draft': { label: '草稿', color: 'bg-slate-400' },
    };
    return statusMap[status?.toLowerCase()] || { label: status || '未知', color: 'bg-slate-300' };
};

export const VoucherDetailCard: React.FC<VoucherDetailCardProps> = ({ voucherId, compact = false, onFieldHover, activeField, sourceType, hideEntries = false }) => {
    const [voucher, setVoucher] = useState<VoucherData | null>(null);
    const [compliance, setCompliance] = useState<ComplianceStatus | null>(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const mapArchiveToVoucher = (archive: Archive): VoucherData => {
        const entries = parseCustomMetadata(archive.customMetadata);
        const summary = extractSummaryFromEntries(entries, archive.title || '');
        const creator = formatCreator(archive.creator, archive.orgName);

        return {
            id: archive.id,
            code: archive.archiveCode || archive.id,
            summary,
            date: archive.docDate || archive.createdTime || '',
            amount: (archive.amount !== null && archive.amount !== undefined) ? `¥ ${Number(archive.amount).toLocaleString()}` : '-',
            creator,
            status: archive.status || '未知',
            entries
        };
    };

    const mapOriginalToVoucher = (ov: OriginalVoucher): VoucherData => {
        return {
            id: ov.id,
            code: ov.voucherNo,
            summary: ov.summary || '原始凭证',
            date: ov.businessDate || (ov as any).createdTime?.split('T')[0] || '',
            amount: (ov.amount !== null && ov.amount !== undefined) ? `¥ ${Number(ov.amount).toLocaleString()}` : '-',
            creator: ov.creator || (ov as any).createdBy || '上传',
            status: ov.archiveStatus || 'DRAFT',
            entries: [] // 原始凭证暂无分录，待 OCR/关联后产生
        };
    };

    useEffect(() => {
        if (!voucherId) return;

        const loadData = async () => {
            setLoading(true);
            setError(null);
            try {
                if (sourceType === 'ORIGINAL') {
                    // 直接获取原始凭证
                    const ov = await originalVoucherApi.getOriginalVoucher(voucherId);
                    if (ov) {
                        setVoucher(mapOriginalToVoucher(ov));
                        // 原始凭证暂无合规性检查
                        setCompliance(null);
                    } else {
                        setError('未找到原始凭证');
                    }
                } else {
                    // 默认或明确为 ARCHIVE，尝试获取归档档案
                    const res = await archivesApi.getArchiveById(voucherId);
                    if (res.code === 200 && res.data) {
                        setVoucher(mapArchiveToVoucher(res.data as Archive));

                        // 获取合规性状态 (仅对正式档案)
                        try {
                            const status = await autoAssociationApi.getComplianceStatus(voucherId);
                            setCompliance(status);
                        } catch {
                            setCompliance(null);
                        }
                    } else if (sourceType === null) {
                        // 如果类型未知且档案接口失败，降级尝试原始凭证
                        const ov = await originalVoucherApi.getOriginalVoucher(voucherId);
                        if (ov) {
                            setVoucher(mapOriginalToVoucher(ov));
                        } else {
                            setError('未找到档案或原始凭证');
                        }
                    } else {
                        setError('未找到该档案');
                    }
                }
            } catch (err: any) {
                console.error("VoucherDetailCard load error:", err);
                setError('加载数据失败');
            } finally {
                setLoading(false);
            }
        };

        loadData();
    }, [voucherId, sourceType]);

    const handleMouseEnter = (fieldId: string) => {
        if (onFieldHover) onFieldHover(fieldId);
    };

    const handleMouseLeave = () => {
        if (onFieldHover) onFieldHover(null);
    };

    if (!voucherId) {
        return (
            <div className="h-full flex items-center justify-center text-slate-400 bg-slate-50/50">
                <div className="text-center">
                    <FileText size={48} className="mx-auto mb-4 opacity-20" />
                    <p>请选择左侧凭证查看详情</p>
                </div>
            </div>
        );
    }

    if (loading) {
        return (
            <div className="h-full flex items-center justify-center text-slate-500">
                <div className="animate-pulse">加载中...</div>
            </div>
        );
    }

    if (error || !voucher) {
        return (
            <div className="h-full flex items-center justify-center text-slate-400 bg-slate-50/50">
                <div className="text-center">
                    <AlertTriangle size={48} className="mx-auto mb-4 text-amber-400" />
                    <p>{error || '暂无数据'}</p>
                </div>
            </div>
        );
    }

    const amountDisplay = typeof voucher.amount === 'string' && voucher.amount !== '-' ? voucher.amount.replace('¥ ', '') : '--';
    const statusInfo = formatStatus(voucher.status);

    // 计算合计借方/贷方
    const totalDebit = voucher.entries.reduce((sum, e) => {
        const val = parseFloat(e.debit.replace(/,/g, '')) || 0;
        return sum + val;
    }, 0);
    const totalCredit = voucher.entries.reduce((sum, e) => {
        const val = parseFloat(e.credit.replace(/,/g, '')) || 0;
        return sum + val;
    }, 0);

    return (
        <div className="h-full flex flex-col bg-white">
            {/* Header */}
            <div className={`${compact ? 'p-4' : 'p-6'} border-b border-slate-100 relative overflow-hidden`}>
                {/* 四性检测状态 */}
                <div className="absolute top-0 right-0 p-4">
                    {compliance === null ? (
                        <div className="flex items-center gap-2 px-3 py-1.5 bg-slate-50 text-slate-500 rounded-full border border-slate-200 shadow-sm">
                            <Info size={16} />
                            <span className="text-xs font-medium">待检测</span>
                        </div>
                    ) : compliance.passed ? (
                        <div className="flex items-center gap-2 px-3 py-1.5 bg-emerald-50 text-emerald-700 rounded-full border border-emerald-100 shadow-sm">
                            <ShieldCheck size={16} />
                            <span className="text-xs font-bold">四性检测通过</span>
                        </div>
                    ) : (
                        <div className="group relative">
                            <div className="flex items-center gap-2 px-3 py-1.5 bg-amber-50 text-amber-700 rounded-full border border-amber-100 shadow-sm cursor-help">
                                <AlertTriangle size={16} />
                                <span className="text-xs font-bold">四性检测未通过</span>
                            </div>
                            {/* 悬浮显示检测详情 */}
                            <div className="absolute right-0 top-full mt-2 w-64 p-3 bg-white border border-slate-200 rounded-lg shadow-lg opacity-0 group-hover:opacity-100 transition-opacity z-10">
                                <p className="text-xs font-bold text-slate-700 mb-2">未通过项目：</p>
                                <ul className="text-xs text-slate-600 space-y-1">
                                    {compliance.details?.authenticity === false && <li>• 真实性检测：哈希值不匹配</li>}
                                    {compliance.details?.integrity === false && <li>• 完整性检测：元数据不完整</li>}
                                    {compliance.details?.usability === false && <li>• 可用性检测：文件格式异常</li>}
                                    {compliance.details?.safety === false && <li>• 安全性检测：存在风险</li>}
                                    {(!compliance.details || (compliance.details.authenticity !== false && compliance.details.integrity !== false && compliance.details.usability !== false && compliance.details.safety !== false)) && (
                                        <li className="text-slate-400">暂无详细信息</li>
                                    )}
                                </ul>
                            </div>
                        </div>
                    )}
                </div>

                <h2 className="text-xl font-bold text-slate-800 mb-2 flex items-center gap-2 pr-32">
                    <FileText className="text-primary-600 flex-shrink-0" />
                    <span className="truncate">{voucher.code}</span>
                </h2>
                <p className="text-slate-600 text-sm mb-3 font-medium">{voucher.summary}</p>

                <div className={`grid ${compact ? 'grid-cols-1 gap-2' : 'grid-cols-2 gap-4'} text-sm`}>
                    <div className="flex items-center gap-2 text-slate-600">
                        <Calendar size={14} className="text-slate-400" />
                        <span>日期: {voucher.date || '-'}</span>
                    </div>
                    <div
                        className={`flex items-center gap-2 text-slate-600 cursor-pointer rounded px-1 -ml-1 transition-colors ${activeField === 'total_amount' ? 'bg-yellow-100 ring-2 ring-yellow-400' : 'hover:bg-yellow-50'
                            }`}
                        onMouseEnter={() => handleMouseEnter('total_amount')}
                        onMouseLeave={handleMouseLeave}
                    >
                        <CreditCard size={14} className="text-slate-400" />
                        <span>金额: <span className="font-mono font-bold text-slate-800">{voucher.amount}</span></span>
                    </div>
                    <div className="flex items-center gap-2 text-slate-600">
                        <Hash size={14} className="text-slate-400" />
                        <span>制单人: {voucher.creator}</span>
                    </div>
                    <div className="flex items-center gap-2 text-slate-600">
                        <div className={`w-2 h-2 rounded-full ${statusInfo.color}`} />
                        <span>状态: {statusInfo.label}</span>
                    </div>
                </div>
            </div>

            {/* Entries Table */}
            {!hideEntries && (
                <div className={`flex-1 overflow-y-auto ${compact ? 'p-4' : 'p-6'} bg-slate-50/30`}>
                    <h3 className="font-bold text-slate-700 mb-4 text-sm uppercase tracking-wider">会计分录</h3>
                    <div className="bg-white border border-slate-200 rounded-lg overflow-hidden shadow-sm">
                        <table className="w-full text-sm text-left">
                            <thead className="bg-slate-50 text-slate-500 font-medium border-b border-slate-200">
                                <tr>
                                    <th className="p-3 w-28">摘要</th>
                                    <th className="p-3">科目</th>
                                    <th className="p-3 text-right w-24">借方</th>
                                    <th className="p-3 text-right w-24">贷方</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-100">
                                {voucher.entries.length === 0 ? (
                                    <tr>
                                        <td colSpan={4} className="p-4 text-center text-slate-400">
                                            暂无分录数据（该凭证可能缺少元数据）
                                        </td>
                                    </tr>
                                ) : (
                                    voucher.entries.map(entry => (
                                        <tr
                                            key={entry.id}
                                            className={`transition-colors ${activeField === `entry_${entry.id}` || activeField === `tax_${entry.id}` // Support tax linking
                                                ? 'bg-yellow-50 ring-2 ring-yellow-400 ring-inset z-10 relative'
                                                : 'hover:bg-slate-50'
                                                }`}
                                        >
                                            <td className="p-3 text-slate-600 truncate max-w-[100px]" title={entry.summary}>
                                                {entry.summary}
                                            </td>
                                            <td className="p-3">
                                                <div className="flex flex-col">
                                                    <span className="font-medium text-slate-700">
                                                        {entry.subjectName}
                                                        {entry.auxInfo && (
                                                            <span className="text-primary-600">
                                                                —{entry.auxInfo.replace(/^(客户|供应商|项目|部门|员工)[：:]\s*/i, '')}
                                                            </span>
                                                        )}
                                                    </span>
                                                    <span className="text-xs text-slate-400 font-mono">{entry.subjectCode}</span>
                                                </div>
                                            </td>
                                            <td
                                                className="p-3 text-right font-mono text-slate-700 cursor-pointer hover:bg-yellow-50 transition-colors"
                                                onMouseEnter={() => handleMouseEnter(`debit_${entry.id}`)}
                                                onMouseLeave={handleMouseLeave}
                                            >
                                                {entry.debit}
                                            </td>
                                            <td
                                                className="p-3 text-right font-mono text-slate-700 cursor-pointer hover:bg-yellow-50 transition-colors"
                                                onMouseEnter={() => handleMouseEnter(`credit_${entry.id}`)}
                                                onMouseLeave={handleMouseLeave}
                                            >
                                                {entry.credit}
                                            </td>
                                        </tr>
                                    ))
                                )}
                            </tbody>
                            <tfoot className="bg-slate-50 font-bold text-slate-700 border-t border-slate-200">
                                <tr className={activeField === 'total_amount' ? 'bg-yellow-100' : ''}>
                                    <td colSpan={2} className="p-3 text-right">合计</td>
                                    <td className="p-3 text-right font-mono">{totalDebit > 0 ? totalDebit.toLocaleString() : amountDisplay}</td>
                                    <td className="p-3 text-right font-mono">{totalCredit > 0 ? totalCredit.toLocaleString() : amountDisplay}</td>
                                </tr>
                            </tfoot>
                        </table>
                    </div>
                </div>
            )}
        </div>
    );
};

// Input: React、lucide-react 图标、本地模块 VoucherDetailCard、EvidencePreview、api/archives
// Output: React 组件 VoucherPlayer
// Pos: src/pages/panorama/VoucherPlayer.tsx
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useState, useEffect, useCallback } from 'react';
import { ChevronLeft, ChevronRight, X, ShieldCheck } from 'lucide-react';
import { VoucherDetailCard } from './VoucherDetailCard';
import { EvidencePreview } from './EvidencePreview';
import { archivesApi } from '../../api/archives';

interface VoucherPlayerProps {
    initialVoucherId: string;
    onClose: () => void;
    sourceType?: 'ARCHIVE' | 'ORIGINAL' | null;
}

export const VoucherPlayer: React.FC<VoucherPlayerProps> = ({ initialVoucherId, onClose, sourceType }) => {
    const [currentVoucherId, setCurrentVoucherId] = useState(initialVoucherId);
    const [hoveredField, setHoveredField] = useState<string | null>(null);

    const [voucherList, setVoucherList] = useState<string[]>([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    // Fetch voucher list dynamically (e.g., from archives API)
    useEffect(() => {
        const fetchVouchers = async () => {
            if (sourceType === 'ARCHIVE') {
                setLoading(true);
                setError(null);
                try {
                    const res = await archivesApi.getArchives({ page: 1, limit: 100, categoryCode: 'AC01' });
                    if (res && res.code === 200 && res.data) {
                        const records = (res.data as any).records || [];
                        setVoucherList(records.map((r: any) => r.id));
                    }
                } catch (e) {
                    console.error('Failed to fetch voucher list in Player:', e);
                    setError('无法获取凭证列表');
                } finally {
                    setLoading(false);
                }
            } else {
                // For ORIGINAL or other modes, use a fallback list or just the initial ID
                setVoucherList([initialVoucherId]);
            }
        };

        fetchVouchers();
    }, [initialVoucherId, sourceType]);

    const currentIndex = voucherList.indexOf(currentVoucherId);

    const handlePrev = useCallback(() => {
        if (currentIndex > 0) {
            setCurrentVoucherId(voucherList[currentIndex - 1]);
        }
    }, [currentIndex, voucherList]);

    const handleNext = useCallback(() => {
        if (currentIndex < voucherList.length - 1) {
            setCurrentVoucherId(voucherList[currentIndex + 1]);
        }
    }, [currentIndex, voucherList]);

    // Keyboard navigation
    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if (e.key === 'ArrowLeft') handlePrev();
            if (e.key === 'ArrowRight') handleNext();
            if (e.key === 'Escape') onClose();
        };

        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [handlePrev, handleNext, onClose]);

    return (
        <div className="fixed inset-0 z-50 bg-slate-900 flex flex-col">
            {/* Top Bar */}
            <div className="h-12 bg-slate-800 flex items-center justify-between px-4 shrink-0 border-b border-slate-700">
                <div className="flex items-center gap-4 text-white">
                    <span className="font-bold text-lg">电子凭证翻阅器</span>
                    <span className="text-slate-400 text-sm">|</span>
                    <span className="text-slate-300 text-sm font-mono">{currentVoucherId}</span>
                </div>
                <div className="flex items-center gap-4">
                    <div className="flex items-center gap-2 text-slate-400 text-xs">
                        <ShieldCheck size={14} className="text-emerald-500" />
                        <span>已通过四性检测</span>
                    </div>
                    <button onClick={onClose} className="p-1 hover:bg-slate-700 rounded-full text-slate-400 hover:text-white transition-colors">
                        <X size={20} />
                    </button>
                </div>
            </div>

            {/* Main Content Area */}
            <div className="flex-1 flex overflow-hidden relative">
                {/* Watermark Overlay */}
                <div className="absolute inset-0 pointer-events-none z-50 flex items-center justify-center opacity-[0.03] overflow-hidden select-none">
                    <div className="rotate-[-30deg] text-slate-900 text-6xl font-bold whitespace-nowrap">
                        {Array(10).fill('操作员：张三  2025-12-04 10:30:00   ').map((text, i) => (
                            <div key={i} className="mb-32">{text}</div>
                        ))}
                    </div>
                </div>

                {/* Left Panel: Voucher (40%) */}
                <div className="w-[40%] bg-white h-full border-r border-slate-200 relative z-10">
                    <VoucherDetailCard
                        voucherId={currentVoucherId}
                        compact={true}
                        onFieldHover={setHoveredField}
                        activeField={hoveredField}
                        sourceType={sourceType}
                    />
                </div>

                {/* Right Panel: Evidence (60%) */}
                <div className="w-[60%] bg-slate-100 h-full relative z-10">
                    <EvidencePreview
                        voucherId={currentVoucherId}
                        highlightField={hoveredField}
                        onInteract={(field) => setHoveredField(field)}
                        sourceType={sourceType}
                    />
                </div>
            </div>

            {/* Bottom Navigation Bar */}
            <div className="h-14 bg-slate-800 border-t border-slate-700 flex items-center justify-center gap-8 shrink-0 relative z-20">
                <button
                    onClick={handlePrev}
                    disabled={currentIndex <= 0}
                    className={`flex items-center gap-2 px-6 py-2 rounded-full transition-all ${currentIndex <= 0
                        ? 'text-slate-600 cursor-not-allowed'
                        : 'text-white hover:bg-slate-700 active:scale-95'
                        }`}
                >
                    <ChevronLeft size={20} />
                    <span>上一张</span>
                </button>

                <div className="flex flex-col items-center">
                    <span className="text-white font-mono font-bold">{currentIndex + 1} / {voucherList.length}</span>
                    <div className="w-64 h-1 bg-slate-700 rounded-full mt-2 overflow-hidden">
                        <div
                            className="h-full bg-primary-500 transition-all duration-300"
                            style={{ width: `${((currentIndex + 1) / voucherList.length) * 100}%` }}
                        />
                    </div>
                </div>

                <button
                    onClick={handleNext}
                    disabled={currentIndex >= voucherList.length - 1}
                    className={`flex items-center gap-2 px-6 py-2 rounded-full transition-all ${currentIndex >= voucherList.length - 1
                        ? 'text-slate-600 cursor-not-allowed'
                        : 'text-white hover:bg-slate-700 active:scale-95'
                        }`}
                >
                    <span>下一张</span>
                    <ChevronRight size={20} />
                </button>
            </div>
        </div>
    );
};

// Input: [voucherId, isOpen, onClose]
// Output: [Slide-over Drawer with Metadata and File Preview]
// Pos: src/pages/panorama/VoucherPreviewDrawer.tsx
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useState, useEffect } from 'react';
import { Drawer, Button, Tag, Collapse, List, Space, message, Spin, Empty } from 'antd';
import { FileText, X, Fullscreen, CloudDownload, Link, Download } from 'lucide-react';
import { VoucherDetailCard } from './VoucherDetailCard';
import { EvidencePreview } from './EvidencePreview';
import { useNavigate } from 'react-router-dom';
import { yonsuiteApi } from '../../api/yonsuite';
import type { VoucherAttachment } from '../../api/yonsuite';

interface VoucherPreviewDrawerProps {
    voucherId: string | null;
    open: boolean;
    onClose: () => void;
}

export const VoucherPreviewDrawer: React.FC<VoucherPreviewDrawerProps> = ({ voucherId, open, onClose }) => {
    const navigate = useNavigate();

    // DEBUG: 在控制台打印版本标记
    React.useEffect(() => {
        console.log('[VoucherPreviewDrawer] Component loaded - VERSION 2025-01-05-12:10');
        if (voucherId) {
            console.log('[VoucherPreviewDrawer] Current voucherId:', voucherId);
        }
    }, [voucherId]);

    // YonSuite 附件相关状态
    const [attachments, setAttachments] = useState<VoucherAttachment[]>([]);
    const [attachmentsLoading, setAttachmentsLoading] = useState(false);
    const [attachmentsFetched, setAttachmentsFetched] = useState(false);

    // 查询 YonSuite 附件
    const handleFetchAttachments = async () => {
        if (!voucherId) return;

        setAttachmentsLoading(true);
        try {
            const configId = 1; // TODO: 从系统配置获取
            const response = await yonsuiteApi.queryVoucherAttachments(configId, [voucherId]);

            if (response && response.data && response.data[voucherId]) {
                setAttachments(response.data[voucherId]);
                setAttachmentsFetched(true);
                message.success(`查询到 ${response.data[voucherId].length} 个附件`);
            } else {
                setAttachments([]);
                setAttachmentsFetched(true);
                message.info('该凭证在 YonSuite 中没有附件');
            }
        } catch (error: any) {
            console.error('查询 YonSuite 附件失败:', error);
            message.error(`查询失败: ${error.message || '未知错误'}`);
            setAttachments([]);
        } finally {
            setAttachmentsLoading(false);
        }
    };

    // 当 voucherId 变化时重置附件状态
    useEffect(() => {
        setAttachments([]);
        setAttachmentsFetched(false);
    }, [voucherId]);

    const handleFullScreen = () => {
        if (voucherId) {
            navigate(`/system/panorama/${voucherId}`);
            onClose();
        }
    };

    return (
        <Drawer
            title={
                <div className="flex items-center justify-between w-full pr-8">
                    <div className="flex items-center gap-2">
                        <div className="w-8 h-8 rounded-lg bg-emerald-100 flex items-center justify-center text-emerald-600">
                            <FileText size={18} />
                        </div>
                        <div>
                            <span className="text-base font-semibold text-slate-800">原始凭证预览</span>
                            <Tag color="blue" className="ml-2 border-none bg-blue-50 text-blue-600">PRE-ARCHIVE</Tag>
                        </div>
                    </div>
                </div>
            }
            placement="right"
            onClose={onClose}
            open={open}
            size="large"
            extra={
                <div className="flex items-center gap-2">
                    <Button
                        type="text"
                        icon={<Fullscreen size={16} />}
                        onClick={handleFullScreen}
                        className="text-slate-500 hover:text-emerald-600"
                    >
                        全屏查看
                    </Button>
                </div>
            }
            closeIcon={<X size={20} className="text-slate-400" />}
            styles={{ body: { padding: 0, overflow: 'hidden' } }}
        >
            {voucherId ? (
                <div className="flex h-full bg-white">
                    {/* Left: Metadata Details + YonSuite Attachments */}
                    <div className="w-[320px] shrink-0 h-full border-r border-slate-100 bg-white overflow-y-auto">
                        {/* Voucher Detail Card */}
                        <VoucherDetailCard
                            voucherId={voucherId}
                            sourceType="ORIGINAL"
                            compact={true}
                            hideEntries={true}
                        />

                        {/* YonSuite Attachments */}
                        <div className="border-t border-slate-100">
                            <Collapse
                                defaultActiveKey={[]}
                                items={[
                                    {
                                        key: 'yonsuite-attachments',
                                        label: (
                                            <Space>
                                                <CloudDownload size={14} />
                                                <span>YonSuite 附件</span>
                                                {attachmentsFetched && (
                                                    <Tag color={attachments.length ? 'success' : 'default'}>
                                                        {attachments.length}
                                                    </Tag>
                                                )}
                                            </Space>
                                        ),
                                        extra: !attachmentsFetched ? (
                                            <Button
                                                size="small"
                                                type="primary"
                                                icon={<CloudDownload size={12} />}
                                                loading={attachmentsLoading}
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    handleFetchAttachments();
                                                }}
                                            >
                                                查询
                                            </Button>
                                        ) : null,
                                        children: (
                                            <div className="p-2">
                                                {attachmentsLoading ? (
                                                    <div className="text-center py-4">
                                                        <Spin size="small" tip="查询中..." />
                                                    </div>
                                                ) : !attachmentsFetched ? (
                                                    <Empty
                                                        image={Empty.PRESENTED_IMAGE_SIMPLE}
                                                        description="查询附件"
                                                    />
                                                ) : attachments.length > 0 ? (
