            {/* Close Button */}
            <button
              onClick={handleCloseQrModal}
              className="w-full py-3 bg-slate-200 text-slate-700 rounded-lg font-medium hover:bg-slate-300 transition-colors"
            >
              关闭
            </button>
          </div>
        </div>
      )}

      {/* Folder Monitor Dialog */}
      <FolderMonitorDialog
        open={isFolderMonitorOpen}
        onClose={() => setIsFolderMonitorOpen(false)}
        onSuccess={loadWorkspace}
      />
    </div>
  );
};

