// Input: React、React Router、Ant Design、scanApi
// Output: MobileUploadPage 组件 - 移动端扫描上传页面
// Pos: src/pages/scan/MobileUploadPage.tsx

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Button, Upload, message, Spin, Alert, Card, Typography } from 'antd';
import { CameraOutlined, UploadOutlined, CheckCircleOutlined } from '@ant-design/icons';
import type { UploadProps } from 'antd';
import { scanApi } from '@api/scan';

const { Title } = Typography;

export const MobileUploadPage: React.FC = () => {
  const { sessionId } = useParams<{ sessionId: string }>();

  const [loading, setLoading] = useState(true);
  const [sessionValid, setSessionValid] = useState(false);
  const [uploadedFiles, setUploadedFiles] = useState<string[]>([]);

  useEffect(() => {
    const validateSession = async () => {
      if (!sessionId) {
        setLoading(false);
        return;
      }
      try {
        const result = await scanApi.validateSession(sessionId);
        setSessionValid(result.valid);
      } catch {
        setSessionValid(false);
      } finally {
        setLoading(false);
      }
    };
    validateSession();
  }, [sessionId]);

  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' }}>
        <Spin size="large" />
      </div>
    );
  }

  if (!sessionValid) {
    return (
      <div style={{ padding: 24, maxWidth: 400, margin: '0 auto', marginTop: 100 }}>
        <Alert
          type="error"
          message="会话无效或已过期"
          description="请返回扫描页面重新获取二维码"
          showIcon
        />
      </div>
    );
  }

  const uploadProps: UploadProps = {
    name: 'file',
    multiple: true,
    accept: 'image/*,.pdf',
    showUploadList: true,
    customRequest: async (options) => {
      const { file, onSuccess, onError } = options;
      const fileObj = file as unknown as File;
      const fileName = fileObj.name || 'unknown';
      try {
        await scanApi.upload(fileObj, 'mobile', sessionId);
        setUploadedFiles([...uploadedFiles, fileName]);
        onSuccess?.({});
        message.success(`${fileName} 上传成功`);
      } catch (error) {
        onError?.(error as Error);
        message.error(`${fileName} 上传失败`);
      }
    },
  };

  return (
    <div
      style={{
        padding: 24,
        maxWidth: 600,
        margin: '0 auto',
        minHeight: '100vh',
        background: '#f5f5f5',
      }}
    >
      <Card>
        <Title level={4}>📱 扫描上传</Title>
        {uploadedFiles.length > 0 && (
          <Alert
            type="success"
            icon={<CheckCircleOutlined />}
            message={`已上传 ${uploadedFiles.length} 个文件`}
            style={{ marginBottom: 16 }}
          />
        )}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
          <Upload {...uploadProps}>
            <Button icon={<UploadOutlined />} size="large" block>
              选择照片
            </Button>
          </Upload>
          <Button type="primary" icon={<CameraOutlined />} size="large" block>
            拍照上传
          </Button>
        </div>
      </Card>
    </div>
  );
};

export default MobileUploadPage;

// Input: React、lucide-react、authTicketApi、fondsApi
// Output: AuthTicketApplyPage 组件
// Pos: 授权票据申请页面
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useState, useEffect } from 'react';
import { FileText, Calendar, Shield, Loader2, CheckCircle2, XCircle } from 'lucide-react';
import { authTicketApi, CreateAuthTicketRequest, AuthScope } from '../../api/authTicket';
import { fondsApi, BasFonds } from '../../api/fonds';
import { useFondsStore } from '../../store';

/**
 * 授权票据申请页面
 * 
 * 功能：
 * 1. 申请跨全宗访问授权票据
 * 2. 设置访问范围（全宗/期间/类型/关键词）
 * 3. 设置有效期和申请原因
 * 
 * PRD 来源: Section 2.4 - 跨全宗访问授权票据
 */
export const AuthTicketApplyPage: React.FC = () => {
    const { currentFonds } = useFondsStore();
    const [fondsList, setFondsList] = useState<BasFonds[]>([]);
    const [loading, setLoading] = useState(false);
    const [submitting, setSubmitting] = useState(false);
    const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

    const [form, setForm] = useState<CreateAuthTicketRequest>({
        targetFonds: '',
        scope: {
            accessType: 'READ_ONLY',
        },
        expiresAt: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().slice(0, 16), // 默认7天后
        reason: '',
    });

    useEffect(() => {
        loadFondsList();
    }, []);

    const loadFondsList = async () => {
        setLoading(true);
        try {
            const res = await fondsApi.list();
            if (res.code === 200 && res.data) {
                // 过滤掉当前全宗
                const filtered = res.data.filter(f => f.fondsCode !== currentFonds?.fondsCode);
                setFondsList(filtered);
            }
        } catch (error) {
            console.error('加载全宗列表失败', error);
        } finally {
            setLoading(false);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!form.targetFonds || !form.reason) {
            setMessage({ type: 'error', text: '请填写完整信息' });
            return;
        }

        setSubmitting(true);
        try {
            const res = await authTicketApi.apply(form);
            if (res.code === 200) {
                setMessage({ type: 'success', text: `授权票据申请成功，票据ID: ${res.data?.ticketId}` });
                setForm({
                    targetFonds: '',
                    scope: { accessType: 'READ_ONLY' },
                    expiresAt: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().slice(0, 16),
                    reason: '',
                });
            } else {
                setMessage({ type: 'error', text: res.message || '申请失败' });
            }
        } catch (error: any) {
            setMessage({ type: 'error', text: error?.response?.data?.message || '申请失败' });
        } finally {
            setSubmitting(false);
        }
    };

    const updateScope = (updates: Partial<AuthScope>) => {
        setForm({
            ...form,
            scope: { ...form.scope, ...updates },
        });
    };

    return (
        <div className="h-full flex flex-col bg-slate-50 p-6">
            <div className="bg-white rounded-lg shadow-sm border border-slate-200 max-w-3xl mx-auto w-full">
                {/* Header */}
                <div className="px-6 py-4 border-b border-slate-200">
                    <div className="flex items-center gap-3">
                        <Shield className="w-6 h-6 text-primary-600" />
                        <h1 className="text-xl font-semibold text-slate-900">申请跨全宗访问授权票据</h1>
                    </div>
                    <p className="text-sm text-slate-500 mt-1">申请访问其他全宗的授权票据，需要审批通过后才能使用</p>
                </div>

                {/* Message */}
                {message && (
                    <div className={`mx-6 mt-4 p-3 rounded-lg flex items-center gap-2 ${
                        message.type === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'
                    }`}>
                        {message.type === 'success' ? (
                            <CheckCircle2 className="w-5 h-5" />
                        ) : (
                            <XCircle className="w-5 h-5" />
                        )}
                        <span>{message.text}</span>
                        <button
                            onClick={() => setMessage(null)}
                            className="ml-auto text-slate-400 hover:text-slate-600"
                        >
                            ×
                        </button>
                    </div>
                )}

                {/* Form */}
                <form onSubmit={handleSubmit} className="p-6 space-y-6">
                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">
                            当前全宗 <span className="text-slate-400">(只读)</span>
                        </label>
                        <input
                            type="text"
                            value={currentFonds ? `${currentFonds.fondsName} (${currentFonds.fondsCode})` : '未选择'}
                            disabled
                            className="w-full px-3 py-2 border border-slate-300 rounded-lg bg-slate-50 text-slate-500"
                        />
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">
                            目标全宗 <span className="text-red-500">*</span>
                        </label>
                        <select
                            value={form.targetFonds}
                            onChange={(e) => setForm({ ...form, targetFonds: e.target.value })}
                            className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-500"
                            required
                            disabled={loading}
                        >
                            <option value="">请选择目标全宗</option>
                            {fondsList.map((f) => (
                                <option key={f.id} value={f.fondsCode}>
                                    {f.fondsName} ({f.fondsCode})
                                </option>
                            ))}
                        </select>
                    </div>

                    {/* 访问范围 */}
                    <div className="border border-slate-200 rounded-lg p-4 space-y-4">
                        <h3 className="text-sm font-medium text-slate-700">访问范围（可选，不填表示访问全部）</h3>

                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">
                                归档年度（多个用逗号分隔）
                            </label>
                            <input
                                type="text"
                                value={form.scope.archiveYears?.join(',') || ''}
                                onChange={(e) => {
                                    const years = e.target.value
                                        .split(',')
                                        .map(s => parseInt(s.trim()))
                                        .filter(n => !isNaN(n));
                                    updateScope({ archiveYears: years.length > 0 ? years : undefined });
                                }}
                                placeholder="例如: 2023,2024"
                                className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-500"
                            />
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">
                                档案类型（多个用逗号分隔）
                            </label>
                            <input
                                type="text"
                                value={form.scope.docTypes?.join(',') || ''}
                                onChange={(e) => {
                                    const types = e.target.value
                                        .split(',')
                                        .map(s => s.trim())
                                        .filter(s => s.length > 0);
                                    updateScope({ docTypes: types.length > 0 ? types : undefined });
                                }}
                                placeholder="例如: AC01,AC02"
                                className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-500"
                            />
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">
                                关键词（多个用逗号分隔）
                            </label>
                            <input
                                type="text"
                                value={form.scope.keywords?.join(',') || ''}
                                onChange={(e) => {
                                    const keywords = e.target.value
                                        .split(',')
                                        .map(s => s.trim())
                                        .filter(s => s.length > 0);
                                    updateScope({ keywords: keywords.length > 0 ? keywords : undefined });
                                }}
                                placeholder="例如: 发票,合同"
                                className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-500"
                            />
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">
                                访问类型
                            </label>
                            <select
                                value={form.scope.accessType || 'READ_ONLY'}
                                onChange={(e) => updateScope({ accessType: e.target.value as 'READ_ONLY' | 'READ_WRITE' })}
                                className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-500"
                            >
                                <option value="READ_ONLY">只读</option>
                                <option value="READ_WRITE">读写</option>
                            </select>
                        </div>
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">
                            有效期 <span className="text-red-500">*</span>
                        </label>
                        <input
                            type="datetime-local"
                            value={form.expiresAt}
                            onChange={(e) => setForm({ ...form, expiresAt: e.target.value })}
                            min={new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString().slice(0, 16)}
                            max={new Date(Date.now() + 90 * 24 * 60 * 60 * 1000).toISOString().slice(0, 16)}
                            className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-500"
                            required
                        />
                        <p className="text-xs text-slate-500 mt-1">有效期必须在1-90天之间</p>
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">
                            申请原因 <span className="text-red-500">*</span>
                        </label>
                        <textarea
                            value={form.reason}
                            onChange={(e) => setForm({ ...form, reason: e.target.value })}
                            rows={4}
                            className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary-500"
                            placeholder="请详细说明申请跨全宗访问的原因..."
                            required
                        />
                    </div>

                    <div className="flex gap-3">
                        <button
                            type="submit"
                            disabled={submitting}
                            className="px-6 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
                        >
                            {submitting ? <Loader2 className="w-4 h-4 animate-spin" /> : <FileText className="w-4 h-4" />}
                            提交申请
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
};

export default AuthTicketApplyPage;

// Input: React、lucide-react、authTicketApi
// Output: AuthTicketListPage 组件
// Pos: 授权票据列表和审批页面
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useState, useEffect } from 'react';
import { Shield, Search, Filter, CheckCircle2, XCircle, Clock, Ban, Eye, Loader2, MessageSquare } from 'lucide-react';
import { authTicketApi, AuthTicketDetail, ApprovalRequest } from '../../api/authTicket';
import { useFondsStore } from '../../store';

/**
 * 授权票据列表和审批页面
 * 
 * 功能：
 * 1. 查看授权票据列表
 * 2. 审批授权票据（第一审批、第二审批）
 * 3. 撤销授权票据
 * 4. 查看授权票据详情
 * 
 * PRD 来源: Section 2.4 - 跨全宗访问授权票据
 */
export const AuthTicketListPage: React.FC = () => {
    const { currentFonds } = useFondsStore();
    const [tickets, setTickets] = useState<AuthTicketDetail[]>([]);
    const [loading, setLoading] = useState(false);
    const [filterStatus, setFilterStatus] = useState<string>('all');
    const [page, setPage] = useState(1);
    const [total, setTotal] = useState(0);
    const pageSize = 20;
    const [selectedTicket, setSelectedTicket] = useState<AuthTicketDetail | null>(null);
    const [showDetailModal, setShowDetailModal] = useState(false);
    const [showApprovalModal, setShowApprovalModal] = useState(false);
    const [approvalType, setApprovalType] = useState<'first' | 'second'>('first');
    const [approvalForm, setApprovalForm] = useState<ApprovalRequest>({
        comment: '',
        approved: true,
    });
    const [submitting, setSubmitting] = useState(false);
    const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

    // 加载授权票据列表
    const loadTickets = async () => {
        setLoading(true);
        try {
            const params: any = {
                page,
                size: pageSize,
            };
            if (filterStatus !== 'all') {
                params.status = filterStatus;
            }
            if (currentFonds?.fondsNo) {
                params.sourceFonds = currentFonds.fondsNo;
            }
            const res = await authTicketApi.list(params);
            if (res.code === 200 && res.data) {
                setTickets(res.data.records || []);
                setTotal(res.data.total || 0);
            } else {
                setMessage({ type: 'error', text: res.message || '加载列表失败' });
            }
        } catch (error: any) {
            console.error('加载授权票据列表失败', error);
            setMessage({ type: 'error', text: error?.response?.data?.message || '加载列表失败' });
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadTickets();
    }, [page, filterStatus, currentFonds]);

    const handleViewDetail = async (ticketId: string) => {
        setLoading(true);
        try {
            const res = await authTicketApi.getDetail(ticketId);
            if (res.code === 200 && res.data) {
                setSelectedTicket(res.data);
                setShowDetailModal(true);
            }
        } catch (error) {
            console.error('查询授权票据详情失败', error);
            setMessage({ type: 'error', text: '查询详情失败' });
        } finally {
            setLoading(false);
        }
    };

    const handleApprove = async (ticketId: string, type: 'first' | 'second') => {
        setSelectedTicket(tickets.find(t => t.id === ticketId) || null);
        setApprovalType(type);
        setApprovalForm({ comment: '', approved: true });
        setShowApprovalModal(true);
    };

    const handleSubmitApproval = async () => {
        if (!selectedTicket) return;

        setSubmitting(true);
        try {
            const res = approvalType === 'first'
                ? await authTicketApi.firstApproval(selectedTicket.id, approvalForm)
                : await authTicketApi.secondApproval(selectedTicket.id, approvalForm);

            if (res.code === 200) {
                setMessage({ type: 'success', text: '审批成功' });
                setShowApprovalModal(false);
                // 重新加载列表
                loadTickets();
            } else {
                setMessage({ type: 'error', text: res.message || '审批失败' });
            }
        } catch (error: any) {
            setMessage({ type: 'error', text: error?.response?.data?.message || '审批失败' });
        } finally {
            setSubmitting(false);
        }
    };

    const handleRevoke = async (ticketId: string) => {
        const reason = prompt('请输入撤销原因:');
        if (!reason) return;

        setSubmitting(true);
        try {
            const res = await authTicketApi.revoke(ticketId, reason);
            if (res.code === 200) {
                setMessage({ type: 'success', text: '撤销成功' });
                // 重新加载列表
                loadTickets();
            } else {
                setMessage({ type: 'error', text: res.message || '撤销失败' });
            }
        } catch (error: any) {
            setMessage({ type: 'error', text: error?.response?.data?.message || '撤销失败' });
        } finally {
            setSubmitting(false);
        }
    };

    const getStatusLabel = (status: string) => {
        const labels: Record<string, string> = {
            'PENDING': '待审批',
            'APPROVED': '已批准',
            'REJECTED': '已拒绝',
            'REVOKED': '已撤销',
            'EXPIRED': '已过期',
        };
        return labels[status] || status;
    };

    const getStatusColor = (status: string) => {
        const colors: Record<string, string> = {
            'PENDING': 'bg-yellow-100 text-yellow-700',
            'APPROVED': 'bg-green-100 text-green-700',
            'REJECTED': 'bg-red-100 text-red-700',
            'REVOKED': 'bg-slate-100 text-slate-700',
            'EXPIRED': 'bg-orange-100 text-orange-700',
        };
        return colors[status] || 'bg-slate-100 text-slate-700';
    };

    const getStatusIcon = (status: string) => {
        switch (status) {
            case 'PENDING':
                return <Clock className="w-4 h-4" />;
            case 'APPROVED':
                return <CheckCircle2 className="w-4 h-4" />;
            case 'REJECTED':
                return <XCircle className="w-4 h-4" />;
            case 'REVOKED':
                return <Ban className="w-4 h-4" />;
            case 'EXPIRED':
                return <Clock className="w-4 h-4" />;
            default:
                return null;
        }
    };

    return (
        <div className="h-full flex flex-col bg-slate-50 p-6">
            <div className="bg-white rounded-lg shadow-sm border border-slate-200 flex-1 flex flex-col">
                {/* Header */}
                <div className="px-6 py-4 border-b border-slate-200">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <Shield className="w-6 h-6 text-primary-600" />
                            <h1 className="text-xl font-semibold text-slate-900">跨全宗访问授权票据</h1>
                        </div>
                        <a
                            href="/system/security/auth-ticket/apply"
                            className="px-4 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 text-sm"
                        >
                            + 申请授权票据
                        </a>
                    </div>
                    <p className="text-sm text-slate-500 mt-1">管理和审批跨全宗访问授权票据</p>
                </div>

                {/* Message */}
                {message && (
                    <div className={`mx-6 mt-4 p-3 rounded-lg flex items-center gap-2 ${
                        message.type === 'success' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'
                    }`}>
                        {message.type === 'success' ? (
                            <CheckCircle2 className="w-5 h-5" />
                        ) : (
                            <XCircle className="w-5 h-5" />
                        )}
                        <span>{message.text}</span>
                        <button
                            onClick={() => setMessage(null)}
                            className="ml-auto text-slate-400 hover:text-slate-600"
                        >
                            ×
                        </button>
                    </div>
                )}

                {/* Filters */}
                <div className="px-6 py-4 border-b border-slate-200 bg-slate-50">
                    <div className="flex gap-4 items-center">
                        <div className="flex items-center gap-2">
                            <Filter className="w-4 h-4 text-slate-400" />
                            <span className="text-sm text-slate-600">状态筛选:</span>
                        </div>
                        <select
                            value={filterStatus}
                            onChange={(e) => setFilterStatus(e.target.value)}
                            className="px-3 py-1.5 border border-slate-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-primary-500"
                        >
                            <option value="all">全部</option>
                            <option value="PENDING">待审批</option>
                            <option value="APPROVED">已批准</option>
                            <option value="REJECTED">已拒绝</option>
                            <option value="REVOKED">已撤销</option>
                            <option value="EXPIRED">已过期</option>
                        </select>
                    </div>
                </div>

                {/* Ticket List */}
                <div className="flex-1 overflow-y-auto p-6">
                    {loading ? (
                        <div className="flex items-center justify-center h-64">
                            <Loader2 className="w-6 h-6 animate-spin text-slate-400" />
                        </div>
                    ) : tickets.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-64 text-slate-400">
                            <Shield className="w-12 h-12 mb-2" />
                            <p>暂无授权票据</p>
                            <a
                                href="/system/security/auth-ticket/apply"
                                className="mt-4 text-primary-600 hover:text-primary-700"
                            >
                                申请授权票据
                            </a>
                        </div>
                    ) : (
                        <div className="space-y-4">
                            {tickets.map((ticket) => (
                                <div
                                    key={ticket.id}
                                    className="border border-slate-200 rounded-lg p-4 hover:shadow-md transition-shadow"
                                >
                                    <div className="flex items-start justify-between mb-3">
                                        <div className="flex items-center gap-3">
                                            <span className={`px-3 py-1 rounded-full text-xs font-medium flex items-center gap-1 ${getStatusColor(ticket.status)}`}>
                                                {getStatusIcon(ticket.status)}
                                                {getStatusLabel(ticket.status)}
                                            </span>
                                            <span className="text-sm text-slate-600">
                                                票据ID: {ticket.id}
