// Input: React、lucide-react、mfaApi
// Output: MfaSettingsPage 组件
// Pos: MFA 设置页面
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useState, useEffect } from 'react';
import { Shield, Loader2, CheckCircle2, XCircle, Copy, Download, Printer, AlertCircle, Eye, EyeOff } from 'lucide-react';
import { mfaApi, MfaStatus, MfaSetupResponse } from '../../api/mfa';

/**
 * MFA 设置页面
 * 
 * 功能：
 * 1. 启用/禁用 MFA
 * 2. TOTP 二维码展示
 * 3. 备用码生成和展示
 * 4. 备用码下载/打印
 * 
 * PRD 来源: Section 5.3 - 多因素认证
 */
export const MfaSettingsPage: React.FC = () => {
    const [status, setStatus] = useState<MfaStatus | null>(null);
    const [setupData, setSetupData] = useState<MfaSetupResponse | null>(null);
    const [loading, setLoading] = useState(false);
    const [verifying, setVerifying] = useState(false);
    const [verificationCode, setVerificationCode] = useState('');
    const [showBackupCodes, setShowBackupCodes] = useState(false);
    const [backupCodes, setBackupCodes] = useState<string[]>([]);
    const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

    useEffect(() => {
        loadStatus();
    }, []);

    const loadStatus = async () => {
        setLoading(true);
        try {
            const res = await mfaApi.getStatus();
            if (res.code === 200 && res.data) {
                setStatus(res.data);
            }
        } catch (error) {
            console.error('加载MFA状态失败', error);
        } finally {
            setLoading(false);
        }
    };

    const handleSetup = async () => {
        setLoading(true);
        try {
            const res = await mfaApi.setup();
            if (res.code === 200 && res.data) {
                setSetupData(res.data);
                setBackupCodes(res.data.backupCodes || []);
                setShowBackupCodes(true);
            } else {
                setMessage({ type: 'error', text: res.message || '设置失败' });
            }
        } catch (error: any) {
            setMessage({ type: 'error', text: error?.response?.data?.message || '设置失败' });
        } finally {
            setLoading(false);
        }
    };

    const handleVerify = async () => {
        if (!verificationCode.trim()) {
            setMessage({ type: 'error', text: '请输入验证码' });
            return;
        }

        setVerifying(true);
        try {
            const res = await mfaApi.verify(verificationCode.trim());
            if (res.code === 200) {
                setMessage({ type: 'success', text: 'MFA已启用' });
                setSetupData(null);
                setVerificationCode('');
                loadStatus();
            } else {
                setMessage({ type: 'error', text: res.message || '验证失败' });
            }
        } catch (error: any) {
            setMessage({ type: 'error', text: error?.response?.data?.message || '验证失败' });
        } finally {
            setVerifying(false);
        }
    };

    const handleDisable = async () => {
        if (!window.confirm('确认禁用MFA吗？禁用后将降低账户安全性。')) {
            return;
        }

        setLoading(true);
        try {
            const res = await mfaApi.disable();
            if (res.code === 200) {
                setMessage({ type: 'success', text: 'MFA已禁用' });
                loadStatus();
            } else {
                setMessage({ type: 'error', text: res.message || '禁用失败' });
            }
        } catch (error: any) {
            setMessage({ type: 'error', text: error?.response?.data?.message || '禁用失败' });
        } finally {
            setLoading(false);
        }
    };

    const handleLoadBackupCodes = async () => {
        try {
            const res = await mfaApi.getBackupCodes();
            if (res.code === 200 && res.data) {
                setBackupCodes(res.data);
                setShowBackupCodes(true);
            }
        } catch (error: any) {
            setMessage({ type: 'error', text: error?.response?.data?.message || '加载备用码失败' });
        }
    };

    const handleCopyBackupCodes = () => {
        const text = backupCodes.join('\n');
        navigator.clipboard.writeText(text).then(() => {
            setMessage({ type: 'success', text: '备用码已复制到剪贴板' });
        });
    };

    const handleDownloadBackupCodes = () => {
        const text = backupCodes.join('\n');
        const blob = new Blob([text], { type: 'text/plain' });
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = 'mfa-backup-codes.txt';
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        window.URL.revokeObjectURL(url);
    };

    const handlePrintBackupCodes = () => {
        const printWindow = window.open('', '_blank');
        if (printWindow) {
            printWindow.document.write(`
                <html>
                    <head><title>MFA备用码</title></head>
                    <body style="font-family: monospace; padding: 20px;">
                        <h2>MFA备用码</h2>
                        <p>请妥善保管这些备用码，每个码只能使用一次：</p>
                        <pre>${backupCodes.join('\n')}</pre>
                        <p><small>生成时间: ${new Date().toLocaleString('zh-CN')}</small></p>
                    </body>
                </html>
            `);
            printWindow.document.close();
            printWindow.print();
        }
    };

    if (loading && !status) {
        return (
            <div className="flex items-center justify-center h-64">
                <Loader2 className="animate-spin text-slate-400" size={32} />
            </div>
        );
    }

    const isMfaEnabled = status?.enabled || false;

    return (
        <div className="p-6 space-y-6">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-2xl font-bold text-slate-800 flex items-center">
                        <Shield className="mr-2" size={28} />
                        多因素认证 (MFA)
                    </h2>
                    <p className="text-slate-500 text-sm mt-1">使用TOTP验证器应用增强账户安全性</p>
                </div>
            </div>

            {/* 消息提示 */}
            {message && (
                <div className={`p-4 rounded-lg flex items-center gap-2 ${
                    message.type === 'success' 
                        ? 'bg-green-50 text-green-800 border border-green-200' 
                        : 'bg-red-50 text-red-800 border border-red-200'
                }`}>
                    {message.type === 'success' ? (
                        <CheckCircle2 size={20} />
                    ) : (
                        <XCircle size={20} />
                    )}
                    <span>{message.text}</span>
                    <button
                        onClick={() => setMessage(null)}
                        className="ml-auto text-slate-400 hover:text-slate-600"
                    >
                        ×
                    </button>
                </div>
            )}

            {/* MFA状态 */}
            <div className="bg-white border border-slate-200 rounded-lg p-6">
                <div className="flex items-center justify-between mb-4">
                    <div>
                        <h3 className="text-lg font-semibold">MFA状态</h3>
                        <p className="text-sm text-slate-500 mt-1">
                            {isMfaEnabled 
                                ? 'MFA已启用，您的账户受到双重保护' 
                                : 'MFA未启用，建议启用以增强账户安全性'}
                        </p>
                    </div>
                    <div className={`px-4 py-2 rounded-lg ${
                        isMfaEnabled 
                            ? 'bg-green-100 text-green-700' 
                            : 'bg-yellow-100 text-yellow-700'
                    }`}>
                        {isMfaEnabled ? '已启用' : '未启用'}
                    </div>
                </div>

                {!isMfaEnabled && !setupData && (
                    <button
                        onClick={handleSetup}
                        disabled={loading}
                        className="px-4 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed"
                    >
                        {loading ? <Loader2 className="animate-spin inline mr-2" size={16} /> : null}
                        启用MFA
                    </button>
                )}

                {isMfaEnabled && (
                    <div className="space-y-4">
                        <button
                            onClick={handleLoadBackupCodes}
                            className="px-4 py-2 border border-slate-300 rounded-lg text-slate-700 hover:bg-slate-50"
                        >
                            查看备用码
                        </button>
                        <button
                            onClick={handleDisable}
                            disabled={loading}
                            className="ml-3 px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 disabled:opacity-50 disabled:cursor-not-allowed"
                        >
                            {loading ? <Loader2 className="animate-spin inline mr-2" size={16} /> : null}
                            禁用MFA
                        </button>
                    </div>
                )}
            </div>

            {/* 设置流程：二维码和验证码输入 */}
            {setupData && !isMfaEnabled && (
                <>
                    <div className="bg-white border border-slate-200 rounded-lg p-6">
                        <h3 className="text-lg font-semibold mb-4">步骤1: 扫描二维码</h3>
                        <div className="flex flex-col items-center space-y-4">
                            <div className="p-4 bg-white border-2 border-slate-200 rounded-lg">
                                <img 
                                    src={setupData.qrCodeUrl} 
                                    alt="MFA QR Code" 
                                    className="w-64 h-64"
                                />
                            </div>
                            <p className="text-sm text-slate-600 text-center max-w-md">
                                使用验证器应用（如 Google Authenticator、Microsoft Authenticator）扫描上方二维码
                            </p>
                        </div>
                    </div>

                    <div className="bg-white border border-slate-200 rounded-lg p-6">
                        <h3 className="text-lg font-semibold mb-4">步骤2: 输入验证码</h3>
                        <div className="space-y-4">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-2">
                                    6位验证码
                                </label>
                                <input
                                    type="text"
                                    value={verificationCode}
                                    onChange={(e) => setVerificationCode(e.target.value.replace(/\D/g, '').slice(0, 6))}
                                    placeholder="000000"
                                    maxLength={6}
                                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500 text-center text-2xl tracking-widest font-mono"
                                />
                                <p className="text-xs text-slate-500 mt-1">
                                    输入验证器应用中显示的6位数字
                                </p>
                            </div>
                            <button
                                onClick={handleVerify}
                                disabled={verifying || verificationCode.length !== 6}
                                className="w-full px-4 py-2 bg-primary-600 text-white rounded-lg hover:bg-primary-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                            >
                                {verifying ? (
                                    <Loader2 className="animate-spin" size={16} />
                                ) : (
                                    <CheckCircle2 size={16} />
                                )}
                                完成设置
                            </button>
                        </div>
                    </div>
                </>
            )}

            {/* 备用码 */}
            {showBackupCodes && backupCodes.length > 0 && (
                <div className="bg-white border border-slate-200 rounded-lg p-6">
                    <div className="flex items-center justify-between mb-4">
                        <div>
                            <h3 className="text-lg font-semibold">备用码</h3>
                            <p className="text-sm text-slate-500 mt-1">
                                请妥善保管这些备用码，每个码只能使用一次。建议保存到安全的地方。
                            </p>
                        </div>
                        <button
                            onClick={() => setShowBackupCodes(false)}
                            className="text-slate-400 hover:text-slate-600"
                        >
                            <XCircle size={20} />
                        </button>
                    </div>
                    <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-4 mb-4 flex items-start gap-3">
                        <AlertCircle className="text-yellow-600 flex-shrink-0 mt-0.5" size={20} />
                        <div className="text-sm text-yellow-800">
                            <div className="font-semibold mb-1">重要提示</div>
                            <div>这些备用码现在只显示一次，请务必保存好。如果丢失，您可能需要重新设置MFA。</div>
                        </div>
                    </div>
                    <div className="grid grid-cols-2 gap-3 mb-4 p-4 bg-slate-50 rounded-lg">
                        {backupCodes.map((code, index) => (
                            <div key={index} className="font-mono text-sm text-center p-2 bg-white rounded border">
                                {code}
                            </div>
                        ))}
                    </div>
                    <div className="flex gap-3">
                        <button
                            onClick={handleCopyBackupCodes}
                            className="px-4 py-2 border border-slate-300 rounded-lg text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                        >
                            <Copy size={16} />
                            复制
                        </button>
                        <button
                            onClick={handleDownloadBackupCodes}
                            className="px-4 py-2 border border-slate-300 rounded-lg text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                        >
                            <Download size={16} />
                            下载
                        </button>
                        <button
                            onClick={handlePrintBackupCodes}
                            className="px-4 py-2 border border-slate-300 rounded-lg text-slate-700 hover:bg-slate-50 flex items-center gap-2"
                        >
                            <Printer size={16} />
                            打印
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
};

export default MfaSettingsPage;

// Input: React、recharts、lucide-react 图标、本地模块 api/stats
// Output: React 组件 StatsView
// Pos: src/pages/stats/StatsView.tsx
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useEffect, useMemo, useState } from 'react';
import { ResponsiveContainer, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, PieChart, Pie, Cell } from 'recharts';
import { AlertTriangle, Loader2 } from 'lucide-react';
import { statsApi, DashboardStats, StorageStats, ArchivalTrendPoint, TaskStatusStats } from '../../api/stats';

interface StatsViewProps {
  drillDown?: string;
  onNavigate?: (...args: any[]) => void;
}

const STORAGE_COLORS = ['#0ea5e9', '#cbd5e1'];
const TASK_COLORS = ['#0ea5e9', '#22c55e', '#f97316', '#f43f5e', '#8b5cf6', '#14b8a6'];

export const StatsView: React.FC<StatsViewProps> = () => {
  const [dashboard, setDashboard] = useState<DashboardStats | null>(null);
  const [storage, setStorage] = useState<StorageStats | null>(null);
  const [trend, setTrend] = useState<ArchivalTrendPoint[]>([]);
  const [taskStatus, setTaskStatus] = useState<TaskStatusStats | null>(null);
  const [loading, setLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  const storagePieData = useMemo(() => {
    if (!storage) return [];
    const used = Number(storage.usagePercent || 0);
    const free = Math.max(0, 100 - used);
    return [
      { name: `已使用 ${storage.used}`, value: used },
      { name: `剩余 (估算)`, value: free }
    ];
  }, [storage]);

  const taskStatusData = useMemo(() => {
    if (!taskStatus?.byStatus) return [];
    return Object.entries(taskStatus.byStatus).map(([name, value]) => ({
      name,
      value
    }));
  }, [taskStatus]);

  const loadData = async () => {
    setLoading(true);
    setError(null);
    try {
      const [dashRes, storageRes, trendRes, taskRes] = await Promise.all([
        statsApi.getDashboard(),
        statsApi.getStorage(),
        statsApi.getTrend(),
        statsApi.getTaskStatus()
      ]);

      const errors: string[] = [];

      if (dashRes.code === 200) {
        setDashboard(dashRes.data);
        if (dashRes.data?.recentTrend?.length) {
          setTrend(dashRes.data.recentTrend);
        }
      } else {
        errors.push('仪表盘指标');
      }

      if (storageRes.code === 200) {
        setStorage(storageRes.data);
      } else {
        errors.push('存储占用');
      }

      if (trendRes.code === 200 && (!dashRes.data?.recentTrend?.length)) {
        setTrend(trendRes.data || []);
      } else if (trendRes.code !== 200) {
        errors.push('归档趋势');
      }

      if (taskRes.code === 200) {
        setTaskStatus(taskRes.data);
      } else {
        errors.push('任务状态');
      }

      if (errors.length) {
        setError(`${errors.join(' / ')} 加载失败`);
      }
    } catch (e: any) {
      setError(e?.response?.data?.message || '统计数据加载失败');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const statCards = [
    { label: '总归档量', value: dashboard?.totalArchives ?? '--' },
    { label: '存储占用', value: dashboard?.storageUsed ?? '--' },
    { label: '待处理任务', value: dashboard?.pendingTasks ?? '--' },
    { label: '今日入库', value: dashboard?.todayIngest ?? '--' }
  ];

  return (
    <div className="p-8 space-y-6 max-w-[1600px] mx-auto animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">数据统计中心</h2>
          <p className="text-slate-500">基于真实接口的归档趋势与任务监控</p>
        </div>
        {loading && (
          <div className="text-sm text-slate-500 flex items-center gap-2">
            <Loader2 className="animate-spin" size={16} /> 数据刷新中...
          </div>
        )}
      </div>

      {error && (
        <div className="bg-rose-50 border border-rose-200 text-rose-700 px-4 py-3 rounded-lg text-sm flex items-center gap-2">
          <AlertTriangle size={16} /> {error}
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {statCards.map((stat, index) => (
          <div
            key={index}
            className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 relative overflow-hidden group"
          >
            <div className="absolute right-0 top-0 w-24 h-24 rounded-bl-full opacity-10 transition-transform group-hover:scale-110 bg-primary-500" />
            <div className="space-y-1">
              <h3 className="text-3xl font-bold text-slate-800 tracking-tight">{stat.value}</h3>
              <p className="text-sm text-slate-500 font-medium">{stat.label}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl shadow-sm border border-slate-200 h-[420px] flex flex-col">
          <div className="flex items-center justify-between mb-4">
            <div>
              <h3 className="text-lg font-bold text-slate-800">归档量趋势</h3>
              <p className="text-xs text-slate-500">近 14 日归档数量</p>
            </div>
          </div>
          <div className="flex-1">
            {trend.length === 0 ? (
              <div className="h-full flex items-center justify-center text-slate-400 text-sm">
                暂无趋势数据
              </div>
            ) : (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={trend}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                  <XAxis dataKey="date" axisLine={false} tickLine={false} />
                  <YAxis axisLine={false} tickLine={false} />
                  <Tooltip contentStyle={{borderRadius: '8px', border:'none', boxShadow:'0 4px 12px rgba(0,0,0,0.1)'}} />
                  <Bar dataKey="count" fill="#0ea5e9" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            )}
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 h-[420px] flex flex-col">
          <h3 className="text-lg font-bold text-slate-800 mb-2">存储占用</h3>
          <p className="text-xs text-slate-500 mb-4">实时容量占比</p>
          <div className="flex-1 flex items-center justify-center">
            {storagePieData.length === 0 ? (
              <div className="text-slate-400 text-sm">暂无存储数据</div>
            ) : (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={storagePieData}
                    cx="50%"
                    cy="50%"
                    innerRadius={70}
                    outerRadius={100}
                    paddingAngle={3}
                    dataKey="value"
                  >
                    {storagePieData.map((_, index) => (
                      <Cell key={index} fill={STORAGE_COLORS[index % STORAGE_COLORS.length]} />
                    ))}
                  </Pie>
                  <Tooltip />
                  <Legend />
                </PieChart>
              </ResponsiveContainer>
            )}
          </div>
          <div className="mt-4 text-center text-sm text-slate-600">
            <div>已使用：{storage?.used || '--'}</div>
            <div className="text-slate-500">总容量：{storage?.total || '未知'}</div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 h-[360px] flex flex-col">
          <h3 className="text-lg font-bold text-slate-800 mb-2">任务状态</h3>
          <p className="text-xs text-slate-500 mb-4">SIP / 归档任务进度</p>
          <div className="flex-1">
            {taskStatusData.length === 0 ? (
              <div className="text-slate-400 text-sm h-full flex items-center justify-center">暂无任务数据</div>
            ) : (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={taskStatusData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} />
                  <YAxis allowDecimals={false} axisLine={false} tickLine={false} />
                  <Tooltip />
                  <Bar dataKey="value" radius={[4, 4, 0, 0]}>
                    {taskStatusData.map((_, index) => (
                      <Cell key={`cell-${index}`} fill={TASK_COLORS[index % TASK_COLORS.length]} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            )}
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 h-[360px] flex flex-col">
          <h3 className="text-lg font-bold text-slate-800 mb-2">执行摘要</h3>
          <div className="grid grid-cols-2 gap-4 text-sm text-slate-700 flex-1">
            <div className="p-4 bg-slate-50 rounded-xl border border-slate-100">
              <div className="text-xs text-slate-500 mb-1">处理中</div>
              <div className="text-2xl font-bold text-slate-800">{taskStatus?.running ?? '--'}</div>
            </div>
            <div className="p-4 bg-slate-50 rounded-xl border border-slate-100">
              <div className="text-xs text-slate-500 mb-1">已完成</div>
              <div className="text-2xl font-bold text-emerald-600">{taskStatus?.completed ?? '--'}</div>
            </div>
            <div className="p-4 bg-slate-50 rounded-xl border border-slate-100">
              <div className="text-xs text-slate-500 mb-1">失败</div>
              <div className="text-2xl font-bold text-rose-600">{taskStatus?.failed ?? '--'}</div>
            </div>
            <div className="p-4 bg-slate-50 rounded-xl border border-slate-100">
              <div className="text-xs text-slate-500 mb-1">等待中</div>
              <div className="text-2xl font-bold text-amber-600">{taskStatus?.pending ?? '--'}</div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default StatsView;

// Input: React、本地模块 api/borrowing、hooks/usePermissions
// Output: React 组件 BorrowingView
// Pos: src/pages/utilization/BorrowingView.tsx
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import React, { useEffect, useMemo, useState, useCallback } from 'react';
import { borrowingApi, BorrowingRecord } from '../../api/borrowing';
import { usePermissions } from '../../hooks/usePermissions';
import {
    Plus,
    Search,
    BookOpen,
    CheckCircle,
    XCircle,
    Clock,
    RotateCcw,
    Loader2,
    ShieldCheck,
    Ban,
    Download,
    FileSpreadsheet
} from 'lucide-react';
import { triggerAuditRefresh } from '../../utils/audit';

const STATUS_OPTIONS = [
    { key: 'ALL', label: '全部' },
    { key: 'PENDING', label: '待审批' },
    { key: 'APPROVED', label: '已通过' },
    { key: 'REJECTED', label: '已拒绝' },
    { key: 'RETURNED', label: '已归还' },
    { key: 'CANCELLED', label: '已取消' }
];

const STATUS_META: Record<
    string,
    { label: string; color: string; icon: React.ReactNode }
> = {
    APPROVED: {
        label: '已通过',
        color: 'bg-emerald-50 text-emerald-700 border-emerald-200',
        icon: <CheckCircle size={12} />
    },
    PENDING: {
        label: '待审批',
        color: 'bg-amber-50 text-amber-700 border-amber-200',
        icon: <Clock size={12} />
    },
    RETURNED: {
        label: '已归还',
        color: 'bg-slate-100 text-slate-700 border-slate-200',
        icon: <RotateCcw size={12} />
    },
    REJECTED: {
        label: '已拒绝',
        color: 'bg-rose-50 text-rose-700 border-rose-200',
        icon: <XCircle size={12} />
    },
    CANCELLED: {
        label: '已取消',
        color: 'bg-slate-100 text-slate-500 border-slate-200',
        icon: <Ban size={12} />
    }
};

export const BorrowingView: React.FC = () => {
    const [borrowings, setBorrowings] = useState<BorrowingRecord[]>([]);
    const [loading, setLoading] = useState(false);
    const [statusFilter, setStatusFilter] = useState('ALL');
    const [onlyMine, setOnlyMine] = useState(false);
    const [page, setPage] = useState(1);
    const [pageSize, setPageSize] = useState(10);
    const [total, setTotal] = useState(0);
    const [search, setSearch] = useState('');
    const [error, setError] = useState<string | null>(null);
    const [toast, setToast] = useState<{ type: 'success' | 'error'; text: string } | null>(null);
    const [showCreateModal, setShowCreateModal] = useState(false);
    const [creating, setCreating] = useState(false);
    const [rowLoading, setRowLoading] = useState<string | null>(null);
    const [createForm, setCreateForm] = useState({
        archiveId: '',
        reason: '',
        expectedReturnDate: ''
    });
    const { hasPermission } = usePermissions();
    const canApprove = hasPermission('borrowing:approve');
    const canReturn = hasPermission('borrowing:return');
    const canCancel = hasPermission('borrowing:cancel');

    const displayedBorrowings = useMemo(() => {
        if (!search.trim()) return borrowings;
        const keyword = search.toLowerCase();
        return borrowings.filter(
            (item) =>
                (item.archiveTitle || '').toLowerCase().includes(keyword) ||
                (item.userName || '').toLowerCase().includes(keyword) ||
                (item.reason || '').toLowerCase().includes(keyword)
        );
    }, [borrowings, search]);

    const totalPages = Math.max(1, Math.ceil(total / pageSize));

    const fetchBorrowings = useCallback(async () => {
        setLoading(true);
        setError(null);
        try {
            const res = await borrowingApi.getBorrowings({
                status: statusFilter === 'ALL' ? undefined : statusFilter,
                my: onlyMine,
                page,
                limit: pageSize
            });
            if (res.code === 200 && res.data) {
                setBorrowings(res.data.records || []);
                setTotal(res.data.total || 0);
            } else {
                setBorrowings([]);
                setTotal(0);
                setError(res.message || '加载借阅列表失败');
            }
        } catch (err) {
            console.error('Failed to fetch borrowings', err);
            setBorrowings([]);
            setTotal(0);
            setError('加载借阅列表失败，请稍后重试');
        } finally {
            setLoading(false);
        }
    }, [statusFilter, onlyMine, page, pageSize]);

    useEffect(() => {
        fetchBorrowings();
    }, [fetchBorrowings]);

    const showToast = (text: string, type: 'success' | 'error' = 'success') => {
        setToast({ text, type });
        setTimeout(() => setToast(null), 2600);
    };

    const handleCreateSubmit = async () => {
        if (!createForm.archiveId.trim()) {
            showToast('请输入档案ID', 'error');
            return;
        }
        setCreating(true);
        try {
            const res = await borrowingApi.createBorrowing({
                archiveId: createForm.archiveId.trim(),
                reason: createForm.reason.trim(),
                expectedReturnDate: createForm.expectedReturnDate || undefined
            });
            if (res.code === 200) {
                showToast('借阅申请已提交');
                setShowCreateModal(false);
                setCreateForm({ archiveId: '', reason: '', expectedReturnDate: '' });
                setPage(1);
                fetchBorrowings();
                triggerAuditRefresh();
            } else {
                showToast(res.message || '提交失败', 'error');
            }
        } catch (err) {
            console.error('Create borrowing failed', err);
            showToast('提交失败，请稍后重试', 'error');
        } finally {
            setCreating(false);
        }
    };

    const handleApprove = async (id: string, approved: boolean) => {
        if (!canApprove) {
            showToast('无审批权限', 'error');
            return;
        }
        const tip = approved ? '通过该借阅申请？' : '拒绝该借阅申请？';
        if (!confirm(tip)) return;
        const comment = prompt('审批意见（可选）', '') || '';
        setRowLoading(id);
        try {
            const res = await borrowingApi.approveBorrowing(id, { approved, comment });
            if (res.code === 200) {
                showToast(approved ? '已审批通过' : '已拒绝申请');
                fetchBorrowings();
                triggerAuditRefresh();
            } else {
                showToast(res.message || '操作失败', 'error');
            }
        } catch (err) {
            console.error('Approve borrowing failed', err);
            showToast('操作失败，请稍后再试', 'error');
        } finally {
            setRowLoading(null);
        }
    };

    const handleReturn = async (id: string) => {
        if (!canReturn) {
            showToast('无归还操作权限', 'error');
            return;
        }
        if (!confirm('确认归还此档案吗？')) return;
        setRowLoading(id);
        try {
            const res = await borrowingApi.returnArchive(id);
            if (res.code === 200) {
                showToast('已归还');
                fetchBorrowings();
                triggerAuditRefresh();
            } else {
                showToast(res.message || '归还失败', 'error');
            }
        } catch (err) {
            console.error('Return borrowing failed', err);
            showToast('归还失败，请稍后重试', 'error');
        } finally {
            setRowLoading(null);
        }
    };

    const handleCancel = async (id: string) => {
        if (!canCancel) {
            showToast('无取消权限', 'error');
            return;
        }
        if (!confirm('确认取消此借阅申请？')) return;
        setRowLoading(id);
        try {
            const res = await borrowingApi.cancelBorrowing(id);
            if (res.code === 200) {
                showToast('已取消申请');
                fetchBorrowings();
                triggerAuditRefresh();
            } else {
                showToast(res.message || '取消失败', 'error');
            }
        } catch (err) {
            console.error('Cancel borrowing failed', err);
            showToast('取消失败，请稍后再试', 'error');
        } finally {
            setRowLoading(null);
        }
    };

    const handleExport = (format: 'csv' | 'excel') => {
        if (displayedBorrowings.length === 0) {
            showToast('当前没有可导出的数据', 'error');
            return;
        }
        const headers = ['申请单号', '档案题名', '申请人', '借阅日期', '预计归还', '实际归还', '状态', '审批意见'];
        const separator = format === 'csv' ? ',' : '\t';
        const rows = displayedBorrowings.map((item) =>
            [
                item.id,
                item.archiveTitle || '-',
                item.userName || '-',
                item.borrowDate || '-',
                item.expectedReturnDate || '-',
                item.actualReturnDate || '-',
                STATUS_META[item.status]?.label || item.status || '-',
                item.approvalComment || '-'
            ].map((cell) => `"${(cell || '').toString().replace(/"/g, '""')}"`).join(separator)
        );
        const content = [headers.join(separator), ...rows].join('\n');
        const blob = new Blob([`\uFEFF${content}`], {
            type: format === 'csv' ? 'text/csv;charset=utf-8;' : 'application/vnd.ms-excel'
        });
        const link = document.createElement('a');
        link.href = URL.createObjectURL(blob);
        link.download = format === 'csv' ? 'borrowing.csv' : 'borrowing.xls';
        link.click();
        URL.revokeObjectURL(link.href);
        showToast('导出开始下载');
    };

    return (
        <div className="p-6 h-full flex flex-col bg-slate-50">
            <div className="flex justify-between items-start mb-6">
                <div>
                    <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
                        <BookOpen className="text-blue-600" /> 档案借阅管理
                    </h2>
                    <p className="text-slate-500 text-sm mt-1">
                        管理借阅申请的发起、审批、归还与取消，支持状态筛选与导出
                    </p>
                </div>
                <div className="flex gap-2">
                    <button
                        onClick={() => handleExport('csv')}
                        className="px-3 py-2 rounded-lg border border-slate-200 text-slate-600 hover:bg-slate-100 flex items-center gap-2"
                    >
                        <Download size={16} /> CSV
                    </button>
                    <button
                        onClick={() => handleExport('excel')}
                        className="px-3 py-2 rounded-lg border border-slate-200 text-slate-600 hover:bg-slate-100 flex items-center gap-2"
                    >
                        <FileSpreadsheet size={16} /> Excel
                    </button>
                    <button
                        onClick={() => setShowCreateModal(true)}
                        className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition-colors shadow-sm"
                    >
                        <Plus size={18} /> 发起借阅
                    </button>
                </div>
            </div>

            <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm mb-4 flex flex-wrap gap-3 items-center">
                <div className="relative flex-1 min-w-[260px] max-w-md">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                    <input
                        type="text"
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                        placeholder="搜索申请人、档案题名或原因..."
                        className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500 transition-all"
                    />
                </div>
                <div className="flex gap-2 flex-wrap">
                    {STATUS_OPTIONS.map((status) => (
                        <button
                            key={status.key}
                            onClick={() => {
                                setStatusFilter(status.key);
                                setPage(1);
                            }}
                            className={`px-3 py-2 rounded-lg text-sm font-medium transition-colors ${statusFilter === status.key
                                    ? 'bg-slate-900 text-white'
                                    : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
                                }`}
                        >
                            {status.label}
                        </button>
                    ))}
                </div>
                <button
                    onClick={() => {
                        setOnlyMine((prev) => !prev);
                        setPage(1);
                    }}
                    className={`px-3 py-2 rounded-lg text-sm font-medium flex items-center gap-2 transition-colors ${onlyMine ? 'bg-blue-600 text-white' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
                        }`}
                >
                    <ShieldCheck size={16} /> 只看我的
                </button>
            </div>

            {error && (
                <div className="bg-rose-50 border border-rose-200 text-rose-700 rounded-lg p-3 mb-3 flex items-center justify-between">
                    <div className="flex items-center gap-2">
                        <XCircle size={16} />
                        <span>{error}</span>
                    </div>
                    <button onClick={fetchBorrowings} className="text-sm text-rose-700 underline">
                        重试
                    </button>
                </div>
            )}

            <div className="bg-white rounded-xl border border-slate-200 shadow-sm flex-1 overflow-hidden flex flex-col">
                <div className="overflow-x-auto flex-1">
                    <table className="w-full text-left text-sm">
                        <thead className="bg-slate-50 border-b border-slate-200 text-slate-500 font-medium">
                            <tr>
                                <th className="p-4 w-12">#</th>
                                <th className="p-4">档案题名</th>
                                <th className="p-4">申请人</th>
                                <th className="p-4">借阅日期</th>
                                <th className="p-4">预计归还</th>
                                <th className="p-4">实际归还</th>
                                <th className="p-4">状态</th>
                                <th className="p-4 text-right">操作</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {loading ? (
                                <tr>
                                    <td colSpan={8} className="p-8 text-center text-slate-400">
                                        <div className="flex items-center justify-center gap-2">
                                            <Loader2 className="animate-spin" size={16} />
                                            正在加载借阅数据...
                                        </div>
                                    </td>
                                </tr>
                            ) : displayedBorrowings.length === 0 ? (
                                <tr>
                                    <td colSpan={8} className="p-10 text-center text-slate-400">
                                        <div className="flex flex-col items-center gap-3">
                                            <BookOpen size={28} className="text-slate-300" />
                                            <div>暂无借阅记录</div>
                                            <button
                                                onClick={() => setShowCreateModal(true)}
                                                className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
                                            >
                                                发起首个借阅
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ) : (
                                displayedBorrowings.map((item, idx) => (
                                    <tr key={item.id} className="hover:bg-slate-50 transition-colors">
                                        <td className="p-4 text-slate-400">{(page - 1) * pageSize + idx + 1}</td>
                                        <td className="p-4">
                                            <div className="font-medium text-slate-800">{item.archiveTitle || '未知档案'}</div>
                                            <div className="text-xs text-slate-500 mt-1 line-clamp-1">{item.reason || '—'}</div>
                                        </td>
                                        <td className="p-4 text-slate-600">{item.userName || '-'}</td>
                                        <td className="p-4 text-slate-600">{item.borrowDate || '-'}</td>
                                        <td className="p-4 text-slate-600">{item.expectedReturnDate || '-'}</td>
                                        <td className="p-4 text-slate-600">{item.actualReturnDate || '-'}</td>
                                        <td className="p-4">
                                            <span
