    expect(result.current.archiveId).toBe(null);
    expect(result.current.activeTab).toBe('metadata'); // Reset to default
  });

  it('should set active tab', () => {
    const { result } = renderHook(() => useDrawerStore());
    act(() => {
      result.current.setActiveTab('attachments');
    });
    expect(result.current.activeTab).toBe('attachments');
  });

  it('should toggle expanded mode', () => {
    const { result } = renderHook(() => useDrawerStore());
    act(() => {
      result.current.setExpandedMode(true);
    });
    expect(result.current.expandedMode).toBe(true);
  });
});

// Input: zustand、persist 中间件与 safeStorage
// Output: useAuthStore 与 User 类型
// Pos: 前端认证状态管理
// 一旦我被更新，务必更新我的开头注释，以及所属的文件夹的 md。

import { create } from 'zustand';
import { persist, createJSONStorage } from 'zustand/middleware';
import { safeStorage } from '../utils/storage';

// ... (keep interfaces)

/**
 * 用户信息接口
 */
export interface User {
    id: string;
    username: string;
    realName?: string;
    fullName?: string;
    email?: string;
    avatar?: string;
    departmentId?: string;
    status?: string;
    roles?: string[];
    permissions?: string[];
    allowedFonds?: string[];  // 允许访问的全宗号列表（数据隔离键）
    // 新增字段：个人资料展示
    phone?: string;
    employeeId?: string;
    jobTitle?: string;
    orgCode?: string;
    lastLoginAt?: string;
    createdTime?: string;
    roleNames?: string[];
}

/**
 * 认证状态接口
 */
interface AuthState {
    // 状态
    token: string | null;
    user: User | null;
    isAuthenticated: boolean;
    isCheckingAuth: boolean;
    _hasHydrated: boolean; // 标记 zustand persist 是否已完成 hydration

    // Actions
    login: (token: string, user: User) => void;
    logout: () => void;
    setCheckingAuth: (checking: boolean) => void;
    setHasHydrated: (hydrated: boolean) => void;
    updateUser: (user: Partial<User>) => void;
    updatePermissions: (permissions: string[], roles?: string[]) => void;

    // 权限检查
    hasPermission: (perm: string) => boolean;
    hasAnyPermission: (perms: string[]) => boolean;
    hasRole: (role: string) => boolean;
    isSuperAdmin: () => boolean;
}

/**
 * 认证状态 Store
 * 
 * 使用 persist 中间件将状态持久化到 localStorage
 * 替代原有的 safeStorage 手动管理
 */
export const useAuthStore = create<AuthState>()(
    persist(
        (set, get) => ({
            // 初始状态
            token: null,
            user: null,
            isAuthenticated: false,
            isCheckingAuth: true,
            _hasHydrated: false, // 初始为 false，hydration 完成后变为 true

            // 登录
            login: (token, user) => {
                console.log('[AuthStore] Login:', user.username);
                set({
                    token,
                    user: {
                        ...user,
                        roles: user.roles || [],
                        permissions: user.permissions || [],
                    },
                    isAuthenticated: true,
                    isCheckingAuth: false,
                });
            },

            // 登出
            logout: () => {
                console.log('[AuthStore] Logout');
                set({
                    token: null,
                    user: null,
                    isAuthenticated: false,
                    isCheckingAuth: false,
                });
            },

            // 设置检查中状态
            setCheckingAuth: (checking) => set({ isCheckingAuth: checking }),

            // 设置 hydration 完成状态
            setHasHydrated: (hydrated) => set({ _hasHydrated: hydrated }),

            // 更新用户信息
            updateUser: (userData) => {
                const { user } = get();
                if (user) {
                    set({ user: { ...user, ...userData } });
                }
            },

            // 更新权限（从 /user/permissions 接口获取后调用）
            updatePermissions: (permissions, roles) => {
                const { user } = get();
                if (user) {
                    set({
                        user: {
                            ...user,
                            permissions,
                            roles: roles || user.roles,
                        },
                    });
                }
            },

            // 检查是否有指定权限（支持通配符匹配）
            hasPermission: (perm) => {
                const { user } = get();
                if (!user) return false;

                const permissions = user.permissions || [];
                return permissions.some((p) => {
                    // 完全匹配
                    if (p === perm) return true;
                    // 超级权限
                    if (p === '*') return true;
                    // 通配符匹配: "archive:*" 匹配 "archive:view"
                    if (p.endsWith('*')) {
                        const prefix = p.slice(0, -1);
                        return perm.startsWith(prefix);
                    }
                    return false;
                });
            },

            // 检查是否有任一权限
            hasAnyPermission: (perms) => {
                const { hasPermission } = get();
                return perms.some((p) => hasPermission(p));
            },

            // 检查是否有指定角色
            hasRole: (role) => {
                const { user } = get();
                return user?.roles?.includes(role) ?? false;
            },

            // 是否为超级管理员
            isSuperAdmin: () => {
                const { hasRole } = get();
                return hasRole('super_admin') || hasRole('SUPER_ADMIN');
            },
        }),
        {
            name: 'nexus-auth', // localStorage key
            version: 1, // 存储版本号，更新时递增以自动清除旧数据
            migrate: (persistedState, version) => {
                // 如果版本不匹配（旧版本或无版本），清除旧数据
                if (version < 1) {
                    console.warn('[AuthStore] Old storage version detected, clearing stale data');
                    return {
                        token: null,
                        user: null,
                        isAuthenticated: false,
                    };
                }
                return persistedState as AuthState;
            },
            partialize: (state) => ({
                // 只持久化这些字段
                token: state.token,
                user: state.user,
                isAuthenticated: state.isAuthenticated,
            }),
            // 使用 createJSONStorage 包装 safeStorage，处理序列化和类型
            storage: createJSONStorage(() => safeStorage),
            // hydration 完成后设置 _hasHydrated 为 true
            onRehydrateStorage: () => {
                console.log('[AuthStore] Starting hydration...');
                return (hydratedState, error) => {
                    if (error) {
                        console.error('[AuthStore] Hydration failed:', error);
                    } else {
                        console.log('[AuthStore] Hydration completed, token:', hydratedState?.token ? 'present' : 'null');
                    }
                };
            },
        }
    )
);

// 在 store 创建后手动检查和设置 hydration 状态
// 使用 persist API 的 onFinishHydration
if (typeof window !== 'undefined') {
    // 使用 zustand persist 的 rehydrate 完成时间很短，通常在下一个 tick 就完成
    // 我们使用 setTimeout 0 来确保在 hydration 完成后设置标志
    useAuthStore.persist.onFinishHydration(() => {
        console.log('[AuthStore] onFinishHydration called');
        useAuthStore.setState({ _hasHydrated: true });
    });

    // 如果 hydration 已经完成（快速加载场景），立即设置
    if (useAuthStore.persist.hasHydrated()) {
        console.log('[AuthStore] Already hydrated on init');
        useAuthStore.setState({ _hasHydrated: true });
    }
}

